export interface TaskListItemProps {
  pullRequest: Pull
  state?: SessionState
  merged: boolean
  lastSessionStartDate?: string
  revisionCount: number
}

export function AgentsViewWrapper() {
  const {agentsEnabled, hasCEorCBAccess, memberRequestEntities, initialAuthToken} =
    useAppPayload<AgentTasksAppPayload>()

  // Initialize auth token from SSR payload before any CAPI requests are made
  useInitializeAuthToken(initialAuthToken)

  return (
    <ConsecutiveCAPI401sProvider>
      <PacerLayout data-testid="agents-layout">
        <PacerLayout.Sidebar>
          <CopilotNavigationWithContext />
        </PacerLayout.Sidebar>

        <PacerLayout.ColumnLeft>
          {!agentsEnabled ? (
            <AgentsBlankslate hasCEorCBAccess={hasCEorCBAccess} memberRequestEntities={memberRequestEntities} />
          ) : (
            <AgentsView />
          )}
        </PacerLayout.ColumnLeft>
      </PacerLayout>
    </ConsecutiveCAPI401sProvider>
  )
}

export function AgentsView() {
  const [activeTab, setActiveTab] = useState<'open' | 'closed'>('open')
  const [searchParams, setSearchParams] = useSearchParams()
  const {
    sessionsPollingInterval,
    showCopilotCodingAgentPremiumRequestsBanner,
    tasks: initialTasks,
    pullRequestsMap: initialPullRequestsMap,
    initialAuthToken,
    transactionalMessageBanner,
  } = useAppPayload<AgentTasksAppPayload>()

  // Initialize auth token from SSR payload to avoid double token fetching
  useInitializeAuthToken(initialAuthToken)

  const isTaskListV2Enabled = useFeatureFlag('copilot_agent_task_list_v2')
  const linkToSessionsInRepo = useFeatureFlag('copilot_mission_control_link_to_sessions_in_repo')
  const linkToSessionsInHyperspace = useFeatureFlag('copilot_mission_control_link_to_hyperspace')
  const takenActionOnAgentsViewRef = useRef(false)

  const [failedTaskCreationAttempts, setFailedTaskCreationAttempts] = useState<FailedAPITaskCreationAttempt[]>([])

  const [isQuotaExhausted, setIsQuotaExhausted] = useState(false)
  const shouldShowQuotaBanner = useShouldShowCodingAgentQuotaBanner()

  // Detect SSO changes and clear cached tasks
  useSSOChangeDetection()

  const decoupledModeEnabled = isFeatureEnabled('copilot_mission_control_decoupled_mode')

  // It's not necessary to get the `isLoading` state from useTasks since it only applies to the first fetch,
  // and we already have all the initial data we need from the app payload.
  // TODO: Remove this call when we remove the old TaskList component below
  const {tasks, isError} = useTasks({
    sessionsPollingInterval,
    initialTasks,
    initialPullRequestsMap,
    // We need to include the filter/counts here in case this mounts before the AgentsList since they share
    // the same query key and we want to ensure the counts are available for the AgentsList to display
    taskFilter: activeTab,
    includeCounts: true,
  })

  const handleCreateTaskError = useCallback((error: Error, variables: CreateAPITaskMutationParams) => {
    setFailedTaskCreationAttempts(prev => [
      ...prev,
      {
        ...variables,
        errorMessage: error.message,
        timestamp: new Date().toISOString(),
      },
    ])
  }, [])

  const {createTask} = useCreateAPITask<FetchTasksResponse>({
    queryKey: getAgentTasksQueryKeyForMutation(),
    onError: handleCreateTaskError,
    pageSize: PAGE_SIZE,
    getFlatTaskList,
    setFlatTaskList,
    decoupledModeEnabled,
  })

  const manager = useChatManager()

  useEffect(() => {
    // Set the title of the page
    setTitle('Agents · GitHub Copilot')

    // Log feature flag values when AgentsView first renders
    sendEvent('agent_sessions.task_view', {
      target: 'AGENTS_VIEW_LOADED',
      defaultToTask: copilotFeatureFlags.defaultToTaskInput,
      defaultToTaskControl: copilotFeatureFlags.defaultToTaskControl,
      askModeDropdown: copilotFeatureFlags.askModeDropdown,
    })

    // Log bounce event if user leaves without creating a task
    return () => {
      if (!takenActionOnAgentsViewRef.current) {
        sendEvent('dotcom_chat.activate', {
          target: 'AGENTS_BOUNCE_TO_CHAT',
          mode: 'immersive',
          bounceToUrl: document.location.href,
          defaultToTask: copilotFeatureFlags.defaultToTaskInput,
          defaultToTaskControl: copilotFeatureFlags.defaultToTaskControl,
        })
      }
    }
  }, [])

  useEffect(() => {
    // clear out the thread on mount
    manager.selectThread(null, {includeThreads: false, clearTopic: true})
  }, [manager])

  const handleUserSubmit = useCallback(
    async (
      content: string,
      selectedRepo: DropdownRepository | null,
      selectedBranch: string,
      selectedAgent: SelectedAgent,
      selectedMode?: IntentDetectionMode,
      modelId?: string,
      createPullRequest?: boolean,
    ) => {
      takenActionOnAgentsViewRef.current = true

      const trimmedContent = content.trim()
      if (trimmedContent === '' || !selectedBranch || selectedBranch.trim() === '') return
      if (selectedRepo) {
        // Reset to open tab and page 1 when creating a new task
        setActiveTab('open')
        searchParams.delete('closed')
        searchParams.delete('page')
        setSearchParams(searchParams)

        // This mutation will automatically invalidate and refetch the tasks after completion
        createTask({
          nwo: selectedRepo.nameWithOwner,
          problemStatement: trimmedContent,
          baseRef: selectedBranch,
          eventType: 'agents_page',
          eventContent: trimmedContent,
          createPullRequest: !decoupledModeEnabled && createPullRequest,
          model: modelId,
          customAgent: selectedAgent?.subAgentSlug,
          agentId: selectedAgent?.topLevelAgentId,
          intentDetectionMode: selectedMode,
        })
      } else {
        manager.sendChatMessage({
          content: trimmedContent,
          thread: null,
          references: [],
        })
      }
    },
    [createTask, manager, searchParams, setSearchParams, decoupledModeEnabled],
  )

  useTaskEntrypoint(handleUserSubmit)

  // TODO: Now that we have uuids on the request, we might be able to use that to correlate requests and responses more easily.
  const handleRetry = (attemptIndex: number) => {
    const attempt = failedTaskCreationAttempts[attemptIndex]
    if (attempt) {
      // Remove this specific attempt from the list
      setFailedTaskCreationAttempts(prev => prev.filter((_, index) => index !== attemptIndex))
      createTask(getAPITaskParamsFromAttempt(attempt))
    }
  }

  const title = 'Agents'
  const description =
    "Delegate tasks to GitHub Copilot coding agent to work on in the background, and then monitor Copilot's progress."

  const [bannerDismissed, setBannerDismissed] = useState(false)

  return (
    <ContentView.Container noHeader width="small">
      {isFeatureEnabled('ipm_global_transactional_message_agents') && transactionalMessageBanner ? (
        <ContentView.Banner>
          <TransactionalMessageBanner banner={transactionalMessageBanner} />
        </ContentView.Banner>
      ) : null}
      {showCopilotCodingAgentPremiumRequestsBanner && !bannerDismissed ? (
        <ContentView.Banner>
          <PremiumRequestsBanner onBannerDismiss={() => setBannerDismissed(true)} />
        </ContentView.Banner>
      ) : null}
      {shouldShowQuotaBanner ? (
        <ContentView.Banner>
          <CopilotCodingAgentQuotaBanner
            onQuotaExhaustedChange={setIsQuotaExhausted}
            entrypointLocation="AGENTS_PAGE"
          />
        </ContentView.Banner>
      ) : null}
      <ContentView.Header>
        <ContentView.Title>{title}</ContentView.Title>
        <ContentView.Description>{description}</ContentView.Description>
      </ContentView.Header>
      <ContentView.Section>
        <NewTaskChatInput
          handleUserSubmit={handleUserSubmit}
          eventType="agents_page"
          isQuotaExhausted={isQuotaExhausted}
          decoupledModeEnabled={decoupledModeEnabled}
        />
        <TaskCreationFailedBannerList
          attempts={failedTaskCreationAttempts}
          onRetry={handleRetry}
          onDismiss={index => setFailedTaskCreationAttempts(prev => prev.filter((_, i) => i !== index))}
          className={styles.failedTaskBanners}
        />
      </ContentView.Section>

      <ContentView.Section>
        {isTaskListV2Enabled ? (
          <AgentsList
            title="Recent sessions"
            initialResultCount={PAGE_SIZE}
            showPillMenu
            showPagination
            linkToSessionsInRepo={shouldLinkToRepoTaskView(linkToSessionsInRepo, linkToSessionsInHyperspace)}
            activeTab={activeTab}
            setActiveTab={setActiveTab}
            includeCounts
          />
        ) : (
          <TaskList tasks={tasks} isError={isError} activeTab={activeTab} setActiveTab={setActiveTab} />
        )}
      </ContentView.Section>

      <CopilotDisclosure />
    </ContentView.Container>
  )
}

import type {SxProp} from '@primer/styled-react'
import {Truncate} from '@primer/react'
import {Text, Link} from '@primer/styled-react'

import styles from './Ago.module.css'

const millisecond = 1
const second = millisecond * 1000
const minute = second * 60
const hour = minute * 60
const day = hour * 24
const month = day * 30
const timeIntervals = [
  {unit: 'month', ms: month},
  {unit: 'day', ms: day},
  {unit: 'hour', ms: hour},
  {unit: 'minute', ms: minute},
  {unit: 'second', ms: second},
]
const fullDateFormatter = new Intl.DateTimeFormat(undefined, {
  year: 'numeric',
  month: 'short',
  day: 'numeric',
  hour: 'numeric',
  minute: 'numeric',
  second: undefined,
  timeZoneName: 'short',
})
const longDateFormatter = new Intl.DateTimeFormat(undefined, {year: 'numeric', month: 'short', day: 'numeric'})
const shortDateFormatter = new Intl.DateTimeFormat(undefined, {month: 'short', day: 'numeric'})

type AgoProps = {
  timestamp: Date
  linkUrl?: string | undefined
  usePreposition?: boolean
} & SxProp

export function agoString(timestamp: Date, usePreposition = true) {
  let timeString = ''
  const now = new Date()
  const difference = now.getTime() - timestamp.getTime()
  const interval = timeIntervals.find(i => i.ms < difference)

  // If the difference is greater than a month, just show the date
  if (interval && interval.unit !== 'month') {
    const ago = Math.floor(difference / interval.ms)
    if (interval.unit === 'day' && ago === 1) {
      timeString = `yesterday`
    } else {
      timeString = `${ago} ${interval.unit}${ago > 1 ? 's' : ''} ago`
    }
  } else {
    const formatter = timestamp.getFullYear() === now.getFullYear() ? shortDateFormatter : longDateFormatter
    timeString = `${usePreposition ? 'on ' : ''}${formatter.format(timestamp)}`
  }

  return timeString
}

// Primer Pattern Request: https://github.com/github/primer/issues/955
/**
 * @deprecated
 * use Primer's `RelativeTime` element instead
 */
export function Ago({timestamp, usePreposition = true, linkUrl, sx}: AgoProps) {
  const timeString = agoString(timestamp, usePreposition)
  const fullDateString = fullDateFormatter.format(timestamp)

  if (!linkUrl) {
    return (
      <Truncate inline title={fullDateString}>
        <Text title={fullDateString} sx={sx}>
          {timeString}
        </Text>
      </Truncate>
    )
  }

  return (
    <Link
      sx={{
        ...sx,
      }}
      href={linkUrl}
      target="_blank"
      className={styles.AgoTimestampLink}
    >
      <Truncate inline title={fullDateString}>
        {/* eslint-disable-next-line github/a11y-no-title-attribute */}
        <span title={fullDateString} className={styles.timestampText}>
          {timeString}
        </span>
      </Truncate>
    </Link>
  )
}

import type {AliveEvent, AliveSessionOptions, MetadataUpdate, Notifier, Subscription} from '@github/alive-client'
import {PresenceMetadataSet, SubscriptionSet, isPresenceChannel} from '@github/alive-client'
import {AliveSession} from './session'
import {debounce} from '@github/mini-throttle'
import {ready} from '@github-ui/document-ready'
import safeStorage from '@github-ui/safe-storage'
import {isSafari} from '@braintree/browser-detection'

export interface Dispatchable {
  dispatchEvent: (e: Event) => unknown
}

function isSharedWorkerSupported(): boolean {
  // There is currently a bug in safari that causes shared workers to stop working after a while
  // see https://github.com/github/web-systems/issues/965
  if (isSafari()) return false
  return 'SharedWorker' in window && safeStorage('localStorage').getItem('bypassSharedWorker') !== 'true'
}

export function workerSrc(): string | null {
  const url = document.head.querySelector<HTMLLinkElement>(`link[rel=shared-web-socket-src]`)?.getAttribute('href')

  // ensure we have a valid URL, otherwise don't use the worker
  if (!url || !url.startsWith('/')) {
    return null
  }

  return url
}

function socketUrl(): string | null {
  return document.head.querySelector<HTMLLinkElement>('link[rel=shared-web-socket]')?.href ?? null
}

function socketRefreshUrl(): string | null {
  return (
    document.head.querySelector<HTMLLinkElement>('link[rel=shared-web-socket]')?.getAttribute('data-refresh-url') ??
    null
  )
}

function sessionIdentifier(): string | null {
  return (
    document.head.querySelector<HTMLLinkElement>('link[rel=shared-web-socket]')?.getAttribute('data-session-id') ?? null
  )
}

/**
 * dispatches events of type: 'socket:message' | 'socket:presence'
 */
function notify(subscribers: Iterable<Dispatchable>, {channel, type, data}: AliveEvent) {
  for (const el of subscribers) {
    el.dispatchEvent(
      new CustomEvent(`socket:${type}`, {
        bubbles: false,
        cancelable: false,
        detail: {name: channel, data},
      }),
    )
  }
}

class AliveSessionProxy {
  #worker: SharedWorker
  #subscriptions = new SubscriptionSet<Dispatchable>()
  #presenceMetadata = new PresenceMetadataSet<Dispatchable>()
  #notify: Notifier<Dispatchable>

  constructor(
    src: string,
    url: string,
    refreshUrl: string,
    sessionId: string,
    notifier: Notifier<Dispatchable>,
    options: AliveSessionOptions,
  ) {
    this.#notify = notifier
    // eslint-disable-next-line ssr-friendly/no-dom-globals-in-constructor
    this.#worker = new SharedWorker(`${src}?module=true`, {
      name: `github-socket-worker-v3-${sessionId}`,
      type: 'module',
    })
    this.#worker.port.onmessage = ({data}) => this.#receive(data)
    this.#worker.port.postMessage({connect: {url, refreshUrl, options}})
  }

  subscribe(subs: Array<Subscription<Dispatchable>>) {
    const added = this.#subscriptions.add(...subs)
    if (added.length) {
      this.#worker.port.postMessage({subscribe: added})
    }

    // We may be adding a subscription to a presence channel which is already subscribed.
    // In this case, we need to explicitly ask the SharedWorker to send us the presence data.
    const addedChannels = new Set(added.map(topic => topic.name))
    const redundantPresenceChannels = subs.reduce((redundantChannels, subscription) => {
      const channel = subscription.topic.name

      if (isPresenceChannel(channel) && !addedChannels.has(channel)) {
        redundantChannels.add(channel)
      }

      return redundantChannels
    }, new Set<string>())

    if (redundantPresenceChannels.size) {
      this.#worker.port.postMessage({requestPresence: Array.from(redundantPresenceChannels)})
    }
  }

  unsubscribeAll(...subscribers: Dispatchable[]) {
    const removed = this.#subscriptions.drain(...subscribers)
    if (removed.length) {
      this.#worker.port.postMessage({unsubscribe: removed})
    }

    const updatedPresenceChannels = this.#presenceMetadata.removeSubscribers(subscribers)
    this.sendPresenceMetadataUpdate(updatedPresenceChannels)
  }

  updatePresenceMetadata(metadataUpdates: Array<MetadataUpdate<Dispatchable>>) {
    const updatedChannels = new Set<string>()

    for (const update of metadataUpdates) {
      // update the local metadata for this specific element
      this.#presenceMetadata.setMetadata(update)
      updatedChannels.add(update.channelName)
    }

    // Send the full local metadata for these channels to the SharedWorker
    this.sendPresenceMetadataUpdate(updatedChannels)
  }

  sendPresenceMetadataUpdate(channelNames: Set<string>) {
    if (!channelNames.size) {
      return
    }

    const updatesForSharedWorker: Array<Omit<MetadataUpdate<Element>, 'subscriber'>> = []

    for (const channelName of channelNames) {
      // get all metadata for this channel (from all elements) to send to the SharedWorker
      updatesForSharedWorker.push({
        channelName,
        metadata: this.#presenceMetadata.getChannelMetadata(channelName),
      })
    }

    // Send the full metadata updates to the SharedWorker
    this.#worker.port.postMessage({updatePresenceMetadata: updatesForSharedWorker})
  }

  online() {
    this.#worker.port.postMessage({online: true})
  }

  offline() {
    this.#worker.port.postMessage({online: false})
  }

  hangup() {
    this.#worker.port.postMessage({hangup: true})
  }

  #notifyPresenceDebouncedByChannel = new Map<string, Notifier<Dispatchable>>()
  #receive(event: AliveEvent) {
    const {channel} = event

    if (event.type === 'presence') {
      // There are times when we get a flood of messages from the SharedWorker, such as a tab that has been idle for a long time and then comes back to the foreground.
      // Since each presence message for a channel contains the full list of users, we can debounce the events and only notify subscribers with the last one
      let debouncedNotify = this.#notifyPresenceDebouncedByChannel.get(channel)
      if (!debouncedNotify) {
        debouncedNotify = debounce((subscribers, debouncedEvent) => {
          this.#notify(subscribers, debouncedEvent)
          this.#notifyPresenceDebouncedByChannel.delete(channel)
        }, 100)
        this.#notifyPresenceDebouncedByChannel.set(channel, debouncedNotify)
      }

      debouncedNotify(this.#subscriptions.subscribers(channel), event)
      return
    }

    // For non-presence messages, we can send them through immediately since they may contain different messages/data
    this.#notify(this.#subscriptions.subscribers(channel), event)
  }
}

async function connect() {
  const src = workerSrc()
  if (!src) return

  const url = socketUrl()
  if (!url) return

  const refreshUrl = socketRefreshUrl()
  if (!refreshUrl) return

  const sessionId = sessionIdentifier()
  if (!sessionId) return

  const createSession = () => {
    const options: AliveSessionOptions = {}

    if (isSharedWorkerSupported()) {
      try {
        return new AliveSessionProxy(src, url, refreshUrl, sessionId, notify, options)
      } catch {
        // ignore errors.  CSP will some times block SharedWorker creation. Fall back to standard AliveSession.
      }
    }

    return new AliveSession(url, refreshUrl, false, notify, options)
  }
  const session = createSession()

  window.addEventListener('online', () => session.online())
  window.addEventListener('offline', () => session.offline())
  window.addEventListener('pagehide', () => {
    if ('hangup' in session) session.hangup()
  })

  return session
}

async function connectWhenReady() {
  await ready
  return connect()
}

let sessionPromise: undefined | ReturnType<typeof connectWhenReady>

export function getSession() {
  return (sessionPromise ||= connectWhenReady())
}

