import {SkeletonText} from '../../Skeleton'
import type {DirectoryItem} from '@github-ui/code-view-types'
import {Link} from '@github-ui/react-core/link'
import type {Commit} from '@github-ui/repos-types'
import {VerifiedHTMLDiv} from '@github-ui/safe-html/VerifiedHTML'
import {FileDirectoryFillIcon, FileIcon, FileSubmoduleIcon, FileSymlinkFileIcon} from '@primer/octicons-react'
import {Link as PrimerLink, RelativeTime} from '@primer/react'
import type React from 'react'

interface ItemCellProps {
  item: DirectoryItem
}

interface NameItemCellProps extends ItemCellProps {
  getItemUrl: (item: DirectoryItem) => string
  onNavigate?: React.MouseEventHandler<HTMLAnchorElement>
  initialFocus: boolean
}

const contentTypeLabels: Record<string, string> = {
  directory: 'Directory',
  submodule: 'Submodule',
  ['symlink_directory']: 'Symlink to directory',
  ['symlink_file']: 'Symlink to file',
}

function getContentTypeLabel({contentType}: DirectoryItem) {
  return `(${contentTypeLabels[contentType] || 'File'})`
}

export function IconCell({item}: ItemCellProps) {
  // We can render up to 1000 <IconCell> on a page, and we get a significant perf improvement
  // by avoiding <Box> and using styles in CSS instead of JS. Please do not regress this.
  switch (item.contentType) {
    case 'directory':
      return <FileDirectoryFillIcon className="icon-directory" />
    case 'submodule':
      return <FileSubmoduleIcon className="icon-directory" />
    case 'symlink_directory':
      return <FileSubmoduleIcon className="icon-directory" />
    case 'symlink_file':
      return <FileSymlinkFileIcon className="icon-directory" />
    default:
      return <FileIcon className="color-fg-muted" />
  }
}

export function NameCell({initialFocus, item, getItemUrl, onNavigate}: NameItemCellProps) {
  let itemUrl = getItemUrl(item)
  const tooltipText = item.hasSimplifiedPath ? 'This path skips through empty directories' : item.name
  if (item.contentType === 'submodule') {
    itemUrl = item.submoduleUrl ?? itemUrl
    onNavigate = e => {
      // doing a react nav into a different repo doesn't work great
      e.preventDefault()
      if (item.submoduleUrl) {
        window.location.href = item.submoduleUrl
      }
    }
  }

  // We can render up to 1000 <NameCell> on a page, and we get a significant perf improvement
  // by avoiding <Box> and using styles in CSS instead of JS. Please do not regress this.
  return (
    <div className="overflow-hidden">
      <div className="react-directory-filename-cell">
        <div className="react-directory-truncate">
          <Link
            title={tooltipText}
            aria-label={`${item.name}, ${getContentTypeLabel(item)}`}
            className={
              item.contentType !== 'symlink_directory' && item.contentType !== 'symlink_file'
                ? 'Link--primary'
                : undefined
            }
            data-react-autofocus={initialFocus ? true : null}
            onClick={onNavigate}
            to={itemUrl}
          >
            <ItemPathName item={item} />
          </Link>
        </div>
      </div>
    </div>
  )
}

export function ItemPathName({item}: {item: DirectoryItem}) {
  // We can render up to 1000 <ItemPathName> on a page, and we get a significant perf improvement
  // by avoiding <Box> and using styles in CSS instead of JS. Please do not regress this.
  if (item.hasSimplifiedPath) {
    return (
      <>
        {item.name.split('/').map((dirName, index, array) => {
          const isLastItem = index === array.length - 1
          return (
            //should be a classname to get us fg.muted color
            <span
              // eslint-disable-next-line @eslint-react/no-array-index-key
              key={index}
              className={isLastItem ? '' : 'react-directory-default-color'}
              data-testid="path-name-segment"
            >
              {`${dirName}${isLastItem ? '' : '/'}`}
            </span>
          )
        })}
      </>
    )
  }

  return item.submoduleDisplayName ? (
    <span style={{color: 'var(--fgColor-accent, var(--color-accent-fg))'}}>{item.submoduleDisplayName}</span>
  ) : (
    <>{item.name}</>
  )
}

interface CommitCellProps {
  commit?: Commit
}

export function CommitMessageCell({commit}: CommitCellProps) {
  if (!commit) {
    return <SkeletonText />
  }

  // We can render up to 1000 <CommitMessageCell> on a page, and we get a significant perf improvement
  // by avoiding <Box> and using styles in CSS instead of JS. Please do not regress this.
  return commit.shortMessageHtmlLink ? (
    <div>
      <VerifiedHTMLDiv className="react-directory-commit-message" html={commit.shortMessageHtmlLink} />
    </div>
  ) : (
    <PrimerLink className="Link--secondary" href={commit.url}>
      No commit message
    </PrimerLink>
  )
}

export function CommitAgeCell({commit}: CommitCellProps) {
  // TODO: align how Ago labels are "1 year ago" vs "12 month age" etc.
  // We can render up to 1000 <CommitAgeCell> on a page, and we get a significant perf improvement
  // by avoiding <Box> and using styles in CSS instead of JS. Please do not regress this.
  return commit?.date ? (
    <div className="react-directory-commit-age">
      {!Number.isNaN(Date.parse(commit.date)) ? <RelativeTime datetime={commit.date} tense="past" /> : 'Invalid date'}
    </div>
  ) : (
    <SkeletonText />
  )
}

import {ChecksStatusBadge} from '@github-ui/commit-checks-status'
import {useMergeabilityLiveUpdates} from '@github-ui/mergebox'
import {useEffect, useMemo} from 'react'

import {useLiveCommitChecksStatus} from '../../hooks/use-live-commit-checks-status'
import styles from './PullRequestOverviewPreview.module.css'

interface ChecksStatusButtonProps {
  headSha: string
  repositoryNwo: string
  commitAliveChannel?: string
}

export function ChecksStatusButton({headSha, repositoryNwo, commitAliveChannel}: ChecksStatusButtonProps) {
  const [ownerLogin = '', name = ''] = repositoryNwo?.split('/') ?? []
  const repo = useMemo(() => ({ownerLogin, name}), [ownerLogin, name])

  const [checksDetails, fetchChecksDetails] = useLiveCommitChecksStatus(headSha, repo)

  // Set up live updates for checks status
  const channels = useMemo(
    () => ({
      stateChannel: commitAliveChannel,
      deployedChannel: null,
      reviewStateChannel: null,
      workflowsChannel: null,
      mergeQueueChannel: null,
      headRefChannel: null,
      baseRefChannel: null,
      gitMergeStateChannel: null,
      pullRequestChannel: null,
    }),
    [commitAliveChannel],
  )

  useMergeabilityLiveUpdates({
    channels,
    refetchQuery: fetchChecksDetails,
  })

  // Fetch initial data when component mounts
  useEffect(() => {
    if (headSha && repositoryNwo) {
      fetchChecksDetails()
    }
  }, [headSha, repositoryNwo, fetchChecksDetails])

  // Don't render if no required data or no checks data loaded yet
  if (!headSha || !repositoryNwo || !checksDetails || checksDetails.checkRuns.length === 0) {
    return null
  }

  const getCheckCountsText = () => {
    if (!checksDetails?.checkRuns) return ''

    const totalChecks = checksDetails.checkRuns.length
    const successfulChecks = checksDetails.checkRuns.filter(run => run.state === 'success').length

    return `${successfulChecks}/${totalChecks}`
  }

  const mapHeaderStateToStatusRollup = (headerState: string) => {
    switch (headerState) {
      case 'SUCCEEDED':
        return 'success'
      case 'FAILED':
        return 'failure'
      case 'PENDING':
        return 'pending'
      case 'UNSUCCESSFUL':
        return 'failure'
      default:
        return 'pending'
    }
  }

  return (
    <span className={styles.checksButton}>
      <ChecksStatusBadge
        statusRollup={mapHeaderStateToStatusRollup(checksDetails?.checksHeaderState || '')}
        combinedStatus={checksDetails}
        onWillOpenPopup={fetchChecksDetails}
        size="small"
        variant="default"
        descriptionText={getCheckCountsText()}
      />
    </span>
  )
}

import type {IconProps} from '@primer/octicons-react'
import type React from 'react'

export type CircleOcticonProps = {
  as?: React.ElementType
  size?: number
  icon: React.ComponentType<React.PropsWithChildren<{size?: IconProps['size']}>>
  bg?: string
  'aria-label'?: string
  style?: React.CSSProperties
  className?: string
}
function CircleOcticon(props: CircleOcticonProps) {
  const {size = 32, as, icon: IconComponent, bg, 'aria-label': ariaLabel, style, className, ...rest} = props
  return (
    <div
      style={{
        backgroundColor: bg,
        overflow: 'hidden',
        borderWidth: 0,
        borderRadius: '50%',
        borderStyle: 'solid',
        borderColor: 'var(--borderColor-default)',
        width: size,
        height: size,
      }}
    >
      <div
        style={{
          display: 'flex',
          width: size,
          height: size,
          alignItems: 'center',
          justifyContent: 'center',
          ...style,
        }}
        className={className}
        {...rest}
      >
        <IconComponent size={size} aria-label={ariaLabel} />
      </div>
    </div>
  )
}

export default CircleOcticon

