interface CopilotInitialMessageProps {
  message: string
  session: Session
}

export const CopilotInitialMessage = ({message, session}: CopilotInitialMessageProps) => {
  const {data: agentInfo, isLoading: isAgentInfoLoading} = useAgentInfo(session.agent_id)
  const {isChatSession} = useIntentDetection(session)
  const agentDisplayName = agentInfo?.display_name ?? 'Agent'

  if (isAgentInfoLoading) {
    return null
  }

  if (isChatSession) {
    return null
  }

  return (
    <div className={styles.container}>
      <AgentAvatar size={32} animationType="static" loopAnimation={false} agentId={session.agent_id} />
      <p className={styles.message}>{`${agentDisplayName} ${message}`}</p>
    </div>
  )
}

