import {AgentAvatar} from '../../AgentAvatar'
import {MarkdownRenderer} from '@github-ui/copilot-markdown'
import {LoadingSkeleton} from '@github-ui/skeleton/LoadingSkeleton'
import {isCompletionChunk, type LogEntry, type ReplyToCommentToolArgs} from '../../../types/session'
import {useLogs} from '../../../hooks/useLogs'
import styles from './CopilotMessage.module.css'
import {useCurrentUser} from '../../../contexts/CurrentUserContext'
import {clsx} from 'clsx'

interface CopilotMessageProps {
  logsPollingInterval: number
}

export function CopilotMessage({logsPollingInterval}: CopilotMessageProps) {
  const {currentUserIsSessionOwner} = useCurrentUser()
  const {
    data: logsData,
    isLoading,
    error,
  } = useLogs({logsPollingInterval, batchCompletedSessions: true, currentUserIsSessionOwner})

  // Extract reply_to_comment tool calls from logs
  const replyToCommentCalls = extractReplyToCommentCalls(logsData)

  if (isLoading) {
    return <LoadingMessage />
  }

  if (error) {
    return null
  }

  if (replyToCommentCalls.length === 0) {
    return null
  }

  return (
    <div className={styles.container}>
      {replyToCommentCalls.map((call, index) => (
        <div className={styles.message} key={call.comment_id}>
          <div className={styles.icon}>
            {index === 0 && <AgentAvatar size={32} animationType="static" loopAnimation={false} />}
          </div>
          <MarkdownRenderer className={styles.text} markdown={call.reply} />
        </div>
      ))}
    </div>
  )
}

const LoadingMessage = () => (
  <div className={styles.container}>
    <div className={styles.message}>
      <div className={styles.icon}>
        <LoadingSkeleton variant="elliptical" height="32px" width="32px" />
      </div>
      <div className={clsx(styles.text, styles.loadingText)}>
        <LoadingSkeleton variant="rounded" height="sm" width="100%" />
        <LoadingSkeleton variant="rounded" height="sm" width="100%" />
        <LoadingSkeleton variant="rounded" height="sm" width="70%" />
      </div>
    </div>
  </div>
)

function extractReplyToCommentCalls(logsData: LogEntry[] = []) {
  const replyToCommentCallsMap = new Map<string, ReplyToCommentToolArgs>()

  for (const logEntry of logsData) {
    if (isCompletionChunk(logEntry)) {
      for (const choice of logEntry.choices) {
        if (choice.delta.role !== 'assistant') {
          continue
        }
        const toolCalls = choice.delta.tool_calls || []
        for (const toolCall of toolCalls) {
          const toolName = toolCall.function?.name ?? toolCall.custom?.name
          const rawArguments = toolCall.function?.arguments ?? toolCall.custom?.input
          if (toolName !== 'reply_to_comment') {
            continue
          }
          if (!rawArguments) {
            continue
          }
          try {
            const args =
              typeof rawArguments === 'string'
                ? (JSON.parse(rawArguments) as ReplyToCommentToolArgs)
                : (rawArguments as ReplyToCommentToolArgs)
            replyToCommentCallsMap.set(logEntry.id, args)
          } catch {
            // Fall back to raw string for custom tools whose arguments are not JSON
            if (typeof rawArguments === 'string') {
              replyToCommentCallsMap.set(logEntry.id, {reply: rawArguments} as ReplyToCommentToolArgs)
            }
            // Skip malformed tool calls
          }
        }
      }
    }
  }

  return [...replyToCommentCallsMap.values()]
}

import React, {useMemo} from 'react'

export interface CopilotSettings {
  copilotAccessAllowed: boolean
  copilotSpacesEnabled: boolean
  modelsAccessAllowed: boolean
  modelsRepoIntegrationEnabled: boolean
}

const CopilotSettingsContext = React.createContext<CopilotSettings>({
  copilotAccessAllowed: false,
  copilotSpacesEnabled: false,
  modelsAccessAllowed: false,
  modelsRepoIntegrationEnabled: false,
})

interface CopilotSettingsProviderProps {
  copilotAccessAllowed?: boolean
  copilotSpacesEnabled?: boolean
  modelsAccessAllowed?: boolean
  modelsRepoIntegrationEnabled?: boolean
}

export function CopilotSettingsProvider({
  children,
  copilotAccessAllowed = false,
  copilotSpacesEnabled = false,
  modelsAccessAllowed = false,
  modelsRepoIntegrationEnabled = false,
}: React.PropsWithChildren<CopilotSettingsProviderProps>) {
  const value = useMemo(
    () => ({
      copilotAccessAllowed,
      copilotSpacesEnabled,
      modelsAccessAllowed,
      modelsRepoIntegrationEnabled,
    }),
    [copilotAccessAllowed, copilotSpacesEnabled, modelsAccessAllowed, modelsRepoIntegrationEnabled],
  )

  return <CopilotSettingsContext value={value}>{children}</CopilotSettingsContext>
}

export function useCopilotSettings() {
  return React.use(CopilotSettingsContext)
}

export function isCopilot(login: string) {
  // need a more dynamic way to check if this is an "Assignable" agent
  const lowercaseLogin = login.toLocaleLowerCase()
  return lowercaseLogin === 'copilot-swe-agent' || lowercaseLogin === 'copilot'
}

import {AlertIcon, CheckIcon, CopyIcon} from '@primer/octicons-react'
import {Spinner} from '@primer/react'
import {Octicon} from '@primer/react/deprecated'
import type React from 'react'

export const CopyState = {
  Idle: 'Idle',
  Fetching: 'Fetching',
  Success: 'Success',
  Error: 'Error',
} as const

export type CopyState = (typeof CopyState)[keyof typeof CopyState]

export function isClipboardSupported(): boolean {
  const hasClipboardApi = 'clipboard' in navigator
  const hasClipboardItem = typeof ClipboardItem !== 'undefined'

  return hasClipboardApi && hasClipboardItem
}

export async function fetchContent(url: string) {
  const res = await fetch(url, {method: 'get'})

  if (!res.ok) {
    throw new Error(`Failed to fetch ${url}: ${res.status} ${res.statusText}`)
  }

  const text = (await res.text()).replace(/\r?\n$/, '')

  return new Blob([text], {type: 'text/plain'})
}

interface CopyStateUI {
  ariaLabel: string
  content: React.ReactNode
}

/**
 * Get common UI for the button and action item based on the current state.
 */
export function getCopyStateUI(state: CopyState): CopyStateUI {
  let ariaLabel
  let content

  switch (state) {
    case CopyState.Success:
      ariaLabel = 'Copied!'
      content = <Octicon icon={CheckIcon} />
      break
    case CopyState.Fetching:
      ariaLabel = 'Copying'
      content = <Spinner size="small" />
      break
    case CopyState.Error:
      ariaLabel = 'Something went wrong. Try again.'
      content = <Octicon icon={AlertIcon} />
      break
    default:
      ariaLabel = 'Copy'
      content = <Octicon icon={CopyIcon} />
  }

  return {ariaLabel, content}
}

import {copyText} from '@github-ui/copy-to-clipboard'
import {CopyIcon} from '@primer/octicons-react'
import {ActionList, type ActionListItemProps} from '@primer/react'
import {useCallback} from 'react'

export type ActionListItemCopyToClipboardProps = {
  /** The content intended to be copied to the clipboard. */
  textToCopy: string
} & Omit<ActionListItemProps, 'onSelect'>

export function ActionListItemCopyToClipboard({textToCopy, children, ...props}: ActionListItemCopyToClipboardProps) {
  const onSelect = useCallback(async () => {
    await copyText(textToCopy)
  }, [textToCopy])

  return (
    <ActionList.Item onSelect={onSelect} {...props}>
      <ActionList.LeadingVisual>
        <CopyIcon />
      </ActionList.LeadingVisual>
      {children}
    </ActionList.Item>
  )
}

