import type {TreePayload} from '@github-ui/code-view-types'
import React, {useMemo} from 'react'

const TreeContext = React.createContext({} as TreePayload)

export function useCurrentTree() {
  return React.use(TreeContext)
}

export function CurrentTreeProvider({payload, children}: React.PropsWithChildren<{payload: TreePayload}>) {
  const {items, readme, totalCount, templateDirectorySuggestionUrl, showBranchInfobar} = payload

  const value = useMemo<TreePayload>(
    () => ({
      items,
      readme,
      totalCount,
      templateDirectorySuggestionUrl,
      showBranchInfobar,
    }),
    [items, readme, totalCount, templateDirectorySuggestionUrl, showBranchInfobar],
  )

  return <TreeContext value={value}>{children}</TreeContext>
}

import React, {useMemo} from 'react'

import type {PublicUser} from '../types/public-user'

interface CurrentUserContextType {
  currentUser: PublicUser | undefined
  currentUserIsSessionOwner: boolean
  isSingleSessionView: boolean
  optedInToFeedback: boolean
}

const CurrentUserContext = React.createContext<CurrentUserContextType | undefined>(undefined)

interface CurrentUserContextProviderProps {
  children: React.ReactNode
  currentUser: PublicUser | undefined
  currentUserIsSessionOwner: boolean
  optedInToFeedback?: boolean
}

export function CurrentUserProvider({
  currentUser,
  currentUserIsSessionOwner,
  optedInToFeedback = false,
  children,
}: CurrentUserContextProviderProps) {
  // A gentle hack. You can only query multiple sessions at once if you're the session owner.
  // So if the current user is not the session owner, we're in a single session view.
  const isSingleSessionView = !currentUserIsSessionOwner
  const value = useMemo(
    () => ({currentUser, currentUserIsSessionOwner, isSingleSessionView, optedInToFeedback}),
    [currentUser, currentUserIsSessionOwner, isSingleSessionView, optedInToFeedback],
  )
  return <CurrentUserContext value={value}> {children} </CurrentUserContext>
}

export function useCurrentUser() {
  const context = React.use(CurrentUserContext)
  if (!context) {
    throw new Error('useCurrentUser must be used within a CurrentUserProvider')
  }
  return context
}

import {Stack} from '@primer/react'
import {SkeletonText} from '@primer/react/experimental'
import type {ReactNode} from 'react'
import {useRef, useState, useEffect, useCallback} from 'react'
import type {CustomAgentSessionGroup} from '../../utils/group-agent-logs'
import {extractAgentName} from '../../utils/group-agent-logs'
import {NewToolHeader} from './tool/NewToolHeader'
import styles from './CustomAgentSessionGroup.module.css'
import toolGroupStyles from './tool-grouping/ToolGroupRenderer.module.css'
import {AgentsIcon16} from '../AgentsIcon'

interface CustomAgentSessionGroupProps {
  customAgentSession: CustomAgentSessionGroup
  children: ReactNode
}

/**
 * Renders a nested subagent session with visual indication of the grouping.
 * Shows the agent name from the start/end markers and renders all logs
 * within the subagent session with indentation.
 */
export function CustomAgentSessionGroup({customAgentSession, children}: CustomAgentSessionGroupProps) {
  const [isDetailsOpen, setIsDetailsOpen] = useState(true)
  const agentInstanceRef = useRef({})

  // Extract agent name from the start message
  const agentName = extractAgentName(customAgentSession.startMessage)

  // Format title as "Subagent: <name>"
  const title = `Subagent: ${agentName}`

  // Listen for global expand/collapse events
  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{expand: boolean; excludeInstance: object}>
      if (customEvent.detail.excludeInstance !== agentInstanceRef.current) {
        setIsDetailsOpen(customEvent.detail.expand)
      }
    }

    document.addEventListener('mission-control-tool-global-toggle', handler)
    return () => {
      document.removeEventListener('mission-control-tool-global-toggle', handler)
    }
  }, [])

  const handleModifierClick = useCallback((expand: boolean) => {
    setIsDetailsOpen(expand)

    // Dispatch event to all other tools
    const event = new CustomEvent('mission-control-tool-global-toggle', {
      detail: {expand, excludeInstance: agentInstanceRef.current},
    })
    document.dispatchEvent(event)
  }, [])

  const handleHeaderToggle = useCallback(() => {
    setIsDetailsOpen(prev => !prev)
  }, [])

  return (
    <div className={styles.detailsContainer}>
      <NewToolHeader
        title={title}
        isCollapsed={!isDetailsOpen}
        isPending={customAgentSession.isPending}
        onModifierClick={handleModifierClick}
        onToggle={handleHeaderToggle}
        leadingVisual={<AgentsIcon16 />}
      />
      {isDetailsOpen && (
        <div className={styles.toolContentWrapper}>
          <div className={toolGroupStyles.connectorLine} />
          <div className={styles.toolContent}>
            {customAgentSession.logs.length === 0 && customAgentSession.isPending ? (
              <LoadingSkeleton />
            ) : (
              <Stack direction="vertical" padding="none" gap="condensed">
                {children}
              </Stack>
            )}
          </div>
        </div>
      )}
    </div>
  )
}

/**
 * Shows a loading skeleton when subagent group is expanded but has no logs yet
 */
function LoadingSkeleton() {
  return (
    <div>
      <SkeletonText size="bodySmall" />
      <SkeletonText size="bodySmall" />
      <SkeletonText size="bodySmall" />
    </div>
  )
}

