import {Banner} from '@primer/react'
import {verifiedFetch} from '@github-ui/verified-fetch'
import {useState} from 'react'
import styles from './DecoupledModeBanner.module.css'

// Banner auto-expires on April 18, 2026 (2 months from launch)
const BANNER_EXPIRY_DATE = new Date('2026-04-18T00:00:00Z')

export function DecoupledModeBanner() {
  const [dismissed, setDismissed] = useState(false)

  // Don't show banner after expiry date
  if (new Date() > BANNER_EXPIRY_DATE) {
    return null
  }

  if (dismissed) {
    return null
  }

  return (
    <Banner
      variant="info"
      title="Pull requests on demand"
      hideTitle
      className={styles.banner}
      onDismiss={async () => {
        setDismissed(true)
        await verifiedFetch('/settings/dismiss-notice/copilot_coding_agent_decoupled_mode_banner', {method: 'POST'})
      }}
    >
      <Banner.Description>
        <span className="text-semibold">Pull requests on demand:</span> Sessions will no longer create a pull request
        upfront. To create one, add &quot;Create a PR&quot; to your prompt, or choose to create one after the session
        completes.
      </Banner.Description>
    </Banner>
  )
}

