import merge from 'lodash.merge'
import type {
  ChatMessage,
  Choice,
  CompletionChunk,
  CompletionUserMessage,
  LogEntry,
  HydratedLogEntry,
  ToolCallMetadataMap,
} from '../types/session'
import {isChatMessage, isCommandMessage, isCompletionChunk} from '../types/session'
import mergeWith from 'lodash.mergewith'
import type {CustomAgentGroupLogEntry} from './group-agent-logs'
import {groupCustomAgentLogs} from './group-agent-logs'
import {parseCopilotAnnotationsToCodeInsights} from './parse-copilot-annotations-to-code-insights'

type LogProcessingOptions = {
  preserveAssistantNarration?: boolean
  groupCustomAgentSessions?: boolean
}
/**
 * Copies assistant narration to `assistant_content` when a choice has both `content` and `tool_calls`.
 * Prevents narration from being overwritten when tool results are merged during deduplication.
 */
function preserveAssistantContent(logEntry: CompletionChunk): CompletionChunk {
  let hasUpdates = false
  const choices = logEntry.choices.map(choice => {
    const shouldPreserveAssistantContent =
      choice.delta.role === 'assistant' &&
      !!choice.delta.content &&
      !choice.delta.assistant_content &&
      (choice.delta.tool_calls?.length ?? 0) > 0
    if (!shouldPreserveAssistantContent) {
      return choice
    }
    hasUpdates = true
    return {
      ...choice,
      delta: {
        ...choice.delta,
        assistant_content: choice.delta.content,
      },
    }
  })

  if (!hasUpdates) {
    return logEntry
  }

  return {
    ...logEntry,
    choices,
  }
}

function maybePreserveAssistantContent(logEntry: CompletionChunk, shouldPreserve: boolean): CompletionChunk {
  if (!shouldPreserve) {
    return logEntry
  }
  return preserveAssistantContent(logEntry)
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function customChoiceMerger(firstValue: any, secondValue: any): any {
  // If we're combining choices arrays, combine tool calls with the same ID
  if (
    Array.isArray(firstValue) &&
    Array.isArray(secondValue) &&
    firstValue[0]?.hasOwnProperty('delta') &&
    secondValue[0]?.hasOwnProperty('delta')
  ) {
    const finalChoices = new Array<Choice>()
    const idToChoiceWithTool = new Map<string, Choice>()
    // Combine choices with the same tool ID
    for (const choice of firstValue.concat(secondValue)) {
      // Explicit assumption there will only be one tool call in a choice
      const tool = choice.delta.tool_calls?.[0]
      // Choices without tool calls are always unique
      if (!tool || !tool.id) {
        finalChoices.push(choice)
        continue
      }
      let newChoice = choice
      const existingChoice = idToChoiceWithTool.get(tool.id)
      if (existingChoice) {
        newChoice = merge({}, existingChoice, choice)
      }
      idToChoiceWithTool.set(tool.id, newChoice)
    }
    return finalChoices.concat(Array.from(idToChoiceWithTool.values()))
  }
  // Otherwise, use the default merge behavior
  return undefined
}

function extractToolCallMetadataFromChunk(chunk: CompletionChunk): ToolCallMetadataMap | undefined {
  const toolCallMetadata: ToolCallMetadataMap = {}

  // Process each choice and associate its annotations with its specific tool call
  for (const choice of chunk.choices) {
    const copilotAnnotations = choice.delta?.copilot_annotations
    if (!copilotAnnotations) {
      continue
    }

    const codeInsights = parseCopilotAnnotationsToCodeInsights(copilotAnnotations)
    if (!codeInsights) {
      continue
    }

    // Associate insights with the specific tool call in this choice
    // In practice there's only one tool call per choice
    const toolCalls = choice.delta?.tool_calls ?? []
    for (const toolCall of toolCalls) {
      if (toolCall.id) {
        const existingInsights = toolCallMetadata[toolCall.id]?.['code-insights']
        if (existingInsights) {
          // Merge with existing insights for this tool call
          toolCallMetadata[toolCall.id] = {
            'code-insights': {
              publicCodeReferences: [...existingInsights.publicCodeReferences, ...codeInsights.publicCodeReferences],
            },
          }
        } else {
          toolCallMetadata[toolCall.id] = {'code-insights': codeInsights}
        }
      }
    }
  }

  return Object.keys(toolCallMetadata).length > 0 ? toolCallMetadata : undefined
}

/**
 * Merges two tool-call metadata maps, concatenating code-insights arrays for matching tool_call_ids.
 * Deduplicates publicCodeReferences by annotationId to avoid duplicates when the same tool
 * appears in multiple chunks.
 */
function mergeToolCallMetadata(
  existing: ToolCallMetadataMap | undefined,
  incoming: ToolCallMetadataMap | undefined,
): ToolCallMetadataMap | undefined {
  if (!incoming) {
    return existing
  }
  if (!existing) {
    return incoming
  }

  const merged: ToolCallMetadataMap = {...existing}

  for (const [toolCallId, incomingBag] of Object.entries(incoming)) {
    const existingBag = merged[toolCallId]
    if (!existingBag) {
      merged[toolCallId] = incomingBag
      continue
    }

    // Merge code-insights if both have it
    const existingInsights = existingBag['code-insights']
    const incomingInsights = incomingBag['code-insights']

    if (existingInsights && incomingInsights) {
      // Deduplicate publicCodeReferences by annotationId
      const seenIds = new Set(existingInsights.publicCodeReferences.map(ref => ref.annotationId))
      const newRefs = incomingInsights.publicCodeReferences.filter(ref => !seenIds.has(ref.annotationId))

      merged[toolCallId] = {
        ...existingBag,
        ...incomingBag,
        'code-insights': {
          publicCodeReferences: [...existingInsights.publicCodeReferences, ...newRefs],
        },
      }
    } else {
      merged[toolCallId] = {...existingBag, ...incomingBag}
    }
  }

  return merged
}

export function dedupeCompletionChunks(
  completionChunks: CompletionChunk[] | undefined,
  options: LogProcessingOptions = {},
): CompletionChunk[] {
  if (!completionChunks) {
    return []
  }
  const shouldPreserve = options.preserveAssistantNarration ?? false
  const idToLogEntry = new Map<string, CompletionChunk>()

  for (const logEntry of completionChunks) {
    const logEntryWithAssistantContent = maybePreserveAssistantContent(logEntry, shouldPreserve)
    let newEntry = logEntryWithAssistantContent
    const existingEntry = idToLogEntry.get(logEntry.id)
    // If we already know about a logEntry with that ID, combine the log entries
    if (existingEntry) {
      newEntry = mergeWith({}, existingEntry, logEntryWithAssistantContent, customChoiceMerger)
    }
    idToLogEntry.set(logEntry.id, newEntry)
  }

  return [...idToLogEntry.values()]
}

export function preprocessLogEntries(
  logEntries: LogEntry[] | undefined,
  options: LogProcessingOptions = {},
): CustomAgentGroupLogEntry[] {
  if (!logEntries) {
    return []
  }
  const shouldPreserve = options.preserveAssistantNarration ?? false
  const idToLogEntry = new Map<string, HydratedLogEntry>()
  let previousCommandId = null
  let previousLogEntries: HydratedLogEntry[] = []

  if (logEntries !== undefined && isChatMessage(logEntries[0])) {
    // We already show the first message from a session chat sequence in
    // from the session content, so exclude it
    logEntries.shift()
  }

  for (const logEntry of logEntries) {
    // Handle chat messages first - they have threadID and may or may not have choices so non-chat messages will never
    // match isChatMessage but chat messages might match isCompletionChunk
    if (isChatMessage(logEntry)) {
      const existingEntry = idToLogEntry.get(logEntry.id)
      if (existingEntry && isChatMessage(existingEntry as LogEntry)) {
        // For assistant messages with choices, concatenate the content
        if (logEntry.role === 'assistant' && logEntry.choices && (existingEntry as ChatMessage).choices) {
          const existingChatMessage = existingEntry as ChatMessage
          const existingContent = existingChatMessage.choices?.[0]?.delta?.content ?? ''
          const newContent = logEntry.choices[0]?.delta?.content ?? ''
          const existingChoice = existingChatMessage.choices?.[0]
          const mergedEntry: ChatMessage = {
            ...logEntry,
            choices: existingChoice
              ? [
                  {
                    ...existingChoice,
                    delta: {
                      ...existingChoice.delta,
                      content: existingContent + newContent,
                    },
                  },
                ]
              : logEntry.choices,
          }
          idToLogEntry.set(logEntry.id, mergedEntry)
        } else {
          // For user messages or messages without choices, just replace
          idToLogEntry.set(logEntry.id, logEntry)
        }
      } else {
        idToLogEntry.set(logEntry.id, logEntry)
      }
    } else if (isCompletionChunk(logEntry)) {
      const logEntryWithAssistantContent = maybePreserveAssistantContent(logEntry, shouldPreserve)

      // Extract tool-call-scoped metadata from this chunk
      const incomingMetadata = extractToolCallMetadataFromChunk(logEntryWithAssistantContent)

      let newEntry: HydratedLogEntry = logEntryWithAssistantContent
      const existingEntry = idToLogEntry.get(logEntry.id)
      // If we already know about a logEntry with that ID, combine the log entries
      if (existingEntry) {
        const mergedBase = mergeWith({}, existingEntry, logEntryWithAssistantContent, customChoiceMerger)

        // Merge tool_call_metadata separately to handle deduplication
        const existingMetadata = 'tool_call_metadata' in existingEntry ? existingEntry.tool_call_metadata : undefined
        const mergedMetadata = mergeToolCallMetadata(existingMetadata, incomingMetadata)

        newEntry = mergedMetadata ? {...mergedBase, tool_call_metadata: mergedMetadata} : mergedBase
      } else if (incomingMetadata) {
        newEntry = {...logEntryWithAssistantContent, tool_call_metadata: incomingMetadata}
      }

      idToLogEntry.set(logEntry.id, newEntry)
      previousCommandId = null
      previousLogEntries = []
    } else if (isCommandMessage(logEntry)) {
      // If the previous entry was a command message, combine the two into a group
      let commandId = null
      let entries: CompletionUserMessage[] = []
      if (previousCommandId && previousLogEntries.length > 0) {
        commandId = previousCommandId
        entries = [...(previousLogEntries as CompletionUserMessage[]), logEntry]
      } else {
        commandId = logEntry.source
        entries = [logEntry]
      }
      idToLogEntry.set(commandId, entries)
      previousCommandId = commandId
      previousLogEntries = entries
    }
  }

  const preprocessed = [...idToLogEntry.values()]

  if (options.groupCustomAgentSessions) {
    return groupCustomAgentLogs(preprocessed)
  }

  return preprocessed
}

import type {DeferredAST} from '@github-ui/code-view-types'
import {type Repository, useCurrentRepository} from '@github-ui/current-repository'
import {isFeatureEnabled} from '@github-ui/feature-flags'
import {deferredASTPath} from '@github-ui/paths'
import {useQuery} from '@github-ui/react-query'
import type {RefInfo} from '@github-ui/repos-types'
import {verifiedFetchJSON} from '@github-ui/verified-fetch'
import React, {useEffect, useState} from 'react'

import {noVirtualizationThreshold} from '../components/blob/BlobContent/Code/CodeLinesNoVirtualization'

export const EmptyDeferredAST: DeferredAST = {
  stylingDirectives: null,
}

const DeferredASTContext = React.createContext(EmptyDeferredAST)

export function DeferredASTProvider({children, ...props}: React.PropsWithChildren<DeferredAST>) {
  return <DeferredASTContext value={props}>{children}</DeferredASTContext>
}

export function useDeferredAST() {
  return React.use(DeferredASTContext)
}

function isValidResponse(obj: DeferredAST): obj is DeferredAST {
  return Array.isArray(obj.stylingDirectives)
}

async function fetchDeferredAST(url: string | null): Promise<DeferredAST> {
  if (!url) return EmptyDeferredAST

  const response = await verifiedFetchJSON(url)

  if (response.ok) {
    const data = await response.json()
    if (data && isValidResponse(data)) {
      return data
    }
  }

  return EmptyDeferredAST
}

export function useDeferredASTQuery(
  refInfo: RefInfo | undefined,
  path: string | undefined,
  has404Error: boolean,
  fileLength: number,
): DeferredAST {
  const isNonVirtualized = isFeatureEnabled('react_blob_overlay')
  const repo = useCurrentRepository()
  const url =
    refInfo && path && !has404Error
      ? deferredASTPath({
          repo,
          commitish: refInfo.name,
          path,
        })
      : null

  const enabled = Boolean(url) && fileLength <= noVirtualizationThreshold && isNonVirtualized

  const {data} = useQuery({
    queryKey: ['deferredAST', repo.ownerLogin, repo.name, refInfo?.name, path, url],
    queryFn: () => fetchDeferredAST(url),
    enabled,
    placeholderData: EmptyDeferredAST,
  })

  return enabled ? (data ?? EmptyDeferredAST) : EmptyDeferredAST
}

export function useLoadDeferredAST(
  repo: Repository,
  refInfo: RefInfo,
  path: string,
  has404Error: boolean,
  fileLength: number,
): DeferredAST {
  const [state, setState] = useState<DeferredAST>(EmptyDeferredAST)
  const isNonVirtualized = isFeatureEnabled('react_blob_overlay')
  const url =
    refInfo && !has404Error
      ? deferredASTPath({
          repo,
          commitish: refInfo.name,
          path,
        })
      : null

  useEffect(() => {
    if (!url) return
    if (fileLength > noVirtualizationThreshold || !isNonVirtualized) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setState(EmptyDeferredAST)
      return
    }
    let cancelled = false
    const update = async () => {
      setState(EmptyDeferredAST)
      const response = await verifiedFetchJSON(url)

      if (cancelled) {
        return
      }

      try {
        if (response.ok) {
          const data = await response.json()
          if (data && isValidResponse(data)) {
            setState(data)
          }
        } else {
          setState(EmptyDeferredAST)
        }
      } catch {
        setState(EmptyDeferredAST)
      }
    }

    update()

    return function cancel() {
      cancelled = true
    }
  }, [url, fileLength, isNonVirtualized])

  return state
}

import type {DeferredMetadata} from '@github-ui/code-view-types'
