import {Button, Flash, Link, Popover} from '@primer/react'
import {useCallback} from 'react'

import {useCurrentBlob} from '../../../hooks/CurrentBlob'
import styles from './DependabotConfigurationBanner.module.css'

export function DependabotConfigurationBanner() {
  const {defaultBranch} = useCurrentRepository()
  const {name: currentRef} = useRefInfo()
  const {
    dependabotInfo: {showConfigurationBanner},
  } = useCurrentBlob()

  if (!showConfigurationBanner) return null

  const isDefaultBranch = defaultBranch === currentRef

  return isDefaultBranch ? <DefaultBranchDependabotConfigurationBanner /> : <DirectionsForNonDefaultBranch />
}

function DefaultBranchDependabotConfigurationBanner() {
  const {
    dependabotInfo: {
      configFilePath,
      networkDependabotPath,
      dismissConfigurationNoticePath,
      configurationNoticeDismissed,
    },
  } = useCurrentBlob()

  const dismissNotice = useCallback(
    () => verifiedFetch(dismissConfigurationNoticePath, {method: 'POST'}),
    [dismissConfigurationNoticePath],
  )

  if (configurationNoticeDismissed) return null

  return (
    <div className={styles.Box}>
      <Popover caret="top" open>
        <Popover.Content>
          <h5 className={styles.Text}>Dependabot</h5>
          <p className={styles.Text_1}>
            Dependabot creates pull requests to keep your dependencies secure and up-to-date.
          </p>
          <p className={styles.Text_1}>
            You can opt out at any time by removing the <code>{configFilePath}</code> config file.
          </p>
          <div className={styles.Box_1}>
            <Button as="a" href={networkDependabotPath}>
              View update status
            </Button>
            <Button variant="invisible" onClick={dismissNotice} className={styles.Button}>
              Dismiss
            </Button>
          </div>
        </Popover.Content>
      </Popover>
    </div>
  )
}

function DirectionsForNonDefaultBranch() {
  const {defaultBranch, name, ownerLogin} = useCurrentRepository()
  const path = usePath()
  const defaultBranchPath = blobPath({owner: ownerLogin, repo: name, commitish: defaultBranch, filePath: path})
  return (
    <Flash variant="warning">
      <h5>
        <AlertIcon />
        Cannot configure Dependabot from this branch
      </h5>
      <p>
        To configure Dependabot, you must use{' '}
        <Link inline href={defaultBranchPath}>
          this repository&apos;s default branch
        </Link>
      </p>
    </Flash>
  )
}

import {useState} from 'react'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {StaticUnifiedDiffPreview} from '@github-ui/diff-lines/static-unified-diff-preview'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import type {StaticDiffLine} from '@github-ui/diff-lines/conversation-types'
import styles from './Tool.module.css'

const COLLAPSE_THRESHOLD = 20

interface DiffPreviewProps {
  diffLines: StaticDiffLine[]
  canCollapse: boolean
}

export function DiffPreview({diffLines, canCollapse}: DiffPreviewProps) {
  const [isExpanded, setIsExpanded] = useState(false)

  const shouldCollapse = canCollapse && diffLines.length > COLLAPSE_THRESHOLD
  const visibleLines = shouldCollapse && !isExpanded ? diffLines.slice(0, COLLAPSE_THRESHOLD) : diffLines

  return (
    <>
      <StaticUnifiedDiffPreview diffLines={visibleLines} tabSize={4} className={styles.diffPreview} />

      {shouldCollapse && (
        <button
          type="button"
          className={styles.diffPreviewFooter}
          onClick={() => setIsExpanded(!isExpanded)}
          aria-label={isExpanded ? 'Collapse diff content' : `Expand diff to show all ${diffLines.length} lines`}
          aria-expanded={isExpanded}
        >
          {isExpanded
            ? `Collapse ${diffLines.length - COLLAPSE_THRESHOLD} lines`
            : `Show all ${diffLines.length} lines`}
        </button>
      )}
    </>
  )
}

import {useCurrentTree} from '../../../contexts/CurrentTreeContext'
