import type {WebCommitInfo} from '@github-ui/code-view-types'
import {ssrSafeLocation} from '@github-ui/ssr-utils'
// eslint-disable-next-line no-restricted-imports
import {useToastContext} from '@github-ui/toast/ToastContext'
import {useNavigate} from '@github-ui/use-navigate'
import {verifiedFetch} from '@github-ui/verified-fetch'
import {AlertIcon, GitBranchIcon, LockIcon, PencilIcon} from '@primer/octicons-react'
import {Banner, Button, Link} from '@primer/react'
import {Octicon} from '@primer/react/deprecated'

import styles from './EditIssues.module.css'

const PullRequestInfoBanner = ({
  webCommitInfo,
  repositoryName,
}: {
  webCommitInfo: WebCommitInfo
  repositoryName: string
}) => {
  const pullRequestEnabled = webCommitInfo.pullRequestEnabled ?? true
  const supportLink = webCommitInfo.supportFileUrl ? (
    <>
      {' '}
      If you need help, view the <b>{repositoryName}</b>{' '}
      <Link inline href={webCommitInfo.supportFileUrl}>
        support resources
      </Link>
      .
    </>
  ) : null

  if (pullRequestEnabled) {
    return (
      <Banner
        className={styles.Banner}
        title="You are not authorized to create pull requests in this repository"
        description={
          <p className={styles.BannerDescription}>
            The repository owner has restricted who can propose changes.{supportLink}
          </p>
        }
      />
    )
  }

  return (
    <Banner
      className={styles.Banner}
      title="Pull requests cannot be created in this repository"
      description={
        <p className={styles.BannerDescription}>The repository owner has disabled pull requests.{supportLink}</p>
      }
    />
  )
}

export function EditIssues({
  binary,
  helpUrl,
  webCommitInfo,
  repositoryName,
}: {
  binary: boolean
  helpUrl: string
  webCommitInfo: WebCommitInfo
  repositoryName: string
}) {
  const {shouldFork, lockedOnMigration, shouldUpdate, userOverRepositoryLimit} = webCommitInfo
  let pathname = ssrSafeLocation.pathname

  // Slice trailing slash because the csrf token is generated without it
  if (pathname.endsWith('/')) {
    pathname = pathname.slice(0, -1)
  }

  const navigate = useNavigate()
  const {addToast} = useToastContext()
  const currentPath = pathname + ssrSafeLocation.search

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()

    try {
      const response = await verifiedFetch(currentPath, {
        method: 'POST',
        headers: {
          Accept: 'application/json',
        },
      })

      if (response.ok) {
        // reload the page to reflect the fork/update
        navigate(currentPath)
      } else {
        // eslint-disable-next-line @github-ui/dotcom-primer/toast-migration
        addToast({
          type: 'error',
          message: 'An unexpected error occurred. Please try again.',
        })
      }
    } catch {
      // eslint-disable-next-line @github-ui/dotcom-primer/toast-migration
      addToast({
        type: 'error',
        message: 'An unexpected error occurred. Please try again.',
      })
    }
  }

  const issue = lockedOnMigration
    ? {
        message: 'This repository is currently being migrated.',
        description: 'Sorry, you’re not able to edit this repository while the migration is in progress.',
        icon: LockIcon,
      }
    : shouldFork
      ? userOverRepositoryLimit
        ? {
            message: 'You are over your repository limit',
            description: 'Sorry, you’re not able to fork this repository.',
            icon: AlertIcon,
          }
        : {
            message: 'You need to fork this repository to propose changes.',
            description:
              'Sorry, you’re not able to edit this repository directly—you need to fork it and propose your changes from there instead.',
            icon: GitBranchIcon,
          }
      : shouldUpdate
        ? {
            message: 'Sorry, it looks like your fork is outdated!',
            description: 'You’ll have to bring it up to date before you can propose changes.',
            icon: AlertIcon,
          }
        : binary
          ? {
              message: 'Binary file content is not editable.',
              description: 'But you can still rename or move it.',
              icon: PencilIcon,
            }
          : null
  if (!issue) return null

  const canCreatePullRequest = webCommitInfo.canCreatePullRequest ?? true
  return (
    <>
      {!canCreatePullRequest && <PullRequestInfoBanner webCommitInfo={webCommitInfo} repositoryName={repositoryName} />}
      <div className={styles.Box}>
        <Octicon icon={issue.icon} size="medium" className={styles.Octicon} />
        <h3 className={styles.Text}>{issue.message}</h3>
        <span className={styles.Text_1}>{issue.description}</span>
        {((shouldFork && !userOverRepositoryLimit) || shouldUpdate) && (
          <form
            onSubmit={handleSubmit}
            data-turbo="false"
            method="post"
            action={currentPath}
            data-testid="edit-issues-form"
          >
            {/** Submit the page as a POST request so we can fork the repository for the user **/}
            <Button type="submit" variant="primary">
              {shouldFork ? 'Fork this repository' : 'Update your fork'}
            </Button>
          </form>
        )}
        {shouldFork && userOverRepositoryLimit ? (
          <Link href={`${helpUrl}/repositories/creating-and-managing-repositories/repository-limits`}>
            Learn more repository limits
          </Link>
        ) : (
          <Link href={`${helpUrl}/articles/fork-a-repo`}>Learn more about forks</Link>
        )}
      </div>
    </>
  )
}

import {AllShortcutsEnabled} from '@github-ui/code-view-shared/components/AllShortcutsEnabled'
import {useEditPermissions} from '@github-ui/code-view-shared/contexts/EditPermissionsContext'
import {useReposAppPayload} from '@github-ui/code-view-shared/contexts/FilesPageInfoContext'
import {useRefInfo} from '@github-ui/code-view-shared/contexts/RefInfoContext'
import {useReposAnalytics} from '@github-ui/code-view-shared/hooks/use-repos-analytics'
import {useUrlCreator} from '@github-ui/code-view-shared/hooks/use-url-creator'
import {useCurrentRepository} from '@github-ui/current-repository'
import {ActionList} from '@primer/react'

import {useCurrentBlob} from '../../../hooks/CurrentBlob'
import OpenWithActionItems from './OpenWithActionItems'

export default function EditMenuActionItems({
  editAllowed,
  hasOpenWithItem,
}: {
  editAllowed: boolean
  hasOpenWithItem: boolean
}) {
  const payload = useCurrentBlob()
  const {name: refName} = useRefInfo()
  const {canEdit, canEditOnDefaultBranch} = useEditPermissions()
  const {githubDevUrl} = useReposAppPayload()
  const {sendRepoClickEvent} = useReposAnalytics()
  const {getUrl} = useUrlCreator()
  const {defaultBranch} = useCurrentRepository()

  const {
    headerInfo: {ghDesktopPath, onBranch},
  } = payload

  const isOnDefaultBranch = refName === defaultBranch
  const showDefaultBranchEditOption = !!canEditOnDefaultBranch && !isOnDefaultBranch

  return (
    <>
      {editAllowed && (
        <ActionList.Group>
          <ActionList.GroupHeading>Edit file...</ActionList.GroupHeading>
          {showDefaultBranchEditOption ? (
            <ActionList.LinkItem
              onClick={() => sendRepoClickEvent('BLOB_EDIT_DROPDOWN.ON_DEFAULT_BRANCH')}
              href={getUrl({action: 'edit', commitish: defaultBranch})}
            >
              On <code>{defaultBranch}</code> branch
            </ActionList.LinkItem>
          ) : (
            <ActionList.LinkItem
              onClick={() => sendRepoClickEvent('BLOB_EDIT_DROPDOWN.IN_PLACE')}
              href={getUrl({action: 'edit'})}
              data-hotkey="e"
            >
              In place
              <ActionList.TrailingVisual aria-hidden="true">
                <AllShortcutsEnabled>
                  <kbd>e</kbd>
                </AllShortcutsEnabled>
              </ActionList.TrailingVisual>
            </ActionList.LinkItem>
          )}
        </ActionList.Group>
      )}
      {editAllowed && hasOpenWithItem && <ActionList.Divider />}
      {hasOpenWithItem && (
        <OpenWithActionItems
          editEnabled={canEdit}
          githubDevUrl={githubDevUrl}
          ghDesktopPath={ghDesktopPath}
          onBranch={onBranch}
        />
      )}
    </>
  )
}

import React, {useMemo} from 'react'

export interface EditPermissionsInfo {
  canEdit: boolean
  canEditOnDefaultBranch: boolean
  fileExistsOnDefault: boolean
}

const EditPermissionsContext = React.createContext<EditPermissionsInfo>({
  canEdit: false,
  canEditOnDefaultBranch: false,
  fileExistsOnDefault: false,
})

interface EditPermissionsProviderProps {
  canEdit?: boolean
  canEditOnDefaultBranch?: boolean
  fileExistsOnDefault?: boolean
}

export function EditPermissionsProvider({
  children,
  canEdit = false,
  canEditOnDefaultBranch = false,
  fileExistsOnDefault = false,
}: React.PropsWithChildren<EditPermissionsProviderProps>) {
  const value = useMemo(
    () => ({
      canEdit,
      canEditOnDefaultBranch,
      fileExistsOnDefault,
    }),
    [canEdit, canEditOnDefaultBranch, fileExistsOnDefault],
  )

  return <EditPermissionsContext value={value}>{children}</EditPermissionsContext>
}

export function useEditPermissions() {
  return React.use(EditPermissionsContext)
}

export function calculateElapsedTime(createdAt: Date | string, completedAt?: Date | string | null): string {
  const created = new Date(createdAt).getTime()
  // Temporary fix for handling the case when completedAt is not set in CAPI. Remove once CAPI is updated.
  const defaultCAPIDate = '0001-01-01T00:00:00Z'
  const nowOrCompleted = completedAt && completedAt !== defaultCAPIDate ? new Date(completedAt).getTime() : Date.now()
  const diffInSeconds = Math.floor((nowOrCompleted - created) / 1000)

  const days = Math.floor(diffInSeconds / (60 * 60 * 24))
  const hours = Math.floor((diffInSeconds % (60 * 60 * 24)) / (60 * 60))
  const minutes = Math.floor((diffInSeconds % (60 * 60)) / 60)
  const seconds = diffInSeconds % 60

  // Create an array of intervals with their labels
  const intervals = [
    {value: days, label: 'd'},
    {value: hours, label: 'h'},
    {value: minutes, label: 'm'},
    {value: seconds, label: 's'},
  ]

  // Filter out intervals with a value of 0
  const nonZeroIntervals = intervals.filter(interval => interval.value > 0)

  // Return the two largest non-zero intervals
  if (nonZeroIntervals.length === 0) return '0s'
  if (nonZeroIntervals.length === 1) return `${nonZeroIntervals[0]?.value ?? 0}${nonZeroIntervals[0]?.label ?? ''}`
  return nonZeroIntervals[1]
    ? `${nonZeroIntervals[0]?.value}${nonZeroIntervals[0]?.label} ${nonZeroIntervals[1].value}${
        nonZeroIntervals[1].label ?? ''
      }`
    : `${nonZeroIntervals[0]?.value ?? 0}${nonZeroIntervals[0]?.label ?? ''}`
}

import type {CustomEventName, CustomEventDetail} from './types/custom-events'

export function emitToCodeMirror(event: CustomEventName, editorTarget: Element | null, detail: CustomEventDetail) {
  if (!editorTarget) return

  // codemirror 6 watches for events on its content element, not the root editor element
  const innerEditorTarget = editorTarget.className.includes('cm-content')
    ? editorTarget
    : editorTarget.querySelector<HTMLDivElement>('.cm-content')

  if (!innerEditorTarget) return

  innerEditorTarget.dispatchEvent(new CustomEvent(event, {detail}))
}

import {
  type Completion,
  type CompletionContext,
  type CompletionResult,
  acceptCompletion,
  autocompletion,
} from '@codemirror/autocomplete'
import {Prec} from '@codemirror/state'
import {keymap} from '@codemirror/view'
import memoize from '@github/memoize'
import {autocompleteTheme} from './theme'
import {getBaseFetchHeaders} from '@github-ui/fetch-headers'

interface Emoji {
  name: string
  src: string
  emoji?: string
}

interface EmojiResponse {
  [name: string]: [src: string, emoji?: string]
}

const emojiRequest = memoize(async function getEmojis() {
  const request = new Request('/autocomplete/emojis_for_editor', {
    method: 'GET',
    credentials: 'same-origin',
    headers: {
      Accept: 'application/json',
      ...getBaseFetchHeaders(),
    },
  })

  const res = await fetch(request)
  if (res.status !== 200) {
    throw new Error(`emoji request failed with a ${res.status}`)
  }

  const emojiData: EmojiResponse = await res.json()

  // flatten the response into something more reasonable to work with
  const emojis: Emoji[] = Object.keys(emojiData).map(emojiName => {
    const emoji = emojiData[emojiName]!

    return {
      name: emojiName,
      src: emoji[0],
      emoji: emoji[1],
    }
  })

  return emojis
})

function emojiAutocompleteContext(context: CompletionContext, data: Emoji[] = []): CompletionResult | null {
  const word = context.matchBefore(/:\w+/)

  if (!word) return null
  if (word && word.from === word.to && !context.explicit) {
    return null
  }

  const filteredEmojis = data.filter(emoji => {
    return emoji.name.indexOf(word.text.replace(':', '')) !== -1
  })

  const completions: Completion[] = filteredEmojis.map(emoji => {
    return {
      label: emoji.name,

      // some emojis don't have a unicode representation and get rendered from markdown pipeline
      apply: emoji.emoji || `:${emoji.name}:`,

      // we can only talk to the render via Completion objects - hack the src in this way
      // alternatively we could push the emoji data into a global store and have the render look it up
      type: emoji.src,
    }
  })

  return {
    from: word.from,
    to: word.to,
    options: completions,
    filter: false,
  }
}

export function emojiAutocomplete() {
  return [
    autocompleteTheme,
    autocompletion({
      override: [
        async (context: CompletionContext) => {
          const emojiData = await emojiRequest()
          return emojiAutocompleteContext(context, emojiData)
        },
      ],
      icons: false,
      addToOptions: [
        {
          render: (completion: Completion) => {
            const emojiOption = document.createElement('img')
            emojiOption.className = 'emoji emoji-result mr-2'
            emojiOption.height = 20
            emojiOption.width = 20
            emojiOption.alt = `:${completion.label}:`
            emojiOption.src = completion.type!
            emojiOption.setAttribute('async', '')

            return emojiOption
          },
          position: 0,
        },
      ],
    }),
    Prec.highest(keymap.of([{key: 'Tab', run: acceptCompletion}])),
  ]
}

import type {CopilotAssignmentResponse, CopilotAssignmentJob} from './copilot-assignment-api'

/**
 * Enhances error messages based on HTTP status codes with actionable guidance.
 *
 * @param baseMessage - The base error message
 * @param status - The HTTP status code
 * @returns An enhanced error message with user guidance
 */
export function enhanceErrorMessage(baseMessage: string, status: number): string {
  switch (status) {
    case 403:
      return `${baseMessage}: Please check that you have permission to assign issues in the target repository.`

    case 404:
      return `${baseMessage}: The repository or branch may not exist or may not be accessible.`

    case 422:
      return `${baseMessage}: Request could not be processed. Please try again or contact support if the issue persists.`

    case 429:
      return `${baseMessage}: Rate limit exceeded. Please wait a few moments and try again.`

    case 0: // Network error or exception
      return `${baseMessage}. Please check your network connection and try again.`

    default:
      if (status >= 500) {
        return `${baseMessage}: There was a server error. Please try again in a few moments.`
      }
      return `${baseMessage}. Please try again or contact support if the issue persists.`
  }
}

/**
 * Formats error messages for Copilot assignment API responses.
 *
 * @param response - The API response object containing error information
 * @param baseMessage - The base error message to enhance
 * @returns A formatted error message string
 */
export function formatAssignmentError(response: CopilotAssignmentResponse, baseMessage: string): string {
  if (response.errorMessage) {
    return `${baseMessage}: ${response.errorMessage}`
  }
  return enhanceErrorMessage(baseMessage, response.status)
}

/**
 * Builds a concise base error message for multi-issue assignment failures, e.g.
 * "Assignment failed for #123, #456 and 2 others".
 * The failed issue numbers are derived by subtracting successful job issue_numbers from the attempted list.
 *
 * @param attemptedIssueNumbers - Array of issue numbers that were attempted to be assigned
 * @param successfulJobs - Array of successful assignment jobs (optional)
 * @returns A formatted error message string describing the failed assignments
 */
export function buildAssignmentFailureBaseMessage(
  attemptedIssueNumbers: number[],
  successfulJobs?: CopilotAssignmentJob[],
): string {
  if (!attemptedIssueNumbers || attemptedIssueNumbers.length === 0) return 'Assignment failed'

  const successful = new Set((successfulJobs || []).map(j => j.issue_number))
  const failed: number[] = []

  for (const issueNum of attemptedIssueNumbers) {
    if (typeof issueNum === 'number' && !isNaN(issueNum) && !successful.has(issueNum)) {
      failed.push(issueNum)
    }
  }

  failed.sort((a, b) => a - b)

  if (failed.length === 0 || failed.length === attemptedIssueNumbers.length) return 'Assignment failed'
  if (failed.length === 1) return `Assignment failed for #${failed[0]}`
  if (failed.length === 2) return `Assignment failed for #${failed[0]} and #${failed[1]}`

  const [first, second, ...rest] = failed
  const remainingCount = rest.length
  return `Assignment failed for #${first}, #${second} and ${remainingCount} other${remainingCount === 1 ? '' : 's'}`
}

/**
 * Formats error messages for caught exceptions.
 *
 * @param error - The caught error
 * @param operation - Brief description of the operation that failed
 * @returns A formatted error message string
 */
export function formatException(error: unknown, operation: string): string {
  const errorMessage =
    error instanceof Error ? `${operation} failed: ${error.message}` : enhanceErrorMessage(`${operation} failed`, 500)
  return errorMessage
}

import {MarkdownRenderer} from '@github-ui/copilot-markdown'
import type {CopilotMarkdownExtension} from '@github-ui/copilot-markdown/extension'
import {useRef, useEffect, useState} from 'react'
import {clsx} from 'clsx'
import {Button} from '@primer/react'
import styles from './ExpandableMarkdown.module.css'

interface ExpandableMarkdownProps {
  markdown: string
  className?: string
  extensions?: readonly CopilotMarkdownExtension[]
  maxHeight?: number
}

export function ExpandableMarkdown({markdown, className, extensions, maxHeight = 500}: ExpandableMarkdownProps) {
  const contentRef = useRef<HTMLDivElement>(null)
  const [isOverflowing, setIsOverflowing] = useState(false)
  const [isExpanded, setIsExpanded] = useState(false)

  useEffect(() => {
    const node = contentRef.current
    if (!node) return

    const checkOverflow = () => {
      const isContentOverflowing = node.scrollHeight > maxHeight
      setIsOverflowing(isContentOverflowing)
    }

    checkOverflow()

    const resizeObserver = new ResizeObserver(() => checkOverflow())
    resizeObserver.observe(node)

    const mutationObserver = new MutationObserver(() => checkOverflow())
    mutationObserver.observe(node, {childList: true, subtree: true, characterData: true})

    return () => {
      resizeObserver.disconnect()
      mutationObserver.disconnect()
    }
  }, [markdown, maxHeight])

  const handleToggle = () => {
    setIsExpanded(e => !e)
  }

  return (
    <div style={{'--max-height': `${maxHeight}px`} as React.CSSProperties}>
      <div
        ref={contentRef}
        className={clsx(isOverflowing && styles.overflowing, isExpanded && styles.expanded)}
        // Make content non-interactive when collapsed and overflowing
        inert={isOverflowing && !isExpanded}
      >
        <MarkdownRenderer markdown={markdown} className={clsx(styles.content, className)} extensions={extensions} />
      </div>
      {isOverflowing && (
        <Button variant="invisible" size="small" onClick={handleToggle} className={styles.toggle}>
          {isExpanded ? 'Show less' : 'Show more'}
        </Button>
      )}
    </div>
  )
}

function _extends() {
  return module.exports = _extends = Object.assign ? Object.assign.bind() : function (n) {
    for (var e = 1; e < arguments.length; e++) {
      var t = arguments[e];
      for (var r in t) ({}).hasOwnProperty.call(t, r) && (n[r] = t[r]);
    }
    return n;
  }, module.exports.__esModule = true, module.exports["default"] = module.exports, _extends.apply(null, arguments);
}
module.exports = _extends, module.exports.__esModule = true, module.exports["default"] = module.exports;
/**
 * Extracts the content of a file from a git diff output.
 * Currently assumes there's only one hunk in the diff.
 *
 * @param diff The git diff output
 * @returns The extracted file content
 */
export function extractContentFromDiff(diff: string | undefined): string | undefined {
  if (!diff) return undefined

  try {
    // Split the diff into lines
    const lines = diff.split('\n')
    let contentStartIndex = -1

    // Find where the actual content begins (after the diff header and hunk header)
    for (let i = 0; i < lines.length; i++) {
      // Look for the hunk header line which starts with @@
      if (lines[i]?.startsWith('@@')) {
        contentStartIndex = i + 1
        break
      }
    }
    // Extract and process the content lines, removing the leading +/- indicators
    const contentLines = lines
      .slice(contentStartIndex)
      .map(line => {
        // Keep both added and removed lines, removing the prefix and any leading space
        if (line.startsWith('+') || line.startsWith('-')) {
          // Remove the +/- prefix, then trim any single leading space if present
          const content = line.substring(1)
          return content.startsWith(' ') ? content.substring(1) : content
        } else {
          // Lines with no prefix are context lines, trim any single leading space if present
          return line.startsWith(' ') ? line.substring(1) : line
        }
      })
      .filter(line => line !== null) // Remove any null entries

    return contentLines.join('\n').trim()
  } catch {
    return diff // Return the original diff if extraction fails
  }
}

import type {RunSetupArgs} from '../types/session'
import {isCompletionChunk} from '../types/session'
import type {CustomAgentGroupLogEntry} from './group-agent-logs'
import {isCustomAgentSessionGroup} from './group-agent-logs'

/**
 * Extracts MCP tool name to display name mappings from log entries that contain
 * run_setup tool calls with mcp_setup details.
 *
 * @param logEntries - Array of preprocessed log entries to search through
 * @returns A record mapping tool names to their display names
 */
export function extractMcpToolNameMappings(logEntries: CustomAgentGroupLogEntry[]): Record<string, string> {
  const mappings: Record<string, string> = {}

  for (const logEntry of logEntries) {
    if (isCustomAgentSessionGroup(logEntry) || !isCompletionChunk(logEntry)) {
      continue
    }

    for (const choice of logEntry.choices) {
      const toolCalls = choice.delta.tool_calls ?? []
      for (const toolCall of toolCalls) {
        const toolCallFunction = toolCall?.function
        if (
          !toolCallFunction ||
          toolCallFunction.name !== 'run_setup' ||
          typeof toolCallFunction.arguments !== 'string'
        ) {
          continue
        }

        try {
          // Defensively replace newlines that may appear in JSON to avoid possible parsing errors
          // This may not be needed if the backend is already handling this correctly, but better safe than sorry
          const parsedArgs = JSON.parse(toolCallFunction.arguments.replace(/\n/g, '\\n')) as RunSetupArgs
          if (
            parsedArgs.details?.type === 'mcp_setup' &&
            typeof parsedArgs.details.toolNamesToDisplayNames === 'object'
          ) {
            Object.assign(mappings, parsedArgs.details.toolNamesToDisplayNames ?? {})
          }
        } catch {
          // Ignore parsing errors
        }
      }
    }
  }

  return mappings
}

import {COPILOT_CHAT_SPEC_TASK_EVENT_TYPE} from './constants'

/**
 * Extracts the thread ID from a copilot-chat-spec-task event identifier.
 * Format: "copilot-chat-spec-task::{threadId}::{taskTag}"
 * Example: "copilot-chat-spec-task::thread-abc123::task-1" -> "thread-abc123"
 *
 * @param eventIdentifier - The event identifier string
 * @returns The thread ID, or undefined if not found
 */
export function extractSpecTaskThreadId(eventIdentifier: string): string | undefined {
  const prefix = `${COPILOT_CHAT_SPEC_TASK_EVENT_TYPE}::`
  const delimiter = '::'

  if (!eventIdentifier.startsWith(prefix)) {
    return undefined
  }

  // Remove the prefix
  const remainder = eventIdentifier.slice(prefix.length)

  // Split by delimiter to separate threadId from taskTag
  const delimiterIndex = remainder.indexOf(delimiter)
  if (delimiterIndex === -1) {
    return undefined
  }

  const threadId = remainder.slice(0, delimiterIndex)
  return threadId || undefined
}

/**
 * Extracts thread ID from any event identifier in a session or task.
 *
 * @param eventIdentifiers - Array of event identifiers from a session or task
 * @returns The thread ID, or undefined if not found
 */
export function extractSpecTaskThreadIdFromEventIdentifiers(eventIdentifiers?: string[] | null): string | undefined {
  if (!eventIdentifiers || eventIdentifiers.length === 0) {
    return undefined
  }

  // Check each event identifier for a copilot-chat-spec-task format
  for (const identifier of eventIdentifiers) {
    const threadId = extractSpecTaskThreadId(identifier)
    if (threadId) {
      return threadId
    }
  }

  return undefined
}

