import type {Extension} from '@codemirror/state'
import {EditorView} from '@codemirror/view'
import {findAndReplace, insertAtCursor, replaceSelection, somethingSelected} from '../utils'
import type {UploadChangeDetail, UploadCursorChangeDetail, UploadEvents} from '../types/custom-events'

const handleUploadChange = (event: Event, view: EditorView) => {
  const customEvent = event as CustomEvent<UploadChangeDetail>
  const {state, placeholder, replacementText} = customEvent.detail

  if (state === 'uploading') {
    if (somethingSelected(view)) {
      replaceSelection(view, placeholder)
    } else {
      insertAtCursor(view, replacementText)
    }
  } else if (state === 'uploaded' || state === 'failed') {
    findAndReplace(view, placeholder, replacementText)
  }
}

// positions the cursor where the user expects the file upload to be insert
const handleCursorChange = (event: Event, view: EditorView) => {
  const customEvent = event as CustomEvent<UploadCursorChangeDetail>
  const {left, top} = customEvent.detail
  const dropPos = view.posAtCoords({x: left, y: top})

  if (!dropPos) return

  view.dispatch({selection: {anchor: dropPos, head: dropPos}})
}

type EventHandlers = {
  [key in UploadEvents]: (event: Event, view: EditorView) => void
}

export function fileUploadListener(): Extension {
  const eventHandlers: EventHandlers = {
    'upload:editor:change': handleUploadChange,
    'upload:editor:cursor': handleCursorChange,
  }

  return [EditorView.domEventHandlers(eventHandlers)]
}

import type React from 'react'
import {createContext, use, useCallback, useMemo, useRef, useState} from 'react'

import {useIsCursorEnabled} from '../hooks/use-cursor-navigation'
import {useSearchTerm, useSetSearchTerm} from './SearchTermContext'

type FindInFileOpenContextType = {
  findInFileOpen: boolean
  setFindInFileOpen: (open: boolean) => void
  searchTerm: string
  setSearchTerm: (term: string) => void
}

const FindInFileOpenContext = createContext<FindInFileOpenContextType>({
  findInFileOpen: false,
  setFindInFileOpen: () => undefined,
  searchTerm: '',
  setSearchTerm: () => undefined,
})

/**
 * This is equivalent to a simple setState, except we save the search state of the find in file panel when it's closed
 * so we can reopen with the last used value
 */
export function FindInFileOpenProvider({children, isBlame}: {children: React.ReactNode; isBlame: boolean}) {
  const searchTerm = useSearchTerm()
  const setSearchTerm = useSetSearchTerm()
  const cursorEnabled = useIsCursorEnabled(isBlame)
  const lastSearchTerm = useRef<string>('')
  const [findInFileOpen, setRawFindInFileOpen] = useState<boolean>(false)
  const setFindInFileOpen = useCallback(
    (open: boolean) => {
      if (open && searchTerm === '' && lastSearchTerm.current !== '') {
        setSearchTerm(lastSearchTerm.current)
      } else if (!open && searchTerm !== '') {
        lastSearchTerm.current = searchTerm
        setSearchTerm('')
      }

      setRawFindInFileOpen(open)
    },
    [searchTerm, setSearchTerm],
  )

  const contextValue: FindInFileOpenContextType = useMemo(() => {
    return {
      findInFileOpen: cursorEnabled ? false : findInFileOpen,
      setFindInFileOpen,
      setSearchTerm,
      searchTerm,
    }
  }, [findInFileOpen, setFindInFileOpen, searchTerm, setSearchTerm, cursorEnabled])

  return <FindInFileOpenContext value={contextValue}>{children}</FindInFileOpenContext>
}

export function useFindInFileOpen() {
  return use(FindInFileOpenContext)
}

import type {DefinitionOrReference} from '@github-ui/code-nav'
import {DuplicateOnKeydownButton} from '@github-ui/code-view-shared/components/DuplicateOnKeydownButton'
import {useShortcut} from '@github-ui/code-view-shared/hooks/shortcuts'
import {useReposAnalytics} from '@github-ui/code-view-shared/hooks/use-repos-analytics'
import {ChevronDownIcon, ChevronUpIcon, SearchIcon, XIcon} from '@primer/octicons-react'
import {IconButton, Label, TextInput} from '@primer/react'
import {Octicon} from '@primer/react/deprecated'
import {clsx} from 'clsx'
import {lazy, Suspense, useEffect, useRef, useState} from 'react'

import {useSearchTerm, useSetSearchTerm} from '../../../../contexts/SearchTermContext'
import {useIsCursorEnabled} from '../../../../hooks/use-cursor-navigation'
import {scrollLineIntoView} from '../../../../hooks/use-scroll-line-into-view'
import {textAreaId} from '../../../../utilities/lines'
import styles from './FindInFilePopover.module.css'

const ScrollMarks = lazy(() => import('./ScrollMarks'))

export default function FindInFilePopover({
  stickied,
  searchResults,
  focusedSearchResult,
  setFocusedSearchResult,
  onClose,
}: {
  stickied?: boolean
  focusedSearchResult: number | undefined
  setFocusedSearchResult: (idx: number | undefined) => void
  searchResults: DefinitionOrReference[]
  onClose: () => void
}) {
  const searchTerm = useSearchTerm()
  const setSearchTerm = useSetSearchTerm()
  const cursorEnabled = useIsCursorEnabled()
  const inputContainer = useRef<HTMLInputElement>(null)

  const {findInFileShortcut, findSelectionShortcut, findNextShortcut, findPrevShortcut} = useShortcut()
  const [escapeToBrowserOnNextKeyPress, setEscapeToBrowserOnNextKeyPress] = useState(true)
  const clearSearch = () => {
    setSearchTerm('')
    setFocusedSearchResult(0)
  }
  const {sendRepoKeyDownEvent} = useReposAnalytics()

  const onChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.value) {
      setEscapeToBrowserOnNextKeyPress(false)
      setSearchTerm(event.target.value)

      if (focusedSearchResult === undefined) {
        setFocusedSearchResult(0)
      }
    } else {
      setEscapeToBrowserOnNextKeyPress(true)
      clearSearch()
    }
  }

  const jumpToResult = (direction: number) => {
    if (focusedSearchResult === undefined) {
      setFocusedSearchResult(0)
      return
    }

    if (direction === 1) {
      setFocusedSearchResult(focusedSearchResult === searchResults.length - 1 ? 0 : focusedSearchResult + 1)
    } else {
      setFocusedSearchResult(focusedSearchResult === 0 ? searchResults.length - 1 : focusedSearchResult - 1)
    }
  }

  useEffect(() => {
    inputContainer.current?.focus()
    inputContainer.current?.select()
  }, [])

  const onHotkey = () => {
    const selected = window.getSelection()?.toString()
    if (selected?.length) {
      setSearchTerm(selected)
      setFocusedSearchResult(0)
      sendRepoKeyDownEvent('BLOB_FIND_IN_FILE_MENU.FIND_IN_FILE_FROM_SELECTION')
    }
    inputContainer.current?.focus()
    inputContainer.current?.select()
  }

  useEffect(() => {
    if (searchResults.length > 0 && focusedSearchResult !== undefined) {
      scrollLineIntoView({
        line: searchResults[focusedSearchResult]!.lineNumber,
        column: searchResults[focusedSearchResult]!.ident.start.column,
      })
    }
  }, [searchResults, focusedSearchResult])

  if (cursorEnabled) return null

  return (
    <div
      className={`find-in-file-popover ${
        stickied ? 'find-in-file-popover-stickied' : 'find-in-file-popover-not-stickied'
      }`}
    >
      <div className={styles.headerRow}>
        <div className={styles.headerLeft}>
          <h5 className={styles.findHeading}>Find</h5>
          <span
            className={clsx(
              'find-text-help-tooltip',
              styles.helpText,
              !escapeToBrowserOnNextKeyPress && styles.helpTextHidden,
            )}
          >
            Press <Label>{findInFileShortcut.text}</Label> again to open the browser&apos;s find menu
          </span>
        </div>
        <div className={styles.spacer} />
        <IconButton
          variant="invisible"
          size="small"
          onClick={onClose}
          icon={XIcon}
          className={styles.closeButton}
          aria-label="Close find in file"
        />
      </div>
      <div className={styles.inputWrapper}>
        <TextInput
          ref={inputContainer}
          className={styles.textInput}
          validationStatus={searchResults.length > 1000 ? 'error' : undefined}
          type="text"
          leadingVisual={() => <Octicon icon={SearchIcon} aria-hidden="true" />}
          aria-labelledby="find-in-file-label"
          aria-expanded="true"
          autoComplete="off"
          name="Find in file input"
          placeholder="Search this file"
          value={searchTerm}
          block
          onChange={onChange}
          trailingAction={
            <div className={styles.trailingActions}>
              <span className={clsx('text-small', styles.resultCount)}>
                {searchResults.length === 0 || focusedSearchResult === undefined ? 0 : focusedSearchResult + 1}/
                {searchResults.length}
              </span>
              <IconButton
                size="small"
                variant="invisible"
                onClick={() => {
                  jumpToResult(-1)
                }}
                icon={ChevronUpIcon}
                aria-label="Up"
                data-testid="up-search"
                className={styles.navButton}
              />
              <IconButton
                size="small"
                variant="invisible"
                onClick={() => {
                  jumpToResult(1)
                }}
                icon={ChevronDownIcon}
                aria-label="Down"
                data-testid="down-search"
                className={styles.navButton}
              />
            </div>
          }
          onKeyDown={(keyboardEvent: React.KeyboardEvent) => {
            if (keyboardEvent.code === 'Enter' || keyboardEvent.code === 'NumpadEnter') {
              if (keyboardEvent.shiftKey) {
                jumpToResult(-1)
              } else {
                jumpToResult(1)
              }
            } else if (
              (keyboardEvent.metaKey || keyboardEvent.ctrlKey) &&
              (keyboardEvent.key === 'g' || keyboardEvent.key === 'G')
            ) {
              keyboardEvent.preventDefault()
              if (keyboardEvent.shiftKey) {
                jumpToResult(-1)
              } else {
                jumpToResult(1)
              }
            } else if (
              (keyboardEvent.metaKey || keyboardEvent.ctrlKey) &&
              (keyboardEvent.key === 'f' || keyboardEvent.key === 'F')
            ) {
              if (escapeToBrowserOnNextKeyPress) {
                // The user wants to use the browser's find in page functionality.
                // So just close this pane and get it out of their way.
                sendRepoKeyDownEvent('BLOB_FIND_IN_FILE_MENU.FALLBACK_TO_BROWSER_SEARCH')
                onClose()
              } else {
                setEscapeToBrowserOnNextKeyPress(true)
                keyboardEvent.preventDefault()
                inputContainer.current?.focus()
                inputContainer.current?.select()
              }
            } else if (keyboardEvent.key === 'Escape') {
              onClose()
            }
          }}
        />

        <DuplicateOnKeydownButton
          buttonFocusId={textAreaId}
          buttonHotkey={findInFileShortcut.hotkey}
          onButtonClick={onHotkey}
          buttonTestLabel={'hotkey-button'}
        />
        <button hidden data-hotkey={findSelectionShortcut.hotkey} onClick={onHotkey} data-testid="selection-hotkey" />
        <button
          hidden
          data-hotkey={findNextShortcut.hotkey}
          onClick={() => jumpToResult(1)}
          data-testid="find-next-button"
        />
        <button
          hidden
          data-hotkey={findPrevShortcut.hotkey}
          onClick={() => jumpToResult(-1)}
          data-testid="find-prev-button"
        />
        <Suspense fallback={null}>
          <ScrollMarks definitionsOrReferences={searchResults} />
        </Suspense>
      </div>
    </div>
  )
}

import {indentLess, indentMore} from '@codemirror/commands'
import {indentUnit} from '@codemirror/language'
import type {Extension, StateCommand} from '@codemirror/state'
import {type KeyBinding, keymap} from '@codemirror/view'
import {toggleWith} from './utils'
import {helpPanelConstructor} from './help-panels'

export const insertIndent: StateCommand = ({state, dispatch}) => {
  if (state.selection.ranges.some(r => !r.empty)) return indentMore({state, dispatch})
  dispatch(state.update(state.replaceSelection(state.facet(indentUnit)), {scrollIntoView: true, userEvent: 'input'}))
  return true
}

// this keymap prevents the editor from losing focus when tab is pressed
const indentWithTab: KeyBinding = {key: 'Tab', run: insertIndent, shift: indentLess}

export function focusTrapToggle(hideHelp?: boolean): Extension {
  // by default, pressing tab will insert an indent
  // pressing Shift-Ctrl-m will toggle the focus trap and allow tab to be used for navigation
  // pressing Shift-Ctrl-m again will toggle the focus trap back on
  // by setting display: none on the panel, its top value will always be 0, so we just set it as a top panel
  // so that codemirror can correctly calculate scroll offsets
  return [
    toggleWith('Shift-Ctrl-m', keymap.of([indentWithTab]), true),
    helpPanelConstructor(focusTrapHelpPanel(), hideHelp ? 'top' : 'bottom'),
  ]
}

function focusTrapHelpPanel() {
  const dom = document.createElement('div')

  const createKbdElement = (key: string) => {
    const kbd = document.createElement('kbd')
    kbd.textContent = key
    return kbd
  }

  // manually create the dom for the help text to avoid unnecessary dependencies (ie- lit-html)
  dom.append(
    'Use ',
    createKbdElement(`Control + Shift + m`),
    ' to toggle the ',
    createKbdElement('tab'),
    ' key moving focus. Alternatively, use ',
    createKbdElement('esc'),
    ' then ',
    createKbdElement('tab'),
    ' to move to the next interactive element on the page.',
  )

  dom.className = 'cm-help-panel'
  dom.id = 'focus-trap-help-panel'
  return dom
}

import {useStickyObserver} from '@github-ui/use-sticky-header/useStickyObserver'
