// Generates links to GitHub Actions pages based on the provided parameters.
// Currently supports generating links for workflow runs
// TODO: Add support for links to specific job logs

export function generateWorkflowRunLink(nwo: string | null, workflowRunId: number | null): string | undefined {
  if (nwo == null || workflowRunId == null) {
    return undefined
  }

  return `/${nwo}/actions/runs/${workflowRunId}`
}

export const syncForkButtonEventPayload = {
  category: 'Branch Infobar',
  label: `ref_loc:fetch_upstream_dropdown`,
}

/**
 * Generates a task path for a given pull request global ID.
 * @param globalId - The global ID of the pull request.
 * @param sessionId - The ID of the session to be focused on page load.
 * @returns The task path URL, or an empty string if globalId is empty.
 */
export const generateTaskPath = (globalId: string, sessionId?: string) => {
  if (!globalId) {
    return ''
  }

  let taskPath = `/copilot/tasks/pull/${encodeURIComponent(globalId)}`
  if (sessionId) {
    taskPath += `?session_id=${encodeURIComponent(sessionId)}`
  }

  return taskPath
}

export interface GenerateTaskPathForRepoOptions {
  /** The repository's name with owner (e.g., "owner/repo"). */
  repositoryNwo?: string
  /** The task ID for direct task linking. */
  taskId?: string
  /** The pull request number. */
  pullRequestNumber?: number
  /** The global ID of the pull request. */
  globalId?: string
  /** The ID of the session to be focused on page load. */
  sessionId?: string
  /** Whether to link to the repository-based task view. */
  linkToSessionsInRepo?: boolean
}

/**
 * Generates a task path for a given pull request global ID within a specific repository context.
 * @param options - The options for generating the task path.
 * @returns The task path URL, or an empty string if globalId is empty.
 */
export const generateTaskPathForRepo = ({
  globalId,
  repositoryNwo,
  pullRequestNumber,
  sessionId,
  linkToSessionsInRepo = false,
  taskId,
}: GenerateTaskPathForRepoOptions) => {
  let taskPath = ''
  if (repositoryNwo && linkToSessionsInRepo) {
    if (taskId) {
      taskPath = `/${repositoryNwo}/tasks/${encodeURIComponent(taskId)}`
    } else if (pullRequestNumber) {
      taskPath = `/${repositoryNwo}/agents/pull/${encodeURIComponent(pullRequestNumber)}`
    }
  }

  // Fall back to globalId path if we couldn't generate a repo-based path
  if (!taskPath && globalId) {
    taskPath = `/copilot/tasks/pull/${encodeURIComponent(globalId)}`
  }

  if (sessionId) {
    taskPath += `?session_id=${encodeURIComponent(sessionId)}`
  }

  return taskPath
}

/**
 * Signifies if we should link to the repository-based task view instead of the hyperspace view.
 * @returns True if the repository-based task view should be used, false otherwise.
 */
export const shouldLinkToRepoTaskView = (linkToSessionsInRepo: boolean, linkToSessionsInHyperspace: boolean) => {
  return linkToSessionsInRepo && !linkToSessionsInHyperspace
}

export function getCommitsCountText(value: number) {
  return `${value} ${value === 1 ? 'commit' : 'commits'}`
}

import {createElement} from 'react'
import {CheckSpinner} from '@github-ui/mergebox'
import {
  CheckCircleFillIcon,
  GitMergeIcon,
  StopIcon,
  SkipIcon,
  GitMergeQueueIcon,
  GitPullRequestClosedIcon,
  DotFillIcon,
  ClockIcon,
  ArchiveIcon,
} from '@primer/octicons-react'
import type {SessionState} from '../types/session'

export interface IconAttributes {
  icon: React.ComponentType | (() => React.ReactElement)
  color: string
  'data-testid': string
  marginTop?: string
}

export function getLeadingVisualIconAttributes(
  prState: string = 'open',
  prInMergeQueue: boolean = false,
  state?: SessionState,
  isArchived?: boolean,
): IconAttributes {
  // Check PR states first
  if (prState === 'merged') {
    return {
      icon: GitMergeIcon,
      color: 'var(--fgColor-done)' as const,
      'data-testid': 'icon-git-merge',
    }
  }

  if (prState === 'closed') {
    return {
      icon: GitPullRequestClosedIcon,
      color: 'var(--fgColor-danger)' as const,
      'data-testid': 'icon-git-pull-request-closed',
    }
  }

  if (prInMergeQueue) {
    return {
      icon: GitMergeQueueIcon,
      color: 'var(--fgColor-attention)' as const,
      'data-testid': 'icon-git-merge-queue',
    }
  }

  // Check if the task is archived next to not mask the PR state
  if (isArchived) {
    return {
      icon: ArchiveIcon,
      color: 'var(--fgColor-muted)' as const,
      'data-testid': 'icon-archive',
    }
  }

  if (state === 'queued') {
    return {
      icon: ClockIcon,
      color: 'var(--fgColor-attention)' as const,
      'data-testid': 'icon-clock',
    }
  }

  if (state === 'waiting_for_user' || state === 'completed') {
    return {
      icon: CheckCircleFillIcon,
      color: 'var(--fgColor-success)' as const,
      'data-testid': 'icon-check-circle-fill',
    }
  }

  if (state === 'failed' || state === 'timed_out') {
    return {
      icon: StopIcon,
      color: 'var(--fgColor-danger)' as const,
      'data-testid': 'icon-stop',
    }
  }

  if (state === 'in_progress') {
    return {
      // eslint-disable-next-line @github-ui/github-monorepo/no-react-create-element -- Convert to JSX Syntax. This Requires changing to a TSX file
      icon: () => createElement(CheckSpinner, {animated: true}),
      color: 'attention.fg' as const,
      'data-testid': 'icon-spinning-circle',
    }
  }

  if (state === 'idle') {
    return {
      icon: DotFillIcon,
      color: 'var(--fgColor-muted)' as const,
      'data-testid': 'icon-dot',
    }
  }

  if (state === 'cancelled') {
    return {
      icon: SkipIcon,
      color: 'var(--fgColor-muted)' as const,
      'data-testid': 'icon-skip',
    }
  }

  return {
    icon: DotFillIcon,
    color: 'var(--fgColor-muted)' as const,
    'data-testid': 'icon-idle',
  }
}

/**
 * Lazy iterator that returns one match at a time
 * @param regex regular expression used for the search
 * @param text raw text blob
 * @param startFromLine line in the text blob indexed from 0
 */

const MatchableType = {
  Text: 'Text',
  Symbol: 'Symbol',
} as const

type MatchableType = (typeof MatchableType)[keyof typeof MatchableType]

export interface Matchable {
  kind: MatchableType
  regexp: RegExp
}

export function symbolMatchable(symbol: string) {
  const escapedRegex = `(\\W|^)${symbol.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(\\W|$)`
  return {
    kind: MatchableType.Symbol,
    regexp: new RegExp(escapedRegex, 'g'),
  }
}

export function textMatchable(query: string) {
  const escapedQuery = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
  return {
    kind: MatchableType.Text,
    regexp: new RegExp(escapedQuery, 'gi'),
  }
}

export function* getMatchGenerator(regex: Matchable, lines: string[], startFromLine = 0) {
  for (let line = startFromLine; line < lines.length; line++) {
    const snippet = lines[line]!

    let match: RegExpExecArray | null

    while ((match = regex.regexp.exec(snippet)) !== null) {
      let matchContent = match[0]
      let column = match.index

      // Symbol matcher regex match leading whitespace, but don't actually include
      // that in the match positions! This is necessary because regex
      // lookbehinds aren't widely supported in browsers...
      if (regex.kind === MatchableType.Symbol) {
        if (matchContent.length > 0 && /\W/.test(matchContent[0]!)) {
          matchContent = matchContent.substring(1)
          column += match[0].length - matchContent.length
        }
        if (matchContent.length > 0 && /\W/.test(matchContent[matchContent.length - 1]!)) {
          matchContent = matchContent.substring(0, matchContent.length - 1)
        }
      }

      yield {
        line,
        column,
        columnEnd: column + matchContent.length,
        text: snippet,
      }
    }
  }
}

const betaLabels = ['(Beta)', '(Preview)']
export const getDisplayName = (modelName: string, modelId: string): string => {
  const name = modelName || modelId
  for (const suffix of betaLabels) {
    if (name.endsWith(suffix)) {
      return name.replace(suffix, '').trim()
    }
  }
  return name
}

import {ssrSafeWindow} from '@github-ui/ssr-utils'

/**
 * Build the GitHub Desktop URL for a pull request.
 * Uses the x-github-client protocol to open GitHub Desktop directly
 * Better solution might be pulling down the actual Desktop URL: /workspaces/github/app/helpers/desktop_helper.rb
 */
export function buildGitHubDesktopPullRequestUrl(repositoryNwo: string, pullNumber: number): string {
  const baseUrl = ssrSafeWindow?.location.origin || 'https://github.com'
  return `x-github-client://openRepo/${baseUrl}/${repositoryNwo}?pr=${pullNumber}`
}

/**
 * Build the GitHub Desktop URL for a branch. Returns undefined if window origin is not available.
 */
export function buildGitHubDesktopBranchUrl(repositoryNwo: string, branchName: string): string | undefined {
  const origin = ssrSafeWindow?.location.origin
  return origin ? `x-github-client://openRepo/${origin}/${repositoryNwo}?branch=${branchName}` : undefined
}

