const githubLightHighlightStyle = [...githubDefaultHighlights, ...codemirrorDefaultHighlightStyle]
const githubDarkHighlightStyle = [...githubDefaultHighlights, ...darkModeHighlights, ...codemirrorDefaultHighlightStyle]

export function getTheme(additionalStyles: TagStyle[] = []) {
  const isDarkMode = document.querySelector('[data-color-mode="dark"]') !== null

  const baseHighlightStyles = isDarkMode ? githubDarkHighlightStyle : githubLightHighlightStyle
  const extendedHighlightStyles = [...baseHighlightStyles, ...additionalStyles]

  return [
    EditorView.theme(ghTheme),
    syntaxHighlighting(HighlightStyle.define(extendedHighlightStyles), {fallback: true}),
  ]
}

import {TOOL_NAMES} from '../constants/tool-names'
import type {CompletionChunk, HydratedLogEntry, StreamingMessage} from '../types/session'
import {isCompletionChunk} from '../types/session'

/**
 * Marker patterns for subagent sessions
 * Supports both legacy "custom agent" and current "subagent" formats for backward compatibility
 */
const AGENT_START_MARKERS = ['▶️ Begin subagent', '▶️ Begin custom agent']
const AGENT_END_MARKERS = ['⏹️ End subagent', '⏹️ End custom agent']

export type CustomAgentGroupLogEntry = HydratedLogEntry | CustomAgentSessionGroup

export interface CustomAgentSessionGroup {
  agentId: string
  startMessage: StreamingMessage | null
  endMessage: StreamingMessage | null
  logs: HydratedLogEntry[]
  isPending: boolean
}

export function isCustomAgentSessionGroup(entry: CustomAgentGroupLogEntry): entry is CustomAgentSessionGroup {
  return typeof entry === 'object' && entry !== null && 'agentId' in entry && 'logs' in entry
}

/**
 * Groups log entries by agentId, creating nested structures for subagent sessions.
 * This does NOT refer to the top-level Session — it groups logs from subagents
 * that run within a parent session.
 *
 * SIMPLIFIED STRATEGY:
 * 1. Single pass through logs.
 * 2. If a log has an agentId, route it to an active subagent session group.
 * 3. If the group doesn't exist yet, create it and add it to the results immediately.
 * 4. Interleaved logs (A, B, A) are handled automatically by the Map reference.
 *
 * The originating tool call (task("...")) stays in the log stream as a separate entry.
 * The group represents the execution results of that task.
 */
export function groupCustomAgentLogs(logs: HydratedLogEntry[]): CustomAgentGroupLogEntry[] {
  const result: CustomAgentGroupLogEntry[] = []

  // Map of agentId -> group reference. A Map is used because multiple subagents
  // can run concurrently, each identified by a unique agentId.
  const activeSubagentSessions = new Map<string, CustomAgentSessionGroup>()

  for (const log of logs) {
    const agentId = getCustomAgentId(log)

    // 1. Standard Log (No Agent ID) - Just push to results
    if (!agentId) {
      result.push(log)
      continue
    }

    // 2. Subagent Log - Check if we have an active subagent session
    let subagentSession = activeSubagentSessions.get(agentId)

    if (!subagentSession) {
      // New Subagent Session Found: Create the group and push reference to result immediately
      subagentSession = {
        agentId,
        startMessage: null, // Will be filled if/when we find the marker
        endMessage: null,
        logs: [],
        isPending: true,
      }
      activeSubagentSessions.set(agentId, subagentSession)
      result.push(subagentSession)
    }

    // 3. Update the Subagent Session
    // Check for markers to update metadata (but don't add them to logs - they're just for grouping)
    if (isCustomAgentStartMarker(log)) {
      subagentSession.startMessage = log as StreamingMessage
    } else if (isCustomAgentEndMarker(log)) {
      subagentSession.endMessage = log as StreamingMessage
      subagentSession.isPending = false
      // Remove from active subagent sessions - this one is complete
      activeSubagentSessions.delete(agentId)
    } else {
      // Only add non-marker logs to the group's internal array
      subagentSession.logs.push(log)
    }
  }

  return result
}

// --- Helpers ---

/**
 * Extracts the agentId from a log entry if present
 */
function getCustomAgentId(log: HydratedLogEntry): string | null {
  if (typeof log === 'object' && log !== null && 'agentId' in log) {
    const {agentId} = log as {agentId: unknown}
    return typeof agentId === 'string' ? agentId : null
  }
  return null
}

/**
 * Extracts the parsed name argument from a run_setup tool call, or null if the log
 * is not a valid run_setup completion chunk with a parseable name.
 */
function getRunSetupName(log: HydratedLogEntry): string | null {
  if (!isCompletionChunk(log)) return null

  const toolCall = log.choices?.[0]?.delta?.tool_calls?.[0]
  if (!toolCall?.function || toolCall.function.name !== TOOL_NAMES.RUN_SETUP) return null

  try {
    const args = JSON.parse(toolCall.function.arguments ?? '')
    return typeof args.name === 'string' ? args.name : null
  } catch {
    return null
  }
}

/**
 * Checks if a log entry is a subagent session start marker
 */
function isCustomAgentStartMarker(log: HydratedLogEntry): boolean {
  const name = getRunSetupName(log)
  return name !== null && AGENT_START_MARKERS.some(marker => name.includes(marker))
}

/**
 * Checks if a log entry is a subagent session end marker
 */
function isCustomAgentEndMarker(log: HydratedLogEntry): boolean {
  const name = getRunSetupName(log)
  return name !== null && AGENT_END_MARKERS.some(marker => name.includes(marker))
}

/**
 * Extracts the agent name from the start marker tool call.
 * Shared with CustomAgentSessionGroup component.
 * Supports both legacy "custom agent" and current "subagent" formats.
 */
export function extractAgentName(startMessage: CompletionChunk | StreamingMessage | null): string {
  if (!startMessage) return 'Subagent'

  try {
    const toolCall = startMessage.choices?.[0]?.delta?.tool_calls?.[0]
    if (!toolCall?.function?.arguments) return 'Subagent'

    const args = JSON.parse(toolCall.function.arguments)
    const name = args.name || ''

    // Extract the agent name from patterns like "▶️ Begin subagent: the-joker" or "▶️ Begin custom agent: the-joker"
    // Must start with the emoji to avoid false positives from arbitrary text containing these words
    const match = name.match(/^▶️ Begin (?:subagent|custom agent):\s*(.+)$/i)
    if (match) {
      return match[1].trim()
    }

    return name || 'Subagent'
  } catch {
    return 'Subagent'
  }
}

import type {GroupingFn, ChoiceWithContext, EntryWithContext} from './types'
import {trimFileName} from '../../../utils/trim-file-name'
import {SETUP_TOOLS, SHELL_TOOLS, TOOL_NAMES} from '../../../constants/tool-names'

/**
 * Type guard to check if a session log item is a choice
 */
function isChoiceItem(item: EntryWithContext): item is ChoiceWithContext {
  return item.type === 'choice'
}

/**
 * Helper to check if a view tool call has a path (viewing a file) vs no path (viewing repository)
 * Uses the exact same logic as getCommandTitle in Tool.tsx: `!!trimFileName(path)?.length`
 */
function hasViewPath(choiceWithContext: ChoiceWithContext): boolean {
  const {choice} = choiceWithContext
  const toolCall = choice?.delta?.tool_calls?.[0]

  if (!toolCall) return false

  const argsString = toolCall.function?.arguments
  if (!argsString) return false

  try {
    const args = JSON.parse(argsString) as {path?: string}
    // Match the exact logic from Tool.tsx getCommandTitle
    const hasPath = !!trimFileName(args.path || '')?.length
    return hasPath
  } catch {
    return false
  }
}

/**
 * Extracts the tool name from a choice.
 */
function getToolName(choiceWithContext: ChoiceWithContext): string | null {
  const {choice} = choiceWithContext
  const delta = choice?.delta

  if (!delta?.tool_calls || delta.tool_calls.length === 0) {
    return null
  }

  const toolCall = delta.tool_calls[0]
  const functionName = toolCall?.function?.name ?? toolCall?.custom?.name ?? null

  if (!functionName) {
    return null
  }

  // For str_replace_editor or edit tools, the actual command is in the arguments
  // This matches the logic in Tool.tsx: `const command = name === TOOL_NAMES.EDIT ? 'str_replace' : strReplaceEditorArgs.command || name`
  if (functionName === TOOL_NAMES.STR_REPLACE_EDITOR || functionName === TOOL_NAMES.EDIT) {
    if (functionName === TOOL_NAMES.EDIT) {
      return 'str_replace'
    }
    // For str_replace_editor, use the command from args if available
    const argsString = toolCall?.function?.arguments ?? null
    if (argsString) {
      try {
        const args = JSON.parse(argsString) as {command?: string}
        return args.command || functionName
      } catch {
        return functionName
      }
    }
    return functionName
  }

  return functionName
}

/**
 * Grouping function that groups consecutive tool calls of the same type.
 * Non-choice items (commands, etc.) are never grouped and break any active grouping.
 */
export const groupByConsecutiveToolName: GroupingFn = (item, lastGroup) => {
  // Non-choice items (commands, etc.) are always standalone and break grouping
  if (!isChoiceItem(item)) {
    return {shouldGroup: false}
  }

  const currentToolName = getToolName(item)

  if (!currentToolName) {
    return {shouldGroup: false}
  }

  // Shell-related tools (Bash and PowerShell) should always be standalone
  if (SHELL_TOOLS.includes(currentToolName as (typeof SHELL_TOOLS)[number])) {
    return {shouldGroup: false}
  }

  // Check if current tool is a setup tool
  const isSetupTool = SETUP_TOOLS.includes(currentToolName as (typeof SETUP_TOOLS)[number])
  const lastGroupToolName = lastGroup?.metadata?.toolName as string | undefined
  const lastGroupIsSetupTool = lastGroup?.metadata?.isSetupTool as boolean | undefined

  // Group all setup tools together regardless of specific name
  if (isSetupTool && lastGroupIsSetupTool && lastGroup) {
    return {
      shouldGroup: true,
      groupId: lastGroup.id,
      groupMetadata: {toolName: lastGroupToolName, isSetupTool: true},
    }
  }

  const isViewRepository = currentToolName === 'view' && !hasViewPath(item)

  // Check if we should continue the last group by comparing tool names
  const lastGroupIsViewRepository = (lastGroup?.metadata?.isViewRepository as boolean | undefined) ?? false

  // Don't group view repository with file views, and vice versa
  // But still allow starting a new group for the new view type
  if (currentToolName === 'view' && lastGroupToolName === 'view') {
    // Both are view operations, but we need to check if they're the same type
    if (isViewRepository !== lastGroupIsViewRepository) {
      // Start a new group instead of returning shouldGroup: false
      return {
        shouldGroup: true,
        groupId: crypto.randomUUID(),
        groupMetadata: {toolName: currentToolName, isViewRepository, isSetupTool},
      }
    }
  }

  const shouldContinueGroup = lastGroupToolName === currentToolName && !lastGroup?.metadata?.standalone

  if (shouldContinueGroup && lastGroup) {
    return {
      shouldGroup: true,
      groupId: lastGroup.id, // Reuse the group's ID to continue the group
      groupMetadata: {toolName: currentToolName, isViewRepository, isSetupTool},
    }
  }

  // Start a new group - allow any tool with a name to be grouped
  if (currentToolName) {
    return {
      shouldGroup: true,
      // Generate deterministic ID based on first entry's identifiers to maintain stable React keys across re-renders
      // this is safe as we never group non-choice items
      groupId: `${currentToolName}-${item.entryId}-${item.choiceIndex}`,
      groupMetadata: {toolName: currentToolName, isViewRepository, isSetupTool},
    }
  }

  return {shouldGroup: false}
}

