export type CreateTaskReference = {
  path: string
  range?: LineRange
}

function makeFileOrSnippetReference({
  referenceRepo,
  reference,
}: {
  referenceRepo: CopilotChatRepo
  reference: CreateTaskReference
}) {
  if (reference.range) {
    return makeSnippetReference(reference.path, reference.range, referenceRepo)
  } else {
    return makeFileReference(reference.path, referenceRepo)
  }
}

/**
 * Unified hook for all image-related concerns in the new-task chat input:
 * paste/drop upload handling, markdown→reference syncing, and image-limit tracking.
 */
function useMarkdownImages({
  textAreaRef,
  repositoryId,
}: {
  textAreaRef: React.RefObject<HTMLTextAreaElement | null>
  repositoryId?: string
}) {
  const isImageUploadEnabled = isFeatureEnabled('copilot_agent_image_upload')

  const {onPaste, dropTargetProps, isDraggedOver, isUploading} = useMarkdownImageHandling({
    textAreaRef,
    repositoryId,
    enabled: isImageUploadEnabled,
  })

  const manager = useChatManager()
  const currentReferences = useChatStateValue('currentReferences')
  const [inputText, setInputText] = useState('')

  const {isAtImageLimit} = useImageReferenceSync({
    text: inputText,
    manager,
    currentReferences,
    enabled: isImageUploadEnabled,
  })

  return {
    onPaste,
    dropTargetProps,
    isDraggedOver,
    isUploading,
    isAtImageLimit,
    onTextChange: setInputText,
  }
}

export type NewTaskChatInputProps = {
  handleUserSubmit: (
    content: string,
    selectedRepo: DropdownRepository | null,
    selectedBranch: string,
    selectedAgent: SelectedAgent,
    selectedMode?: IntentDetectionMode,
    modelId?: string,
    createPullRequest?: boolean,
  ) => Promise<void>
  initialRepo?: Repository | null
  initialReference?: CreateTaskReference | null
  hideRepoSelector?: boolean
  isInPortal?: ChatInputProps['isInPortal']
  textAreaRef?: ChatInputProps['textAreaRef']
  chatInputRef?: ChatInputProps['chatInputRef']
  size?: 'small' | 'large'
  className?: string
  eventType?: string
  shouldClearTextOnSubmit?: boolean
  initialText?: string
  initialBranch?: string
  /**
   * Whether the user's chat quota is exhausted.
   * When true, the submit button will be disabled.
   */
  isQuotaExhausted?: boolean
  isNewConversation?: boolean
  maxTextareaHeight?: number
  submitWithModifier?: boolean
  decoupledModeEnabled: boolean
}

export function NewTaskChatInput({
  handleUserSubmit,
  initialRepo,
  initialReference,
  hideRepoSelector,
  isInPortal,
  chatInputRef,
  textAreaRef: textAreaRefFromProps,
  size = 'large',
  className,
  eventType,
  shouldClearTextOnSubmit = true,
  initialText,
  initialBranch,
  isQuotaExhausted = false,
  isNewConversation,
  maxTextareaHeight,
  submitWithModifier = true,
  decoupledModeEnabled,
}: NewTaskChatInputProps) {
  // Use the chat manager to clear references when a new task is started
  const manager = useChatManager()
  const {plan} = useEntitlement()
  const {models: availableModels} = useAgentModels()

  const [selectedModelId, setSelectedModelId] = useLatestAgentModel()

  const [lastUsedRepo, setLastUsedRepo] = useLastUsedRepository()
  const [selectedRepo, setSelectedRepo] = useState<DropdownRepository | null>(null)

  const textAreaRef = useRef<HTMLTextAreaElement>(null)
  useImperativeHandle<HTMLTextAreaElement | null, HTMLTextAreaElement | null>(
    textAreaRefFromProps ?? null,
    () => textAreaRef.current,
  )

  const {
    onPaste,
    dropTargetProps,
    isDraggedOver,
    isUploading: isImageUploading,
    isAtImageLimit,
    onTextChange,
  } = useMarkdownImages({
    textAreaRef,
    repositoryId: selectedRepo?.id?.toString(),
  })

  const [currentPrompt, setCurrentPrompt] = useState(initialText || '')

  const handleTextChange = useCallback(
    (text: string) => {
      onTextChange(text)
      setCurrentPrompt(text)
    },
    [onTextChange],
  )

  const shouldSubmitWithModifier = submitWithModifier && isFeatureEnabled('copilot_agent_task_submit_with_modifier')
  const [referenceRepo, setReferenceRepo] = useState<CopilotChatRepo | null>(null)
  const [selectedBranch, setSelectedBranch] = useState<string>(initialBranch || '')
  const [selectedAgent, setSelectedAgent] = useLastSelectedAgent()

  const {isUsingIntentDetection} = useIntentDetection()
  const {mode: selectedMode, setMode: setSelectedMode} = useIntentDetectionContext()

  const {data: agentInfo} = useAgentInfo(selectedAgent.topLevelAgentId ? Number(selectedAgent.topLevelAgentId) : null)

  const shouldShowModelPicker =
    copilotFeatureFlags.codingAgentModelSelection &&
    (copilotFeatureFlags.codingAgentModelSelectionAllSkus ||
      plan === CopilotPlan.IndividualPro ||
      plan === CopilotPlan.IndividualProPlus) &&
    isCopilotOrCustomAgent(selectedAgent, agentInfo?.slug)

  const [reference, setReference] = useState<CreateTaskReference | null>(initialReference || null)
  const chatReference = useMemo(
    () => (referenceRepo && reference ? makeFileOrSnippetReference({reference, referenceRepo}) : undefined),
    [referenceRepo, reference],
  )
  const [createPullRequest, setCreatePullRequest] = useState<boolean>(!decoupledModeEnabled)
  const [searchParams] = useSearchParams()
  const branchParam = searchParams.get('branch')

  const isImageUploadEnabled = isFeatureEnabled('copilot_agent_image_upload')
  const isSubAgentsEnabled = isFeatureEnabled('copilot_swe_agent_use_subagents')
  const isValidRepo = initialRepo && Object.keys(initialRepo).length > 0
  const nwoParam = searchParams.get('repo')
  let initialNameWithOwner = ''
  if (isValidRepo) {
    initialNameWithOwner = `${initialRepo.ownerLogin}/${initialRepo.name}`
  } else if (nwoParam) {
    initialNameWithOwner = nwoParam
  } else if (lastUsedRepo) {
    initialNameWithOwner = `${lastUsedRepo.ownerLogin}/${lastUsedRepo.name}`
  }

  const onSubmit = useCallback(
    async (content: string) => {
      sendEvent('agent_sessions.task_view', {
        target: 'NEW_TASK_SUBMIT',
        defaultToTask: copilotFeatureFlags.defaultToTaskInput,
        defaultToTaskControl: copilotFeatureFlags.defaultToTaskControl,
        askModeDropdown: copilotFeatureFlags.askModeDropdown,
      })

      // Save the selected repository to localStorage when task is created
      if (selectedRepo?.id != null) {
        const result = await manager.service.fetchRepo(selectedRepo.id)
        if (result.ok && result.payload) {
          setLastUsedRepo(result.payload)
        }
      }

      const modelIdToUse =
        selectedModelId ?? availableModels?.find(m => m.is_chat_default)?.id ?? availableModels?.[0]?.id
      return handleUserSubmit(
        content,
        selectedRepo,
        selectedBranch,
        selectedAgent,
        selectedMode,
        modelIdToUse,
        createPullRequest,
      )
    },
    [
      selectedRepo,
      selectedModelId,
      availableModels,
      handleUserSubmit,
      selectedBranch,
      selectedAgent,
      selectedMode,
      createPullRequest,
      manager.service,
      setLastUsedRepo,
    ],
  )

  const handleRepoSelect = useCallback((repo: DropdownRepository | undefined) => {
    if (!repo) return

    setSelectedRepo(repo)
    setSelectedBranch(repo.defaultBranch || '')
  }, [])

  // Fetch the reference repo
  useEffect(() => {
    if (initialRepo?.id != null) {
      ;(async () => {
        const repoResponse = await manager.service.fetchRepo(initialRepo.id)
        if (repoResponse.payload) setReferenceRepo(repoResponse.payload)
      })()
    }
  }, [initialRepo, manager])

  useEffect(() => {
    // If the repo selector is hidden and we have an initial repo NWO, try to auto-select it.
    if (hideRepoSelector && initialNameWithOwner) {
      const fetchInitialRepo = async () => {
        try {
          const repositories = await queryForRepos(initialNameWithOwner)
          const repo = repositories.find(
            (repoData: {nameWithOwner: string}) => repoData.nameWithOwner === initialNameWithOwner,
          )
          if (repo && repo.enabled) {
            setSelectedRepo(repo)
            setSelectedBranch(initialBranch ?? branchParam ?? repo.defaultBranch)
            return
          }
        } catch {
          // Error querying for specific repo
        }
      }
      fetchInitialRepo()
    }
    // We only want this hook to run once since it's fetching the initial repo.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  return (
    <>
      <ChatInput
        initialText={initialText}
        className={clsx(className, {[styles.isDraggedOver]: isDraggedOver})}
        modes={[
          {
            name: ModeSupportName.Task,
            icon: AgentIcon,
            submitLabel: isUsingIntentDetection ? 'Send now' : 'Start task',
            placeholder: isUsingIntentDetection
              ? 'Ask anything with intent'
              : decoupledModeEnabled
                ? 'Give Copilot a background task to work on'
                : 'Describe a coding task to work on',
            textAreaAriaLabel: isUsingIntentDetection ? 'Ask anything with intent' : 'Coding task prompt',
            supportsAttachments: false,
            supportsReferenceAttachments: isImageUploadEnabled,
            supportedReferenceTypes: isImageUploadEnabled ? ['image'] : undefined,
            supportsModelSwitching: shouldShowModelPicker,
            supportsAttachmentsMenu: isImageUploadEnabled ? false : undefined,
          },
        ]}
        size={size}
        onSubmit={onSubmit}
        shouldSubmitWithModifier={shouldSubmitWithModifier}
        isNewConversation={isNewConversation}
        initialReference={chatReference}
        extraToolbar={
          <>
            {isUsingIntentDetection && <ModeSelector selectedMode={selectedMode} setMode={setSelectedMode} />}
            <TaskChatInputToolbar
              hideRepoSelector={hideRepoSelector}
              initialRepoNWO={initialNameWithOwner}
              initialBranch={initialBranch ?? branchParam ?? undefined}
              selectedRepo={selectedRepo || undefined}
              selectedBranch={selectedBranch}
              selectedAgent={selectedAgent}
              onRepoSelect={handleRepoSelect}
              onBranchSelect={(branch: string | undefined) => setSelectedBranch(branch || '')}
              onAgentSelect={(agent: SelectedAgent) => setSelectedAgent(agent)}
              agentSelectionEnabled={isSubAgentsEnabled}
              textAreaRef={textAreaRef}
              isAtImageLimit={isAtImageLimit}
              currentPrompt={currentPrompt}
            />
          </>
        }
        submitDisabled={!selectedRepo || isQuotaExhausted || isImageUploading}
        onRemoveReference={() => {
          setReference(null)
        }}
        isInPortal={isInPortal}
        textAreaRef={textAreaRef}
        chatInputRef={chatInputRef}
        onPaste={onPaste}
        dropTargetProps={dropTargetProps}
        onTextChange={handleTextChange}
        // Intentionally passing an empty function to onNewThreadSelected to enable the model picker UI.
        // ChatInput requires this prop to show the model picker, even if thread creation is not needed here.
        onNewThreadSelected={async () => {}}
        customModelPicker={
          shouldShowModelPicker
            ? () => <ModelPicker selectedModelId={selectedModelId} onUpdateModel={setSelectedModelId} />
            : undefined
        }
        storageKeySuffix={eventType}
        source="task"
        showStartTaskButton={copilotFeatureFlags.defaultToTaskInput}
        shouldClearTextOnSubmit={shouldClearTextOnSubmit}
        maxTextareaHeight={maxTextareaHeight}
        maxPromptLength={MAX_AGENT_TASK_PROMPT_LENGTH}
      />

      {!isUsingIntentDetection && copilotFeatureFlags.codingAgentPullRequestToggle && (
        <PullRequestToggleAddon checked={createPullRequest} onChange={setCreatePullRequest} />
      )}

      {!copilotFeatureFlags.codingAgentPullRequestToggle && decoupledModeEnabled && <DecoupledModeBanner />}
    </>
  )
}

import type {ReactNode} from 'react'
import {ChevronDownIcon, ChevronRightIcon, AlertIcon} from '@primer/octicons-react'
import {Button, Spinner} from '@primer/react'
import styles from './NewToolHeader.module.css'
import {clsx} from 'clsx'
import {useSessionLogsContext} from '../Context'
import {sendEvent} from '@github-ui/hydro-analytics'

export interface ToolHeaderProps {
  /**
   * The leading visual element to display before the title (e.g., an icon)
   */
  leadingVisual?: ReactNode
  /**
   * The trailing visual element to display after the title (e.g., an indicator icon)
   */
  trailingVisual?: ReactNode
  /**
   * Indicates whether the file is in a collapsed state
   */
  isCollapsed?: boolean
  /**
   * Title details of tool-driven titles
   */
  title: string
  /**
   * The path to the file, if part of the args
   */
  path?: string
  /**
   * Indicates whether the tool has references rendered as children (for chat variant)
   */
  hasReferences?: boolean
  /**
   * Indicates whether the tool is in an error state
   */
  isError?: boolean
  /**
   * Indicates whether the tool is in a pending state
   */
  isPending?: boolean
  /**
   * Callback for handling modifier + click to expand/collapse all tools
   */
  onModifierClick?: (expand: boolean) => void
  /**
   * Callback for handling regular click to toggle this tool
   */
  onToggle?: () => void
  /**
   * Indicates whether the tool is part of a group
   */
  isInGroup?: boolean
  /**
   * Indicates whether this header is for a group (not a child inside a group)
   */
  isGroupHeader?: boolean
}

/**
 * Props that can be passed to the Tool component to configure the ToolHeader.
 * This is a subset of ToolHeaderProps, containing only the customizable visual elements.
 */
export type ToolHeaderPropsType = Pick<ToolHeaderProps, 'leadingVisual' | 'trailingVisual'>

export function NewToolHeader({
  leadingVisual,
  trailingVisual,
  title,
  path,
  isCollapsed,
  hasReferences = true,
  isError = false,
  isPending = false,
  isInGroup = false,
  isGroupHeader = false,
  onModifierClick,
  onToggle,
}: ToolHeaderProps) {
  const {variant, onToolExpand} = useSessionLogsContext()

  const handleClick = (event: React.MouseEvent) => {
    // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
    if ((event.altKey || event.metaKey) && onModifierClick) {
      event.preventDefault()
      event.stopPropagation()
      // If currently collapsed, expand all; if expanded, collapse all
      onModifierClick(!!isCollapsed)

      sendEvent('agent_sessions.task_view', {
        target: 'TOOL_HEADER_MODIFIER',
        action: isCollapsed ? 'EXPAND_ALL' : 'COLLAPSE_ALL',
        tool_title: title,
      })

      return false // Prevent further event handling
    } else {
      // Regular click - toggle this tool
      onToggle?.()
      onToolExpand?.(!!isCollapsed)

      sendEvent('agent_sessions.task_view', {
        target: 'TOOL_HEADER',
        action: isCollapsed ? 'EXPAND' : 'COLLAPSE',
        tool_title: title,
      })
    }
  }

  if (variant === 'mission-control' || variant === 'chat') {
    return (
      <div className={styles.headerContainer}>
        <button
          type="button"
          className={clsx(styles.missionControl, {
            [styles.inGroup]: isInGroup,
            [styles.groupHeader]: isGroupHeader,
            [styles.nonInteractive]: !hasReferences,
          })}
          onClick={hasReferences ? handleClick : undefined}
          aria-disabled={!hasReferences}
          aria-expanded={!isCollapsed}
          tabIndex={hasReferences ? 0 : -1}
        >
          {leadingVisual ? <span className={styles.leadingVisualContainer}>{leadingVisual}</span> : null}
          <span className={styles.text}>
            <span className={clsx(styles.title, {[styles.titleInGroup]: isInGroup})}>{title}</span>
            {path && (
              <>
                {' '}
                <span className={styles.path}>{path}</span>
              </>
            )}
          </span>
          {hasReferences && (
            <ChevronRightIcon size={12} className={styles.toggleIcon} data-expanded={!isCollapsed} aria-hidden="true" />
          )}
          {isPending && (
            <div className={styles.spinnerContainer}>
              <Spinner size="small" />
            </div>
          )}
          {isError && <AlertIcon size={16} className="color-fg-attention flex-shrink-0" />}
        </button>
        {trailingVisual ? <div className={styles.trailingVisualContainer}>{trailingVisual}</div> : null}
      </div>
    )
  }

  return (
    <Button
      as="summary"
      block
      className={clsx('Button', styles.button)}
      alignContent="start"
      aria-expanded={!isCollapsed}
      aria-labelledby="tool-header-title"
      leadingVisual={isCollapsed ? <ChevronRightIcon /> : <ChevronDownIcon />}
      trailingVisual={isError ? <AlertIcon size={16} className="color-fg-attention flex-shrink-0" /> : null}
      onClick={handleClick}
    >
      <>
        <span className="overflow-hidden text-truncate flex-1">{title}</span>{' '}
        {path && <span className="text-mono fgColor-default">{path}</span>}
      </>
    </Button>
  )
}

