import {TerminalIcon, VscodeIcon, DesktopDownloadIcon} from '@primer/octicons-react'
import {ActionList, Link} from '@primer/react'
import {CodeDropdownButton} from '@github-ui/code-dropdown-button'
import {CloneUrl} from '@github-ui/code-dropdown-button/components/LocalTab'
import {isEnterprise} from '@github-ui/runtime-environment'
import {buildCodespacesPath} from '@github-ui/code-dropdown-button/build-codespaces-path'
import {buildGitHubDesktopPullRequestUrl} from '../../utils/github-desktop'
import type {Pull} from '../../types/pull'
import type {Session} from '../../types/session'
import {isActiveSession} from '../../types/session'
import styles from './OpenInMenu.module.css'
import {isFeatureEnabled} from '@github-ui/feature-flags'

export interface OpenInMenuProps {
  pull: Pull
  session?: Session
}

// Build a VS Code deep link URL that opens the PR in the GitHub Pull Requests extension
export function buildVSCodePullRequestUrl(owner: string, repo: string, pullNumber: number): string {
  const payload = {owner, repo, pullRequestNumber: pullNumber}
  const encodedPayload = encodeURIComponent(JSON.stringify(payload))
  return `vscode://github.vscode-pull-request-github/open-pull-request-webview?${encodedPayload}`
}

export function attemptOpenUrlWithFallback(url: string, repositoryNwo: string) {
  const command = `git clone https://github.com/${repositoryNwo}.git && code ${repositoryNwo.split('/')[1]}`

  window.open(url, '_self')

  // Fallback: let's also copy to clipboard a basic git clone command
  if (navigator.clipboard) {
    void navigator.clipboard.writeText(command)
  }
}

export function buildVSCodeAgentSessionUrl(
  protocol: 'vscode' | 'vscode-insiders',
  repositoryNwo: string,
  globalId: string,
  headRefName: string,
): string {
  const repoUrl = `https://github.com/${repositoryNwo}.git`
  return `${protocol}://GitHub.copilot-chat/openAgentSession?id=${globalId}&type=copilot&url=${encodeURIComponent(
    repoUrl,
  )}&branch=${encodeURIComponent(headRefName)}`
}

export const createHandleOpenInVSCode = (repositoryNwo: string, globalId: string, headRefName: string) => () => {
  const vscodeUrl = buildVSCodeAgentSessionUrl('vscode', repositoryNwo, globalId, headRefName)
  attemptOpenUrlWithFallback(vscodeUrl, repositoryNwo)
}

export const createHandleOpenInVSCodeInsiders =
  (repositoryNwo: string, globalId: string, headRefName: string) => () => {
    const vscodeInsidersUrl = buildVSCodeAgentSessionUrl('vscode-insiders', repositoryNwo, globalId, headRefName)
    attemptOpenUrlWithFallback(vscodeInsidersUrl, repositoryNwo)
  }

export const createHandleOpenInGitHubDesktop = (repositoryNwo: string, pullNumber: number) => () => {
  const desktopUrl = buildGitHubDesktopPullRequestUrl(repositoryNwo, pullNumber)
  attemptOpenUrlWithFallback(desktopUrl, repositoryNwo)
}

export const createHandleOpenInCodespaces = (repositoryId: number, headRefName: string) => () => {
  const codespacesPath = buildCodespacesPath(repositoryId, headRefName)
  if (codespacesPath) {
    window.open(codespacesPath, '_self')
  }
}

export function OpenInMenu({pull, session}: OpenInMenuProps) {
  const openAgentSessionInVSCodeInsiders = isFeatureEnabled('open_agent_session_in_vscode_insiders')
  const openAgentSessionInVSCodeStable = isFeatureEnabled('open_agent_session_in_vscode_stable')
  const handleOpenInVSCode = createHandleOpenInVSCode(pull.repository_nwo, pull.global_relay_id, pull.head_ref_name)
  const handleOpenInVSCodeInsiders = createHandleOpenInVSCodeInsiders(
    pull.repository_nwo,
    pull.global_relay_id,
    pull.head_ref_name,
  )
  const handleOpenInGitHubDesktop = createHandleOpenInGitHubDesktop(pull.repository_nwo, pull.number)
  const codespacesPath = buildCodespacesPath(pull.repository_id, pull.head_ref_name)

  const isEnterpriseMode = isEnterprise()
  const shouldShowCodespacesTab = !!codespacesPath
  const isSessionActive = session ? isActiveSession(session) : false

  return (
    <CodeDropdownButton
      primary={false}
      size="small"
      isEnterprise={isEnterpriseMode}
      showCodespacesTab={shouldShowCodespacesTab}
      codespacesPath={codespacesPath}
      refName={pull.head_ref_name}
      localTab={
        <CustomLocalTab
          pullURL={pull.url}
          pullGlobalRelayID={pull.global_relay_id}
          onOpenInVSCode={handleOpenInVSCode}
          onOpenInVSCodeInsiders={handleOpenInVSCodeInsiders}
          onOpenInGitHubDesktop={handleOpenInGitHubDesktop}
          showVSCodeStable={openAgentSessionInVSCodeStable}
          showVSCodeInsiders={openAgentSessionInVSCodeInsiders}
          isSessionActive={isSessionActive}
          sessionId={session?.id}
        />
      }
    />
  )
}

interface CustomLocalTabProps {
  pullURL: string
  pullGlobalRelayID: string
  onOpenInVSCode: () => void
  onOpenInVSCodeInsiders: () => void
  onOpenInGitHubDesktop: () => void
  showVSCodeInsiders: boolean
  showVSCodeStable: boolean
  isSessionActive: boolean
  sessionId?: string
}

// Exported only for testing
export function CustomLocalTab({
  pullURL,
  pullGlobalRelayID,
  onOpenInVSCode,
  onOpenInVSCodeInsiders,
  onOpenInGitHubDesktop,
  showVSCodeInsiders,
  showVSCodeStable,
  isSessionActive,
  sessionId,
}: CustomLocalTabProps) {
  // Use session ID if available
  const target = sessionId || pullURL
  const ghCommand = `gh agent-task view ${target} --log${isSessionActive ? ' --follow' : ''}`
  const copilotCLICommand = `copilot --resume=${pullGlobalRelayID}`

  return (
    <ActionList>
      {showVSCodeStable && (
        <>
          <ActionList.Item onSelect={onOpenInVSCode}>
            <ActionList.LeadingVisual>
              <VscodeIcon />
            </ActionList.LeadingVisual>
            Open in VS Code
          </ActionList.Item>
        </>
      )}
      {showVSCodeInsiders && (
        <ActionList.Item onSelect={onOpenInVSCodeInsiders}>
          <ActionList.LeadingVisual>
            <VscodeIcon />
          </ActionList.LeadingVisual>
          Open in VS Code Insiders
        </ActionList.Item>
      )}
      <ActionList.Item onSelect={onOpenInGitHubDesktop}>
        <ActionList.LeadingVisual>
          <DesktopDownloadIcon />
        </ActionList.LeadingVisual>
        Open with GitHub Desktop
      </ActionList.Item>
      <ActionList.Divider />
      <CLICommandListItem
        toolName="GitHub CLI"
        buttonAriaLabel="Copy GitHub agent-task command to clipboard"
        inputId="github-cli"
        command={ghCommand}
        additionalInfo={
          <>
            Work fast with our official CLI.{' '}
            <Link inline href="https://cli.github.com" target="_blank" rel="noopener noreferrer">
              Learn more<span className="sr-only"> about the GitHub CLI</span>
            </Link>
          </>
        }
      />
      {isFeatureEnabled('mission_control_show_copilot_cli_handoff_command') && (
        <>
          <ActionList.Divider />
          <CLICommandListItem
            toolName="Copilot CLI"
            buttonAriaLabel="Copy Copilot CLI command to clipboard"
            inputId="copilot-cli"
            command={copilotCLICommand}
            additionalInfo={
              <>
                Automate coding tasks with Copilot CLI.{' '}
                <Link inline href="https://github.com/features/copilot/cli" target="_blank" rel="noopener noreferrer">
                  Learn more<span className="sr-only"> about the Copilot CLI</span>
                </Link>
              </>
            }
          />
        </>
      )}
    </ActionList>
  )
}

export function CLICommandListItem({
  toolName,
  buttonAriaLabel,
  inputId,
  command,
  additionalInfo,
}: {
  toolName: string
  buttonAriaLabel: string
  inputId: string
  command: string
  additionalInfo?: React.ReactElement
}) {
  return (
    <ul>
      <li className={styles.cliSection}>
        <div className={styles.cliHeader}>
          <TerminalIcon className="fgColor-muted" />
          <span>{toolName}</span>
        </div>
        <CloneUrl
          buttonAriaLabel={buttonAriaLabel}
          inputId={inputId}
          inputLabel={`${toolName} command`}
          url={command}
        />
        {additionalInfo && <p className="text-small fgColor-muted mb-0">{additionalInfo}</p>}
      </li>
    </ul>
  )
}

import {copyText} from '@github-ui/copy-to-clipboard'
import {useCurrentRepository} from '@github-ui/current-repository'
import {isFeatureEnabled} from '@github-ui/feature-flags'
import {sendEvent} from '@github-ui/hydro-analytics'
import {
  CodeIcon,
  CodespacesIcon,
  CopyIcon,
  DesktopDownloadIcon,
  TerminalIcon,
  TriangleDownIcon,
  VscodeIcon,
} from '@primer/octicons-react'
import {ActionList, ActionMenu, Button, ButtonGroup} from '@primer/react'
import type {Pull} from '../../types/pull'
import {buildGitHubDesktopBranchUrl} from '../../utils/github-desktop'
import {AgentsIcon16} from '../AgentsIcon'
import {attemptOpenUrlWithFallback, createHandleOpenInVSCode, createHandleOpenInVSCodeInsiders} from './OpenInMenu'
import styles from './OpenInMenuV2.module.css'

interface OpenInMenuV2Props {
  branchName: string
  pull?: Pull
  className?: string
  taskId?: string
  isCurrentUserTaskCreator?: boolean
}

export function OpenInMenuV2({pull, branchName, className, taskId, isCurrentUserTaskCreator}: OpenInMenuV2Props) {
  const repo = useCurrentRepository()

  // Button on left side of button group (default action when PR is present)
  const getOpenInVSCodeButton = () => {
    if (!pull) {
      return null
    }

    const handleOpenInVSCode = createHandleOpenInVSCode(pull.repository_nwo, pull.global_relay_id, pull.head_ref_name)
    return (
      <Button
        onClick={() => {
          sendEvent('repo_agents', {
            target: 'open_in_vscode',
            task_id: taskId,
            pull_id: pull.global_relay_id,
            branch_name: branchName,
          })
          handleOpenInVSCode()
        }}
        leadingVisual={<VscodeIcon className="hide-sm" />}
        size="small"
      >
        Open in VS Code
      </Button>
    )
  }

  // Menu button on right side of button group (or standalone button if no PR)
  const getActionMenuButton = () => {
    if (pull) {
      return (
        <ActionMenu.Button
          size="small"
          aria-label="More options"
          icon={<TriangleDownIcon className={styles.dropdownIcon} />}
        />
      )
    }

    return (
      <ActionMenu.Button leadingVisual={<CodeIcon className="hide-sm" />} size="small" aria-label="More options">
        Code
      </ActionMenu.Button>
    )
  }

  const getOpenInVSCodeInsidersItem = () => {
    // TODO: Allow this for non-PR tasks once VS Code supports task ID
    if (!pull) {
      return null
    }

    const handleOpenInVSCodeInsiders = createHandleOpenInVSCodeInsiders(
      pull.repository_nwo,
      pull.global_relay_id,
      pull.head_ref_name,
    )

    return (
      <ActionList.Item
        onSelect={() => {
          sendEvent('repo_agents', {
            target: 'open_in_vscode_insiders',
            task_id: taskId,
            pull_id: pull.global_relay_id,
            branch_name: branchName,
          })
          handleOpenInVSCodeInsiders()
        }}
      >
        <ActionList.LeadingVisual>
          <VscodeIcon size={16} />
        </ActionList.LeadingVisual>
        Open in VS Code Insiders
      </ActionList.Item>
    )
  }

  const getContinueInCopilotCLIItem = () => {
    const disableCLIResume = isFeatureEnabled('copilot_mc_cli_resume_any_users_task') && !isCurrentUserTaskCreator

    // TODO: Allow this for non-PR tasks once the Copilot CLI supports task ID
    if (!pull) {
      return null
    }

    const cliCommand = `copilot --resume=${pull.global_relay_id}`

    return (
      <>
        <ActionList.Item
          onSelect={() => {
            sendEvent('repo_agents', {
              target: 'continue_in_copilot_cli',
              task_id: taskId,
              pull_id: pull.global_relay_id,
            })
            copyText(cliCommand)
          }}
          disabled={disableCLIResume}
          inactiveText={disableCLIResume ? 'Only session creator can resume' : undefined}
        >
          <ActionList.LeadingVisual>
            <AgentsIcon16 />
          </ActionList.LeadingVisual>
          Continue in Copilot CLI
          {!disableCLIResume ? (
            <ActionList.Description className={styles.cliDescription} variant="block">
              {cliCommand}
            </ActionList.Description>
          ) : null}
          <ActionList.TrailingVisual>
            <CopyIcon size={16} />
          </ActionList.TrailingVisual>
        </ActionList.Item>
        <ActionList.Divider />
      </>
    )
  }

  const getCheckoutWithGitHubCLIItem = () => {
    return (
      <ActionList.Item
        onSelect={() => {
          sendEvent('repo_agents', {
            target: 'checkout_with_github_cli',
            task_id: taskId,
            pull_id: pull?.global_relay_id,
          })
          copyText(`gh pr checkout ${branchName}`)
        }}
      >
        <ActionList.LeadingVisual>
          <TerminalIcon size={16} />
        </ActionList.LeadingVisual>
        Checkout with GitHub CLI
        <ActionList.TrailingVisual>
          <CopyIcon size={16} />
        </ActionList.TrailingVisual>
      </ActionList.Item>
    )
  }

  const getCreateCodespaceItem = () => {
    if (!repo) {
      return null
    }

    const createCodespacePath = `/codespaces/new?skip_quickstart=true&repo=${repo.id}&ref=${encodeURIComponent(
      branchName,
    )}`
    return (
      <ActionList.Item
        onSelect={() => {
          sendEvent('repo_agents', {
            target: 'create_codespace',
            task_id: taskId,
            pull_id: pull?.global_relay_id,
            repo_id: repo.id.toString(),
          })
          window.open(createCodespacePath, '_self')
        }}
      >
        <ActionList.LeadingVisual>
          <CodespacesIcon size={16} />
        </ActionList.LeadingVisual>
        Create a codespace
      </ActionList.Item>
    )
  }

  const getCheckoutWithGitHubDesktopItem = () => {
    if (!repo) {
      return null
    }

    const repoNwo = `${repo.ownerLogin}/${repo.name}`
    const desktopUrl = buildGitHubDesktopBranchUrl(repoNwo, branchName)
    if (!desktopUrl) {
      return null
    }

    return (
      <ActionList.Item
        onSelect={() => {
          sendEvent('repo_agents', {
            target: 'checkout_with_github_desktop',
            task_id: taskId,
            pull_id: pull?.global_relay_id,
            repo_nwo: repoNwo,
          })
          attemptOpenUrlWithFallback(desktopUrl, repoNwo)
        }}
      >
        <ActionList.LeadingVisual>
          <DesktopDownloadIcon size={16} />
        </ActionList.LeadingVisual>
        Checkout with GitHub Desktop
      </ActionList.Item>
    )
  }

  const getActionMenu = () => {
    return (
      <ActionMenu>
        {getActionMenuButton()}
        <ActionMenu.Overlay className={styles.overlay} align="end" side="outside-top">
          <ActionList>
            {getContinueInCopilotCLIItem()}
            {getOpenInVSCodeInsidersItem()}
            {getCheckoutWithGitHubCLIItem()}
            {getCreateCodespaceItem()}
            {getCheckoutWithGitHubDesktopItem()}
          </ActionList>
        </ActionMenu.Overlay>
      </ActionMenu>
    )
  }

  return (
    <div className={className}>
      {pull ? ( // TODO: Once VS Code supports opening sessions with task ID, we can always show the button group
        <ButtonGroup>
          {getOpenInVSCodeButton()}
          {getActionMenu()}
        </ButtonGroup>
      ) : (
        getActionMenu()
      )}
    </div>
  )
}

import {type FilePagePayload, isTreePayload, type LayoutPayload, type PanelType} from '@github-ui/code-view-types'
import {useCurrentUser} from '@github-ui/current-user'
import safeStorage from '@github-ui/safe-storage'
// eslint-disable-next-line no-restricted-imports
import {ScreenSize, useScreenSize} from '@github-ui/screen-size'
import React, {createContext, useCallback, use, useEffect, useLayoutEffect, useRef, useState} from 'react'
import {useIsDataRouterEnabled} from '@github-ui/react-core/future/use-is-data-router-enabled'

const safeLocalStorage = safeStorage('localStorage')

export type SetPanelOpenType = (panelType: PanelType | undefined, returnFocusTarget?: HTMLElement | null) => void

// Split contexts: state is dynamic, dispatch is stable
export const OpenPanelStateContext = createContext<PanelType | undefined>(undefined)
export const OpenPanelDispatchContext = createContext<SetPanelOpenType>(() => undefined)

// Keep the combined type for backward compatibility
type OpenPanelContextType = {
  openPanel: PanelType | undefined
  setOpenPanel: SetPanelOpenType
}

/** @deprecated Use OpenPanelStateContext and OpenPanelDispatchContext directly */
export const OpenPanelContext = createContext<OpenPanelContextType>({
  openPanel: undefined,
  setOpenPanel: () => undefined,
})

/**
 * This is equivalent to a simple setState, except we will not show the
 * state as 'codeNav' or allow it to be set to 'codeNav' when on the blame page.
 * This also adds a listener to hide the panel on smaller viewports
 */
export function OpenPanelProvider({
  children,
  payload,
  openPanelRef,
  action,
}: {
  children: React.ReactNode
  payload: FilePagePayload | LayoutPayload
  openPanelRef: React.MutableRefObject<string | undefined>
  action?: string
}) {
  const isDataRouter = useIsDataRouterEnabled()

  // Legacy: derive from payload
  const hasBlameFromPayload = 'blame' in payload
  const isTreeViewFromPayload = isTreePayload(payload)

  // Compute derived values
  const hasBlame = isDataRouter ? action === 'blame' : hasBlameFromPayload
  const isTreeView = isDataRouter ? action === 'tree' : isTreeViewFromPayload

  // Use refs to keep setOpenPanel stable while still accessing current values
  const hasBlameRef = useRef(hasBlame)
  const isTreeViewRef = useRef(isTreeView)
  useLayoutEffect(() => {
    hasBlameRef.current = hasBlame
    isTreeViewRef.current = isTreeView
  })

  const currentUser = useCurrentUser()

  const returnFocusTargetRef = useRef<HTMLElement | null | undefined>(undefined)
  const [rawOpenPanel, setRawOpenPanel] = useState<PanelType | undefined>(() => {
    const storedSetting = safeLocalStorage.getItem('codeNavOpen')
    //only use the cookie if the user isn't logged in
    if (!currentUser && storedSetting !== '' && storedSetting !== null) {
      return 'codeNav'
    }
    if (currentUser && payload.symbolsExpanded) {
      return 'codeNav'
    }
  })

  const openPanel = (hasBlame || isTreeView) && rawOpenPanel === 'codeNav' ? undefined : rawOpenPanel

  React.useEffect(() => {
    openPanelRef.current = openPanel
  }, [openPanel, openPanelRef])

  const setOpenPanel = useCallback((panelType: PanelType | undefined, returnFocusTarget?: HTMLElement | null) => {
    setRawOpenPanel(currentPanel => {
      if (currentPanel && returnFocusTargetRef.current) {
        returnFocusTargetRef.current.focus()
      }
      returnFocusTargetRef.current = returnFocusTarget
      return hasBlameRef.current || (isTreeViewRef.current && panelType === 'codeNav') ? undefined : panelType
    })
  }, [])

  useHandlePanelScreenResize(setOpenPanel)

  return (
    <OpenPanelStateContext value={openPanel}>
      <OpenPanelDispatchContext value={setOpenPanel}>{children}</OpenPanelDispatchContext>
    </OpenPanelStateContext>
  )
}

// This should be SSR safe since it won't run on the server
function useHandlePanelScreenResize(setOpenPanel: (panel: PanelType | undefined) => void) {
  const {screenSize} = useScreenSize()
  const previousScreenSize = useRef(screenSize)

  useEffect(() => {
    // hide the panel if our previous render was on large screen size and the current size is smaller
    // (this prevents the panel from hiding when resizing between small/medium screen sizes)
    // or if the screenSize is a small viewport on our initial load
    const isChangingToSmallViewport = previousScreenSize.current >= ScreenSize.large
    const isInitialLoad = previousScreenSize.current === screenSize

    if (screenSize < ScreenSize.large && (isChangingToSmallViewport || isInitialLoad)) {
      setOpenPanel(undefined)
    }

    previousScreenSize.current = screenSize
  }, [screenSize, setOpenPanel])
}

export function useOpenPanel() {
  return {
    openPanel: use(OpenPanelStateContext),
    setOpenPanel: use(OpenPanelDispatchContext),
  }
}

/** Use when you only need the current panel state (will re-render when panel changes) */
export function useOpenPanelState() {
  return use(OpenPanelStateContext)
}

/** Use when you only need to set the panel (won't re-render when panel changes) */
export function useSetOpenPanel() {
  return use(OpenPanelDispatchContext)
}

import {ListBlock} from '@github-ui/pacer/ListBlock'
import {AlertIcon} from '@primer/octicons-react'
import type {UITask} from '../../types/task'
import {OptimisticTaskListItem, TaskListItem} from './TaskListItem'
import type {TaskListProps} from '../../types/task-list'

interface OpenTaskListProps extends TaskListProps {
  tasks: UITask[]
}

export function OpenTaskList({tasks, isError}: OpenTaskListProps) {
  return (
    <ListBlock.List id="tasks-list" aria-labelledby="open-tab">
      {isError ? (
        <ListBlock.EmptyState>
          <AlertIcon size={24} />
          <p>Sorry, something went wrong</p>
        </ListBlock.EmptyState>
      ) : tasks.length === 0 ? (
        <ListBlock.EmptyState>
          <p>No open tasks yet. Start a new task to see it here.</p>
        </ListBlock.EmptyState>
      ) : (
        <>
          {tasks.map(task => {
            // Handle optimistic tasks (newly created tasks that haven't been confirmed by server yet)
            if (task.isOptimistic) {
              return (
                <OptimisticTaskListItem
                  key={task.clientGeneratedId}
                  title={`Creating: ${task.problemStatement ?? ''}`}
                  repositoryNwo={task.nwo ?? ''}
                />
              )
            }

            // Handle tasks with pull request data
            return (
              task.pull && (
                <TaskListItem
                  key={task.pull.id}
                  state={task.latest_session_state}
                  startedAt={task.latest_session_updated_at}
                  revisionCount={task.session_count - 1}
                  prState={task.pull.state}
                  prUrl={task.pull.url}
                  prTitle={task.pull.title}
                  prNwo={task.pull.repository_nwo}
                  prNumber={task.pull.number}
                  prGlobalId={task.pull.global_relay_id}
                  prInMergeQueue={task.pull.inMergeQueue ?? false}
                  prDiffSummary={task.pull.pr_diff_summary}
                />
              )
            )
          })}
        </>
      )}
    </ListBlock.List>
  )
}

import {AllShortcutsEnabled} from '@github-ui/code-view-shared/components/AllShortcutsEnabled'
import {useShortcut} from '@github-ui/code-view-shared/hooks/shortcuts'
import {useReposAnalytics} from '@github-ui/code-view-shared/hooks/use-repos-analytics'
import {useIsPlatform} from '@github-ui/use-is-platform'
import {ActionList} from '@primer/react'

export default function OpenWithActionItems({
  editEnabled,
  githubDevUrl,
  ghDesktopPath,
  onBranch,
}: {
  editEnabled: boolean
  githubDevUrl: string | null
  ghDesktopPath: string | null
  onBranch: boolean
}) {
  const {sendRepoClickEvent} = useReposAnalytics()
  const isMacOrWindows = useIsPlatform(['windows', 'mac'])
  const {openWithGitHubDevShortcut} = useShortcut()
  return (
    <ActionList.Group>
      <ActionList.GroupHeading>Open with...</ActionList.GroupHeading>
      {
        // TODO: add support for codespaces here
      }
      {githubDevUrl ? (
        <ActionList.LinkItem
          onClick={() =>
            sendRepoClickEvent('BLOB_EDIT_DROPDOWN.DEV_LINK', {
              ['edit_enabled']: editEnabled,
            })
          }
          className="js-blob-dropdown-click js-github-dev-shortcut"
          href={githubDevUrl}
          data-hotkey={openWithGitHubDevShortcut.hotkey}
        >
          github.dev
          <ActionList.TrailingVisual aria-hidden="true">
            <AllShortcutsEnabled>
              <kbd>.</kbd>
            </AllShortcutsEnabled>
          </ActionList.TrailingVisual>
        </ActionList.LinkItem>
      ) : null}
      {onBranch && isMacOrWindows && ghDesktopPath ? (
        <ActionList.LinkItem onClick={() => sendRepoClickEvent('BLOB_EDIT_DROPDOWN.DESKTOP')} href={ghDesktopPath}>
          GitHub Desktop
        </ActionList.LinkItem>
      ) : null}
    </ActionList.Group>
  )
}

export function useHasOpenWithItems(githubDevUrl: string | null, onBranch: boolean, ghDesktopPath: string | null) {
  const isMacOrWindows = useIsPlatform(['windows', 'mac'])
  return !!(githubDevUrl || (onBranch && isMacOrWindows && ghDesktopPath))
}

import linkButtonStyles from '@github-ui/code-view-shared/css/LinkButton.module.css'
import {ownerPath, repositoryPath} from '@github-ui/paths'
import type {SafeHTMLString} from '@github-ui/safe-html'
import {VerifiedHTMLBox} from '@github-ui/safe-html/VerifiedHTML'
// eslint-disable-next-line no-restricted-imports
import {ScreenSize} from '@github-ui/screen-size'
import {ssrSafeWindow} from '@github-ui/ssr-utils'
import {FileIcon} from '@primer/octicons-react'
import {Breadcrumbs, Link, LinkButton} from '@primer/react'
import {Octicon} from '@primer/react/deprecated'
import {clsx} from 'clsx'
import type {PropsWithChildren} from 'react'

import styles from './OrgOnboardingTip.module.css'

interface OrgOnboardingTipProps {
  mediaUrl?: string
  mediaPreviewSrc?: string
  iconSvg: SafeHTMLString
  taskTitle: string
  taskPath: string
  org: string
}

export function OrgOnboardingTip({
  children,
  mediaUrl,
  mediaPreviewSrc,
  iconSvg,
  taskTitle,
  taskPath,
  org,
}: PropsWithChildren<OrgOnboardingTipProps>) {
  return (
    <section className={styles.Box}>
      <div className={styles.Box_1}>
        <SuggestIcon iconSvg={iconSvg} />

        <div className={styles.Box_2}>
          <Breadcrumbs>
            <Breadcrumbs.Item href={ownerPath({owner: org})}>Tasks</Breadcrumbs.Item>
            <Breadcrumbs.Item href={taskPath} className={styles.Breadcrumbs_Item}>
              {taskTitle}
            </Breadcrumbs.Item>
          </Breadcrumbs>
          {children}
        </div>
      </div>
      <Media mediaPreviewSrc={mediaPreviewSrc} mediaUrl={mediaUrl} />
    </section>
  )
}

function SuggestIcon({iconSvg}: {iconSvg: SafeHTMLString}) {
  return (
    <div className={styles.Box_3}>
      <VerifiedHTMLBox html={iconSvg} className={styles.VerifiedHTMLBox} />
      <Bubble size={6} color="#6c84e9" bottom={-7} left={-7} />
      <Bubble size={4} color="#9e7bff" top={-4} right={4} />
      <Bubble size={6} color="#6c84e9" top={-7} right={-8} />
    </div>
  )
}

function Bubble({
  size,
  color,
  left,
  right,
  top,
  bottom,
}: {
  size: number
  color: string
  left?: number
  right?: number
  top?: number
  bottom?: number
}) {
  return (
    <div
      style={{
        width: size,
        height: size,
        left: `${left}px`,
        right: `${right}px`,
        top: `${top}px`,
        bottom: `${bottom}px`,
        backgroundColor: color,
      }}
      className={styles.Box_4}
    />
  )
}

function Media({mediaUrl, mediaPreviewSrc}: Pick<OrgOnboardingTipProps, 'mediaUrl' | 'mediaPreviewSrc'>) {
  //on the server assume we are on mobile where an image rendering then disappearing would be far more annoying
  //than an image popping in on a desktop browser
  if ((ssrSafeWindow?.innerWidth ?? 0) < ScreenSize.xlarge || !mediaUrl || !mediaPreviewSrc) return null

  return (
    <div className={clsx('org-onboarding-tip-media', styles.Box_5)}>
      <Link href={mediaUrl} className={styles.Link}>
        <img src={mediaPreviewSrc} alt="Guidance" loading="lazy" style={{width: '50%', height: '50%'}} />
      </Link>
    </div>
  )
}

interface ActionsOnboardingPromptProps {
  repo: string
  owner: string
}
export function ActionsOnboardingPrompt({repo, owner}: ActionsOnboardingPromptProps) {
  return (
    <div>
      <h3 className={styles.Text}>Auto-assign new issue with GitHub Actions</h3>
      <div className={styles.Box_6}>
        <p>
          The <span className={styles.Text_1}>auto-assign.yml</span> file below lives inside your{' '}
          <span className={styles.Text_1}>demo-repository</span> and defines when and how it’s automatically triggered.
          This{' '}
          <a href="https://github.com/marketplace/actions/auto-assign-issues-prs" target="_blank" rel="noreferrer">
            “Auto Assign” workflow
          </a>{' '}
          happens to add reviewers and assignees to issues and pull requests when they’re opened in this repository.
        </p>

        <p>
          You can see the results of this workflow in any{' '}
          <a href={repositoryPath({owner, repo, action: 'issues'})}>issue</a> or{' '}
          <a href={repositoryPath({owner, repo, action: 'pulls'})}>pull request</a> that you create in this repository,
          as it’ll assign them to the specified members. And you can see a log of any workflows you run in{' '}
          <a href={repositoryPath({owner, repo, action: 'actions'})}>your repository’s “Actions” tab.</a>
        </p>

        <div className={styles.Box_7}>
          <LinkButton
            variant="primary"
            href={repositoryPath({owner, repo, action: 'issues/new'})}
            className={linkButtonStyles.linkButton}
          >
            Create new issue to see results
          </LinkButton>

          <Link href="https://docs.github.com/actions" target="_blank" className={styles.Link_1}>
            <Octicon icon={FileIcon} className={styles.Octicon} />
            Learn how automation works on GitHub
          </Link>
        </div>
      </div>
    </div>
  )
}

import {testIdProps} from '@github-ui/test-id-props'
import {KebabHorizontalIcon} from '@primer/octicons-react'
import {ActionList, ActionMenu, IconButton, type IconButtonProps} from '@primer/react'
import {merge} from '@primer/styled-react'
import {Fragment, useMemo} from 'react'

import {useActionBarContent} from './ActionBarContentContext'
import {useActionBarRef} from './ActionBarRefContext'
import {useActionBarResize} from './ActionBarResizeContext'
import styles from './OverflowMenu.module.css'

export type OverflowMenuProps = {
  anchorProps?: Omit<IconButtonProps, 'aria-labelledby'>
  /** Optional controlled open state for the overflow menu. */
  open?: boolean
  /** Callback when the menu requests an open state change. */
  onOpenChange?: (open: boolean) => void
}

const defaultMenuToggleIcon = KebabHorizontalIcon
const defaultMenuToggleVariant = 'invisible'

export const OverflowMenu = ({
  anchorProps: {
    'aria-label': ariaLabel,
    icon = defaultMenuToggleIcon,
    variant = defaultMenuToggleVariant,
    ...otherAnchorProps
    // eslint-disable-next-line @eslint-react/no-unstable-default-props
  } = {
    icon: defaultMenuToggleIcon,
    variant: defaultMenuToggleVariant,
  },
  open,
  onOpenChange,
}: OverflowMenuProps) => {
  const {anchorRef} = useActionBarRef()
  const {actions, staticMenuActions, label} = useActionBarContent()
  const {visibleChildEndIndex} = useActionBarResize()

  const anchorProps = useMemo(
    () =>
      merge(otherAnchorProps, {
        'aria-label': ariaLabel?.trim() || `More ${label}`,
        icon,
        className: styles.IconButton_0,
        variant,
      }),
    [ariaLabel, icon, label, variant, otherAnchorProps],
  )

  const overflowActions = useMemo(() => actions?.slice(visibleChildEndIndex), [actions, visibleChildEndIndex])

  const hasOverflowActions = overflowActions && overflowActions.length > 0
  const hasStaticMenuActions = staticMenuActions && staticMenuActions.length > 0

  if (!hasOverflowActions && !hasStaticMenuActions) return null

  return (
    <ActionMenu anchorRef={anchorRef} open={open} onOpenChange={onOpenChange}>
      <ActionMenu.Anchor>
        <IconButton {...testIdProps('overflow-menu-anchor')} {...anchorProps} />
      </ActionMenu.Anchor>
      <ActionMenu.Overlay align="end" data-overflow-menu-overlay>
        <ActionList>
          {hasStaticMenuActions &&
            staticMenuActions.map(staticMenuAction => (
              <Fragment key={staticMenuAction.key}>{staticMenuAction.render()}</Fragment>
            ))}

          {overflowActions?.map(action => (
            <Fragment key={action.key}>{action.render(true)}</Fragment>
          ))}
        </ActionList>
      </ActionMenu.Overlay>
    </ActionMenu>
  )
}

