import type {CodeNavigationInfo, CodeSymbol, DefinitionOrReference} from '@github-ui/code-nav'
import TableOfContentsPanel from '@github-ui/code-view-shared/components/TableOfContentsPanel'
import type {PanelType} from '@github-ui/code-view-types'
// eslint-disable-next-line no-restricted-imports
import {ScreenSize, useScreenSize} from '@github-ui/screen-size'
import type {SearchInFileStatus} from '@github-ui/use-in-file-search-results'
import {useStickyObserver} from '@github-ui/use-sticky-header/useStickyObserver'
import {Dialog} from '@primer/react/experimental'
import React from 'react'

import {useCurrentBlob} from '../hooks/CurrentBlob'
import {updateExpandPreferences} from '../hooks/use-update-panel-expand-preferences'
import type {CodeNavData} from './blob/BlobContent/BlobContent'
import {CodeNavInfoPanel} from './blob/BlobContent/CodeNav/CodeNavInfoPanel'
import {Panel} from './Panel'

interface InnerPanelContentProps {
  stickyStyle: React.CSSProperties | undefined
  stickyHeaderElement: Element | null
  openPanel: PanelType
  isCodeNavLoading: boolean
  codeNavInfo: CodeNavigationInfo
  setOpenPanel: (panel: PanelType | undefined) => void
  showCodeNavWithSymbol: (symbol: CodeSymbol) => void
  searchingText: CodeNavData
  setSearchingText: React.Dispatch<React.SetStateAction<CodeNavData>>
  searchStatus: SearchInFileStatus
  searchResults: DefinitionOrReference[]
  setSearchResults: (results: DefinitionOrReference[]) => void
  setFocusedSearchResult: (index: number | undefined) => void
  autoFocusSearch: boolean
  className?: string
}

interface OuterPanelContentProps extends Omit<InnerPanelContentProps, 'isNarrow'> {
  setOpenPanel: (panel: PanelType | undefined) => void
}

export const PanelContent = React.memo(PanelContentUnmemoized)

function PanelContentUnmemoized(props: OuterPanelContentProps) {
  const {...innerProps} = props
  const [isNarrow, setIsNarrow] = React.useState(false)
  const {screenSize} = useScreenSize()

  React.useEffect(() => {
    setIsNarrow(screenSize < ScreenSize.large)
  }, [screenSize])

  return (
    <>
      {!isNarrow && <InnerPanelContent className={'inner-panel-content-not-narrow'} {...props} />}
      {isNarrow && (
        <Dialog
          onClose={() => innerProps.setOpenPanel(undefined)}
          renderHeader={() => null}
          renderBody={() => InnerPanelContent({...innerProps})}
        />
      )}
    </>
  )
}

function InnerPanelContent({
  stickyStyle,
  stickyHeaderElement,
  openPanel,
  isCodeNavLoading,
  codeNavInfo,
  setOpenPanel,
  showCodeNavWithSymbol,
  searchingText,
  setSearchingText,
  setSearchResults,
  setFocusedSearchResult,
  autoFocusSearch,
  className,
}: InnerPanelContentProps) {
  const {
    headerInfo: {toc},
  } = useCurrentBlob()

  const isStickied = useStickyObserver(stickyHeaderElement)
  const borderStyle: React.CSSProperties = isStickied ? {borderRadius: '0px 0px 6px 6px', borderTop: 0} : {}

  return (
    <Panel
      style={{...stickyStyle, ...borderStyle}}
      className={`panel-content-narrow-styles ${className ? className : ''}`}
    >
      {openPanel === 'toc' ? (
        <TableOfContentsPanel
          toc={toc}
          onClose={() => {
            setOpenPanel(undefined)
          }}
        />
      ) : (
        openPanel === 'codeNav' && (
          <CodeNavInfoPanel
            codeNavInfo={codeNavInfo}
            showCodeNavWithSymbol={showCodeNavWithSymbol}
            selectedText={searchingText.selectedText}
            lineNumber={searchingText.lineNumber - 1}
            offset={searchingText.offset}
            onClose={() => {
              setOpenPanel(undefined)
              localStorage.setItem('codeNavOpen', '')
              updateExpandPreferences(null, false, null)
              // return focus to symbols button
              document.getElementById('symbols-button')?.focus()
            }}
            isLoading={isCodeNavLoading}
            onClear={() => setSearchingText({selectedText: '', lineNumber: 0, offset: -1})}
            setSearchResults={setSearchResults}
            setFocusedSearchResult={setFocusedSearchResult}
            autoFocusSearch={autoFocusSearch}
          />
        )
      )}
    </Panel>
  )
}

import type {
  CopilotAnnotation,
  CopilotAnnotationItem,
  CodeInsightsInfo,
  PublicCodeReferenceInfo,
} from '../types/code-insights-metadata'

function extractNwoFromURL(url: string): string | undefined {
  try {
    const urlObj = new URL(url, 'https://github.com')
    // Extract path segments, typically: /owner/repo/...
    const pathParts = urlObj.pathname.split('/').filter(Boolean)
    if (pathParts.length >= 2) {
      return `${pathParts[0]}/${pathParts[1]}`
    }
    return undefined
  } catch {
    return undefined
  }
}

function mapCopilotAnnotationItemToPublicCodeReference(
  item: CopilotAnnotationItem,
): PublicCodeReferenceInfo | undefined {
  const citations = item.citations
  if (!citations || !citations.url) {
    return undefined
  }

  return {
    annotationId: item.id,
    sourceURL: citations.url,
    license: citations.license || undefined,
    language: undefined, // Not available in the raw annotation format
    nwo: extractNwoFromURL(citations.url),
  }
}

export function parseCopilotAnnotationsToCodeInsights(copilotAnnotations: unknown): CodeInsightsInfo | undefined {
  if (!copilotAnnotations) {
    return undefined
  }

  let parsed: CopilotAnnotation
  try {
    parsed = typeof copilotAnnotations === 'string' ? JSON.parse(copilotAnnotations) : copilotAnnotations
  } catch {
    return undefined
  }

  const publicCodeReferences = Object.values(parsed)
    .flat()
    .flatMap(item => {
      const ref = mapCopilotAnnotationItemToPublicCodeReference(item)
      return ref ? [ref] : []
    })

  return publicCodeReferences.length > 0 ? {publicCodeReferences} : undefined
}

import {DiffLineType} from '@github-ui/diffs/types'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import type {StaticDiffLine} from '@github-ui/diff-lines/conversation-types'

/**
 * Escapes HTML special characters to prevent XSS
 */
function escapeHtml(text: string): string {
  const map: Record<string, string> = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;',
  }
  return text.replace(/[&<>"']/g, m => map[m] ?? m)
}

/**
 * Parses a unified diff string into an array of StaticDiffLine objects
 * for rendering with StaticUnifiedDiffPreview
 */
export function parseUnifiedDiff(diffString: string): StaticDiffLine[] {
  const lines = diffString.split('\n')
  const diffLines: StaticDiffLine[] = []
  let leftLineNum = 0
  let rightLineNum = 0

  for (const line of lines) {
    if (line.startsWith('@@')) {
      const match = line.match(/@@ -(\d+)(?:,\d+)? \+(\d+)(?:,\d+)? @@/)
      if (match && match[1] && match[2]) {
        leftLineNum = parseInt(match[1], 10)
        rightLineNum = parseInt(match[2], 10)
      }

      diffLines.push({
        type: DiffLineType.Hunk,
        left: null,
        right: null,
        html: escapeHtml(line),
        text: line,
      })
    } else if (line.startsWith('+') && !line.startsWith('+++')) {
      const content = line.slice(1)
      diffLines.push({
        type: DiffLineType.Addition,
        left: null,
        right: rightLineNum++,
        html: escapeHtml(content),
        text: content,
      })
    } else if (line.startsWith('-') && !line.startsWith('---')) {
      const content = line.slice(1)
      diffLines.push({
        type: DiffLineType.Deletion,
        left: leftLineNum++,
        right: null,
        html: escapeHtml(content),
        text: content,
      })
    } else if (line.startsWith(' ')) {
      const content = line.slice(1)
      diffLines.push({
        type: DiffLineType.Context,
        left: leftLineNum++,
        right: rightLineNum++,
        html: escapeHtml(content),
        text: content,
      })
    }
  }

  return diffLines
}

import React from 'react'

const PathContext = React.createContext<string>('')

export function PathProvider({children, path}: React.PropsWithChildren<{path: string}>) {
  return <PathContext value={path}>{children}</PathContext>
}

export function usePath() {
  return React.use(PathContext)
}

import {DuplicateOnKeydownButton} from '@github-ui/code-view-shared/components/DuplicateOnKeydownButton'
import {useShortcut} from '@github-ui/code-view-shared/hooks/shortcuts'
import {useUrlCreator} from '@github-ui/code-view-shared/hooks/use-url-creator'
import {addUrlToHistoryStack} from '@github-ui/history'

import {textAreaId} from '../utilities/lines'

export function PermalinkShortcut() {
  const urlCreator = useUrlCreator()
  const {permalinkShortcut} = useShortcut()

  if (urlCreator.isCurrentPagePermalink()) {
    return (
      <DuplicateOnKeydownButton
        buttonFocusId={textAreaId}
        buttonHotkey={permalinkShortcut.hotkey}
        buttonTestLabel={'header-permalink-button'}
        onlyAddHotkeyScopeButton
        onButtonClick={() => {
          //no-op so that the user isn't moved to the bottom of the page while the text area has focus
        }}
      />
    )
  }

  return (
    <DuplicateOnKeydownButton
      buttonFocusId={textAreaId}
      buttonHotkey={permalinkShortcut.hotkey}
      buttonTestLabel={'header-permalink-button'}
      onButtonClick={() => {
        const permalink = urlCreator.createPermalink()
        if (window.location.href.indexOf(permalink) < 0) {
          addUrlToHistoryStack(permalink)
        }
      }}
    />
  )
}

import type {PlanSupportInfo} from '@github-ui/code-view-types'
import {Button, Flash} from '@primer/react'

import styles from './PlanSupportBanner.module.css'

export interface PlanSupportBannerProps extends PlanSupportInfo {
  feature?: string
  featureName?: string
}

export function PlanSupportBanner({
  feature,
  featureName,
  repoIsFork,
  repoOwnedByCurrentUser,
  requestFullPath,
  showFreeOrgGatedFeatureMessage,
  showPlanSupportBanner,
  upgradeDataAttributes,
  upgradePath,
}: PlanSupportBannerProps) {
  const dataAttributes: {[key: string]: string} = {}
  if (upgradeDataAttributes) {
    for (const key in upgradeDataAttributes) {
      dataAttributes[`data-${key}`] = upgradeDataAttributes[key]!
    }
  }
  return showPlanSupportBanner ? (
    <Flash variant="warning" className={styles.Flash}>
      {repoOwnedByCurrentUser ? (
        repoIsFork ? (
          `This repository is a fork, and inherits the features of the parent repository. Contact the owner of the root repository to enable ${
            featureName || 'this feature'
          }`
        ) : (
          <div className={styles.Box}>
            <span className={styles.Text}>{`Upgrade to GitHub Pro or make this repository public to enable ${
              featureName || 'this feature'
            }.`}</span>
            <UpgradeButton
              dataAttributes={dataAttributes}
              individual
              requestFullPath={requestFullPath}
              feature={feature}
              upgradePath={upgradePath}
            />
          </div>
        )
      ) : showFreeOrgGatedFeatureMessage ? (
        <div className={styles.Box}>
          <span className={styles.Text}>{`Upgrade to GitHub Team or make this repository public to enable ${
            featureName || 'this feature'
          }.`}</span>
          <UpgradeButton
            dataAttributes={dataAttributes}
            individual={false}
            requestFullPath={requestFullPath}
            feature={feature}
            upgradePath={upgradePath}
          />
        </div>
      ) : (
        `Contact the owner of the repository to enable ${featureName || 'this feature'}.`
      )}
    </Flash>
  ) : null
}

function UpgradeButton({
  dataAttributes,
  individual,
  requestFullPath,
  feature,
  upgradePath,
}: {
  dataAttributes: {[key: string]: string}
  individual: boolean
  requestFullPath: string
  feature?: string
  upgradePath: string
}) {
  return (
    <Button
      {...dataAttributes}
      data-ga-click={`Change ${
        individual ? 'individual' : 'organization'
      }, click to upgrade, ref_page:${requestFullPath};ref_cta:Upgrade now;ref_loc:${feature};location:${feature};text:Upgrade now`}
      onClick={() => {
        location.href = upgradePath
      }}
    >
      Upgrade now
    </Button>
  )
}

export const isBrowser = () => typeof window !== 'undefined'

export const checkPrefersReducedMotion = () => {
  let prefersReducedMotion = false
  if (!isBrowser()) return prefersReducedMotion

  if (window.matchMedia) {
    const motionMediaQuery = window.matchMedia('(prefers-reduced-motion)')
    prefersReducedMotion = motionMediaQuery.matches
  }

  return prefersReducedMotion
}

export const hasWebGLSupport = () => {
  if (!isBrowser()) return false
  const canvas = document.createElement('canvas')
  const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl')
  return gl && gl instanceof WebGLRenderingContext
}

import {Banner} from '@primer/react'
import {verifiedFetch} from '@github-ui/verified-fetch'
import {useState} from 'react'

interface PremiumRequestsBannerProps {
  onBannerDismiss?: () => void
  enabled?: boolean
}

export function PremiumRequestsBanner({onBannerDismiss, enabled = true}: PremiumRequestsBannerProps) {
  const [internalDismissed, setInternalDismissed] = useState(false)

  if (!enabled || internalDismissed) {
    return null
  }

  return (
    <Banner
      variant="upsell"
      title="Copilot premium requests announcement"
      hideTitle
      description={
        <>
          <span className="text-bold">Copilot coding agent now uses fewer premium requests!</span> From now on, each
          session uses just one premium request.
        </>
      }
      primaryAction={
        <Banner.PrimaryAction
          as="a"
          href="https://docs.github.com/copilot/concepts/copilot-billing/understanding-and-managing-requests-in-copilot"
        >
          Learn more
        </Banner.PrimaryAction>
      }
      onDismiss={async () => {
        setInternalDismissed(true)
        if (onBannerDismiss) {
          onBannerDismiss()
        }
        await verifiedFetch('/settings/dismiss-notice/copilot_coding_agent_premium_requests_banner', {method: 'POST'})
      }}
    />
  )
}

import {sendEvent} from '@github-ui/hydro-analytics'
import {useNavigableRef} from '@github-ui/navigable-ref'
import {SidebarExpandIcon} from '@primer/octicons-react'
