import {verifiedFetch} from '@github-ui/verified-fetch'
import {XIcon} from '@primer/octicons-react'
import {Flash, IconButton, LinkButton} from '@primer/react'

import {useState} from 'react'
import linkButtonStyles from '../css/LinkButton.module.css'

import styles from './PublishBanners.module.css'
import {clsx} from 'clsx'

export default function PublishBanners({
  showPublishActionBanner,
  releasePath,
  dismissActionNoticePath,
  className,
}: {
  showPublishActionBanner: boolean
  releasePath: string
  dismissActionNoticePath: string
  className?: string
}) {
  const [hidden, setHidden] = useState(false)

  const onDismissPublishAction = () => {
    verifiedFetch(dismissActionNoticePath, {method: 'POST'})
    setHidden(true)
  }

  return showPublishActionBanner ? (
    <Flash hidden={hidden} className={clsx(className, styles.Flash)}>
      {showPublishActionBanner && <div className="flex-1">You can publish this Action to the GitHub Marketplace</div>}
      <LinkButton href={releasePath} className={clsx(linkButtonStyles.linkButton, 'f6 mr-2')}>
        Draft a release
      </LinkButton>
      <IconButton
        icon={XIcon}
        tooltipDirection="s"
        aria-label="Dismiss"
        className="bgColor-transparent border-0 pr-0"
        onClick={showPublishActionBanner ? onDismissPublishAction : () => {}}
      />
    </Flash>
  ) : null
}

import {createContext, use, useMemo} from 'react'
import type {Pull} from '../types/pull'

interface PullContextType {
  pull: Pull | undefined
}

export const PullContext = createContext<PullContextType | undefined>(undefined)

export function usePullContext() {
  const context = use(PullContext)
  if (!context) {
    throw new Error('usePullContext must be used within a PullContextProvider')
  }
  return context
}

interface PullContextProviderProps extends PullContextType {
  children: React.ReactNode
}

export function PullContextProvider({pull, children}: PullContextProviderProps) {
  const value = useMemo(() => ({pull}), [pull])
  return <PullContext value={value}>{children}</PullContext>
}

import {sendEvent} from '@github-ui/hydro-analytics'
import {FileDiffIcon, GitPullRequestIcon, type Icon} from '@primer/octicons-react'
import {Button, ButtonGroup, Spinner} from '@primer/react'

import {useCreatePullRequestForTask} from '../../hooks/use-create-pull-request-for-task'
import styles from './PullRequestButton.module.css'
import {isFeatureEnabled} from '@github-ui/feature-flags'

interface PullRequestButtonProps {
  pullUrl?: string
  repoNwo: string
  baseRef?: string
  headRef?: string
  taskId?: string
  disabled?: boolean
  onError?: (message: string) => void
}

export function PullRequestButton({
  pullUrl,
  taskId,
  repoNwo,
  baseRef,
  headRef,
  disabled = false,
  onError,
}: PullRequestButtonProps) {
  const useCopilotAuthoredPullRequest = isFeatureEnabled('copilot_authors_decoupled_pr')

  const {createPullRequest, isLoading} = useCreatePullRequestForTask()

  const handleViewPRClick = () => {
    sendEvent('agent_sessions.task_view', {
      target: 'VIEW_PULL_REQUEST_BUTTON',
      pull_url: pullUrl,
      task_id: taskId,
    })
  }

  const handleViewDiffClick = () => {
    sendEvent('agent_sessions.task_view', {
      target: 'VIEW_PULL_REQUEST_DIFF_BUTTON',
      pull_url: pullUrl,
      task_id: taskId,
    })
  }

  const handleCreatePRClick = () => {
    sendEvent('agent_sessions.task_view', {
      target: 'CREATE_PULL_REQUEST_BUTTON',
      task_id: taskId,
    })
  }

  const handleCreatePRViaAPI = () => {
    if (!taskId) return

    sendEvent('agent_sessions.task_view', {
      target: 'CREATE_PULL_REQUEST_BUTTON',
      task_id: taskId,
    })

    createPullRequest(
      {repoNwo, taskId},
      {
        onSuccess: response => {
          window.location.href = `/${repoNwo}/pull/${response.number}`
        },
        onError: error => {
          onError?.(error instanceof Error ? error.message : 'Failed to create pull request')
        },
      },
    )
  }

  const generateCreatePullRequestPath = () => {
    return `/${repoNwo}/compare/${baseRef}...${headRef}`
  }

  const renderCreatePRButton = () => {
    if (useCopilotAuthoredPullRequest && taskId) {
      return (
        <Button
          className={styles.button}
          leadingVisual={isLoading ? () => <Spinner size="small" /> : GitPullRequestIcon}
          variant="primary"
          size="small"
          onClick={handleCreatePRViaAPI}
          aria-label="Create pull request"
          aria-disabled={disabled || isLoading}
          inactive={disabled || isLoading}
          disabled={disabled || isLoading}
        >
          Create pull request
        </Button>
      )
    }

    return (
      <ButtonComponent
        url={generateCreatePullRequestPath()}
        icon={<GitPullRequestIcon className="hide-sm" />}
        onClick={handleCreatePRClick}
        label="Create pull request"
        disabled={disabled}
      />
    )
  }

  return pullUrl ? (
    <ButtonGroup>
      <ButtonComponent
        url={pullUrl}
        icon={<GitPullRequestIcon />}
        onClick={handleViewPRClick}
        label="View pull request"
      />
      <ButtonComponent
        url={`${pullUrl}/files`}
        icon={<FileDiffIcon className={styles.diffIcon} />}
        onClick={handleViewDiffClick}
        ariaLabel="View pull request files"
      />
    </ButtonGroup>
  ) : baseRef && headRef ? (
    renderCreatePRButton()
  ) : null
}

function ButtonComponent({
  url,
  icon,
  onClick,
  label,
  ariaLabel,
  disabled = false,
}: {
  url: string
  icon: React.ReactElement | Icon
  onClick: () => void
  label?: string
  ariaLabel?: string
  disabled?: boolean
}) {
  return (
    <Button
      as="a"
      href={disabled ? undefined : url}
      target="_self"
      className={styles.button}
      leadingVisual={icon}
      variant="primary"
      size="small"
      onClick={disabled ? undefined : onClick}
      aria-label={ariaLabel || label}
      aria-disabled={disabled}
      inactive={disabled}
      tabIndex={disabled ? 0 : undefined}
    >
      {label}
    </Button>
  )
}

import {Stack} from '@primer/react'
import type {PullRequestDiffSummary} from '../../types/pull-request-diff-summary'
import styles from './PullRequestDiffSummaryText.module.css'

function buildScreenReaderHint({linesAdded, linesDeleted}: {linesAdded: number; linesDeleted: number}): string {
  let labelText = 'Lines changed: '
  labelText += `${linesAdded} ${linesAdded === 1 ? 'addition' : 'additions'} & `
  labelText += `${linesDeleted} ${linesDeleted === 1 ? 'deletion' : 'deletions'}`
  return labelText
}

export function PullRequestDiffSummaryText({prDiffSummary}: {prDiffSummary?: PullRequestDiffSummary}) {
  if (!prDiffSummary || (prDiffSummary.lines_added === 0 && prDiffSummary.lines_deleted === 0)) return null

  return (
    <Stack direction="horizontal" gap="condensed">
      <span aria-hidden="true" className={`${styles.prDiffSummary} ${styles.added}`}>
        +{prDiffSummary.lines_added.toLocaleString()}
      </span>
      <span aria-hidden="true" className={`${styles.prDiffSummary} ${styles.deleted}`}>
        -{prDiffSummary.lines_deleted.toLocaleString()}
      </span>
      <span className="sr-only">
        {buildScreenReaderHint({linesAdded: prDiffSummary.lines_added, linesDeleted: prDiffSummary.lines_deleted})}
      </span>
    </Stack>
  )
}

