import {DiffComparisonViewer} from '@github-ui/pull-requests/components/DiffComparisonViewer'
import {Banner} from '@primer/react'
import {InfoIcon} from '@primer/octicons-react'
import styles from './PullRequestFilesChangedPreview.module.css'

export interface PullRequestFilesChangedPreviewProps {
  headSha: string
  basePath: string
  isSessionRunning?: boolean
  isSessionReadonly?: boolean
  agentDisplayName?: string
}

export function PullRequestFilesChangedPreview({
  headSha,
  basePath,
  isSessionRunning,
  isSessionReadonly,
  agentDisplayName = 'Agent',
}: PullRequestFilesChangedPreviewProps) {
  return (
    <div className={styles.container}>
      {isSessionRunning && (
        <Banner
          variant="info"
          title={`${agentDisplayName} is working`}
          description={
            isSessionReadonly
              ? `${agentDisplayName} code review in progress.`
              : `${agentDisplayName} is still working. Changes will automatically appear once they have been committed to the branch.`
          }
          hideTitle
          icon={<InfoIcon />}
          className={styles.banner}
        />
      )}
      <DiffComparisonViewer.Container>
        <DiffComparisonViewer.Viewer
          headSha={headSha}
          basePath={basePath}
          forceUnifiedView
          treeEnableInlineCompactMode
          key={basePath}
          useFileTree
          useBasicToolbar
          useInlineComments={isSessionReadonly}
          userCanComment={!isSessionReadonly}
        />
      </DiffComparisonViewer.Container>
    </div>
  )
}

