import {MarkdownPreview} from '@github-ui/copilot-immersive-v1/components/ContentPreview/MarkdownPreview'
import {NewMarkdownViewer} from '@github-ui/markdown-viewer/NewMarkdownViewer'
import type {SafeHTMLString} from '@github-ui/safe-html'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import type {PullRequestOverviewReference} from '@github-ui/copilot-chat/utils/copilot-chat-types'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {copilotFeatureFlags} from '@github-ui/copilot-chat/utils/copilot-feature-flags'
import {GitHubAvatar} from '@github-ui/github-avatar'
import {ArrowLeftIcon, CheckCircleFillIcon, CopilotIcon, XCircleFillIcon} from '@primer/octicons-react'
import {BranchName, Heading, Link, PageHeader, RelativeTime} from '@primer/react'
