import {ChecksStatusButton} from './ChecksStatusButton'
import {InProgressSpinner} from '../StatusIcon'
import styles from './PullRequestOverviewPreview.module.css'
import pluralize from 'pluralize'
import {isFeatureEnabled} from '@github-ui/feature-flags'

export function PullRequestOverviewPreview({
  title,
  number,
  body,
  bodyHTML,
  repositoryNwo,
  baseRef,
  headRef,
  headSha,
  sessionState,
  sessionUpdatedAt,
  sessionCount,
  premiumRequestCount,
  selectedModel,
  isSingleSessionView,
  commitAliveChannel,
  isCopilotCodingAgent,
}: PullRequestOverviewReference) {
  const useBodyHTML = isFeatureEnabled('mission_control_use_body_html')

  const getSessionIcon = () => {
    if (!sessionState) return null

    switch (sessionState) {
      case 'completed':
        return <CheckCircleFillIcon className={styles.iconCompleted} size={16} />
      case 'failed':
      case 'timed_out':
        return <XCircleFillIcon className={styles.iconFailed} size={16} />
      case 'in_progress':
        return <InProgressSpinner />
      default:
        return null
    }
  }

  const getSessionStatusText = () => {
    return (
      <span className={styles.sessionStatusWrapper}>
        {sessionState === 'completed' && <span>Completed</span>}
        {sessionState === 'failed' && <span>Failed</span>}
        {sessionState === 'timed_out' && <span>Timed out</span>}
        {sessionState === 'in_progress' && <span>Started</span>}
        {sessionUpdatedAt && <RelativeTime date={new Date(sessionUpdatedAt)} tense="past" />}
      </span>
    )
  }

  const getPullRequestContext = () => {
    return (
      <>
        {repositoryNwo && (
          <Link href={`/${repositoryNwo}`} className={styles.repositoryName}>
            {repositoryNwo}
          </Link>
        )}
        {baseRef && headRef && (
          <span className={styles.branchWrapper}>
            <span className={styles.branchComparison}>
              <BranchName href={`/${repositoryNwo}/tree/${baseRef}`}>{baseRef}</BranchName>
              <ArrowLeftIcon />
              <BranchName href={`/${repositoryNwo}/tree/${headRef}`}>{headRef}</BranchName>
            </span>
            <span className={styles.copyButtonWrapper}>
              <CopyToClipboardButton ariaLabel="Copy head branch name to clipboard" size="small" textToCopy={headRef} />
            </span>
          </span>
        )}
      </>
    )
  }

  return (
    <div className={styles.container}>
      <PageHeader>
        <PageHeader.TitleArea>
          <PageHeader.Title className={styles.titleContainer} as="h1">
            <span>
              <span>{title}</span>{' '}
              <Link className={styles.pullNumber} href={`/${repositoryNwo}/pull/${number}`}>
                #{number}
              </Link>
            </span>
          </PageHeader.Title>
        </PageHeader.TitleArea>
        <PageHeader.Description>
          <div className={styles.sessionStatus}>
            <span className={styles.sessionStatusWrapper}>
              {getSessionIcon()}
              {getSessionStatusText()}
            </span>
            {sessionUpdatedAt && repositoryNwo && <span className={styles.separator}> · </span>}
            {getPullRequestContext()}
            <ChecksStatusButton
              headSha={headSha || ''}
              repositoryNwo={repositoryNwo || ''}
              commitAliveChannel={commitAliveChannel}
            />
          </div>
        </PageHeader.Description>
      </PageHeader>

      <div className={styles.summaryBox}>
        <div
          className={
            copilotFeatureFlags.codingAgentModelSelection
              ? !isSingleSessionView && premiumRequestCount > 0 && sessionCount !== undefined && sessionCount > 0
                ? styles.summaryHeader // Has session data
                : styles.summaryHeaderModelOnly // Model only
              : styles.summaryHeader // Feature flag disabled
          }
        >
          <Heading as="h2" className={styles.summaryHeading}>
            Summary
          </Heading>
          {copilotFeatureFlags.codingAgentModelSelection && isCopilotCodingAgent ? (
            // Feature flag enabled - show model + optional session data
            !isSingleSessionView && premiumRequestCount > 0 && sessionCount !== undefined && sessionCount > 0 ? (
              // Show model with session/premium/updated data
              <div className={styles.summaryMetadata}>
                {selectedModel && (
                  <span className={styles.modelDisplay}>
                    {selectedModel.logoURL ? (
                      <GitHubAvatar
                        alt={`${selectedModel.vendor} logo`}
                        square
                        size={18}
                        src={selectedModel.logoURL}
                        className={styles.modelIcon}
                      />
                    ) : (
                      <CopilotIcon className={styles.modelIcon} />
                    )}
                    <span>{selectedModel.displayName}</span>
                  </span>
                )}
                <span>
                  {selectedModel && <span className={styles.separator}> · </span>}
                  {sessionCount} {pluralize('session', sessionCount)}
                </span>
                {premiumRequestCount > 0 && (
                  <span>
                    <span className={styles.separator}> · </span>
                    {premiumRequestCount} premium {pluralize('request', premiumRequestCount)}
                  </span>
                )}
                {sessionUpdatedAt && (
                  <span>
                    <span className={styles.separator}> · </span>
                    Last updated <RelativeTime date={new Date(sessionUpdatedAt)} tense="past" />
                  </span>
                )}
              </div>
            ) : (
              // Show only model
              <div className={styles.summaryMetadata}>
                {selectedModel && (
                  <span className={styles.modelDisplay}>
                    {selectedModel.logoURL ? (
                      <GitHubAvatar
                        alt={`${selectedModel.vendor} logo`}
                        square
                        size={18}
                        src={selectedModel.logoURL}
                        className={styles.modelIcon}
                      />
                    ) : (
                      <CopilotIcon className={styles.modelIcon} />
                    )}
                    <span>{selectedModel.displayName}</span>
                  </span>
                )}
              </div>
            )
          ) : (
            // Feature flag disabled - original behavior without model
            <div className={styles.summaryMetadata}>
              {!isSingleSessionView && premiumRequestCount > 0 && sessionCount !== undefined && sessionCount > 0 && (
                <>
                  {sessionCount} {pluralize('session', sessionCount)}
                  {premiumRequestCount > 0 && (
                    <span>
                      {' '}
                      · {premiumRequestCount} premium {pluralize('request', premiumRequestCount)}
                    </span>
                  )}
                  {sessionUpdatedAt && (
                    <span>
                      {' '}
                      · Last updated <RelativeTime date={new Date(sessionUpdatedAt)} tense="past" />
                    </span>
                  )}
                </>
              )}
            </div>
          )}
        </div>
        <div className={styles.summaryContent}>
          {useBodyHTML && bodyHTML ? (
            <div className={styles.markdownBody}>
              <NewMarkdownViewer
                // eslint-disable-next-line @github-ui/github-monorepo/no-cast-as-safe-html-string -- HTML is sanitized server-side. TODO: Move type assertion to data ingress point.
                verifiedHTML={bodyHTML as SafeHTMLString}
              />
            </div>
          ) : body ? (
            <MarkdownPreview
              content={{
                value: body,
                name: `pull-request-${number}-${repositoryNwo}.md`,
              }}
              hideHeadingAnchors
              fallbackToRaw
              useLoadingSkeletonWithOptions={[
                {size: 'bodyMedium', lines: 3},
                {size: 'titleLarge', lines: 1},
                {size: 'bodyMedium', lines: 8},
              ]}
            />
          ) : (
            <p className={styles.emptyDescription}>No description provided.</p>
          )}
        </div>
      </div>
    </div>
  )
}

