import {useShortcut} from '@github-ui/code-view-shared/hooks/shortcuts'
import {useReposAnalytics} from '@github-ui/code-view-shared/hooks/use-repos-analytics'
import {ActionList} from '@primer/react'
import {useCallback} from 'react'

import {useCurrentBlob} from '../../../hooks/CurrentBlob'
import {type CopyState, getCopyStateUI} from '../../../utilities/Copy'
import {KeyboardVisual} from '../../../utilities/KeyboardVisual'

export default function RawMenuActionItems({
  viewable,
  onCopy,
  name,
  updateTooltipMessage,
  all,
}: {
  viewable: boolean
  onCopy: () => Promise<CopyState>
  name: string
  updateTooltipMessage: (message: string) => void
  all?: boolean
}) {
  const {sendRepoClickEvent} = useReposAnalytics()
  const {rawBlobUrl} = useCurrentBlob()
  const {downloadRawContentShortcut} = useShortcut()
  const downloadFileCallback = useCallback(async () => await downloadFile(rawBlobUrl, name), [name, rawBlobUrl])

  return (
    <ActionList.Group>
      <ActionList.GroupHeading>Raw file content</ActionList.GroupHeading>
      {all && <CopyActionItem viewable={viewable} onCopy={onCopy} updateTooltipMessage={updateTooltipMessage} />}
      {all && <RawActionItem onClick={() => sendRepoClickEvent('BLOB_RAW_DROPDOWN.VIEW')} rawHref={rawBlobUrl} />}
      <ActionList.LinkItem onClick={downloadFileCallback}>
        Download
        {downloadRawContentShortcut.text && (
          <ActionList.TrailingVisual aria-hidden="true" className="d-flex">
            <KeyboardVisual shortcut={downloadRawContentShortcut} />
          </ActionList.TrailingVisual>
        )}
      </ActionList.LinkItem>
    </ActionList.Group>
  )
}

export async function downloadFile(rawHref: string, name: string) {
  const result = await fetch(rawHref, {method: 'get'})
  const blob = await result.blob()
  const aElement = document.createElement('a')
  aElement.setAttribute('download', name)
  const href = URL.createObjectURL(blob)
  aElement.href = href
  aElement.setAttribute('target', '_blank')
  aElement.click()
  URL.revokeObjectURL(href)
}

function CopyActionItem({
  viewable,
  onCopy,
  updateTooltipMessage,
}: {
  viewable: boolean
  onCopy: () => Promise<CopyState>
  updateTooltipMessage: (message: string) => void
}): React.ReactElement | null {
  const {copyRawContentShortcut} = useShortcut()
  return viewable ? (
    <ActionList.Item
      onSelect={async () => {
        const result = await onCopy()
        const {ariaLabel} = getCopyStateUI(result)
        updateTooltipMessage(ariaLabel)
      }}
    >
      Copy
      {copyRawContentShortcut.text && (
        <ActionList.TrailingVisual aria-hidden="true" className="d-flex">
          <KeyboardVisual shortcut={copyRawContentShortcut} />
        </ActionList.TrailingVisual>
      )}
    </ActionList.Item>
  ) : null
}

function RawActionItem({onClick, rawHref}: {onClick?: () => void; rawHref: string}) {
  const {viewRawContentShortcut} = useShortcut()
  return (
    <ActionList.LinkItem onClick={onClick} href={rawHref}>
      View
      {viewRawContentShortcut.text && (
        <ActionList.TrailingVisual aria-hidden="true" className="d-flex">
          <KeyboardVisual shortcut={viewRawContentShortcut} />
        </ActionList.TrailingVisual>
      )}
    </ActionList.LinkItem>
  )
}

import {EditorState, type Extension, Annotation} from '@codemirror/state'

// Annotation to mark external updates that should bypass readonly protection
export const externalUpdate = Annotation.define<boolean>()

export function readOnly(): Extension {
  return [
    EditorState.readOnly.of(true),
    EditorState.transactionFilter.of(tr => {
      // Allow transactions marked as external updates, block all other document changes
      if (tr.docChanged && !tr.annotation(externalUpdate)) {
        return []
      }
      return tr
    }),
  ]
}

import type {RecentlyTouchedBranch} from '@github-ui/code-view-types'
import React, {useMemo} from 'react'

export interface RecentlyTouchedBranches {
  branches?: RecentlyTouchedBranch[] | null
  channel?: string | null
  canCreatePullRequest?: boolean
}

export interface RecentlyTouchedBranchesContextData extends RecentlyTouchedBranches {
  refetch: () => void
}

const noop = () => {}

const defaultValue: RecentlyTouchedBranchesContextData = {
  branches: null,
  channel: null,
  canCreatePullRequest: true,
  refetch: noop,
}

const RecentlyTouchedBranchesContext = React.createContext<RecentlyTouchedBranchesContextData>(defaultValue)

export function useRecentlyTouchedBranches() {
  return React.use(RecentlyTouchedBranchesContext)
}

export function RecentlyTouchedBranchesProvider({
  branches,
  channel,
  canCreatePullRequest = true,
  refetch,
  children,
}: React.PropsWithChildren<{
  branches?: RecentlyTouchedBranch[] | null
  channel?: string | null
  canCreatePullRequest?: boolean
  refetch: () => void
}>) {
  const value = useMemo(
    () => ({branches, channel, canCreatePullRequest, refetch}),
    [branches, channel, canCreatePullRequest, refetch],
  )

  return <RecentlyTouchedBranchesContext value={value}>{children}</RecentlyTouchedBranchesContext>
}

import type {RefComparison} from '@github-ui/code-view-types'
import type {Repository} from '@github-ui/current-repository'
import {comparePath} from '@github-ui/paths'
import {BranchName} from '@primer/react'
import {Link, type LinkProps} from '@primer/styled-react'

import {getCommitsCountText} from './get-commits-count-text'
import {useReposAnalytics} from '../../../hooks/use-repos-analytics'

interface Props {
  repo: Repository
  comparison: RefComparison
  linkify?: boolean
}

export function RefComparisonText({comparison, repo, linkify = false}: Props) {
  const {sendRepoClickEvent} = useReposAnalytics()
  const {ahead, behind, baseBranch, baseBranchRange, currentRef} = comparison

  const aheadLink = comparePath({repo, base: baseBranchRange, head: currentRef})
  const behindLink = comparePath({repo, base: currentRef, head: baseBranchRange})

  const sendAheadLinkAnalytics = () =>
    sendRepoClickEvent('AHEAD_BEHIND_LINK', {
      category: 'Branch Infobar',
      action: 'Ahead Compare',
      label: `ref_loc:bar;is_fork:${repo.isFork}`,
    })

  const sendBehindLinkAnalytics = () =>
    sendRepoClickEvent('AHEAD_BEHIND_LINK', {
      category: 'Branch Infobar',
      action: 'Behind Compare',
      label: `ref_loc:bar;is_fork:${repo.isFork}`,
    })

  if (ahead === 0 && behind === 0) {
    return (
      <span>
        This branch is up to date with <BranchName as="span">{baseBranch}</BranchName>.
      </span>
    )
  }

  if (ahead > 0 && behind > 0) {
    return (
      <span>
        This branch is{' '}
        <LinkOrText linkify={linkify} href={aheadLink} onClick={sendAheadLinkAnalytics}>
          {getCommitsCountText(ahead)} ahead of
        </LinkOrText>
        {' and '}
        <LinkOrText linkify={linkify} href={behindLink} onClick={sendBehindLinkAnalytics}>
          {getCommitsCountText(behind)} behind
        </LinkOrText>{' '}
        <BranchName as="span">{baseBranch}</BranchName>.
      </span>
    )
  }

  if (ahead > 0) {
    return (
      <span>
        This branch is{' '}
        <LinkOrText linkify={linkify} href={aheadLink} onClick={sendAheadLinkAnalytics}>
          {getCommitsCountText(ahead)} ahead of
        </LinkOrText>{' '}
        <BranchName as="span">{baseBranch}</BranchName>.
      </span>
    )
  } else {
    return (
      <span>
        This branch is{' '}
        <LinkOrText linkify={linkify} href={behindLink} onClick={sendBehindLinkAnalytics}>
          {getCommitsCountText(behind)} behind
        </LinkOrText>{' '}
        <BranchName as="span">{baseBranch}</BranchName>.
      </span>
    )
  }
}

function LinkOrText({sx, href, linkify, children, ...props}: Omit<LinkProps, 'as'> & {linkify: boolean}) {
  if (linkify) {
    return (
      <Link sx={sx} href={href} {...props}>
        {children}
      </Link>
    )
  }

  return <span>{children}</span>
}

import type {RefInfo} from '@github-ui/repos-types'
import React, {useMemo} from 'react'

/**
 * Core RefInfo without edit permission fields.
 * canEdit, canEditOnDefaultBranch, and fileExistsOnDefault are in EditPermissionsContext
 * since they change more frequently.
 */
export type CoreRefInfo = Omit<RefInfo, 'canEdit' | 'canEditOnDefaultBranch' | 'fileExistsOnDefault'>

const RefInfoContext = React.createContext<CoreRefInfo | null>(null)

export function RefInfoProvider({children, refInfo}: React.PropsWithChildren<{refInfo?: RefInfo}>) {
  const value = useMemo(
    () => ({
      name: refInfo?.name ?? '',
      listCacheKey: refInfo?.listCacheKey ?? '',
      refType: refInfo?.refType,
      currentOid: refInfo?.currentOid ?? '',
    }),
    [refInfo?.name, refInfo?.listCacheKey, refInfo?.refType, refInfo?.currentOid],
  )

  return <RefInfoContext value={value}>{children}</RefInfoContext>
}

export function useRefInfo(): CoreRefInfo {
  const context = React.use(RefInfoContext)
  if (context === null) {
    throw new Error('useRefInfo must be used within a RefInfoProvider')
  }
  return context
}

