import {SessionLogs} from '../session-logs/SessionLogs'
import {SessionHeader} from './SessionHeader'
import {SessionFeedbackButtons} from './feedback/SessionFeedbackButtons'

import {clsx} from 'clsx'
import pluralize from 'pluralize'
import {useEffect, useRef, useState} from 'react'
import {useSessionContext} from '../../contexts/SessionContext'
import type {PublicUser} from '../../types/public-user'
import type {Pull} from '../../types/pull'
import {isActiveSession, SessionState, isPendingSession} from '../../types/session'
import {SessionLogsProvider} from '../session-logs/Context'
import styles from './Session.module.css'
import {useIntentDetection} from '../../hooks/useIntentDetection'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {WithShimmerEffect} from '@github-ui/copilot-chat/components/WithShimmerEffect'
import {Stack} from '@primer/react'
import {AgentAvatar} from '../AgentAvatar'
import {CopilotAnimationType} from '@github-ui/copilot-animation'

const GLOBAL_TOGGLE_EVENT = 'session-global-toggle'

interface SessionProps {
  defaultOpen?: boolean
  onOpenChange: (open: boolean) => void
  scrollContainerRef: React.RefObject<HTMLDivElement | null>
  hideStopButton?: boolean
  onToolExpand: (expand: boolean) => void
  shouldHighlight?: boolean
  stickyHeaders?: boolean
  currentUserCanPush?: boolean
  pull?: Pull
  logsPollingInterval?: number
  currentUser?: PublicUser
  clearPendingChat?: () => void
  pendingChat?: string | null
  nwo?: string
  isStreamingChat?: boolean
  streamingChatResponse?: string | null
}

export function Session({
  defaultOpen = false,
  onOpenChange,
  scrollContainerRef,
  hideStopButton = false,
  onToolExpand,
  shouldHighlight = false,
  stickyHeaders = true,
  currentUserCanPush,
  pull,
  logsPollingInterval,
  currentUser,
  clearPendingChat,
  pendingChat,
  isStreamingChat,
  streamingChatResponse,
  nwo,
}: SessionProps) {
  const {session} = useSessionContext()

  // Use provided nwo, fall back to pull's repository_nwo for backwards compatibility
  const effectiveNwo = nwo ?? pull?.repository_nwo

  const [isOpen, setIsOpen] = useState(defaultOpen)
  const [logsAreLoading, setLogsAreLoading] = useState(false)
  const sessionContainerRef = useRef<HTMLDivElement>(null)
  const toolInstanceRef = useRef({})

  const {isChatSession, isUsingIntentDetection} = useIntentDetection(session)

  const handlerRef = useRef<(event: Event) => void>((event: Event) => {
    const customEvent = event as CustomEvent<{expand: boolean; excludeInstance: object}>
    if (customEvent.detail.excludeInstance !== toolInstanceRef.current) {
      const shouldExpand = customEvent.detail.expand
      setIsOpen(shouldExpand)
    }
  })

  // Set up global expand/collapse event listener
  useEffect(() => {
    const globalToggleHandler = (event: Event) => {
      handlerRef.current?.(event)
    }

    document.addEventListener(GLOBAL_TOGGLE_EVENT, globalToggleHandler)

    return () => {
      document.removeEventListener(GLOBAL_TOGGLE_EVENT, globalToggleHandler)
    }
  }, [])

  const handleModifierClick = (expand: boolean) => {
    setIsOpen(expand)

    // Dispatch event to all other tools
    const event = new CustomEvent(GLOBAL_TOGGLE_EVENT, {
      detail: {expand, excludeInstance: toolInstanceRef.current},
    })
    document.dispatchEvent(event)
  }

  const handleOpenChange = (open: boolean) => {
    setIsOpen(open)
    onOpenChange(open)
  }

  const isActive = isActiveSession(session)
  const isPending = isPendingSession(session)
  const contentId = `session-content-${session.id}`

  // Scroll to this session if it should be highlighted.
  useEffect(() => {
    if (!shouldHighlight) return
    if (!sessionContainerRef.current) return

    // Use back-to-back `requestAnimationFrame`s to wait for layout to settle before scrolling.
    let frameId = 0
    let secondFrameId = 0
    frameId = requestAnimationFrame(() => {
      secondFrameId = requestAnimationFrame(() => {
        sessionContainerRef.current?.scrollIntoView({
          behavior: 'smooth',
          block: 'start',
        })
      })
    })

    return () => {
      cancelAnimationFrame(frameId)
      cancelAnimationFrame(secondFrameId)
    }
  }, [shouldHighlight])

  // For intent detection POC we don't want to show things like the session box early.
  // Use a more classic chat display, then it will shift to session or chat as needed.
  if (isPending && isUsingIntentDetection) {
    return (
      <Stack direction="horizontal" padding="none" align="center" justify="start" gap="condensed">
        <AgentAvatar animationType={CopilotAnimationType.Thinking} loopAnimation />
        <WithShimmerEffect className="color-fg-muted">Planning response...</WithShimmerEffect>
      </Stack>
    )
  }

  const containerClassNames = isChatSession
    ? `${styles.contentContainer} ${styles.chatContentContainer}`
    : styles.contentContainer

  return (
    <div
      ref={sessionContainerRef}
      className={clsx(styles.detailsContainer, {
        [styles.permalinkedSession]: shouldHighlight,
      })}
      data-active={isActive}
      data-session-id={session.id}
    >
      <SessionHeader
        nwo={effectiveNwo}
        currentUserCanPush={!!currentUserCanPush}
        isCollapsed={!isOpen}
        onModifierClick={handleModifierClick}
        scrollContainerRef={scrollContainerRef}
        hideStopButton={hideStopButton}
        contentId={contentId}
        onOpenChange={handleOpenChange}
        sticky={stickyHeaders}
      />
      <div id={contentId} className={containerClassNames} data-expanded={isOpen || isChatSession}>
        <div className={styles.logsContainer}>
          <SessionLogsProvider
            variant="mission-control"
            onToolExpand={onToolExpand}
            session={session}
            sessionNwo={effectiveNwo}
          >
            <SessionLogs
              logsPollingInterval={logsPollingInterval ?? 3000}
              nwo={effectiveNwo}
              currentUser={currentUser}
              batchCompletedSessions
              onLogsLoadingChange={setLogsAreLoading}
              clearPendingChat={clearPendingChat}
              pendingChat={pendingChat}
              isStreamingChat={isStreamingChat}
              streamingChatResponse={streamingChatResponse}
            />
          </SessionLogsProvider>
        </div>
        {(session.state === SessionState.Completed || session.state === SessionState.InProgress) &&
          session.premium_requests > 0 &&
          !logsAreLoading && (
            <div className={styles.bottomFooter}>
              <div>
                <span className="text-semibold">{session.premium_requests} </span>
                <span className="fgColor-muted">premium {pluralize('request', session.premium_requests)}</span>
              </div>
              {!isActiveSession(session) && !logsAreLoading && <SessionFeedbackButtons />}
            </div>
          )}
      </div>
    </div>
  )
}

import {Banner} from '@primer/react'
import {SkipIcon} from '@primer/octicons-react'
import {useSessionContext} from '../../contexts/SessionContext'
import {useAgentInfo} from '../../hooks/use-agent-info'

interface SessionCancelledBannerProps {
  cancellationMessage: string | null
  workflowRunLink: string | null
}

export function SessionCancelledBanner({cancellationMessage, workflowRunLink}: SessionCancelledBannerProps) {
  const {session} = useSessionContext()
  const {data: agentInfo} = useAgentInfo(session.agent_id)
  const defaultCancellationMessage = 'The session was cancelled.'
  const sessionCancelledMessage = cancellationMessage || defaultCancellationMessage
  return (
    <Banner
      aria-label="Session Cancelled"
      title={`${agentInfo?.display_name || 'Agent'}'s work was cancelled`}
      description={sessionCancelledMessage}
      variant="warning"
      icon={<SkipIcon />}
      primaryAction={
        workflowRunLink && (
          <Banner.PrimaryAction as="a" href={workflowRunLink}>
            View detailed logs
          </Banner.PrimaryAction>
        )
      }
    />
  )
}

import {createContext, use, useMemo, useState, type Dispatch, type SetStateAction} from 'react'
import type {LogEntry, Session} from '../types/session'
import type {PublicUser} from '../types/public-user'

interface SessionContextType {
  session: Session
  sessionOwner: PublicUser | undefined
  logs?: LogEntry[]
  logsAreLoading?: boolean
  mcpToolNameMappings: Record<string, string>
  setMcpToolNameMappings: Dispatch<SetStateAction<Record<string, string>>>
}

export const SessionContext = createContext<SessionContextType | undefined>(undefined)

export function useSessionContext() {
  const context = use(SessionContext)
  if (!context) {
    throw new Error('useSessionContext must be used within a SessionContextProvider')
  }
  return context
}

interface SessionContextProviderProps {
  session: Session
  sessionOwner: PublicUser | undefined
  logs?: LogEntry[]
  logsAreLoading?: boolean
  children: React.ReactNode
}

export function SessionContextProvider({
  session,
  sessionOwner,
  logs,
  logsAreLoading,
  children,
}: SessionContextProviderProps) {
  const [mcpToolNameMappings, setMcpToolNameMappings] = useState<Record<string, string>>({})
  const value = useMemo(
    () => ({session, sessionOwner, logs, logsAreLoading, mcpToolNameMappings, setMcpToolNameMappings}),
    [session, sessionOwner, logs, logsAreLoading, mcpToolNameMappings],
  )
  return <SessionContext value={value}>{children}</SessionContext>
}

import {useEffect, useState} from 'react'
import {calculateElapsedTime} from '../utils/elapsed-time-util'
import {SessionState} from '../types/session'

function SessionElapsedTime({
  createdAt,
  completedAt,
  state,
}: {
  createdAt: Date | string
  completedAt?: Date | string
  state: SessionState
}) {
  // Use useEffect to update the elapsed time when props change
  const [elapsedTime, setElapsedTime] = useState<string>(() => calculateElapsedTime(createdAt, completedAt))

  // Calculate initial elapsed time and update when props change
  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setElapsedTime(calculateElapsedTime(createdAt, completedAt))

    if (state === SessionState.InProgress || state === SessionState.Queued) {
      const interval = setInterval(() => {
        setElapsedTime(calculateElapsedTime(createdAt, completedAt))
      }, 500)
      return () => clearInterval(interval)
    }
  }, [createdAt, completedAt, state])
  return (
    <time aria-live="off" className="text-tabular-nums">
      {elapsedTime}
    </time>
  )
}

export default SessionElapsedTime

import {Banner} from '@primer/react'
import {StopIcon} from '@primer/octicons-react'
import {useSessionContext} from '../../contexts/SessionContext'
import {useAgentInfo} from '../../hooks/use-agent-info'

interface SessionFailedBannerProps {
  errorMessage: string | null
  workflowRunLink: string | null
}

export function SessionFailedBanner({errorMessage, workflowRunLink}: SessionFailedBannerProps) {
  const {session} = useSessionContext()
  const {data: agentInfo} = useAgentInfo(session.agent_id)
  const defaultErrorMessage = 'An unexpected error occurred. For more details, see the detailed logs in GitHub Actions.'
  const sessionFailedError = errorMessage || defaultErrorMessage

  return (
    <Banner
      aria-label="Session Error"
      title={`${agentInfo?.display_name || 'Agent'} stopped work due to an error`}
      description={sessionFailedError}
      variant="critical"
      icon={<StopIcon />}
      primaryAction={
        workflowRunLink && (
          <Banner.PrimaryAction as="a" href={workflowRunLink}>
            View detailed logs
          </Banner.PrimaryAction>
        )
      }
    />
  )
}

import {ThumbsupIcon, ThumbsdownIcon} from '@primer/octicons-react'
import {IconButton} from '@primer/react'
import {useCallback, useEffect, useState} from 'react'
import capitalize from 'lodash-es/capitalize'
import {useFeedbackDialog} from './useFeedbackDialog'
import {useSessionContext} from '../../../contexts/SessionContext'
import styles from './SessionFeedbackButtons.module.css'
import {type RatingOption, thumbsDownIcon, thumbsUpIcon} from '@github-ui/user-feedback'

const ratingOptions: Array<RatingOption<'NEGATIVE' | 'POSITIVE'>> = [
  {
    name: 'Bad',
    value: 'NEGATIVE' as const,
    icon: thumbsDownIcon,
    color: 'bad',
  },
  {
    name: 'Good',
    value: 'POSITIVE' as const,
    icon: thumbsUpIcon,
    color: 'good',
  },
]

type Rating = (typeof ratingOptions)[number]['value']

export function SessionFeedbackButtons() {
  const {session} = useSessionContext()

  const [submittedFeedback, setSubmittedFeedback] = useState<Rating | null>(null)
  const [currentSessionId, setCurrentSessionId] = useState(session.id)

  // Reset feedback state when session changes
  useEffect(() => {
    if (currentSessionId !== session.id) {
      // eslint-disable-next-line react-hooks/set-state-in-effect -- Intentionally resetting state when session changes
      setSubmittedFeedback(null)
      setCurrentSessionId(session.id)
    }
  }, [session.id, currentSessionId])

  const {openFeedback, FeedbackDialog} = useFeedbackDialog(`session-log:session_id=${session.id}`, ratingOptions)
  const onClick = useCallback(
    (rating: Rating) => {
      setSubmittedFeedback(rating) // Feedback isn't submitted at this point, but we're optimistically updating the UI
      openFeedback(rating)
    },
    [openFeedback],
  )

  const onFeedbackSubmitted = useCallback((rating: Rating) => setSubmittedFeedback(rating), [])
  const onFeedbackDialogClose = useCallback((reason: 'submit' | 'cancel' | 'dismiss') => {
    if (reason === 'cancel') {
      // User cancelled - reset to allow them to try again
      setSubmittedFeedback(null)
    }
    // For 'submit' and 'dismiss', keep the submitted feedback state
  }, [])

  return (
    <div className={styles.container}>
      {submittedFeedback != null ? (
        <IconButton
          aria-label={`${capitalize(submittedFeedback)} Feedback Submitted`}
          icon={submittedFeedback === 'POSITIVE' ? ThumbsupIcon : ThumbsdownIcon}
          variant="invisible"
          size="small"
          inactive
          aria-disabled
        />
      ) : (
        <>
          <IconButton
            icon={ThumbsupIcon}
            aria-label="Positive Feedback"
            onClick={() => onClick('POSITIVE')}
            variant="invisible"
            size="small"
          />
          <IconButton
            icon={ThumbsdownIcon}
            aria-label="Negative Feedback"
            onClick={() => onClick('NEGATIVE')}
            variant="invisible"
            size="small"
          />
        </>
      )}
      <FeedbackDialog onClose={onFeedbackDialogClose} onSubmitted={onFeedbackSubmitted} />
    </div>
  )
}

import {useEffect, useRef, useState, useMemo, useCallback} from 'react'
import {ChevronRightIcon, KebabHorizontalIcon, SkipIcon, XCircleFillIcon, CheckIcon} from '@primer/octicons-react'
import {IconButton, ActionMenu, ActionList} from '@primer/react'
import {useSessionContext} from '../../contexts/SessionContext'
import {
  isActiveSession,
  isPendingSession,
  isCancelledSession,
  isCompletedSession,
  isFailedSession,
} from '../../types/session'
import {generateWorkflowRunLink} from '../../utils/generate-actions-link'
import {generateTaskPath, generateTaskPathForRepo, shouldLinkToRepoTaskView} from '../../utils/generate-task-path'
import styles from './SessionHeader.module.css'
import {clsx} from 'clsx'
import {SessionStopButton} from '../SessionStopButton'
import SessionElapsedTime from '../SessionElapsedTime'
import {copyText} from '@github-ui/copy-to-clipboard'
import {sendEvent} from '@github-ui/hydro-analytics'
import {useScrollToBottom} from '../../hooks/use-scroll-to-bottom'
import {useIntentDetection} from '../../hooks/useIntentDetection'
import {useFeatureFlag} from '@github-ui/react-core/use-feature-flag'

export function SessionHeader({
  nwo,
  currentUserCanPush,
  isCollapsed,
  onModifierClick,
  scrollContainerRef,
  hideStopButton = false,
  contentId,
  onOpenChange,
  sticky = true,
}: {
  nwo: string | undefined
  currentUserCanPush: boolean
  isCollapsed: boolean
  onModifierClick: (expand: boolean) => void
  scrollContainerRef: React.RefObject<HTMLDivElement | null>
  hideStopButton?: boolean
  contentId?: string
  onOpenChange: (open: boolean) => void
  sticky?: boolean
}) {
  const {session} = useSessionContext()
  const workflowLink = generateWorkflowRunLink(nwo ?? null, session.workflow_run_id)

  const linkToSessionsInRepo = useFeatureFlag('copilot_mission_control_link_to_sessions_in_repo')
  const linkToSessionsInHyperspace = useFeatureFlag('copilot_mission_control_link_to_hyperspace')
  const shouldLinkToRepoTaskUrl = shouldLinkToRepoTaskView(linkToSessionsInRepo, linkToSessionsInHyperspace)
  let sessionLink = generateTaskPath(session.resource_global_id, session.id)
  if (shouldLinkToRepoTaskUrl && nwo) {
    const taskUrl = generateTaskPathForRepo({
      globalId: session.resource_global_id,
      repositoryNwo: nwo,
      linkToSessionsInRepo,
      taskId: session.task_id,
      sessionId: session.id,
    })
    if (taskUrl) {
      sessionLink = taskUrl
    }
  }

  const showMoreActionsMenu = !!(workflowLink || sessionLink)

  const ref = useRef<HTMLDivElement>(null)

  const isActive = isActiveSession(session)
  const isPending = isPendingSession(session)
  const isCompleted = isCompletedSession(session)
  const isCancelled = isCancelledSession(session)
  const isFailed = isFailedSession(session)

  const {isChatSession} = useIntentDetection(session)

  const [isStoppingSession, setIsStoppingSession] = useState(false)

  const {scrollToBottom} = useScrollToBottom({
    containerRef: scrollContainerRef,
    behavior: 'smooth',
  })

  // Function to handle stopping state changes from SessionStopButton
  const handleStoppingStateChange = (isStopping: boolean) => {
    if (isStopping) {
      setIsStoppingSession(true)
      sendEvent('agent_sessions.task_view', {
        target: 'STOP_SESSION_BUTTON',
        session_id: session.id,
        task_id: session.resource_global_id,
      })
    }
  }

  // Reset stopping state when session becomes cancelled
  useEffect(() => {
    if (isCancelled && isStoppingSession) {
      const timer = setTimeout(() => setIsStoppingSession(false), 0)
      return () => clearTimeout(timer)
    }
  }, [isCancelled, isStoppingSession])

  const {isLeaving} = useElementLeavingContainer({
    scrollContainerRef,
    elementRef: ref,
    enabled: isActive,
    offset: -8,
  })

  const handleClick = (event: React.MouseEvent) => {
    // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
    if ((event.altKey || event.metaKey) && onModifierClick) {
      event.preventDefault()
      event.stopPropagation()
      // If currently collapsed, expand all; if expanded, collapse all
      onModifierClick(!!isCollapsed)

      sendEvent('agent_sessions.task_view', {
        target: 'SESSION_HEADER_MODIFIER',
        action: isCollapsed ? 'EXPAND_ALL' : 'COLLAPSE_ALL',
        session_id: session.id,
        task_id: session.resource_global_id,
      })

      return false // Prevent further event handling
    } else {
      sendEvent('agent_sessions.task_view', {
        target: 'SESSION_HEADER',
        action: isCollapsed ? 'EXPAND' : 'COLLAPSE',
        session_id: session.id,
        task_id: session.resource_global_id,
      })

      // If session is sticky to chat, expand and scroll to bottom
      if (isLeaving) {
        onOpenChange(true)
        setTimeout(() => {
          scrollToBottom()
        }, 50) // short timeout to account for open change to fire first
        return
      }
    }

    onOpenChange(isCollapsed)
  }

  const handleLinkClick = (e: React.MouseEvent) => {
    sendEvent('agent_sessions.task_view', {
      target: 'CLICK_WORKFLOW_LOGS_LINK',
      session_id: session.id,
      task_id: session.resource_global_id,
    })
    // Allow cmd/ctrl + click to open in new tab
    // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
    if (e.metaKey || e.ctrlKey) {
      e.stopPropagation()
      return
    }
  }

  const handleCopyLink = useCallback(
    async (event: React.SyntheticEvent) => {
      if (sessionLink) {
        try {
          const fullUrl = window.location.origin + sessionLink
          await copyText(fullUrl)
          sendEvent('agent_sessions.task_view', {
            target: 'COPY_SESSION_LINK',
            session_id: session.id,
            task_id: session.resource_global_id,
          })
        } catch {
          // prevent menu from closing on error
          event.preventDefault()
          event.stopPropagation()
        }
      }
    },
    [sessionLink, session],
  )

  const sessionName = useMemo(() => {
    if (isPending) {
      return 'New session'
    }

    return session.name
  }, [isPending, session.name])

  const statusIcon = useMemo(() => {
    if (isStoppingSession || isCancelled) {
      return <SkipIcon className="fgColor-muted" />
    } else if (isCompleted) {
      return <CheckIcon className="fgColor-success" />
    } else if (isFailed) {
      return <XCircleFillIcon className="fgColor-danger" />
    }
    return null
  }, [isCompleted, isStoppingSession, isCancelled, isFailed])

  const duration = useMemo(() => {
    if (isPending) return null

    if (isActive || isCompleted || isCancelled || isFailed) {
      return (
        <SessionElapsedTime createdAt={session.created_at} completedAt={session.completed_at} state={session.state} />
      )
    }
    return null
  }, [isPending, isActive, isCompleted, isCancelled, isFailed, session.created_at, session.completed_at, session.state])

  const shouldShowStopButton = useMemo(() => {
    if (hideStopButton) return false
    return isActive // this included stopping state
  }, [isActive, hideStopButton])

  if (isChatSession) {
    return null
  }

  const content = (
    <>
      <div className={styles.mainContent}>
        <button
          onClick={handleClick}
          type="button"
          className={styles.toggleButton}
          aria-expanded={!isCollapsed}
          aria-controls={contentId}
          aria-labelledby="session-header-title"
        >
          <ChevronRightIcon className={styles.icon} data-expanded={!isCollapsed} />
        </button>

        <span className={styles.sessionName} id="session-header-title">
          {sessionName}
        </span>
      </div>

      <div className={styles.rightContent}>
        {(statusIcon || duration) && (
          <div className="d-flex align-items-center gap-1 mr-2">
            {statusIcon && <span className={styles.statusIcon}>{statusIcon}</span>}
            {duration && <span className="text-small text-medium text-tabular-nums">{duration}</span>}
          </div>
        )}
        {shouldShowStopButton && (
          <SessionStopButton
            variant="icon-text-button"
            nwo={nwo}
            currentUserCanPush={currentUserCanPush}
            onStoppingStateChange={handleStoppingStateChange}
            loading={isStoppingSession}
          />
        )}
        {showMoreActionsMenu && (
          <ActionMenu>
            <ActionMenu.Anchor>
              <IconButton icon={KebabHorizontalIcon} aria-label="More actions" variant="invisible" />
            </ActionMenu.Anchor>
            <ActionMenu.Overlay align="end">
              <ActionList>
                {workflowLink && (
                  <ActionList.LinkItem href={workflowLink} onClick={handleLinkClick}>
                    View verbose logs
                  </ActionList.LinkItem>
                )}
                {sessionLink && <ActionList.Item onSelect={handleCopyLink}>Copy link</ActionList.Item>}
              </ActionList>
            </ActionMenu.Overlay>
          </ActionMenu>
        )}
      </div>
    </>
  )

  return (
    <>
      <div
        ref={ref}
        className={clsx(styles.containerWrapper, {
          [styles.containerStickyToTop]: !isLeaving && sticky,
        })}
      >
        <div data-active={isActive} data-expanded={!isCollapsed} className={styles.container}>
          {content}
        </div>
      </div>
      {isLeaving && (
        <div className={clsx(styles.container, sticky && styles.containerStickyToChatInput)}>{content}</div>
      )}
    </>
  )
}

type UseElementLeavingContainerOptions = {
  scrollContainerRef: React.RefObject<HTMLDivElement | null>
  elementRef: React.RefObject<HTMLDivElement | null>
  enabled: boolean
  offset?: number
}

function useElementLeavingContainer(options: UseElementLeavingContainerOptions) {
  const {scrollContainerRef, elementRef, enabled, offset = 0} = options

  const [isLeaving, setIsLeaving] = useState(false)
  const isLeavingRef = useRef(isLeaving)

  useEffect(() => {
    isLeavingRef.current = isLeaving
  }, [isLeaving])

  useEffect(() => {
    const container = scrollContainerRef.current
    const element = elementRef.current

    if (!enabled || !container || !element) {
      return
    }

    const compute = () => {
      const containerRect = container.getBoundingClientRect()
      const elementRect = element.getBoundingClientRect()

      // check if the element is leaving at the bottom of the container's visible area
      // trigger earlier than the actual bottom by the offset amount
      const isElementLeaving = elementRect.bottom > containerRect.bottom + offset

      // only update state if it has changed to avoid unnecessary re-renders
      if (isElementLeaving !== isLeavingRef.current) {
        setIsLeaving(isElementLeaving)
      }
    }

    compute()

    // throttle the scroll event handling using requestAnimationFrame
    let animationFrameId: number | null = null
    const throttledCompute = () => {
      if (animationFrameId == null) {
        animationFrameId = window.requestAnimationFrame(() => {
          compute()
          animationFrameId = null
        })
      }
    }

    // ideally we want to use IntersectionObserver here, but couldn't get it to work reliably
    // so fallback to scroll event listener for now
    // eslint-disable-next-line github/prefer-observers
    container.addEventListener('scroll', throttledCompute)

    return () => {
      setIsLeaving(false)
      container.removeEventListener('scroll', throttledCompute)
    }
  }, [enabled, scrollContainerRef, elementRef, offset])

  return {isLeaving}
}

import {MarkdownRenderer} from '@github-ui/copilot-markdown'
import {Banner} from '@primer/react'
import {useState, useEffect, useMemo} from 'react'
import type {
  LogEntry,
  Choice,
  MessageRole,
  Command,
  ToolArgs,
  ChatMessage,
  ToolCallMetadataMap,
} from '../../types/session'
import {isCompletionUserMessage, isCommandGroup, isChatMessage, isCompletionChunk} from '../../types/session'
import {useLogs} from '../../hooks/useLogs'
import {useListCommands} from '../../hooks/useListCommands'
import {useSyncFavicon} from '../../hooks/useSyncFavicon'
import {Tool, ToolPrimaryContent, ToolRenderer} from './tool/Tool'
import {useSessionContext} from '../../contexts/SessionContext'
import {useAgentInfo} from '../../hooks/use-agent-info'
import {SessionFailedBanner} from './SessionFailedBanner'
import {SessionCancelledBanner} from './SessionCancelledBanner'
import {generateWorkflowRunLink} from '../../utils/generate-actions-link'
import {BootingUpMessage, LoadingMessage} from './LoadingMessage'
import {preprocessLogEntries} from '../../utils/dedupe-logs-data'
import {fetchCAPI} from '../../utils/fetch-capi'
import {StickySteeringCommand} from './StickySteeringCommand'
import {ChatCommands, LogCommands} from './UserCommand'
import {useCurrentUser as useDeprecatedCurrentUser} from '@github-ui/current-user'
import {useCurrentUser} from '../../contexts/CurrentUserContext'
import {useSessionLogsContext} from './Context'
import {isFeatureEnabled} from '@github-ui/feature-flags'
import {isCopilotCodingAgent} from '../../utils/agent-helpers'
import type {PublicUser} from '../../types/public-user'
import styles from './SessionLogs.module.css'
import {extractMcpToolNameMappings} from '../../utils/extract-mcp-setup-details'
import {ToolGrouping} from './tool-grouping/ToolGrouping'
import {groupByConsecutiveToolName} from './tool-grouping/grouping-strategies'
import {defaultGroupHeader} from './tool-grouping/header-strategies'
import {isCustomAgentSessionGroup} from '../../utils/group-agent-logs'
import type {CustomAgentGroupLogEntry} from '../../utils/group-agent-logs'
import {CustomAgentSessionGroup} from './CustomAgentSessionGroup'
import {GitHubAvatar} from '@github-ui/github-avatar'
import {AgentAvatar} from '../AgentAvatar'
import {CopilotAnimationType} from '@github-ui/copilot-animation'
import type {EntryWithContext} from './tool-grouping/types'
import {splitChoiceWithReasoningText, shouldSplitChoice} from '../../utils/split-reasoning-text'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {MarkdownViewer} from '@github-ui/copilot-immersive-v1/components/MarkdownViewer'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {ChatMessageProvider} from '@github-ui/copilot-chat/components/ChatMessageContext'

const ASSISTANT_ROLE: MessageRole = 'assistant'

type SessionLogsProps = {
  logsPollingInterval: number
  nwo?: string | null
  batchCompletedSessions: boolean // can be deleted with session view
  currentUser?: PublicUser | null
  onLogsLoadingChange?: (isLoading: boolean) => void
  clearPendingChat?: () => void
  pendingChat?: string | null
  isStreamingChat?: boolean
  streamingChatResponse?: string | null
}

export function SessionLogs({
  logsPollingInterval,
  nwo,
  batchCompletedSessions,
  currentUser,
  onLogsLoadingChange,
  clearPendingChat,
  pendingChat,
  isStreamingChat,
  streamingChatResponse,
}: SessionLogsProps) {
  const {session, setMcpToolNameMappings} = useSessionContext()

  // deprecatedCurrentUser can be deleted with the session view
  const deprecatedCurrentUser = useDeprecatedCurrentUser()
  // we can grab currentUserIsSessionOwner from useCurrentUser and can replace the currentUser param when deleting the session view
  const currentUserOwnsSession = currentUser?.id === session.user_id || deprecatedCurrentUser?.id === session.user_id

  const {variant} = useSessionLogsContext()

  const {data: agentInfo, isLoading: isAgentInfoLoading} = useAgentInfo(session.agent_id)

  const {data: commandsData} = useListCommands({
    pollingInterval: logsPollingInterval, // Use same interval as logs
  })

  const [steeringCommandError, setSteeringCommandError] = useState<string | null>(null)

  const handleSteeringCommandSubmit = async (message: string) => {
    try {
      setSteeringCommandError(null)
      const response = await fetchCAPI({
        path: `/agents/sessions/${session.id}/commands`,
        method: 'POST',
        body: {content: message},
      })
      if (!response.ok) {
        const errorMessage = `Failed to create command: ${response.statusText}`
        setSteeringCommandError(errorMessage)
        return
      }
    } catch {
      setSteeringCommandError('Failed to submit command. Please try again.')
    }
  }

  const {
    data: logsData,
    isLoading: logsIsLoading,
    showPollingError,
  } = useLogs({
    logsPollingInterval,
    batchCompletedSessions,
    currentUserIsSessionOwner: currentUserOwnsSession,
    clearPendingChat,
    pendingChat,
    isStreamingChat,
  })
  useSyncFavicon(session.state)

  const agentGroupingEnabled =
    isFeatureEnabled('copilot_mission_control_custom_agent_group') && isCopilotCodingAgent(agentInfo?.slug)

  const preprocessedLogEntries = useMemo(
    () =>
      preprocessLogEntries(logsData, {
        preserveAssistantNarration: false,
        groupCustomAgentSessions: agentGroupingEnabled,
      }),
    [logsData, agentGroupingEnabled],
  )

  const logsToShow = useMemo(() => {
    if (!isStreamingChat || !streamingChatResponse) {
      return preprocessedLogEntries
    }

    // If the last entry in our actual logs from server matches up with the
    // incoming stream, exclude it until we're done...
    const lastEntry = preprocessedLogEntries[preprocessedLogEntries.length - 1] as ChatMessage
    const lastContent = lastEntry?.choices?.[0]?.delta?.content ?? ''
    const lastMatches =
      lastContent &&
      streamingChatResponse &&
      (lastContent.startsWith(streamingChatResponse) || streamingChatResponse.startsWith(lastContent))
    const logs = lastMatches ? preprocessedLogEntries.slice(0, -1) : preprocessedLogEntries
    logs.push({content: streamingChatResponse, role: 'assistant', id: '', threadID: ''})

    return logs
  }, [preprocessedLogEntries, isStreamingChat, streamingChatResponse])

  useEffect(() => {
    onLogsLoadingChange?.(!!logsIsLoading)
  }, [logsIsLoading, onLogsLoadingChange])

  // Extract and save MCP tool name mappings from log entries
  useEffect(() => {
    const mappings = extractMcpToolNameMappings(logsToShow)
    if (Object.keys(mappings).length > 0) {
      setMcpToolNameMappings(prevMappings => ({...prevMappings, ...mappings}))
    }
  }, [logsToShow, setMcpToolNameMappings])

  // Return early if in the queued state
  if (session.state === 'queued') {
    return (
      <>
        <BootingUpMessage agentId={session.agent_id} />
        <ChatCommands commands={getCommandsNotInLogs(commandsData, logsData)} />
      </>
    )
  }
  const workflowLink = session.workflow_run_id
    ? generateWorkflowRunLink(nwo ?? null, session.workflow_run_id)
    : undefined

  return (
    <>
      {logsIsLoading && !showPollingError && <LoadingMessage message="Loading…" agentId={session.agent_id} />}
      {!logsIsLoading && !showPollingError && logsData?.length === 0 && session.state !== 'in_progress' && (
        <div>No logs to display</div>
      )}
      {!logsIsLoading && logsData && logsData?.length > 0 && (
        <>
          {/* Renders user messages, tool calls, and assistant messages with tool grouping enabled */}
          <GroupedSessionLogs preprocessedLogEntries={logsToShow} commandsData={commandsData} logsData={logsData} />
          {/* Render pending/failed commands */}
          <ChatCommands commands={getCommandsNotInLogs(commandsData, logsData)} />
        </>
      )}
      {showPollingError && (
        <Banner
          title="Error"
          hideTitle
          description="There was an error loading the logs. Please try again later."
          variant="critical"
          primaryAction={(() => {
            return workflowLink ? (
              <Banner.PrimaryAction as="a" href={workflowLink}>
                View detailed logs
              </Banner.PrimaryAction>
            ) : undefined
          })()}
        />
      )}
      {session.state === 'in_progress' && session.event_type !== 'chat' && !logsIsLoading && !showPollingError && (
        <>
          {!isAgentInfoLoading &&
            (logsData && logsData.length > 0 ? (
              <LoadingMessage
                message={`${agentInfo?.display_name ?? 'Agent'} is working…`}
                agentId={session.agent_id}
              />
            ) : (
              <BootingUpMessage agentId={session.agent_id} />
            ))}
          {variant === 'default' && currentUserOwnsSession && (
            <StickySteeringCommand onSubmit={handleSteeringCommandSubmit} error={steeringCommandError} />
          )}
        </>
      )}
      {session.error?.message &&
        !showPollingError &&
        (session.state === 'cancelled' ? (
          <SessionCancelledBanner cancellationMessage={session.error.message} workflowRunLink={workflowLink ?? null} />
        ) : (
          <SessionFailedBanner errorMessage={session.error.message} workflowRunLink={workflowLink ?? null} />
        ))}
    </>
  )
}

type LogEntryChoiceProps = {
  choice: Choice
  isInGroup?: boolean
  isEditGroup?: boolean
  toolCallMetadata?: ToolCallMetadataMap
}

function LogEntryChoice({choice, isInGroup, isEditGroup, toolCallMetadata}: LogEntryChoiceProps) {
  const {mcpToolNameMappings} = useSessionContext()

  return renderLogEntryChoice(choice, mcpToolNameMappings, isInGroup, isEditGroup, toolCallMetadata)
}

// Rendering logic for log entry choices
function renderLogEntryChoice(
  choice: Choice,
  mcpToolNameMappings: ReturnType<typeof useSessionContext>['mcpToolNameMappings'],
  isInGroup?: boolean,
  isEditGroup?: boolean,
  toolCallMetadata?: ToolCallMetadataMap,
) {
  const toolCalls = choice.delta.tool_calls ?? []
  const tool = toolCalls[0]

  // Handle reasoning_text-only choices (no tool, no content)
  if (!tool && !choice.delta.content && choice.delta.reasoning_text) {
    return <ReasoningText content={choice.delta.reasoning_text} />
  }

  if (!tool && choice.delta.content && choice.delta.role === ASSISTANT_ROLE) {
    return <CopilotMessage content={choice.delta.content} />
  }

  const isCustomTool = !!tool?.custom
  const toolName = tool?.function?.name ?? tool?.custom?.name
  const rawArgs = isCustomTool ? tool?.custom?.input : tool?.function?.arguments

  if (!tool || !tool.id || !toolName) {
    return null
  }

  let parsedArgs: ToolArgs = {}
  let hasParsingError = false

  if (isCustomTool) {
    // Custom tool args are freeform strings and should not be parsed as JSON
    parsedArgs = typeof rawArgs === 'string' ? ({content: rawArgs} as unknown as ToolArgs) : ({} as ToolArgs)
  } else if (typeof rawArgs === 'string') {
    try {
      // Defensively replace newlines that may appear in JSON to avoid possible parsing errors
      // This may not be needed if the backend is already handling this correctly, but better safe than sorry
      parsedArgs = JSON.parse(rawArgs.replace(/\n/g, '\\n'))
    } catch {
      hasParsingError = true
    }
  } else if (rawArgs) {
    parsedArgs = rawArgs as ToolArgs
  }

  const component = hasParsingError ? (
    <Tool title={'Error parsing tool call arguments'} isError>
      <ToolPrimaryContent
        language={'text'}
        markdown={typeof rawArgs === 'string' ? rawArgs : JSON.stringify(rawArgs ?? {}, null, 2)}
      />
    </Tool>
  ) : (
    <ToolRenderer
      name={toolName}
      delta={choice.delta}
      args={parsedArgs}
      mcpToolNameMappings={mcpToolNameMappings}
      isInGroup={isInGroup}
      isEditGroup={isEditGroup}
      metadata={tool.id ? toolCallMetadata?.[tool.id] : undefined}
    />
  )

  if (choice.delta.reasoning_text) {
    return (
      <>
        <ReasoningText content={choice.delta.reasoning_text} />
        {component}
      </>
    )
  }

  return component
}

function CopilotMessage({content}: {content: string}) {
  content = content.replace(/<pr_title>.*?<\/pr_title>|<pr_description>.*?<\/pr_description>|<empty>/gs, '').trim()

  // Don't render anything if content is empty after removing PR tags
  if (!content) {
    return null
  }

  return (
    <div className={styles.copilotMessage}>
      <div className={styles.copilotMessageContent}>
        <MarkdownRenderer markdown={content} />
      </div>
    </div>
  )
}

function ReasoningText({content}: {content: string}) {
  return (
    <div className={styles.markdownWrapper}>
      <MarkdownRenderer markdown={content} />
    </div>
  )
}

/**
 * Helper function to render session log entries with tool grouping.
 * Builds a unified timeline where choices are flattened in place,
 * allowing commands to appear in their chronological position while
 * consecutive tool calls can still be grouped together.
 */
function GroupedSessionLogs({
  preprocessedLogEntries,
  commandsData,
  logsData,
}: {
  preprocessedLogEntries: CustomAgentGroupLogEntry[]
  commandsData: Command[] | undefined
  logsData: LogEntry[] | undefined
}) {
  const shouldUngroupReasoningText = isFeatureEnabled('session_logs_ungroup_reasoning_text')

  // Build flattened session log items: flatten choices in place, keep other entries as-is.
  // Subagent session groups are kept as 'other' items so they render inline.
  // This preserves chronological order while enabling choice-level grouping
  // (e.g. consecutive run_setup calls grouped under "Setting up environment").
  const sessionLogItems: EntryWithContext[] = useMemo(() => {
    let otherIndex = 0
    const items: EntryWithContext[] = []

    for (const entry of preprocessedLogEntries) {
      // Subagent session groups are rendered as standalone 'other' items
      if (isCustomAgentSessionGroup(entry)) {
        items.push({
          type: 'other',
          entry,
          index: otherIndex++,
        })
        continue
      }

      const toolCallMetadata = 'tool_call_metadata' in entry ? entry.tool_call_metadata : undefined
      if (isCompletionChunk(entry) && !isChatMessage(entry)) {
        // Flatten choices from CompletionChunks
        for (const [choiceIndex, choice] of entry.choices.entries()) {
          // When flag is enabled and choice has BOTH reasoning_text AND tool_calls,
          // split into two items so reasoning_text renders outside of tool groups
          if (shouldUngroupReasoningText && shouldSplitChoice(choice)) {
            const splitChoices = splitChoiceWithReasoningText(choice)
            for (const splitChoice of splitChoices) {
              items.push({
                type: 'choice',
                choice: splitChoice,
                entryId: entry.id,
                choiceIndex,
                toolCallMetadata,
              })
            }
          } else {
            items.push({
              type: 'choice',
              choice,
              entryId: entry.id,
              choiceIndex,
              toolCallMetadata,
            })
          }
        }
      } else {
        // non-choice entries (commands, etc.)
        items.push({
          type: 'other',
          entry,
          index: otherIndex++,
        })
      }
    }

    return items
  }, [preprocessedLogEntries, shouldUngroupReasoningText])

  return (
    <ToolGrouping entries={sessionLogItems} groupingFn={groupByConsecutiveToolName} groupHeaderFn={defaultGroupHeader}>
      {(item, groupContext) => {
        // Render subagent session groups inline
        if (item.type === 'other' && isCustomAgentSessionGroup(item.entry)) {
          return (
            <CustomAgentSessionGroup customAgentSession={item.entry}>
              <GroupedSessionLogs
                preprocessedLogEntries={item.entry.logs}
                commandsData={commandsData}
                logsData={logsData}
              />
            </CustomAgentSessionGroup>
          )
        }

        return (
          <GroupedLogEntryRenderer
            item={item}
            commandData={commandsData ?? []}
            isInGroup={groupContext?.isInGroup}
            isEditGroup={groupContext?.isEditGroup}
            logsData={logsData}
          />
        )
      }}
    </ToolGrouping>
  )
}

// These are expected to only be found in the session logs when the intent detection
// feature flag is enabled.
export function LogChatMessage({logEntry, logsData}: {logEntry: ChatMessage; logsData?: LogEntry[]}) {
  const {currentUser} = useCurrentUser()
  const isUser = logEntry.role === 'user'
  const roleClassName = isUser ? styles.intentDetectionChatUserContainer : styles.intentDetectionChatAssistantContainer
  const messageClassName = isUser
    ? styles.intentDetectionChatUserMessageContainer
    : styles.intentDetectionChatAssistantMessageContainer
  // Content is merged by deduplication, so we can use the first choice if present
  const content = isUser ? logEntry.content : (logEntry.choices?.[0]?.delta?.content ?? logEntry.content ?? '')

  const messageIndex = logsData ? logsData.indexOf(logEntry) : 0

  return (
    <div className={`${styles.intentDetectionChatContainer} ${roleClassName}`}>
      {!isUser ? <AgentAvatar animationType={CopilotAnimationType.Static} /> : null}
      <div className={`${styles.intentDetectionChatMessageContainer} ${messageClassName}`}>
        {isUser ? (
          <p className={styles.intentDetectionChatMessageText}>{content}</p>
        ) : (
          <div className={styles.intentDetectionChatMessageText}>
            <ChatMessageProvider
              message={{
                id: logEntry.id,
                role: logEntry.role,
                content: logEntry.content,
                createdAt: '',
                threadID: logEntry.threadID,
                references: [],
              }}
            >
              <MarkdownViewer
                markdown={content ?? ''}
                messageId={logEntry.id}
                messageIndex={messageIndex}
                messageTimestamp={''}
                autoOpenPreviewPane
              />
            </ChatMessageProvider>
          </div>
        )}
      </div>
      {isUser ? <GitHubAvatar src={currentUser?.primaryAvatarUrl || ''} size={24} /> : null}
    </div>
  )
}

/**
 * Renders a single log entry in the grouped session logs view.
 * Handles both individual choices (from flattened CompletionChunks) and other entries (commands).
 *
 * This is specifically for the grouped view where choices are flattened and can receive
 * the `isInGroup` context from ToolGrouping.
 */
function GroupedLogEntryRenderer({
  item: entryWithContext,
  commandData,
  isInGroup,
  isEditGroup,
  logsData,
}: {
  item: EntryWithContext
  commandData: Command[]
  isInGroup?: boolean
  isEditGroup?: boolean
  logsData?: LogEntry[]
}) {
  if (entryWithContext.type === 'choice') {
    return (
      <LogEntryChoice
        choice={entryWithContext.choice}
        isInGroup={isInGroup}
        isEditGroup={isEditGroup}
        toolCallMetadata={entryWithContext.toolCallMetadata}
      />
    )
  }

  // Handle other entry types (commands, etc.)
  const {entry} = entryWithContext
  if (isCustomAgentSessionGroup(entry)) {
    return null // Handled by GroupedSessionLogs render function
  }
  if (isCommandGroup(entry)) {
    return <LogCommands rawCommands={entry} commandData={commandData} />
  }
  if (isChatMessage(entry)) {
    return <LogChatMessage logEntry={entry} logsData={logsData} />
  }

  return null
}

// TODO: remove this once we are updating state in the sessions service. It's a temporary measure to prevent
// duplicates on the UI while we're not updating state.
function getCommandsNotInLogs(commandsData: Command[] | undefined, logsData: LogEntry[] | undefined) {
  if (!commandsData?.length || !logsData) {
    return []
  }

  return commandsData.filter(command => !logsData.some(logEntry => isCommandInLogs(command, logEntry)))
}

function isCommandInLogs(command: Command, logEntry: LogEntry) {
  return isCompletionUserMessage(logEntry) && logEntry.source && logEntry.source === `command-${command.external_id}`
}

import {useState, useEffect} from 'react'
import {Button} from '@primer/react'
import {SquareFillIcon, SquareCircleIcon} from '@primer/octicons-react'
import {SessionState} from '../types/session'
import {useSessionContext} from '../contexts/SessionContext'
import {useIntentDetection} from '../hooks/useIntentDetection'
import {useStopSession} from '../hooks/use-stop-session'

export function SessionStopButton({
  nwo,
  currentUserCanPush,
  variant = 'button',
  onStoppingStateChange,
  loading: externalLoading,
}: {
  nwo: string | undefined
  currentUserCanPush: boolean
  variant?: 'button' | 'icon-text-button'
  onStoppingStateChange?: (isStopping: boolean) => void
  loading?: boolean
}) {
  const {session} = useSessionContext()

  const [isSessionStopped, setIsSessionStopped] = useState(false)
  const stoppableStates: string[] = [SessionState.InProgress, SessionState.Idle, SessionState.WaitingForUser]
  const sessionStoppable = stoppableStates.includes(session.state) && !isSessionStopped
  const {isChatSession} = useIntentDetection(session)

  const {isSuccess, isPending, mutate} = useStopSession({nwo, session})

  // Listen for query success state
  useEffect(() => {
    if (isSuccess && !isPending) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setIsSessionStopped(true)
    }
  }, [isSuccess, isPending])

  const stoppingSession = isPending
  const buttonText = stoppingSession ? 'Stopping session...' : 'Stop session'
  const handleStopSession = () => mutate()

  // Notify parent component when stopping state changes
  useEffect(() => {
    onStoppingStateChange?.(stoppingSession)
  }, [stoppingSession, onStoppingStateChange])

  const isLoading = externalLoading ?? stoppingSession
  const iconButtonText = isLoading ? '' : 'Stop'

  if (isChatSession) return null

  if (variant === 'icon-text-button') {
    return (
      <Button
        leadingVisual={SquareCircleIcon}
        aria-label="Stop session"
        variant="invisible"
        size="small"
        onClick={handleStopSession}
        aria-disabled={stoppingSession}
        loading={isLoading}
      >
        {iconButtonText}
      </Button>
    )
  }

  // No button if the user lacks permission or the session is not stoppable
  if (!nwo || !currentUserCanPush || !sessionStoppable) return null

  return (
    <Button
      className="mr-2"
      leadingVisual={SquareFillIcon}
      variant="danger"
      onClick={handleStopSession}
      loading={isLoading}
      loadingAnnouncement="Stopping session"
      aria-disabled={stoppingSession}
    >
      {buttonText}
    </Button>
  )
}

function _setPrototypeOf(t, e) {
  return module.exports = _setPrototypeOf = Object.setPrototypeOf ? Object.setPrototypeOf.bind() : function (t, e) {
    return t.__proto__ = e, t;
  }, module.exports.__esModule = true, module.exports["default"] = module.exports, _setPrototypeOf(t, e);
}
module.exports = _setPrototypeOf, module.exports.__esModule = true, module.exports["default"] = module.exports;
import safeStorage from '@github-ui/safe-storage'
import {type CodeViewOption, codeWrappingName, useCodeViewOptions} from '@github-ui/use-code-view-options'
import {ActionList} from '@primer/react'
import {startTransition, useCallback} from 'react'

import {updateExpandPreferences} from '../../../hooks/use-update-panel-expand-preferences'

const safeLocalStorage = safeStorage('localStorage')

export default function SettingsMenuItems({symbolsEnabled}: {symbolsEnabled: boolean}) {
  const {codeFoldingOption, codeWrappingOption, codeCenterOption, openSymbolsOption} = useCodeViewOptions()

  return (
    <>
      <OptionsElement option={codeFoldingOption} />
      <OptionsElement option={codeWrappingOption} />
      <OptionsElement option={codeCenterOption} />
      {symbolsEnabled && <OptionsElement option={openSymbolsOption} />}
    </>
  )
}

export function OptionsElement({option}: {option: CodeViewOption}) {
  const onSelect = useCallback(() => {
    //need to start the transition because we might be swapping between no virtualization/virtualized versions,
    //and we lazy load components in either approach
    startTransition(() => option.setEnabled(!option.enabled))
    // Defer localStorage write to avoid blocking interaction
    const newValue = String(!option.enabled)
    // eslint-disable-next-line compat/compat -- we polyfill safari
    requestIdleCallback(() => safeLocalStorage.setItem(option.name, newValue))
    if (option.name === codeWrappingName) updateExpandPreferences(null, null, !option.enabled)
  }, [option])

  return (
    <ActionList.Item selected={option.enabled} key={option.name} onSelect={onSelect}>
      {option.label}
    </ActionList.Item>
  )
}

import {useCurrentRepository} from '@github-ui/current-repository'
import isHashNavigation from '@github-ui/is-hash-navigation'
import type {SafeHTMLString} from '@github-ui/safe-html'
import {VerifiedHTMLBox} from '@github-ui/safe-html/VerifiedHTML'
import {useNavigate} from '@github-ui/use-navigate'
import {useLocation} from '@github-ui/react-router'
import type React from 'react'
import {memo, useLayoutEffect, useEffect, useImperativeHandle, useRef, useEffectEvent} from 'react'

import {decodeFragmentValue, findElementByFragmentName} from '../utilities/fragment-target'

export interface SharedMarkdownContentProps {
  onAnchorClick?: (event: React.MouseEvent) => void
  richText: SafeHTMLString
  stickyHeaderHeight?: number
  sx?: React.ComponentProps<typeof VerifiedHTMLBox>['sx']
  suppressHydrationWarning?: boolean
  className?: string
  ref?: React.Ref<HTMLDivElement>
}

export const SharedMarkdownContent = memo(function SharedMarkdownContent({
  ref,
  onAnchorClick,
  richText,
  stickyHeaderHeight,
  sx,
  suppressHydrationWarning,
  className,
}: SharedMarkdownContentProps) {
  const {hash} = useLocation()
  const currentRepo = useCurrentRepository()
  const navigate = useNavigate()
  const markdownContainerRef = useRef<HTMLDivElement>(null)

  useImperativeHandle(ref, () => markdownContainerRef.current as HTMLDivElement)

  const handleHashChange = useEffectEvent(() => {
    onHashChange(window.location.hash, stickyHeaderHeight)
  })
  useEffect(() => {
    const hashChange = () => {
      handleHashChange()
    }

    window.addEventListener('load', hashChange)
    window.addEventListener('hashchange', hashChange)
    return () => {
      window.removeEventListener('load', hashChange)
      window.removeEventListener('hashchange', hashChange)
    }
  }, [])

  useLayoutEffect(() => {
    if (markdownContainerRef?.current) {
      handleHashChange()
    }
  }, [hash])

  return (
    <VerifiedHTMLBox
      ref={markdownContainerRef}
      className={`js-snippet-clipboard-copy-unpositioned ${className}`}
      html={richText}
      sx={sx}
      suppressHydrationWarning={suppressHydrationWarning}
      data-hpc
      // @ts-expect-error React 19 Polymorphic types
      onClick={event => {
        // don't soft navigate if the user cmd/ctrl + click
        // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
        const isCmdClick = event.metaKey || event.ctrlKey
        const anchor = (event.target as HTMLElement).closest('a')
        if (anchor && anchor.href) {
          if (!isCmdClick) {
            const href = anchor.href
            const url = new URL(href, window.location.origin)

            if (isHashNavigation(window.location.href, href)) {
              onHashChange(url.hash, stickyHeaderHeight)
              if (window.location.hash === url.hash) {
                event.preventDefault()
              }
            } else if (href.startsWith(`${window.location.origin}/${currentRepo.ownerLogin}/${currentRepo.name}/`)) {
              navigate(url.pathname + url.search + url.hash)
              event.preventDefault()
            }
          }
          onAnchorClick?.(event)
        }
      }}
    />
  )
})

// 125px is the blob sticky header height
export function onHashChange(hash: string, stickyHeaderHeight: number = 125) {
  if (!hash) {
    return
  }

  const targetId = decodeFragmentValue(hash).toLowerCase()
  // a user can generate their own hash links that already include the prefix (typically for cross document links)
  // the majority of targetIds provided to the helper will exclude the prefix
  const normalizedTarget = targetId.startsWith('user-content-') ? targetId : `user-content-${targetId}`
  const target = findElementByFragmentName(document, normalizedTarget) as HTMLElement | null
  if (target && document && document.defaultView) {
    // On Soft Nav, this scrollTo and focus loginc can run essentialy one tick after it's called to ensure elements are in the DOM
    setTimeout(() => {
      window.requestAnimationFrame(() => {
        // Batch layout reads together to minimize forced reflow
        const targetTop = target.getBoundingClientRect().top
        const bodyTop = document.body.getBoundingClientRect().top
        const targetScroll = targetTop - bodyTop - stickyHeaderHeight

        window.scrollTo({top: targetScroll})
        const focusElement = target.closest<HTMLElement>('h1,h2,h3,h4,h5,h6,li,span')
        if (focusElement) {
          focusElement.focus()
          // Set this attribute so soft-navs will autofocus
          focusElement.setAttribute('data-react-autofocus', 'true')
        }
      })
    }, 1)
  }
}

