// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {useEntitlement} from '@github-ui/copilot-chat/components/quota/EntitlementContext'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {CopilotPlan} from '@github-ui/copilot-chat/utils/copilot-chat-types'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {copilotFeatureFlags} from '@github-ui/copilot-chat/utils/copilot-feature-flags'
import {useLatestAgentModel} from '../../hooks/use-latest-agent-model'
import {useAgentModels} from '../../hooks/useAgentModels'
import {ModelPicker as AgentModelPicker} from '../task-view/ModelPicker'
import {useLastSelectedAgent} from '../../hooks/use-last-selected-agent'
import {useAgentInfo} from '../../hooks/use-agent-info'
import {isCopilotOrCustomAgent} from '../../utils/agent-helpers'
import type {SelectedAgent} from '../../types/session'

interface SlashCommandModelPickerProps {
  /**
   * The currently selected agent, passed from the parent ChatInput context.
   * This ensures the model picker updates reactively when the agent selection changes.
   */
  selectedAgent?: SelectedAgent
}

/**
 * Model picker component for the /task slash command.
 * This wraps the base ModelPicker with state management via useLatestAgentModel hook
 * and adds feature flag checks for when the model picker should be shown.
 */
export function SlashCommandModelPicker({selectedAgent: selectedAgentProp}: SlashCommandModelPickerProps) {
  const {plan} = useEntitlement()
  const [selectedAgentModelId, setSelectedAgentModelId] = useLatestAgentModel()
  const {models: agentModels} = useAgentModels()
  const [selectedAgentFromStorage] = useLastSelectedAgent()
  const selectedAgent = selectedAgentProp ?? selectedAgentFromStorage
  const {data: agentInfo} = useAgentInfo(selectedAgent.topLevelAgentId ? Number(selectedAgent.topLevelAgentId) : null)

  // Only render when feature flag is enabled, user has Pro/Pro+ plan, and models are available
  const shouldShowModelPicker =
    copilotFeatureFlags.codingAgentModelSelection &&
    (copilotFeatureFlags.codingAgentModelSelectionAllSkus ||
      plan === CopilotPlan.IndividualPro ||
      plan === CopilotPlan.IndividualProPlus) &&
    isCopilotOrCustomAgent(selectedAgent, agentInfo?.slug)

  if (!shouldShowModelPicker || !agentModels || agentModels.length === 0) {
    return null
  }

  return (
    <AgentModelPicker
      onUpdateModel={(modelId: string) => {
        setSelectedAgentModelId(modelId)
      }}
      selectedModelId={selectedAgentModelId}
    />
  )
}

import {indentUnit} from '@codemirror/language'
import {EditorState, type Extension} from '@codemirror/state'
import {EditorView} from '@codemirror/view'
import type {SpacingOptions} from '../CodeMirror'

export const spacingControls = (options: SpacingOptions): Extension[] => {
  const extensions: Extension[] = [EditorState.tabSize.of(options.indentUnit)]

  if (options.indentWithTabs) {
    extensions.push(indentUnit.of('\t'))
  } else {
    extensions.push(indentUnit.of(' '.repeat(options.indentUnit)))
  }

  if (options.lineWrapping) {
    extensions.push(EditorView.lineWrapping)
  }

  return extensions
}

