import type {Choice} from '../types/session'

/**
 * When a choice has BOTH reasoning_text AND tool_calls, split it into two separate choices:
 * 1. First choice: reasoning_text only (no tool_calls, no content) - renders outside groups
 * 2. Second choice: tool_calls and content (no reasoning_text) - can be grouped with other tools
 *
 * This ensures reasoning_text renders before tool groups rather than inside them.
 */
export function splitChoiceWithReasoningText(choice: Choice): Choice[] {
  const hasReasoningText = !!choice.delta.reasoning_text
  const hasToolCalls = !!(choice.delta.tool_calls && choice.delta.tool_calls.length > 0)

  if (hasReasoningText && hasToolCalls) {
    return [
      // First: reasoning_text only (won't be grouped since no tool_calls)
      {
        ...choice,
        delta: {
          ...choice.delta,
          tool_calls: undefined,
          content: undefined,
        },
      },
      // Second: tool_calls only (will be grouped normally)
      {
        ...choice,
        delta: {
          ...choice.delta,
          reasoning_text: undefined,
        },
      },
    ]
  }

  return [choice]
}

/**
 * Determines whether a choice should be split based on having both reasoning_text and tool_calls.
 */
export function shouldSplitChoice(choice: Choice): boolean {
  const hasReasoningText = !!choice.delta.reasoning_text
  const hasToolCalls = !!(choice.delta.tool_calls && choice.delta.tool_calls.length > 0)
  return hasReasoningText && hasToolCalls
}

import {usePath} from '../contexts/PathContext'
import {useRefInfo} from '../contexts/RefInfoContext'
import {useCurrentRepository} from '@github-ui/current-repository'
import {useLatestCommit} from '@github-ui/use-latest-commit'
import {AlertIcon} from '@primer/octicons-react'
import {Flash} from '@primer/react'
import {Octicon} from '@primer/react/deprecated'

import styles from './SpoofedCommitWarning.module.css'
import {useIsDataRouterEnabled} from '@github-ui/react-core/future/use-is-data-router-enabled'
import {useLatestCommitContext} from '../contexts/LatestCommitContext'

export function SpoofedCommitWarning() {
  const isDataRouter = useIsDataRouterEnabled()

  return isDataRouter ? <SpoofedCommitWarningDataRouter /> : <SpoofedCommitWarningInternal />
}

function SpoofedCommitWarningDataRouter() {
  const {latestCommit} = useLatestCommitContext()
  const isSpoofed = latestCommit?.isSpoofed ?? false

  if (!isSpoofed) {
    return null
  }

  return <SpoofedCommitWarningBanner className={styles.SpoofedCommitWarningBanner} />
}

function SpoofedCommitWarningInternal() {
  if (!useLatestCommitIsSpoofed()) {
    return null
  }

  return <SpoofedCommitWarningBanner className={styles.SpoofedCommitWarningBanner} />
}

export function SpoofedCommitWarningBanner({className}: {className?: string}) {
  return (
    <Flash variant="warning" className={className} data-testid="spoofed-commit-warning-banner">
      <Octicon icon={AlertIcon} />
      <span>
        This commit does not belong to any branch on this repository, and may belong to a fork outside of the
        repository.
      </span>
    </Flash>
  )
}

export function useLatestCommitIsSpoofed() {
  const repo = useCurrentRepository()
  const path = usePath()
  const refInfo = useRefInfo()
  const [latestCommit] = useLatestCommit(repo.ownerLogin, repo.name, refInfo.name, path)
  return latestCommit?.isSpoofed ?? false
}

import {
  CheckCircleFillIcon,
  XCircleFillIcon,
  QuestionIcon,
  DotFillIcon,
  SquareFillIcon,
  ClockIcon,
} from '@primer/octicons-react'
import {SessionState} from '../types/session'

export function getSessionStatusIcon(status: SessionState) {
  switch (status) {
    case SessionState.InProgress:
      return <InProgressSpinner />
    case SessionState.Completed:
      return <CheckCircleFillIcon className="fgColor-success" aria-label="Completed" />
    case SessionState.Failed:
    case SessionState.TimedOut:
      return <XCircleFillIcon className="fgColor-danger" aria-label="Failed" />
    case SessionState.Idle:
      return <DotFillIcon className="fgColor-attention" aria-label="Idle" />
    case SessionState.WaitingForUser:
      return <QuestionIcon className="fgColor-attention" aria-label="Waiting for user" />
    case SessionState.Cancelled:
      return <SquareFillIcon className="fgColor-muted" aria-label="Cancelled" />
    case SessionState.Queued:
      return <ClockIcon className="fgColor-attention" aria-label="Queued" />
    default:
      return null
  }
}

export function InProgressSpinner() {
  return (
    <svg
      role="img"
      aria-label="Currently running"
      width="16px"
      height="16px"
      fill="none"
      viewBox="0 0 16 16"
      className="anim-rotate"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        fill="none"
        stroke="var(--color-fg-attention, #bf8700)"
        strokeWidth="2"
        d="M3.05 3.05a7 7 0 1 1 9.9 9.9 7 7 0 0 1-9.9-9.9Z"
        opacity=".5"
      />
      <path
        fill="var(--color-fg-attention, #bf8700)"
        fillRule="evenodd"
        d="M8 4a4 4 0 1 0 0 8 4 4 0 0 0 0-8Z"
        clipRule="evenodd"
      />
      <path fill="var(--color-fg-attention, #bf8700)" d="M14 8a6 6 0 0 0-6-6V0a8 8 0 0 1 8 8h-2Z" />
    </svg>
  )
}

// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {DelegatedDismissalRequestStatuses, AutomatedCommentSource} from '@github-ui/diff-lines/conversation-types'
import type {AutomatedComment} from '../types'

interface StatusMessageProps {
  automatedComment: AutomatedComment
  resourceName: string
}

export function StatusMessage({automatedComment, resourceName}: StatusMessageProps) {
  if (automatedComment.source === AutomatedCommentSource.LicenseCompliance) {
    return <LicenseComplianceStatusMessage automatedComment={automatedComment} resourceName={resourceName} />
  }

  return <DefaultStatusMessage automatedComment={automatedComment} resourceName={resourceName} />
}

function DefaultStatusMessage({automatedComment, resourceName}: StatusMessageProps) {
  const {delegatedDismissalRequest, isDismissed, dismissalReason, dismissedBy} = automatedComment

  if (delegatedDismissalRequest) {
    const {requester, status, reason, reviewer} = delegatedDismissalRequest
    const reasonText = reason ? ` as ${reason}` : ''
    switch (status) {
      case DelegatedDismissalRequestStatuses.Pending:
        return (
          <span className="fgColor-muted f6">
            <span className="text-bold">{requester}</span> requested to dismiss{reasonText}
          </span>
        )
      case DelegatedDismissalRequestStatuses.Rejected:
        return reviewer ? (
          <span className="fgColor-muted f6">
            <span className="text-bold">{reviewer}</span> denied request to dismiss
          </span>
        ) : (
          <span className="fgColor-muted f6">Request to dismiss was denied</span>
        )
    }
  }

  if (isDismissed) {
    const dismissalReasonText = dismissalReason ? ` as ${dismissalReason}` : ''
    if (!dismissedBy) {
      return (
        <span className="fgColor-muted f6">
          This {resourceName} was dismissed{dismissalReasonText}
        </span>
      )
    } else {
      return (
        <span className="fgColor-muted f6">
          <span className="text-bold">{dismissedBy}</span> dismissed this {resourceName}
          {dismissalReasonText}
        </span>
      )
    }
  }

  return (
    <span className="fgColor-muted f6">Dismissing the {resourceName} will mark this conversation as resolved.</span>
  )
}

function LicenseComplianceStatusMessage({automatedComment, resourceName}: StatusMessageProps) {
  const {delegatedDismissalRequest} = automatedComment

  if (!delegatedDismissalRequest) {
    return null
  }

  const {requester, status, reason} = delegatedDismissalRequest
  const reasonText = reason ? ` as ${reason}` : ''
  switch (status) {
    case DelegatedDismissalRequestStatuses.Pending:
      return (
        <span className="fgColor-muted f6">
          <span className="text-bold">{requester}</span> requested to close{reasonText}
        </span>
      )
    case DelegatedDismissalRequestStatuses.Rejected:
      return (
        <span className="fgColor-muted f6">
          <span className="text-bold">{requester}</span> denied request to close
        </span>
      )
    case DelegatedDismissalRequestStatuses.Approved:
      return (
        <span className="fgColor-muted f6">
          <span className="text-bold">{requester}</span> closed this {resourceName}
          {reasonText}
        </span>
      )
    default:
      // Handle unrecognized statuses (e.g., Cancelled) by showing no status message
      return null
  }
}

import {PaperAirplaneIcon, AlertIcon} from '@primer/octicons-react'
import {IconButton} from '@primer/react'
import {useState, useRef} from 'react'
import {ScopedCommands} from '@github-ui/ui-commands'
import styles from './SteeringCommandInput.module.css'

// Maximum height for textarea in pixels, equivalent to approximately 6 lines
const MAX_TEXTAREA_HEIGHT_PX = 256

type SteeringCommandInputProps = {
  onSubmit: (message: string) => void
  error?: string | null
}

export function SteeringCommandInput({onSubmit, error}: SteeringCommandInputProps) {
  const [value, setValue] = useState('')
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setValue(e.target.value)

    // Auto-resize textarea to fit content
    const textarea = e.target
    textarea.style.height = 'auto'
    textarea.style.height = `${Math.min(textarea.scrollHeight, MAX_TEXTAREA_HEIGHT_PX)}px`
  }

  const handleSubmit = () => {
    if (value.trim()) {
      onSubmit(value)
      setValue('')
      // Reset textarea height
      if (textareaRef.current) {
        textareaRef.current.style.height = 'auto'
      }
    }
  }

  return (
    <ScopedCommands commands={{'copilot-chat:send-message': handleSubmit}}>
      <div className={styles.steeringCommandInputContainer}>
        <div className={styles.steeringCommandInputWrapper}>
          <textarea
            ref={textareaRef}
            className={styles.steeringCommandInputTextarea}
            value={value}
            onChange={handleChange}
            placeholder="What would you like to change?"
            autoComplete="off"
            autoCorrect="off"
            spellCheck="false"
            rows={1}
          />
          <IconButton
            className={styles.steeringCommandInputSubmitButton}
            variant="invisible"
            size="small"
            icon={PaperAirplaneIcon}
            aria-label="Send"
            disabled={!value.trim()}
            onClick={handleSubmit}
          />
        </div>
        {error && (
          <div className={styles.errorMessage}>
            <AlertIcon className={styles.errorIcon} />
            <span>{error}</span>
          </div>
        )}
      </div>
    </ScopedCommands>
  )
}

