import type {MutableRefObject} from 'react'
import type {HandleUserSubmit} from '../types/user-submit'
import {AGENT_TASKS_SELECTED_MODEL_KEY} from './constants'

export function submitTask(message: string, handleUserSubmitRef: MutableRefObject<HandleUserSubmit>) {
  try {
    // Try to parse as JSON to see if it contains repo/branch data
    const parsed = JSON.parse(message)
    if (parsed.text !== undefined) {
      // It's the new format with repo/branch data
      const selectedRepo = parsed.selectedRepo
        ? {
            ...parsed.selectedRepo,
            private: parsed.selectedRepo.visibility === 'private',
          }
        : null
      const selectedBranch = parsed.selectedBranch || ''
      const selectedAgent = parsed.selectedAgent

      let modelId = parsed.model?.id // Model ID will be present if passed from task-request reference

      // If no model ID in parsed data, try to get it from localStorage
      if (!modelId) {
        try {
          modelId = localStorage.getItem(AGENT_TASKS_SELECTED_MODEL_KEY) ?? undefined
        } catch {
          // localStorage might not be available (SSR, etc)
        }
      }

      handleUserSubmitRef.current(parsed.text, selectedRepo, selectedBranch, selectedAgent || '', undefined, modelId)
    } else {
      // JSON parsed but doesn't have expected structure, treat as plain text

      handleUserSubmitRef.current(message, null, '', {})
    }
  } catch {
    // Not JSON, treat as plain text (old format)

    handleUserSubmitRef.current(message, null, '', {})
  }
}

"use strict";
var isChrome = require("./is-chrome");
var MINIMUM_SUPPORTED_CHROME_VERSION = 61;
function isSupportedChromeVersion(ua) {
    var match = ua.match(/Chrome\/(\d+)\./);
    if (!match) {
        return false;
    }
    var version = parseInt(match[1], 10);
    return version >= MINIMUM_SUPPORTED_CHROME_VERSION;
}
module.exports = function supportsPaymentRequestApi(ua) {
    ua = ua || window.navigator.userAgent;
    if (!window.PaymentRequest) {
        return false;
    }
    if (!isChrome(ua)) {
        // if browser is not chrome based, but has Payment Request API
        // this means that it implemented the API after it was finalized
        return true;
    }
    // Chrome introduce the Payment Request API in some versions of
    // Android Chrome as early as Chrome v53, but it was not
    // finalized until v61
    return isSupportedChromeVersion(ua);
};

"use strict";
var MINIMUM_SUPPORTED_CHROME_IOS_VERSION = 48;
var isAndroid = require("./is-android");
var isIosFirefox = require("./is-ios-firefox");
var isIosWebview = require("./is-ios-webview");
var isChrome = require("./is-chrome");
var isSamsungBrowser = require("./is-samsung");
var isDuckDuckGo = require("./is-duckduckgo");
function isUnsupportedIosChrome(ua) {
    ua = ua || window.navigator.userAgent;
    var match = ua.match(/CriOS\/(\d+)\./);
    if (!match) {
        return false;
    }
    var version = parseInt(match[1], 10);
    return version < MINIMUM_SUPPORTED_CHROME_IOS_VERSION;
}
function isOperaMini(ua) {
    ua = ua || window.navigator.userAgent;
    return ua.indexOf("Opera Mini") > -1;
}
function isAndroidWebview(ua) {
    var androidWebviewRegExp = /Version\/[\d.]+/i;
    ua = ua || window.navigator.userAgent;
    if (isAndroid(ua)) {
        return (androidWebviewRegExp.test(ua) && !isOperaMini(ua) && !isDuckDuckGo(ua));
    }
    return false;
}
function isOldSamsungBrowserOrSamsungWebview(ua) {
    return !isChrome(ua) && !isSamsungBrowser(ua) && /samsung/i.test(ua);
}
module.exports = function supportsPopups(ua) {
    ua = ua || window.navigator.userAgent;
    return !(isIosWebview(ua) ||
        isIosFirefox(ua) ||
        isAndroidWebview(ua) ||
        isOperaMini(ua) ||
        isUnsupportedIosChrome(ua) ||
        isOldSamsungBrowserOrSamsungWebview(ua));
};

