import type {SymbolKind} from '@github-ui/code-nav'
import {clsx} from 'clsx'

import styles from './SymbolIndicator.module.css'

export function SymbolIndicator({symbolKind, showFullSymbol}: {symbolKind: SymbolKind; showFullSymbol?: boolean}) {
  if (!symbolKind) {
    return null
  }

  return (
    <div className={clsx(styles.symbolWrapper, !showFullSymbol && styles.symbolWrapperCompact)}>
      <div className={styles.symbolBackground} style={{backgroundColor: symbolKind.plColor}} />
      <div
        className={clsx(styles.symbolLabel, showFullSymbol ? styles.symbolLabelMedium : styles.symbolLabelSmall)}
        style={{color: symbolKind.plColor}}
      >
        {showFullSymbol ? symbolKind.fullName : symbolKind.shortName}
      </div>
    </div>
  )
}

import type {Repository} from '@github-ui/current-repository'

import type {RefInfo} from '@github-ui/repos-types'
import type {BlackbirdSymbol, StylingDirectivesDocument} from '@github-ui/code-view-types'
import {CodeReference, CodeSymbol, SymbolSource} from './code-symbol'
import type {AlephSymbol, CodeNavBackendType} from './code-nav-types'

interface Options {
  stylingDirectives: StylingDirectivesDocument | undefined
  path: string
  repo: Repository
  refInfo: RefInfo
}

interface AlephSymbolOptions extends Options {
  backend: CodeNavBackendType
}

export function outlineSymbolToCodeSymbol(
  outlineSymbol: BlackbirdSymbol,
  snippet: string,
  {stylingDirectives, repo, refInfo, path}: Options,
): CodeSymbol {
  const {extent_utf16: extentUtf16, ident_utf16: identUtf16} = outlineSymbol

  const codeSymbol = new CodeSymbol({
    kind: outlineSymbol.kind,
    fullyQualifiedName: outlineSymbol.fully_qualified_name,
    name: outlineSymbol.name,
    extent: {
      start: {line: extentUtf16.start.line_number, column: extentUtf16.start.utf16_col},
      end: {line: extentUtf16.end.line_number, column: extentUtf16.end.utf16_col},
    },
    ident: {
      start: {line: identUtf16.start.line_number, column: identUtf16.start.utf16_col},
      end: {line: identUtf16.end.line_number, column: identUtf16.end.utf16_col},
    },
    source: SymbolSource.BLACKBIRD_ANALYSIS,
  })

  codeSymbol.setSnippet(undefined, stylingDirectives?.[identUtf16.start.line_number], snippet, undefined)
  codeSymbol.setFileInfo(repo, refInfo, path)

  return codeSymbol
}

export function alephSymbolToCodeSymbol(
  alephSymbol: AlephSymbol,
  {symbol, refInfo, repo, path, backend}: AlephSymbolOptions & {symbol: string},
): CodeSymbol {
  const symbolStartIdx = alephSymbol.ident?.start?.character
  const symbolEndIdx = alephSymbol.ident?.end?.character ?? alephSymbol.ident?.start?.character
  const ident = {
    start: {
      line: alephSymbol.ident.start.line,
      column: symbolStartIdx ? symbolStartIdx - alephSymbol.leadingWhitespace : 0,
    },
    end: {
      line: alephSymbol.ident?.end?.line ?? alephSymbol.ident.start.line,
      column: symbolEndIdx ? symbolEndIdx - alephSymbol.leadingWhitespace : 0,
    },
  }

  const extentStartIdx = alephSymbol.extent?.start?.character
  const extentEndIdx = alephSymbol.extent?.end?.character ?? alephSymbol.extent?.start?.character
  const extent = {
    start: {
      line: alephSymbol.extent.start.line,
      column: extentStartIdx ? extentStartIdx : 0,
    },
    end: {
      line: alephSymbol.extent.end?.line ?? alephSymbol.extent.start.line,
      column: extentEndIdx ? extentEndIdx : 0,
    },
  }

  const codeSymbol = new CodeSymbol({
    ident,
    extent,
    kind: alephSymbol.symbolKind,
    name: symbol,
    // I guess aleph doesn't support fully qualified names? Just use the name
    fullyQualifiedName: symbol,
    source: backend === 'search' ? SymbolSource.BLACKBIRD_SEARCH : SymbolSource.ALEPH_PRECISE,
  })

  if (alephSymbol.local) {
    codeSymbol.setFileInfo(repo, refInfo, path)
  } else if (alephSymbol.commitOid && alephSymbol.path) {
    let symbolRefInfo = refInfo

    if (alephSymbol.commitOid !== refInfo.currentOid) {
      symbolRefInfo = {
        name: '',
        listCacheKey: alephSymbol.commitOid,
        currentOid: alephSymbol.commitOid,
        canEdit: false,
      }
    }

    codeSymbol.setFileInfo(alephSymbol.repo ?? repo, symbolRefInfo, alephSymbol.path)
  }

  const whiteSpace = new Array(alephSymbol.leadingWhitespace).fill(' ').join('')
  const firstLineWithWhiteSpace = whiteSpace + (alephSymbol.firstLine || '')
  codeSymbol.setSnippet(alephSymbol.highlightedText, undefined, firstLineWithWhiteSpace, alephSymbol.leadingWhitespace)
  return codeSymbol
}

export function alephSymbolToCodeReference(
  alephSymbol: AlephSymbol,
  {refInfo, path, repo, backend}: AlephSymbolOptions,
): CodeReference {
  let symbolRefInfo = refInfo
  let symbolPath = path

  if (!alephSymbol.local && alephSymbol.commitOid && alephSymbol.path) {
    symbolRefInfo = refInfo
    symbolPath = alephSymbol.path

    if (alephSymbol.commitOid !== refInfo.currentOid) {
      symbolRefInfo = {
        name: '',
        listCacheKey: alephSymbol.commitOid,
        currentOid: alephSymbol.commitOid,

        // TODO: this is probably the wrong value sometimes... but we most
        // likely won't read this field
        canEdit: false,
      }
    }
  }

  const identStartSymbolIdx = alephSymbol.ident.start.character
  const identEndSymbolIdx = alephSymbol.ident.end?.character
  const codeReference = new CodeReference({
    repo,
    refInfo: symbolRefInfo,
    path: symbolPath,
    ident: {
      start: {
        line: alephSymbol.ident.start.line,
        column: identStartSymbolIdx ? identStartSymbolIdx - alephSymbol.leadingWhitespace : 0,
      },
      end: {
        line: alephSymbol.ident.end?.line || alephSymbol.ident.start.line,
        column: identEndSymbolIdx ? identEndSymbolIdx - alephSymbol.leadingWhitespace : 0,
      },
    },
    source: backend === 'search' ? SymbolSource.BLACKBIRD_SEARCH : SymbolSource.ALEPH_PRECISE,
  })

  const firstLineWithWhiteSpace =
    new Array(alephSymbol.leadingWhitespace).fill(' ').join('') + (alephSymbol.firstLine || '')
  codeReference.setSnippet(
    alephSymbol.highlightedText,
    undefined,
    firstLineWithWhiteSpace,
    alephSymbol.leadingWhitespace,
  )
  return codeReference
}

import {useCurrentRepository} from '@github-ui/current-repository'
import {codeNavGeneralSearchPath, codeNavSearchPath} from '@github-ui/paths'
import {SearchIcon} from '@primer/octicons-react'
import {Link} from '@primer/react'
import {Octicon} from '@primer/react/deprecated'
import {useEffect, useEffectEvent, useRef, useState} from 'react'

import styles from './SymbolZeroState.module.css'

export function SymbolZeroState({filterText, isFindInFile}: {filterText?: string; isFindInFile?: boolean}) {
  const [message, setMessage] = useState(isFindInFile ? 'No matches found' : 'No symbols found')
  const repo = useCurrentRepository()

  const firstUpdateRef = useRef(true)

  const handleAriaMessageAnnounceAfterFirstRender = useEffectEvent(() => {
    if (firstUpdateRef.current) {
      firstUpdateRef.current = false
      return
    }

    // This is a hack because aria-live doesn't re-announce updates with the same content
    // But we don't need to do this on the first render or else aria-live will announce twice
    setMessage(`${message}\u200B`) // 0 width space
  })
  useEffect(() => {
    handleAriaMessageAnnounceAfterFirstRender()
  }, [filterText])

  return (
    <div className={styles.container}>
      {filterText === '' && (
        <>
          <div className={styles.emptyStateCard}>
            <div className={styles.emptyStateCardContent}>
              <h3 className={styles.emptyStateHeading}>Symbol outline not available for this file</h3>
              <div className={styles.emptyStateDescription}>
                To inspect a symbol, try clicking on the symbol directly in the code view.
              </div>
            </div>
          </div>
          <div className={styles.languageSupportNote}>
            {' '}
            Code navigation supports a limited number of languages.{' '}
            <Link
              inline
              href="https://docs.github.com/repositories/working-with-files/using-files/navigating-code-on-github"
            >
              See which languages are supported.
            </Link>
          </div>
        </>
      )}
      {filterText && (
        <>
          <Octicon icon={SearchIcon} size={24} />
          <h3 className={styles.filterResultHeading} role="alert" aria-relevant="all">
            {message}
          </h3>
        </>
      )}
      {filterText && (
        <span id="filter-zero-state" className={styles.filterZeroState}>
          No lines in this file contain that string.
          <br />
          Search in{' '}
          <Link
            href={codeNavSearchPath({
              owner: repo.ownerLogin,
              repo: repo.name,
              searchTerm: filterText,
            })}
            inline
          >
            {repo.ownerLogin}/{repo.name}
          </Link>{' '}
          or{' '}
          <Link href={codeNavGeneralSearchPath({searchTerm: filterText})} inline>
            all of GitHub
          </Link>
        </span>
      )}
    </div>
  )
}

/* eslint github/unescaped-html-literal: off */
import type {StylingDirectivesLine} from '@github-ui/code-view-types'
import {showHiddenUnicodeCharactersHTML} from '@github-ui/hidden-unicode-banner/HiddenUnicodeCharacter'
import type {SafeHTMLString} from '@github-ui/safe-html'
import {VerifiedHTMLDiv} from '@github-ui/safe-html/VerifiedHTML'
import {useRuntimeEnvironment} from '@github-ui/ssr-utils/use-runtime-environment'
import {useCodeHTML} from '@github-ui/syntax-highlighted-lines/hooks/use-code-html'
import type {HighlightingStrategy} from '@github-ui/syntax-highlighted-lines/types'
import React, {useMemo} from 'react'

import {useCurrentBlob} from '../../../../hooks/CurrentBlob'
import {useIsCursorEnabled} from '../../../../hooks/use-cursor-navigation'
import {useIsFirefox, useShouldUseInert} from '../../../../utilities/lines'
import {isHiddenUnicodeShown} from '../../Banners/HiddenUnicode'
import {numberOfLinesPerContentVisibility} from './CodeLinesNoVirtualization'
import type {CodeLineData} from './hooks/use-code-lines'

interface SyntaxHighlightedLineProps {
  id?: string
  rawText?: string
  stylingDirectivesLine?: StylingDirectivesLine
  lineNumber: number
  current?: boolean
  forceVisible?: boolean
  shouldUseInert: boolean
  colorizedLine?: SafeHTMLString
  ref?: React.Ref<HTMLDivElement>
}

export const SyntaxHighlightedLine = React.memo(SyntaxHighlightedLineWithRef)

function SyntaxHighlightedLineWithRef({
  id,
  stylingDirectivesLine,
  rawText,
  lineNumber,
  current,
  forceVisible,
  shouldUseInert,
  colorizedLine,
  ref,
}: SyntaxHighlightedLineProps) {
  const strategy = useSyntaxHighlightingStrategy()
  const {tabSize} = useCurrentBlob()
  const hiddenUnicodeShown = isHiddenUnicodeShown()
  const codeLineHTML = useCodeHTML(
    colorizedLine,
    stylingDirectivesLine,
    rawText,
    forceVisible ? 'plain' : strategy,
    tabSize,
    hiddenUnicodeShown,
  )

  return (
    <VerifiedHTMLDiv
      id={id}
      className="react-file-line html-div"
      data-testid="code-cell"
      data-line-number={lineNumber}
      html={codeLineHTML}
      ref={ref}
      style={{position: 'relative'}}
      aria-current={current ? 'location' : undefined}
      inert={shouldUseInert}
    />
  )
}

export const SyntaxHighlightedOverlay = React.memo(SyntaxHighlightedOverlayUnmemoed)

function SyntaxHighlightedOverlayUnmemoed({
  linesData,
  colorizedLines,
}: {
  linesData: CodeLineData[]
  colorizedLines: SafeHTMLString[] | null | undefined
}) {
  const hiddenUnicodeShown = isHiddenUnicodeShown()
  const documentHTML = useCodeHTMLDocument(linesData, colorizedLines ?? null, hiddenUnicodeShown)
  const shouldUseInert = useShouldUseInert()

  return <VerifiedHTMLDiv inert={shouldUseInert} html={documentHTML} />
}

function useSyntaxHighlightingStrategy(): HighlightingStrategy {
  const hiddenFromFind = useIsCursorEnabled()
  const isFirefox = useIsFirefox()
  const shouldUseInert = useShouldUseInert()

  if (!hiddenFromFind || shouldUseInert) return 'plain'
  if (isFirefox && !shouldUseInert) return 'separated-characters-chunked'

  return 'data-attribute'
}

export function useCodeHTMLDocument(
  linesData: CodeLineData[],
  colorizedLines: SafeHTMLString[] | null | undefined,
  hiddenUnicodeShown: boolean,
): SafeHTMLString {
  const {isServer: isSSR} = useRuntimeEnvironment()
  return useMemo(
    () =>
      colorizedLines
        ? /* eslint-disable-next-line @github-ui/github-monorepo/no-cast-as-safe-html-string -- HTML is sanitized server-side. TODO: Move type assertion to data ingress point. */
          (colorizedLines
            .map((colorizedLine, i) => {
              if (i >= linesData.length) return null
              let divWrapStart = ''
              let divWrapEnd = ''
              //we need to put content visibility=auto on boxes of content rather than on each individual line,
              //that allows the page to do significantly fewer content visibility calculations when doing layout and
              //style updates. Starting with boxes of 60 lines for now
              if (i % numberOfLinesPerContentVisibility === 0 && !isSSR) {
                divWrapStart = isSSR ? '<div>' : '<div class="react-no-virtualization-wrapper">'
              }
              if (((i + 1) % numberOfLinesPerContentVisibility === 0 || i === colorizedLines.length) && !isSSR) {
                divWrapEnd = '</div>'
              }

              /* eslint-disable-next-line @github-ui/github-monorepo/no-cast-as-safe-html-string -- Static string literal is safe */
              const lineContent = colorizedLine.length !== 0 ? colorizedLine : ('\n' as SafeHTMLString)
              const processedLineContent = hiddenUnicodeShown
                ? (showHiddenUnicodeCharactersHTML(lineContent) ?? lineContent)
                : lineContent

              return `${divWrapStart}<div id="LC${
                i + 1
              }" class="react-code-text react-code-line-contents-no-virtualization react-file-line html-div ${
                linesData[i]?.codeLineClassName
              }">${processedLineContent}</div>${divWrapEnd}`
            })
            .join('\n') as SafeHTMLString)
        : /* eslint-disable-next-line @github-ui/github-monorepo/no-cast-as-safe-html-string -- Static string literal is safe */
          ('<div></div>' as SafeHTMLString),
    [linesData, colorizedLines, isSSR, hiddenUnicodeShown],
  )
}

import styles from './ToolCodeBlock.module.css'
import {type PropsWithChildren, useId, useState, useEffect} from 'react'

export interface ToolCodeBlockProps {
  language?: string
  shellLoading?: boolean
  code: string
  startOffset: number
  endOffset: number
}

export function ToolCodeBlock({shellLoading, children}: PropsWithChildren<ToolCodeBlockProps>) {
  const codeBlockLabelId = useId()
  const [loaderChar, setLoaderChar] = useState('|')

  useEffect(() => {
    let intervalId: NodeJS.Timeout | undefined
    if (shellLoading) {
      const loaderChars = ['|', '/', '-', '\\']
      let currentCharIndex = 0
      intervalId = setInterval(() => {
        currentCharIndex = (currentCharIndex + 1) % loaderChars.length
        setLoaderChar(loaderChars[currentCharIndex] || '|')
      }, 250)
    } else {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setLoaderChar('|') // Reset loader char when not loading
    }
    return () => clearInterval(intervalId)
  }, [shellLoading])

  return (
    <figure className={styles.container} aria-labelledby={codeBlockLabelId}>
      <div className={styles.codeContainer}>
        {/* eslint-disable-next-line jsx-a11y/no-noninteractive-tabindex */}
        <pre className={styles.code} tabIndex={0}>
          <code className={styles.codeWrap}>
            {children}
            {shellLoading && <span>{loaderChar}</span>}
          </code>
        </pre>
      </div>
    </figure>
  )
}

import type {CopilotMarkdownExtension, ReactComponentsExtension} from '@github-ui/copilot-markdown/extension'
import {dataAttrToPropName, parseJsonAttribute} from '@github-ui/copilot-markdown/utils'
import {ToolCodeBlock, type ToolCodeBlockProps} from './ToolCodeBlock'

import {visit} from 'unist-util-visit'

const codeblockAttribute = 'data-tool-codeblock-props'
const codeblockProperty = dataAttrToPropName(codeblockAttribute)

const reactComponents: ReactComponentsExtension = {
  code: (props, fallthrough) => {
    const codeblockProps = parseJsonAttribute<ToolCodeBlockProps>(props, codeblockAttribute)
    if (!codeblockProps) return fallthrough

    return <ToolCodeBlock {...codeblockProps}>{props.children}</ToolCodeBlock>
  },
}

export type ToolCodeBlockExtensionArgs = {
  shellLoading?: boolean
}

export default function toolCodeBlockExtension(args: ToolCodeBlockExtensionArgs = {}): CopilotMarkdownExtension {
  const {shellLoading} = args
  return {
    transformMarkdown: tree =>
      visit(tree, 'code', node => {
        node.data = {
          ...node.data,
          hName: 'code',
          hProperties: {
            [codeblockProperty]: JSON.stringify({
              language: node.lang ?? '',
              code: node.value,
              // Every component will receive a node. This is the original Element from hast element being turned into a React element.
              // see https://github.com/remarkjs/react-markdown/tree/main?tab=readme-ov-file#appendix-b-components
              startOffset: node.position?.start.offset ?? -1,
              endOffset: node.position?.end.offset ?? -1,

              shellLoading: !!shellLoading,
            } satisfies ToolCodeBlockProps),
          },
        }
      }),
    transformHtml: tree =>
      // Code nodes render as two nested elements (pre > code) by default, so we transform the html to remove the outer element
      visit(tree, 'element', (node, i, parent) => {
        const child = node.children?.[0]
        if (
          parent &&
          i !== undefined &&
          node.tagName === 'pre' &&
          node.children?.length === 1 &&
          child?.type === 'element' &&
          child.tagName === 'code' &&
          codeblockProperty in child.properties
        )
          parent.children.splice(i, 1, child)
      }),
    reactComponents,
  }
}

import {useCallback, useMemo, useState} from 'react'
import styles from './ToolProposeWork.module.css'
import {Button, Spinner} from '@primer/react'
import {CheckCircleIcon, MaximizeIcon, PlayIcon} from '@primer/octicons-react'
import {MarkdownRenderer} from '@github-ui/copilot-markdown'
import type {CreateAPITaskParams} from '../../../../types/api-task'
import {useCreateAPITask} from '../../../../hooks/use-create-api-task'
import {
  getAgentTasksQueryKeyForMutation,
  getFlatTaskList,
  setFlatTaskList,
  PAGE_SIZE,
  type FetchTasksResponse,
} from '../../../../hooks/useTasks'
import {useSessionLogsContext} from '../../Context'
import {NewRepoAgentTaskButton} from '@github-ui/new-repo-agent-task-button/NewRepoAgentTaskButton'
import type {Repository} from '@github-ui/current-repository'
import {PROPOSE_WORK_MAX_TEXTAREA_HEIGHT} from '../../../../utils/constants'
import {useCurrentUser} from '../../../../contexts/CurrentUserContext'

export interface ToolProposeWorkProps {
  title: string
  description: string
  type: 'code_change' | 'task'
}

export function ToolProposeWork({title, description, type}: ToolProposeWorkProps) {
  const {createTask, isCreating} = useCreateAPITask<FetchTasksResponse>({
    queryKey: getAgentTasksQueryKeyForMutation(),
    pageSize: PAGE_SIZE,
    getFlatTaskList,
    setFlatTaskList,
    decoupledModeEnabled: false,
  })

  const {session, sessionNwo} = useSessionLogsContext()
  const {currentUser} = useCurrentUser()
  const [isStarted, setIsStarted] = useState(false)
  const [isDialogOpen, setIsDialogOpen] = useState(false)

  const handleSubmit = useCallback(
    (e: React.FormEvent) => {
      e.preventDefault()
      e.stopPropagation()

      // If the task is already started or being created, do nothing
      if (isStarted || isCreating) {
        return
      }

      // We can only create a task if we have the nwo for the current session;
      // that's determined by the session's pull request.
      if (!sessionNwo) {
        return
      }

      const newTask: CreateAPITaskParams = {
        problemStatement: description,
        eventType: 'propose_work',
        eventContent: `Proposed work: ${title}`,
        nwo: sessionNwo,
        createPullRequest: type === 'code_change',
        eventIdentifiers: session?.workflow_run_id ? [session.workflow_run_id.toString()] : undefined,
      }

      createTask(newTask)
      setIsStarted(true)
    },
    [title, description, type, createTask, sessionNwo, isStarted, isCreating, session],
  )

  const handleCardClick = useCallback(
    (e: React.MouseEvent) => {
      // Don't open dialog if it's already open or if clicking on interactive elements
      if (isDialogOpen) {
        return
      }
      const target = e.target as HTMLElement
      // Don't open dialog when clicking on interactive elements (buttons, forms, links, inputs)
      if (target.closest('button') || target.closest('form') || target.closest('a') || target.closest('input')) {
        return
      }
      setIsDialogOpen(true)
    },
    [isDialogOpen],
  )

  const [ownerLogin, repoName] = sessionNwo ? sessionNwo.split('/') : [null, null]

  const initialRepo =
    sessionNwo && repoName && ownerLogin && session?.repo_id
      ? ({
          nameWithOwner: sessionNwo,
          name: repoName,
          ownerLogin,
          id: session.repo_id,
        } as Repository)
      : undefined

  return (
    <>
      {/* eslint-disable-next-line jsx-a11y/click-events-have-key-events, jsx-a11y/no-static-element-interactions */}
      <div className={styles.container} onClick={handleCardClick}>
        <div className={styles.titleContainer}>
          <h3 className="h4">{title}</h3>
          <div className={styles.buttonsContainer}>
            {initialRepo && (
              <NewRepoAgentTaskButton
                icon={MaximizeIcon}
                label="Edit task"
                repository={initialRepo}
                currentUserId={currentUser?.id}
                currentUserLogin={currentUser?.login}
                eventType="propose_work"
                size="small"
                variant="invisible"
                initialText={description}
                maxTextareaHeight={PROPOSE_WORK_MAX_TEXTAREA_HEIGHT}
                isOpen={isDialogOpen}
                onOpenChange={setIsDialogOpen}
                eventIdentifiers={session?.workflow_run_id ? [session.workflow_run_id.toString()] : undefined}
                decoupledModeEnabled={false}
              />
            )}
            <form onSubmit={handleSubmit} className={styles.startTaskButton}>
              <StartTaskButton isCreating={isCreating} isStarted={isStarted} />
            </form>
          </div>
        </div>

        <div className={styles.descriptionContainer}>
          <MarkdownRenderer markdown={description} />
        </div>
      </div>
    </>
  )
}

function StartTaskButton({isCreating, isStarted}: {isCreating: boolean; isStarted: boolean}) {
  const [text, icon] = useMemo(() => {
    if (isCreating) {
      return ['Creating...', ButtonSpinner]
    }
    if (isStarted) {
      return ['Task started', CheckCircleIcon]
    }
    return ['Start task', PlayIcon]
  }, [isCreating, isStarted])
  return (
    <Button type="submit" leadingVisual={icon} inactive={isCreating || isStarted}>
      {text}
    </Button>
  )
}

function ButtonSpinner() {
  return <Spinner size="small" srText="Starting task…" />
}

