import type {SetPanelOpenType} from '@github-ui/code-view-shared/contexts/OpenPanelContext'
import type {PanelType, TocEntry} from '@github-ui/code-view-types'
import {ListUnorderedIcon} from '@primer/octicons-react'
import {IconButton} from '@primer/react'
import {clsx} from 'clsx'
import React from 'react'

import styles from './TableOfContents.module.css'

export default function TableOfContents({
  toc,
  openPanel,
  setOpenPanel,
  isDirectoryReadme,
}: {
  toc: TocEntry[] | null
  openPanel?: PanelType | undefined
  setOpenPanel?: SetPanelOpenType
  isDirectoryReadme?: boolean
}) {
  const ref = React.useRef<HTMLButtonElement>(null)
  return showToc(toc) ? (
    <IconButton
      ref={ref}
      tooltipDirection="n"
      className={clsx(!isDirectoryReadme && 'pr-mr-2', styles.IconButton)}
      icon={ListUnorderedIcon}
      variant="invisible"
      aria-label="Outline"
      aria-pressed={openPanel === 'toc'}
      onClick={() => {
        setOpenPanel?.(openPanel === 'toc' ? undefined : 'toc', ref.current)
      }}
      size="small"
    />
  ) : null
}

function showToc(toc: TocEntry[] | null) {
  return toc && toc.length >= 2
}

import type {TocEntry} from '@github-ui/code-view-types'
import {VerifiedHTMLBox} from '@github-ui/safe-html/VerifiedHTML'
import {FilterIcon, XIcon} from '@primer/octicons-react'
import {IconButton, NavList, TextInput} from '@primer/react'
import React, {useCallback, useEffect, useDeferredValue, useMemo, useRef, useState} from 'react'

import {onHashChange} from './SharedMarkdownContent'

import styles from './TableOfContentsPanel.module.css'

// CSS class lookup for level-based indentation (avoids creating style objects)
const levelClasses: Record<number, string> = {
  1: styles.TocLevel1,
  2: styles.TocLevel2,
  3: styles.TocLevel3,
  4: styles.TocLevel4,
  5: styles.TocLevel5,
  6: styles.TocLevel6,
}

interface TocItemProps extends Pick<TocEntry, 'anchor' | 'htmlText' | 'level'> {
  hash: string
  index: number
}

// Memoized list item to avoid re-renders when filter/hash doesn't affect this item
const TocItem = React.memo(function TocItem({htmlText, anchor, level, hash, index}: TocItemProps) {
  const hashString = `#${anchor}`
  const isCurrent = hash === hashString
  // Clamp level to valid range (1-6) to handle any unexpected values
  const levelClass = levelClasses[Math.max(1, Math.min(6, level))]

  const handleClick = useCallback(
    (e: React.MouseEvent) => {
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      if (e.button === 1 || e.metaKey || e.ctrlKey) {
        return
      }
      if (!isCurrent) {
        location.href = hashString
      }
      onHashChange(hashString)
      e.preventDefault()
    },
    [hashString, isCurrent],
  )

  return (
    <NavList.Item
      key={`outline-${anchor}-${index}`}
      aria-current={isCurrent ? 'page' : undefined}
      href={hashString}
      onClick={handleClick}
    >
      <VerifiedHTMLBox className={levelClass} html={htmlText} />
    </NavList.Item>
  )
})

export default function TableOfContentsPanel({onClose, toc}: {onClose?: () => void; toc: TocEntry[] | null}) {
  const [filter, setFilter] = useState<string>('')
  // Defer filter to keep typing responsive while filtering happens in background
  const deferredFilter = useDeferredValue(filter)
  const [hash, setHash] = useState<string>('')
  const headingRef = useRef<HTMLHeadingElement>(null)
  useEffect(() => {
    headingRef.current?.focus()
  }, [])

  useEffect(() => {
    const hashChange = () => {
      if (window.location.hash) {
        setHash(window.location.hash)
      }
    }

    hashChange()
    window.addEventListener('hashchange', hashChange)
    return () => {
      window.removeEventListener('hashchange', hashChange)
    }
  }, [])

  // Filter TOC using deferred value so input stays responsive
  const filteredToc = useMemo(() => {
    if (!toc) return []
    if (!deferredFilter) return toc
    const lowerFilter = deferredFilter.toLowerCase()
    return toc.filter(({htmlText}) => htmlText && htmlText.toLowerCase().includes(lowerFilter))
  }, [toc, deferredFilter])

  if (!toc) {
    return null
  }

  return (
    <section aria-labelledby="outline-id" className={styles.Box}>
      {onClose ? (
        <div className="d-flex flex-justify-between flex-items-center">
          <h3
            id="outline-id"
            ref={headingRef}
            className="d-flex flex-justify-between flex-items-center f5 text-bold px-2"
            tabIndex={-1}
          >
            Outline
          </h3>
          <IconButton
            aria-label="Close outline"
            tooltipDirection="sw"
            className="fgColor-muted"
            icon={XIcon}
            onClick={onClose}
            variant="invisible"
          />
        </div>
      ) : null}
      {toc.length >= 8 ? (
        <div className="tmp-pt-3 px-2">
          <TextInput
            leadingVisual={FilterIcon}
            placeholder="Filter headings"
            aria-label="Filter headings"
            className="width-full"
            onChange={e => {
              setFilter(e.target.value)
            }}
          />
        </div>
      ) : null}
      <NavList className={styles.NavList}>
        {filteredToc.map((entry, index) => (
          <TocItem
            key={`outline-${entry.anchor}-${index}`}
            anchor={entry.anchor}
            htmlText={entry.htmlText}
            level={entry.level}
            hash={hash}
            index={index}
          />
        ))}
      </NavList>
    </section>
  )
}

import {sendEvent} from '@github-ui/hydro-analytics'
import {SidebarListItem} from '@github-ui/pacer/SidebarListItem'
import {SidebarSection} from '@github-ui/pacer/SidebarNavigation'
import {useLocation} from '@github-ui/react-router'
import {KebabHorizontalIcon} from '@primer/octicons-react'
import {ActionMenu, IconButton} from '@primer/react'
import {useCallback, useRef} from 'react'
import {ConsecutiveCAPI401sProvider} from '../contexts/ConsecutiveCAPI401sContext'
import {useSSOChangeDetection} from '../hooks/use-sso-change-detection'
import {useTasks} from '../hooks/useTasks'
import type {OptimisticTask, UITask} from '../types/task'
import {generateTaskPathForRepo, shouldLinkToRepoTaskView} from '../utils/generate-task-path'
import {getTaskTitle} from '../utils/task-helpers'
import {useFeatureFlag} from '@github-ui/react-core/use-feature-flag'
import {TaskActions} from './TaskActions'
import {ArchiveDialogProvider} from '../contexts/ArchiveDialogContext'
import {TaskLeadingVisual} from './TaskLeadingVisual'
import {useIntentDetection} from '../hooks/useIntentDetection'

const PAGE_SIZE = 5

export function TasksListWrapper({
  viewAllLink,
  showTitle,
  trailingAction,
  onTaskClick,
}: {
  viewAllLink?: React.ReactNode
  showTitle?: boolean
  trailingAction?: React.ReactNode
  onTaskClick?: () => void
}) {
  return (
    <ConsecutiveCAPI401sProvider>
      <ArchiveDialogProvider>
        <TasksList
          viewAllLink={viewAllLink}
          showTitle={showTitle}
          trailingAction={trailingAction}
          onTaskClick={onTaskClick}
        />
      </ArchiveDialogProvider>
    </ConsecutiveCAPI401sProvider>
  )
}

function TasksList({
  viewAllLink,
  showTitle,
  trailingAction,
  onTaskClick,
}: {
  viewAllLink?: React.ReactNode
  showTitle?: boolean
  trailingAction?: React.ReactNode
  onTaskClick?: () => void
}) {
  const location = useLocation()
  const {tasks, isLoading} = useTasks({
    taskFilter: 'open',
    pageSize: PAGE_SIZE,
    // We need to include the counts here in case this mounts before the AgentsList since they share
    // the same query key and we want to ensure the counts are available for the AgentsList to display
    includeCounts: true,
  })
  useSSOChangeDetection()

  const visibleTasks = tasks.slice(0, PAGE_SIZE)
  const isEmpty = visibleTasks.length === 0
  const linkToSessionsInRepo = useFeatureFlag('copilot_mission_control_link_to_sessions_in_repo')
  const linkToSessionsInHyperspace = useFeatureFlag('copilot_mission_control_link_to_hyperspace')
  const reloadDocument = shouldLinkToRepoTaskView(linkToSessionsInRepo, linkToSessionsInHyperspace)
  const {isUsingIntentDetection} = useIntentDetection()

  return (
    <>
      <SidebarSection
        title={showTitle ? 'Agent sessions' : undefined}
        isEmpty={isEmpty}
        isLoading={isLoading}
        trailingAction={trailingAction}
      >
        {visibleTasks.map(task => {
          const href = isUsingIntentDetection
            ? `/copilot/t/${task.nwo}/${task.task_id}`
            : generateTaskPathForRepo({
                globalId: task.resource_global_id ?? '',
                repositoryNwo: task.nwo,
                pullRequestNumber: task.pull?.number ?? 0,
                sessionId: task.latest_session_id,
                linkToSessionsInRepo: reloadDocument,
                taskId: task.id,
              })
          const isSelected = location.pathname === href

          const nwo = task.nwo
          const [owner, repo] = nwo ? nwo.split('/') : [undefined, undefined]
          return (
            <TaskListEntry
              key={task.clientGeneratedId ?? task.id ?? task.resource_id}
              task={task}
              href={href}
              isSelected={isSelected}
              reloadDocument={reloadDocument}
              secondaryText={nwo ?? 'Initializing...'}
              onTaskClick={onTaskClick}
              repoOwner={owner}
              repoName={repo}
            />
          )
        })}
      </SidebarSection>
      {!isEmpty && viewAllLink}
    </>
  )
}

export interface TaskListEntryProps {
  task: UITask
  href: string
  isSelected: boolean
  secondaryText: string | React.ReactNode
  reloadDocument: boolean
  onTaskClick?: () => void
  repoOwner?: string
  repoName?: string
  currentUserIsOwner?: boolean
}

export function TaskListEntry({
  task,
  href,
  isSelected,
  secondaryText,
  reloadDocument,
  onTaskClick,
  repoOwner,
  repoName,
  currentUserIsOwner,
}: TaskListEntryProps) {
  const anchorRef = useRef<HTMLButtonElement>(null)

  const sessionState = task.latest_session_state
  const prState = task.pull?.state
  const archivedAt = task.archived_at
  const prInMergeQueue = task.pull?.inMergeQueue
  const isOptimistic = !!task.isOptimistic
  const isArchived = !!archivedAt

  const trailingAction = (
    <ActionMenu anchorRef={anchorRef}>
      <ActionMenu.Anchor>
        <IconButton
          icon={KebabHorizontalIcon}
          aria-label="Manage session"
          variant="invisible"
          onClick={() =>
            sendEvent('dotcom_chat.activate', {
              target: 'TASK_CONTEXT_MENU',
              mode: 'immersive',
            })
          }
        />
      </ActionMenu.Anchor>
      <ActionMenu.Overlay>
        <TaskActions
          state={task.latest_session_state}
          pull={task.pull}
          taskId={task.id}
          repoOwner={repoOwner}
          repoName={repoName}
          currentUserIsOwner={currentUserIsOwner}
          archivedAt={task.archived_at}
          eventType={task.event_type}
          eventIdentifiers={task.event_identifiers}
        />
      </ActionMenu.Overlay>
    </ActionMenu>
  )

  // Memoize the leading visual component to prevent animation restarts when the list updates.
  // Creating a new function component on every render causes React to unmount/remount,
  // which resets animation state (e.g., spinning icons).
  const leadingVisual = useCallback(
    () => (
      <TaskLeadingVisual
        isOptimistic={isOptimistic}
        prState={prState}
        prInMergeQueue={prInMergeQueue}
        sessionState={sessionState}
        isArchived={isArchived}
      />
    ),
    [isOptimistic, prState, prInMergeQueue, sessionState, isArchived],
  )

  return (
    <SidebarListItem
      href={href}
      text={getTaskTitle(task, task.pull?.title)}
      leadingVisual={leadingVisual}
      isSelected={isSelected}
      trailingAction={trailingAction}
      secondaryText={secondaryText}
      reloadDocument={reloadDocument}
      onClick={() => {
        onTaskClick?.()
        sendEvent('agent_sessions.task_view', {
          target: 'VIEW_TASK_FROM_MISSION_CONTROL',
          task_id: task.resource_global_id,
        })
      }}
    />
  )
}

export function isOpenTask(task: UITask): boolean {
  return !task.pull || (task.pull.state !== 'merged' && task.pull.state !== 'closed')
}

export function isOptimisticTask(task: UITask): task is OptimisticTask {
  return !!task.isOptimistic
}

import {CommentDiscussionIcon, CopyIcon, GitPullRequestIcon, ArchiveIcon} from '@primer/octicons-react'
import {ActionList} from '@primer/react'
import {SessionState} from '../types/session'
import type {Pull} from '../types/pull'
import {copyText} from '@github-ui/copy-to-clipboard'
import {useCallback} from 'react'
import {sendEvent} from '@github-ui/hydro-analytics'
import {extractSpecTaskThreadIdFromEventIdentifiers} from '../utils/extract-spec-task-thread-id'
import {COPILOT_CHAT_SPEC_TASK_EVENT_TYPE} from '../utils/constants'
import {isFeatureEnabled} from '@github-ui/feature-flags'
import {useArchiveDialog} from '../contexts/ArchiveDialogContext'
import {generateTaskPathForRepo} from '../utils/generate-task-path'

interface TaskActionsProps {
  state?: SessionState
  taskId?: string
  pull?: Pull
  repoOwner?: string
  repoName?: string
  currentUserIsOwner?: boolean
  archivedAt?: string | null
  eventType?: string | null
  eventIdentifiers?: string[] | null
  hideCopy?: boolean
}

export function TaskActions({
  state,
  taskId,
  pull,
  repoOwner,
  repoName,
  currentUserIsOwner,
  archivedAt,
  eventType,
  eventIdentifiers,
  hideCopy = false,
}: TaskActionsProps) {
  const sessionCompleted =
    state &&
    [SessionState.Completed, SessionState.Failed, SessionState.Cancelled].map(s => s.toLowerCase()).includes(state)
  const isTaskPlanLinksEnabled = isFeatureEnabled('copilot_immersive_task_hyperlinking')
  const {openArchiveDialog} = useArchiveDialog()

  const handleCopyLink = useCallback(
    async (event: React.SyntheticEvent) => {
      try {
        const path = generateTaskPathForRepo({
          repositoryNwo: `${repoOwner}/${repoName}`,
          pullRequestNumber: pull?.number,
          linkToSessionsInRepo: true,
          taskId,
        })
        const fullUrl = `${window.location.origin}${path}`
        await copyText(fullUrl)
        sendEvent('agent_sessions.task_actions', {
          target: 'COPY_TASK_LINK',
          task_id: taskId ?? pull?.global_relay_id,
        })
      } catch {
        // prevent menu from closing on error
        event.preventDefault()
        event.stopPropagation()
      }
    },
    [repoOwner, repoName, taskId, pull],
  )

  const handleViewPullRequest = () => {
    sendEvent('dotcom_chat.activate', {
      target: 'TASK_ACTION_VIEW_PR',
      mode: 'immersive',
    })
    if (pull?.url) {
      window.location.href = pull.url
    }
  }

  const handleGoToConversation = () => {
    sendEvent('dotcom_chat.activate', {
      target: 'TASK_ACTION_GO_TO_CONVERSATION',
      mode: 'immersive',
    })
    const threadId = extractSpecTaskThreadIdFromEventIdentifiers(eventIdentifiers)
    if (threadId) {
      window.location.href = `/copilot/c/${threadId}`
    }
  }

  const hasConversationAction = eventType === COPILOT_CHAT_SPEC_TASK_EVENT_TYPE && isTaskPlanLinksEnabled

  return (
    <ActionList>
      {!hideCopy && repoOwner && repoName && (
        <ActionList.Item onSelect={handleCopyLink}>
          <ActionList.LeadingVisual>
            <CopyIcon />
          </ActionList.LeadingVisual>
          Copy link
        </ActionList.Item>
      )}
      {pull && (
        <ActionList.Item onSelect={handleViewPullRequest}>
          <ActionList.LeadingVisual>
            <GitPullRequestIcon />
          </ActionList.LeadingVisual>
          View pull request
        </ActionList.Item>
      )}
      {hasConversationAction && (
        <ActionList.Item onSelect={handleGoToConversation}>
          <ActionList.LeadingVisual>
            <CommentDiscussionIcon />
          </ActionList.LeadingVisual>
          Go to parent conversation
        </ActionList.Item>
      )}
      {sessionCompleted && !archivedAt && taskId && repoOwner && repoName && currentUserIsOwner && (
        <ActionList.Item
          onSelect={async () => {
            openArchiveDialog(taskId, repoOwner, repoName)
          }}
        >
          <ActionList.LeadingVisual>
            <ArchiveIcon />
          </ActionList.LeadingVisual>
          Archive session
        </ActionList.Item>
      )}
      {/* TODO: Re-enable once we can stop session by task ID */}
      {/* {sessionStoppable && currentUserCanPush && (
        <ActionList.Item
          onSelect={() => {
            stopSession()
          }}
        >
          <ActionList.LeadingVisual>
            <SquareCircleIcon />
          </ActionList.LeadingVisual>
          Stop running session
        </ActionList.Item>
      )} */}
    </ActionList>
  )
}

import type {
  APITaskArtifact,
  BranchArtifact,
  BranchArtifactData,
  GitHubArtifactData,
  GitHubResourceArtifact,
} from '../types/api-task'

/**
 * Type guard to check if an artifact is a branch artifact.
 */
function isBranchArtifact(artifact: APITaskArtifact): artifact is BranchArtifact {
  return artifact.type === 'branch' && artifact.provider === 'github'
}

/**
 * Type guard to check if an artifact is a GitHub resource artifact.
 */
function isGitHubResourceArtifact(artifact: APITaskArtifact): artifact is GitHubResourceArtifact {
  return artifact.type === 'github_resource' && artifact.provider === 'github'
}

export const getBranchArtifactData = (artifacts?: APITaskArtifact[]): BranchArtifactData | undefined => {
  const branchArtifact = artifacts?.find(isBranchArtifact)
  return branchArtifact?.data
}

export const getGitHubArtifactData = (artifacts?: APITaskArtifact[]): GitHubArtifactData | undefined => {
  const ghArtifact = artifacts?.find(isGitHubResourceArtifact)
  return ghArtifact?.data
}

