interface TaskChatSuspendedWrapperPayload extends AgentTaskAppPayload {
  repository?: Repository
}

// Wrapper for showing the repo-agents style page, but under Copilot Immersive
export function TaskChatSuspendedWrapper() {
  const [streamingChatResponse, setStreamingChatResponse] = useState<string | null>(null)
  const [isStreamingChat, setIsStreamingChat] = useState<boolean>(false)
  const {data: payload} = useOrFetchOrCreateTaskPayload(setStreamingChatResponse, setIsStreamingChat)

  const {taskCreationRequest} = useIntentDetectionContext()
  const [createOwner, createRepo] = taskCreationRequest?.nwo?.split('/') || []

  const {taskID} = useParams<{taskID?: string}>()
  const navigate = useNavigate()

  const ref = useNavigableRef<HTMLTextAreaElement>()

  const isContentPreviewOpen = useContentPreviewOpen()
  const {openPreviewPane, closePreviewPane} = useContentPreview()

  const {currentUser, repository, sessionOwners} = (payload || {}) as TaskChatSuspendedWrapperPayload
  if (payload && !repository) {
    throw new Error('No repository found in payload')
  }

  // Once we're received the real payload after creation, reset the URL
  useEffect(() => {
    if (payload && taskID === 'new') {
      navigate(`/copilot/t/${repository?.ownerLogin}/${repository?.name}/${payload.taskId}`, {replace: true})
    }
  }, [taskID, payload, repository?.ownerLogin, repository?.name, navigate])

  const originalPayload = useAppPayload<AgentTaskAppPayload>()

  const currentUserIsSessionOwner = sessionOwners && !!sessionOwners.some(owner => owner.id === currentUser?.id)

  const setContentPreviewPaneOpen = useCallback(
    (open: boolean) => {
      if (open) {
        openPreviewPane()
      } else {
        closePreviewPane()
      }
    },
    [openPreviewPane, closePreviewPane],
  )

  return (
    <ConsecutiveCAPI401sProvider>
      <ArchiveDialogProvider>
        <PacerLayout
          mainColumn="left"
          data-hpc
          secondaryColumnState={[isContentPreviewOpen, setContentPreviewPaneOpen]}
          slimLineTopTabs={copilotFeatureFlags.copilotWorkbenchSlimLineTopTabs}
        >
          <PacerLayout.Sidebar>
            <CopilotNavigationWithContext />
          </PacerLayout.Sidebar>
          <PacerLayout.ColumnLeft>
            {(!payload || !repository) && !taskCreationRequest && (
              <div className={styles.suspenseSpinner}>
                <Spinner size="medium" />
              </div>
            )}
            {!payload && taskCreationRequest && (
              <CurrentUserProvider currentUser={originalPayload?.currentUser} currentUserIsSessionOwner>
                <TaskChatDuringCreation
                  content={taskCreationRequest.problemStatement}
                  currentUser={originalPayload?.currentUser}
                  owner={createOwner}
                  repo={createRepo}
                />
              </CurrentUserProvider>
            )}
            {payload && repository && (
              <CurrentRepositoryProvider repository={repository}>
                <CurrentUserProvider
                  currentUser={payload.currentUser}
                  currentUserIsSessionOwner={currentUserIsSessionOwner}
                >
                  <TaskChat
                    forceV2Input
                    repoOwner={repository.ownerLogin}
                    repoName={repository.name}
                    showHeader
                    streamingChatResponse={streamingChatResponse}
                    setStreamingChatResponse={setStreamingChatResponse}
                    isStreamingChat={isStreamingChat}
                    setIsStreamingChat={setIsStreamingChat}
                    {...payload}
                  />
                </CurrentUserProvider>
              </CurrentRepositoryProvider>
            )}
          </PacerLayout.ColumnLeft>
          <PacerLayout.ColumnRight>
            <ContentPreview returnFocusRef={ref} />
          </PacerLayout.ColumnRight>
        </PacerLayout>
      </ArchiveDialogProvider>
    </ConsecutiveCAPI401sProvider>
  )
}

// This component is the placeholder while task creation is actually happening
// on the backend. Its intent is to mimic what the real page will look like when
// we start getting the real data back.
function TaskChatDuringCreation({
  currentUser,
  content,
  owner,
  repo,
}: {
  currentUser: PublicUser | undefined
  content: string
  owner?: string
  repo?: string
}) {
  // This is hokey but provide just enough to get the components to play along
  const fakeSession = {
    event_content: content,
    event_type: 'chat',
    state: 'in_progress',
  } as SessionType

  return (
    <div className={styles.root}>
      <div className={styles.container}>
        <div className={styles.stickableContainer}>
          <div className={styles.content}>
            <div className={styles.taskChatDuringCreationContainer}>
              <TaskChatHeader
                sessions={[fakeSession]}
                sessionOwners={[]}
                pull={undefined}
                task={undefined}
                repoOwner={owner}
                repoName={repo}
              />
              <div className={styles.initialMessages}>
                <UserInitialMessage
                  currentUser={currentUser}
                  sessionOwner={currentUser}
                  threadId={undefined}
                  session={fakeSession}
                  message={''}
                  agentId={null}
                />
              </div>
              <Stack direction="horizontal" padding="normal" align="center" justify="start" gap="condensed">
                <AgentAvatar animationType={CopilotAnimationType.Thinking} loopAnimation />
                <WithShimmerEffect className="color-fg-muted">Planning response...</WithShimmerEffect>
              </Stack>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

export function TaskChatSuspended() {
  const {data: payload, isLoading} = useOrFetchTaskViewPayload()

  if (isLoading) {
    return (
      <div className={styles.suspenseSpinner}>
        <Spinner size="medium" />
      </div>
    )
  }

  return payload && <TaskChat {...payload} />
}

export function CenteredSpinner() {
  return (
    <div className={styles.blankSlateContainer} style={{alignItems: 'center'}}>
      <Spinner />
    </div>
  )
}

