interface TaskChatProps extends AgentTaskAppPayload {
  showHeader?: boolean
  isRepoAgentsView?: boolean
  forceV2Input?: boolean
  streamingChatResponse?: string | null
  setStreamingChatResponse?: (response: string | null) => void
  repoOwner?: string
  repoName?: string
  taskId?: string
  branchAliveChannel?: string
  task?: HydratedAPITask
  isStreamingChat?: boolean
  setIsStreamingChat?: (isStreamingChat: boolean) => void
}

export function TaskChat({
  showHeader = false,
  isRepoAgentsView = false,
  forceV2Input = false,
  streamingChatResponse = null,
  setStreamingChatResponse = undefined,
  isStreamingChat = false,
  setIsStreamingChat = undefined,
  repoOwner,
  repoName,
  taskId,
  branchAliveChannel,
  task,
  ...payload
}: TaskChatProps) {
  const {
    agentMentions,
    pull,
    sessions,
    logsPollingInterval = 3000,
    sessionsPollingInterval = 3000,
    sessionOwners: initialSessionOwners,
    currentUserCanPush,
  } = payload

  const effectiveTaskId = taskId ?? pull?.global_relay_id
  const repoNwo = repoOwner && repoName ? `${repoOwner}/${repoName}` : undefined

  // Compute effective nwo: prefer repoNwo (repo-agents view) over pull's nwo
  const effectiveNwo = repoNwo ?? pull?.repository_nwo

  const [searchParams] = useSearchParams()
  const urlSessionId = searchParams.get('session_id')
  const {currentUser, currentUserIsSessionOwner} = useCurrentUser()
  const [highlightedSessionId, setHighlightedSessionId] = useState<string | null>(
    currentUserIsSessionOwner && urlSessionId ? urlSessionId : null,
  )
  // Prevents multiple calls to removeSessionIdFromUrl for the same urlSessionId (e.g., from multiple event handlers firing).
  const sessionIdClearedRef = useRef(false)

  const scrollContainerRef = useRef<HTMLDivElement>(null)
  const sentinelRef = useRef<HTMLDivElement>(null)
  const chatInputRef = useRef<ChatInputRef>(null)
  const textAreaRef = useRef<HTMLTextAreaElement>(null)

  const {pendingChat, setPendingChat, isUsingIntentDetection} = useIntentDetection()
  const clearPendingChat = () => {
    setPendingChat(null)
  }
  const {data: taskData} = useTask({
    owner: repoOwner,
    repo: repoName,
    taskId,
    initialTask: task,
  })

  const {
    data: sessionsData,
    isError: sessionsIsError,
    timedOut: sessionsTimedOut,
  } = useSessions({
    pullId: pull?.id,
    taskId,
    initialData: sessions,
    sessionsPollingInterval,
    clearPendingChat,
  })

  const {data: sessionOwners} = useSessionOwners({
    sessions: sessionsData,
    initialData: initialSessionOwners,
  })

  const mostRecentSession = sessionsData?.[sessionsData.length - 1]

  // Fetch mentions for the current sessions
  const {data: mentions, isFetching: isFetchingMentions} = useAgentMentions({
    pull,
    sessions: sessionsData,
    initialData: agentMentions ?? [],
    agentId: mostRecentSession?.agent_id,
  })

  // Manage pending sessions and mentions
  const {allSessions, allMentions, addPendingSession, clearPendingSession} = usePendingSession({
    pullId: pull?.id,
    taskId: effectiveTaskId,
    sessions: sessionsData,
    mentions,
    currentUser,
  })

  // With the intent detection POC, we have both a pending session and pending chat to maybe clear
  // Whenever we clear one, we should clear the other
  const clearPending = () => {
    clearPendingSession()
    clearPendingChat()
  }

  // For 'readonly' sessions like Copilot code review
  const everySessionReadonly = sessionsData?.every(s => isReadonlyAgent(s)) ?? false

  // Sort sessions by creation time
  const sortedSessions = allSessions.sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime())

  // Alive notifications are a bit laggy behind the initial render with a new session
  // This tries to suppress our pending chat messages as soon as possible
  const alreadyShowingPendingChat = sortedSessions[sortedSessions.length - 1]?.event_content === pendingChat

  const {
    data: inactiveLogs,
    isLoading: inactiveLogsIsLoading,
    isFetching: inactiveLogsIsFetching,
  } = useInactiveLogs({
    sessions: sortedSessions,
    pullId: pull?.id,
    repoOwner,
    repoName,
    taskId,
  })

  // Extract thread ID from the copilot-chat-spec-task session's event identifiers (feature flagged)
  const isTaskHyperlinkingEnabled = isFeatureEnabled('copilot_immersive_task_hyperlinking')
  const threadId = isTaskHyperlinkingEnabled
    ? (() => {
        const specTaskSession = allSessions.find(session => session.event_type === COPILOT_CHAT_SPEC_TASK_EVENT_TYPE)
        return extractSpecTaskThreadIdFromEventIdentifiers(specTaskSession?.event_identifiers)
      })()
    : undefined

  // Function to get the mention for a specific session
  const getMentionForSession = (session: SessionType): AgentMention | undefined => {
    if (!allMentions || !session.event_identifiers) {
      return undefined
    }

    // There should only be one mention
    return allMentions.find(mention => session.event_identifiers?.includes(mention.id.toString()))
  }

  // Determine which session should be expanded by default
  const getDefaultOpenState = (sessionId: string, index: number, isPending: boolean) => {
    if (urlSessionId) {
      // If a specific session ID is provided in URL, expand that session
      return sessionId === urlSessionId
    }

    // We're expanding pending sessions by default
    if (isPending) {
      return true
    }

    // If there's an active session, that one takes precedence unless explicitly provided above
    if (sessionsData && sessionsData.some(session => isActiveSession(session))) {
      return sessionId === sessionsData.find(session => isActiveSession(session))?.id
    }

    // Otherwise, expand the most recent session (last in the sorted array)
    return index === sortedSessions.length - 1
  }

  const {scrollToBottom} = useScrollToBottom({
    containerRef: scrollContainerRef,
    behavior: 'smooth',
  })
  const {setIsAtBottom} = useStickToBottom({
    containerRef: scrollContainerRef,
    sentinelRef,
    offset: 4,
  })

  const removeSessionIdFromUrl = useCallback(() => {
    if (!urlSessionId) return
    if (typeof window === 'undefined') return
    if (sessionIdClearedRef.current) return

    sessionIdClearedRef.current = true
    const newParams = new URLSearchParams(searchParams)
    newParams.delete('session_id')
    const searchString = newParams.toString()
    const newUrl = `${window.location.pathname}${searchString ? `?${searchString}` : ''}${window.location.hash}`
    addUrlToHistoryStack(newUrl)
    queueMicrotask(() => setHighlightedSessionId(null))
  }, [searchParams, urlSessionId])

  // If the user clicks outside the highlighted session, remove the session_id from the URL (and un-highlight the session).
  const handleContainerClick = useCallback(
    (event: React.MouseEvent) => {
      if (!highlightedSessionId) return

      const target = event.target as HTMLElement
      const highlightedSession = scrollContainerRef.current?.querySelector(
        `[data-session-id="${highlightedSessionId}"]`,
      )

      if (highlightedSession && !highlightedSession.contains(target)) {
        removeSessionIdFromUrl()
      }
    },
    [highlightedSessionId, removeSessionIdFromUrl],
  )

  // If session_id changes in the URL, reset sessionIdClearedRef to allow possible removal of it from the URL.
  useEffect(() => {
    sessionIdClearedRef.current = false
  }, [urlSessionId])

  useEffect(() => {
    if (urlSessionId) {
      setIsAtBottom(false)
    }
  }, [urlSessionId, setIsAtBottom])

  // Handle diff events to populate chat input with file references
  useDiffEventHandler({
    chatInputRef,
    textAreaRef,
    isReadonly: everySessionReadonly,
    taskId: effectiveTaskId ?? '',
  })

  // Remove session_id from URL when a new session becomes active.
  useEffect(() => {
    if (!urlSessionId) return
    if (!sessionsData) return

    const activeSession = sessionsData.find(isActiveSession)
    const activeSessionId = activeSession?.id ?? null

    if (!activeSessionId) return
    if (activeSessionId === urlSessionId) return

    removeSessionIdFromUrl()
  }, [urlSessionId, sessionsData, removeSessionIdFromUrl])

  // Clear chat input when switching tasks/pulls
  useEffect(() => {
    if (chatInputRef.current) {
      chatInputRef.current.setText('')
    }

    if (urlSessionId) {
      setIsAtBottom(false)
      return
    }

    setIsAtBottom(true)
    scrollToBottom({behavior: 'instant'})
  }, [effectiveTaskId, setIsAtBottom, scrollToBottom, urlSessionId])

  return !sessionsData || !sessionOwners ? (
    <CenteredSpinner />
  ) : sessionsIsError && sessionsTimedOut ? (
    <CenteredBlankSlate
      title="Activity cannot be loaded"
      description="The activity on this task is temporarily unavailable due to a system error. Try reloading the page, or if the problem persists, contact support."
      statusLink="https://www.githubstatus.com/"
    />
  ) : !sessionsData.length ? (
    <CenteredBlankSlate
      title="This task is not viewable"
      description={`You can't view this task because you do not have any active sessions${
        pull ? ' for this pull request' : ''
      }.`}
      pullLink={pull?.url}
    />
  ) : (
    <div className={styles.root}>
      <div className={styles.container}>
        <div className={styles.stickableContainer}>
          <ChatScrollContainer
            containerRef={scrollContainerRef}
            disabled={false}
            className={styles.scrollContainer}
            onClick={handleContainerClick}
          >
            <div className={clsx(styles.content, isRepoAgentsView && styles.repoAgentsViewContent)}>
              {showHeader && (
                <TaskChatHeader
                  sessions={sortedSessions}
                  sessionOwners={sessionOwners}
                  pull={pull}
                  task={taskData}
                  repoOwner={repoOwner}
                  repoName={repoName}
                />
              )}
              {sortedSessions.map((session, index) => {
                const isFirstSession = index === 0
                const mention = getMentionForSession(session)
                const isPending = isPendingSession(session)
                const isReadonly = isReadonlyAgent(session)
                const sessionOwner = sessionOwners.find(owner => owner.id === session.user_id)

                return (
                  <div className="d-flex flex-column" key={session.id}>
                    {isFirstSession && ( // Render the initial timeline messages only for the first session
                      <div className={styles.initialMessages}>
                        <UserInitialMessage
                          currentUser={currentUser}
                          sessionOwner={sessionOwner}
                          threadId={threadId}
                          session={session}
                          message={isReadonly ? 'requested a review' : 'started a task'}
                          agentId={session.agent_id}
                        />
                        <CopilotInitialMessage
                          session={session}
                          message={isReadonly ? 'started a review' : 'started work'}
                        />
                      </div>
                    )}
                    {/* Subsequent sessions: show PR comment mention or problem statement */}
                    {!isFirstSession && !isReadonly && (mention || isFetchingMentions) && (
                      <UserMessage
                        key={mention?.id}
                        mention={mention}
                        isLoading={!mention && isFetchingMentions}
                        agentId={session.agent_id}
                      />
                    )}
                    {!isFirstSession && !isReadonly && !mention && !isFetchingMentions && (
                      <UserProblemStatementMessage session={session} sessionOwner={sessionOwner} />
                    )}
                    {/* Readonly sessions need different messaging */}
                    {!isFirstSession && isReadonly && (
                      <div className={styles.readonlyMessageContainer}>
                        <CopilotInitialMessage session={session} message="started a review" />
                      </div>
                    )}
                    <SessionContextProvider
                      session={session}
                      sessionOwner={sessionOwner}
                      logs={inactiveLogs?.[session.id]}
                      logsAreLoading={
                        inactiveLogsIsLoading || (inactiveLogsIsFetching && inactiveLogs?.[session.id] === undefined)
                      }
                    >
                      <Session
                        defaultOpen={getDefaultOpenState(session.id, index, isPending)}
                        scrollContainerRef={scrollContainerRef}
                        hideStopButton={isPending}
                        onOpenChange={() => setIsAtBottom(false)}
                        onToolExpand={() => setIsAtBottom(false)}
                        shouldHighlight={session.id === highlightedSessionId}
                        stickyHeaders={!isRepoAgentsView} // We don't want sticky headers in repo agents view
                        currentUserCanPush={currentUserCanPush}
                        pull={pull}
                        logsPollingInterval={logsPollingInterval}
                        currentUser={currentUser}
                        clearPendingChat={clearPendingChat}
                        pendingChat={pendingChat}
                        streamingChatResponse={streamingChatResponse}
                        isStreamingChat={isStreamingChat}
                        nwo={effectiveNwo}
                      />
                      {session.state === 'completed' &&
                        // At the moment, Copilot will never have a message on the first session so we don't want to show it in that case.
                        // However, if this is single session view, we won't know if it's the first session or not so we should show the message to be safe.
                        ((currentUserIsSessionOwner && !isFirstSession) || !currentUserIsSessionOwner) && (
                          <CopilotMessage logsPollingInterval={logsPollingInterval ?? 3000} />
                        )}
                    </SessionContextProvider>
                  </div>
                )
              })}
              {isUsingIntentDetection && !alreadyShowingPendingChat && pendingChat && (
                <>
                  <LogChatMessage logEntry={{id: '', threadID: '', content: pendingChat, role: 'user'}} />
                  <Stack direction="horizontal" padding="normal" align="center" justify="start" gap="condensed">
                    {!streamingChatResponse && (
                      <>
                        <AgentAvatar animationType={CopilotAnimationType.Thinking} loopAnimation />
                        <WithShimmerEffect className="color-fg-muted">Planning response...</WithShimmerEffect>
                      </>
                    )}
                    {streamingChatResponse && (
                      <LogChatMessage
                        logEntry={{id: '', threadID: '', content: streamingChatResponse, role: 'assistant'}}
                      />
                    )}
                  </Stack>
                </>
              )}
              {/* used for auto-scrolling */}
              <div ref={sentinelRef} aria-hidden style={{height: 1}} />
            </div>
          </ChatScrollContainer>
        </div>
        {!everySessionReadonly && (
          <div className={clsx(styles.chatInputContainer, isRepoAgentsView && styles.repoAgentsViewChatInput)}>
            {(isRepoAgentsView || forceV2Input) && repoNwo && taskData ? (
              <TaskChatInputV2
                taskAgentId={allSessions[0]?.agent_id}
                activeSession={allSessions?.find(isActiveSession) ?? null}
                onAddPendingSession={addPendingSession}
                onAddPendingChat={setPendingChat}
                onClearPendingSession={clearPending}
                payload={payload}
                scrollToBottom={scrollToBottom}
                repoNwo={repoNwo}
                task={taskData}
                branchAliveChannel={branchAliveChannel}
                setStreamingChatResponse={setStreamingChatResponse}
                setIsStreamingChat={setIsStreamingChat}
              />
            ) : (
              <TaskChatInput
                taskAgentId={allSessions[0]?.agent_id}
                activeSession={allSessions?.find(isActiveSession) ?? null}
                onAddPendingSession={addPendingSession}
                onClearPendingSession={clearPendingSession}
                payload={payload}
                scrollToBottom={scrollToBottom}
                chatInputRef={chatInputRef}
                inputRef={textAreaRef}
              />
            )}
          </div>
        )}
      </div>
    </div>
  )
}

import styles from './TaskChatHeader.module.css'
import {ActionMenu, IconButton, PageHeader, RelativeTime} from '@primer/react'
import type {Session} from '../../types/session'
import {KebabHorizontalIcon, CopilotIcon, CopyIcon} from '@primer/octicons-react'
import type {Pull} from '../../types/pull'
import pluralize from 'pluralize'
import type {PublicUser} from '../../types/public-user'
import {useCurrentUser} from '../../contexts/CurrentUserContext'
import {FeedbackButton} from './feedback/FeedbackButton'
import {GitHubAvatar} from '@github-ui/github-avatar'
import {useAgentModels} from '../../hooks/useAgentModels'
import {useAgentInfo} from '../../hooks/use-agent-info'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {copilotFeatureFlags} from '@github-ui/copilot-chat/utils/copilot-feature-flags'
import {trimModelName} from '../../utils/trim-model-name'
import type {HydratedAPITask} from '../../types/api-task'
import {TaskActions} from '../TaskActions'
import {getTaskTitle} from '../../utils/task-helpers'
import {useMemo} from 'react'
import {getLeadingVisualIconAttributes} from '../../utils/get-leading-visual-icon-attributes'
import {Icon} from '@github-ui/pacer/Icon'
import {isCopilotCodingAgent} from '../../utils/agent-helpers'
import {CopyToClipboardButton} from '@github-ui/copy-to-clipboard/Button'
import {generateTaskPathForRepo} from '../../utils/generate-task-path'

interface TaskChatHeaderProps {
  sessions: Session[]
  sessionOwners: PublicUser[]
  pull?: Pull
  task?: HydratedAPITask
  repoOwner?: string
  repoName?: string
}

export function TaskChatHeader({sessions, sessionOwners, pull, task, repoOwner, repoName}: TaskChatHeaderProps) {
  const mostRecentSession = sessions[sessions.length - 1]
  const firstSession = sessions[0]
  const taskCreatedAt = sessions.length > 0 ? firstSession?.created_at : null
  const premiumRequests = sessions.reduce((total, session) => total + (session.premium_requests || 0), 0)
  const taskOwnerLogin = sessionOwners.find(owner => owner.id === firstSession?.user_id)?.login ?? 'Unknown'
  const modelId = mostRecentSession?.model
  const {data: agentInfo} = useAgentInfo(mostRecentSession?.agent_id ?? null)
  const {models: agentModels} = useAgentModels()
  const availableModels = copilotFeatureFlags.codingAgentModelSelection ? agentModels : undefined
  const isCopilotAgent = isCopilotCodingAgent(agentInfo?.slug)
  const selectedModel =
    modelId && availableModels && isCopilotAgent
      ? availableModels.find(m => m.id === trimModelName(modelId))
      : undefined
  const {currentUser, optedInToFeedback} = useCurrentUser()
  const currentUserIsOwner = currentUser?.id === firstSession?.user_id
  const separator = ' · '

  const iconAttributes = useMemo(
    () =>
      getLeadingVisualIconAttributes(pull?.state, pull?.inMergeQueue, mostRecentSession?.state, !!task?.archived_at),
    [pull?.state, pull?.inMergeQueue, mostRecentSession?.state, task?.archived_at],
  )

  const taskUrl = useMemo(() => {
    if (!repoOwner || !repoName) return ''
    const path = generateTaskPathForRepo({
      repositoryNwo: `${repoOwner}/${repoName}`,
      pullRequestNumber: pull?.number,
      linkToSessionsInRepo: true,
      taskId: task?.id,
    })
    return `${window.location.origin}${path}`
  }, [repoOwner, repoName, pull?.number, task?.id])

  const getTaskAuthorLogin = () => {
    if (currentUserIsOwner) {
      return 'You'
    }

    return taskOwnerLogin
  }

  return (
    <PageHeader aria-label="Agent session header">
      <PageHeader.TitleArea className={styles.headerTitleArea}>
        <PageHeader.Title as="h1" className={styles.headerTitle}>
          {getTaskTitle(task, pull?.title)}
        </PageHeader.Title>
      </PageHeader.TitleArea>
      <PageHeader.Description>
        <div className={styles.headerDescriptionContent}>
          <div className={styles.headerStatus}>
            <Icon icon={iconAttributes.icon} color={iconAttributes.color} />
            <span className={styles.headerUser}>{getTaskAuthorLogin()}</span>
            <span>created the session</span>
            {taskCreatedAt && <RelativeTime date={new Date(taskCreatedAt)} tense="past" />}
            <span>{separator}</span>
            {selectedModel && (
              <span className={styles.modelDisplay}>
                {selectedModel.logoURL ? (
                  <GitHubAvatar
                    alt={`${selectedModel.vendor} logo`}
                    square
                    size={18}
                    src={selectedModel.logoURL}
                    className={styles.modelIcon}
                  />
                ) : (
                  <CopilotIcon className={styles.modelIcon} />
                )}
                <span>
                  {selectedModel.displayName}
                  {separator}
                </span>
              </span>
            )}
            <span>
              {sessions.length} {pluralize('session', sessions.length)}
            </span>
            {premiumRequests > 0 && (
              <span>
                {separator}
                {premiumRequests} {pluralize('premium request', premiumRequests)}
              </span>
            )}
          </div>
        </div>
      </PageHeader.Description>
      <PageHeader.Actions>
        {optedInToFeedback && <FeedbackButton sessionId={mostRecentSession?.id} />}
        {repoOwner && repoName && (
          <CopyToClipboardButton
            textToCopy={taskUrl}
            ariaLabel="Copy session link"
            icon={CopyIcon}
            tooltipProps={{direction: 's'}}
          />
        )}
        <ActionMenu>
          <ActionMenu.Anchor>
            <IconButton icon={KebabHorizontalIcon} variant="invisible" aria-label="More actions" />
          </ActionMenu.Anchor>
          <ActionMenu.Overlay align="end">
            <TaskActions
              state={mostRecentSession?.state}
              taskId={task?.id}
              repoOwner={repoOwner}
              repoName={repoName}
              currentUserIsOwner={currentUserIsOwner}
              archivedAt={task?.archived_at}
              eventType={firstSession?.event_type}
              eventIdentifiers={firstSession?.event_identifiers}
              pull={pull}
              hideCopy
            />
          </ActionMenu.Overlay>
        </ActionMenu>
      </PageHeader.Actions>
    </PageHeader>
  )
}

// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {ChatInput, type ChatInputRef} from '@github-ui/copilot-chat/components/ChatInput'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {ModeSupportName} from '@github-ui/copilot-chat/utils/copilot-chat-types'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {ChatInputValidationError} from '@github-ui/copilot-chat/utils/validation-error'
import {AgentIcon, LockIcon} from '@primer/octicons-react'
import {FormControl, Link} from '@primer/react'
import {useEffect, useState} from 'react'
import {useAgentMentions} from '../../hooks/useAgentMentions'
import {useAgentInfo} from '../../hooks/use-agent-info'
import {useTopLevelAgents} from '../../hooks/useTopLevelAgents'
import {type Session as SessionType, isPendingSession} from '../../types/session'
import styles from './TaskChatInput.module.css'
import type {AgentTaskAppPayload} from '../../types/agent-task-app-payload'
import {useCurrentUser} from '../../contexts/CurrentUserContext'
import {useCreateCommand} from '../../hooks/useCreateCommand'

interface TaskChatInputProps {
  taskAgentId?: number
  activeSession: SessionType | null
  onAddPendingSession: (text: string, options?: {agentId?: number; isPRComment?: boolean}) => void
  onClearPendingSession: () => void
  payload: AgentTaskAppPayload
  scrollToBottom: (options?: {behavior?: ScrollBehavior; offset?: number}) => void
  inputRef: React.RefObject<HTMLTextAreaElement | null>
  chatInputRef?: React.RefObject<ChatInputRef | null>
}

export function TaskChatInput({
  taskAgentId,
  activeSession,
  onAddPendingSession,
  onClearPendingSession,
  payload,
  scrollToBottom,
  inputRef,
  chatInputRef,
}: TaskChatInputProps) {
  const {pull, steeringEnabled, currentUserCanPush} = payload
  const [failedToSubmit, setFailedToSubmit] = useState(false)
  const {data: agentInfo, isLoading: isAgentInfoLoading} = useAgentInfo(taskAgentId)
  const {data: topLevelAgents, isLoading: isLoadingTopLevelAgents} = useTopLevelAgents(pull?.repository_nwo)
  const agentNotEnabled =
    taskAgentId &&
    !isLoadingTopLevelAgents &&
    topLevelAgents &&
    topLevelAgents.length > 0 &&
    !topLevelAgents.some(agent => Number(agent.id) === taskAgentId)
  const name = agentInfo?.display_name?.toLowerCase() || 'agent'
  const isAgentCopilot = isAgentInfoLoading || name === 'copilot'
  const steerable = !!activeSession && isAgentCopilot
  const startingSession = activeSession && isPendingSession(activeSession)
  const activeSessionOwner = payload.sessionOwners.find(owner => owner.id === activeSession?.user_id) || null
  const {currentUserIsSessionOwner} = useCurrentUser()

  // Reset error state when user starts typing, with a small delay to prevent swallowing the first character
  useEffect(() => {
    const inputElement = inputRef.current
    if (!inputElement) return

    let timeout: NodeJS.Timeout
    const handleInput = () => {
      if (failedToSubmit) {
        // Use a small timeout to ensure the character is processed first
        timeout = setTimeout(() => {
          setFailedToSubmit(false)
        }, 0)
      }
    }

    inputElement.addEventListener('input', handleInput)
    return () => {
      inputElement.removeEventListener('input', handleInput)
      if (timeout) clearTimeout(timeout)
    }
  }, [failedToSubmit, inputRef])

  // Use the agent mentions hook for handling comment creation
  const {createMention} = useAgentMentions({
    pull,
    agentId: taskAgentId,
  })

  const {createCommand} = useCreateCommand({
    onError: () => {
      setFailedToSubmit(true)
    },
  })

  const handleActiveSessionCommandSubmit = (message: string) => {
    if (!steerable || !activeSession) return

    createCommand({
      sessionId: activeSession.id,
      content: message,
    })
  }

  const handleSubmit = async (text: string) => {
    // Always reset the error state when attempting a new submission
    setFailedToSubmit(false)

    try {
      if (steerable) {
        handleActiveSessionCommandSubmit(text)
        scrollToBottom()
        return
      }

      // Show the pending mention/session immediately
      onAddPendingSession(text, {agentId: taskAgentId})

      // Attempt to create the mention
      await createMention(text, {
        onError: () => {
          // Clear the pending session
          onClearPendingSession()
        },
      })

      scrollToBottom()
    } catch {
      setFailedToSubmit(true)

      // Throwing this error will repopulate the text in the input
      throw new ChatInputValidationError(text)
    }
  }

  const getBlockedText = (): string | React.ReactNode | undefined => {
    if (agentNotEnabled) {
      return 'Your organization has removed access for this agent. Contact your administrator for more information.'
    }

    // 3P agent is running, can't steer
    if (activeSession && !isAgentCopilot) {
      return `Wait for the session to be complete to steer ${agentInfo?.display_name || 'agent'} sessions`
    }

    // User doesn't have access to steering features
    if (!steeringEnabled) {
      return 'Steering Copilot requires an active subscription'
    }

    // User doesn't have write access
    if (!currentUserCanPush) {
      return 'You do not have write permission on the repository'
    }

    // Pull is closed/merged, no steering allowed
    if (pull?.state && pull.state !== 'open') {
      return `Pull request is ${pull.state}`
    }

    // Single session view
    if (!currentUserIsSessionOwner) {
      if (steerable) {
        return `Only ${activeSessionOwner?.login ?? 'the session owner'} can steer this session`
      }

      if (pull?.url) {
        return (
          <>
            Only the author of the task can ask for changes.{' '}
            <Link href={pull.url} inline>
              View pull request
            </Link>{' '}
            to request more changes.
          </>
        )
      }

      return 'Only the author of the task can ask for changes.'
    }

    return undefined
  }

  const agentName = agentInfo?.display_name || 'Agent'

  const placeHolderText = startingSession
    ? `Waiting for ${agentName} to start session...`
    : steerable
      ? `Steer active session while ${agentName} is working`
      : 'What would you like to change?'

  // Consider the input blocked if there's any blocked text to show
  const blockedText = getBlockedText()
  const isBlocked = !!blockedText

  // Determine if help text should be shown
  const shouldShowHelpText = !isBlocked && !steerable && !startingSession
  const helpTextId = 'task-chat-input-help'

  // Set aria-describedby attribute for accessibility
  useEffect(() => {
    const inputElement = inputRef.current
    if (!inputElement) return

    if (shouldShowHelpText) {
      inputElement.setAttribute('aria-describedby', helpTextId)
    } else {
      inputElement.removeAttribute('aria-describedby')
    }
  }, [helpTextId, shouldShowHelpText, inputRef])

  return (
    <FormControl className={styles.formControl}>
      <FormControl.Label visuallyHidden>New prompt</FormControl.Label>
      <div className={styles.inputWrapper}>
        <ChatInput
          onSubmit={handleSubmit}
          textAreaRef={inputRef}
          chatInputRef={chatInputRef}
          modes={[
            {
              name: ModeSupportName.Task,
              supportsAttachments: false,
              supportsAutocompletion: false,
              supportsSpaces: false,
              supportsReferenceAttachments: false,
              icon: AgentIcon,
              placeholder: placeHolderText,
              submitLabel: startingSession ? 'Wait for the session to be started' : undefined,
            },
          ]}
          size="large"
          isStreaming={false}
          disabled={isBlocked}
          submitDisabled={startingSession || isBlocked}
          extraToolbar={
            shouldShowHelpText ? (
              <p id={helpTextId} className={styles.extraToolbarText}>
                Submitting will post a pull request comment
              </p>
            ) : null
          }
        />
        {isBlocked && (
          <div className={styles.blockedOverlay}>
            <div className={styles.blockedContent}>
              <LockIcon size={16} className={styles.blockedIcon} />
              <p className="mb-0">{blockedText}</p>
            </div>
          </div>
        )}
      </div>
      {failedToSubmit && !isBlocked && (
        <FormControl.Validation variant="error" className="pt-2">
          Failed to submit latest message
        </FormControl.Validation>
      )}
    </FormControl>
  )
}

import {ActionList, Banner} from '@primer/react'
import type {Pull} from '../../types/pull'
import styles from './TaskChatInputHeader.module.css'
import {PullRequestButton} from './PullRequestButton'
import {DiffStats} from '@github-ui/diffs/DiffParts'
import {ChevronRightIcon, FileAddedIcon, FileDiffIcon, FileRemovedIcon} from '@primer/octicons-react'
import {useState} from 'react'
import {useBranchAliveUpdates} from '../../hooks/use-branch-alive-updates'
import {useTaskDiffs} from '../../hooks/use-task-diffs'
import {OpenInMenuV2} from './OpenInMenuV2'
import {CopyToClipboardButton} from '@github-ui/copy-to-clipboard/Button'
import {useCurrentUser} from '../../contexts/CurrentUserContext'

interface TaskChatInputHeaderProps {
  pull?: Pull
  repoNwo: string
  taskId: string
  baseRef: string
  headRef: string
  branchAliveChannel?: string
  isSessionInProgress?: boolean
}

export function TaskChatInputHeader({
  pull,
  repoNwo,
  taskId,
  baseRef,
  headRef,
  branchAliveChannel,
  isSessionInProgress = false,
}: TaskChatInputHeaderProps) {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false)
  const [prError, setPrError] = useState<string | null>(null)
  const {data: diffs, refetch: refetchDiffs} = useTaskDiffs(repoNwo, taskId, baseRef, headRef)
  const hasDiffs = !!diffs && diffs.files.length > 0
  const {currentUserIsSessionOwner} = useCurrentUser()
  useBranchAliveUpdates(branchAliveChannel, () => {
    refetchDiffs()
  })

  if (!hasDiffs) return null

  const getPathComponents = (filePath: string) => {
    const lastSlashIndex = filePath.lastIndexOf('/')
    if (lastSlashIndex === -1) {
      return ['', filePath]
    }
    return [filePath.slice(0, lastSlashIndex), filePath.slice(lastSlashIndex + 1)]
  }

  const getFileStatusIcon = (status: string) => {
    switch (status) {
      case 'A':
        return <FileAddedIcon className={styles.fileAdded} />
      case 'D':
      case 'R':
        return <FileRemovedIcon className={styles.fileDeleted} />
      default:
        return <FileDiffIcon className={styles.fileChanged} />
    }
  }

  const handleClick = () => {
    setIsDrawerOpen(!isDrawerOpen)
  }

  return (
    <div className={styles.root}>
      <div className={styles.container}>
        <div className={styles.info}>
          <button
            onClick={handleClick}
            type="button"
            className={styles.toggleButton}
            aria-expanded={isDrawerOpen}
            aria-controls="task-diff-drawer"
            aria-label={isDrawerOpen ? 'Collapse changed files' : 'View changed files'}
          >
            <ChevronRightIcon className={styles.icon} data-expanded={isDrawerOpen} />
          </button>
          <div className={styles.branch}>
            <span className={styles.branchText}>{headRef}</span>
            <CopyToClipboardButton
              textToCopy={headRef}
              variant="invisible"
              ariaLabel={`Copy branch name ${headRef}`}
              className={styles.copyIcon}
            />
          </div>
          {hasDiffs && (
            <DiffStats
              linesAdded={diffs.additions}
              linesDeleted={diffs.deletions}
              linesChanged={diffs.changes}
              hideSquares
            />
          )}
        </div>
        <div className={styles.actions}>
          <OpenInMenuV2
            className={styles.openInMenu}
            branchName={headRef}
            pull={pull}
            taskId={taskId}
            isCurrentUserTaskCreator={currentUserIsSessionOwner}
          />
          <PullRequestButton
            pullUrl={pull?.url}
            taskId={taskId}
            repoNwo={repoNwo}
            baseRef={baseRef}
            headRef={headRef}
            disabled={isSessionInProgress}
            onError={setPrError}
          />
        </div>
        {prError && (
          <Banner
            className={styles.prErrorBanner}
            variant="critical"
            title="Error creating pull request"
            hideTitle
            description={prError}
            onDismiss={() => setPrError(null)}
          />
        )}
      </div>
      <div id="task-diff-drawer" className={styles.diffContainer} data-expanded={isDrawerOpen}>
        <ActionList className={styles.diffList}>
          {diffs.files.map(diff => {
            const [directory, fileName] = getPathComponents(diff.path)
            const fileUrl = pull
              ? `/${repoNwo}/pull/${pull.number}/files#diff-${diff.path_digest}`
              : `/${repoNwo}/blob/${headRef}/${diff.path}`
            return (
              <ActionList.Item
                key={diff.path}
                className={styles.diffItem}
                onSelect={() => {
                  window.open(fileUrl)
                }}
              >
                <ActionList.LeadingVisual>{getFileStatusIcon(diff.status)}</ActionList.LeadingVisual>
                <div className={styles.fileInfo}>
                  <span className={styles.fileName}>{fileName}</span>
                  <span className={styles.fileDirectory}>{directory}</span>
                </div>
                <ActionList.TrailingVisual>
                  <DiffStats
                    linesAdded={diff.additions}
                    linesDeleted={diff.deletions}
                    linesChanged={diff.changes}
                    hideSquares
                  />
                </ActionList.TrailingVisual>
              </ActionList.Item>
            )
          })}
        </ActionList>
      </div>
    </div>
  )
}

// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {ChatInputValidationError} from '@github-ui/copilot-chat/utils/validation-error'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {ImageAttachButton} from '@github-ui/copilot-chat/components/ImageAttachButton'
import {LockIcon, PaperAirplaneIcon} from '@primer/octicons-react'
import {FormControl, IconButton, Link, Stack} from '@primer/react'
import {useEffect, useRef, useState} from 'react'
import {useAgentInfo} from '../../hooks/use-agent-info'
import {useTopLevelAgents} from '../../hooks/useTopLevelAgents'
import {useCreateAPISession} from '../../hooks/use-create-api-session'
import {type Session as SessionType, isPendingSession, isActiveSession} from '../../types/session'
import styles from './TaskChatInputV2.module.css'
import type {AgentTaskAppPayload} from '../../types/agent-task-app-payload'
import {useCurrentUser} from '../../contexts/CurrentUserContext'
import {useCreateCommand} from '../../hooks/useCreateCommand'
import {TaskChatInputHeader} from './TaskChatInputHeader'
import {clsx} from 'clsx'
import {useIntentDetection} from '../../hooks/useIntentDetection'
import {getBranchArtifactData} from '../../utils/task-artifact-helpers'
import type {APITask} from '../../types/api-task'
import {isFeatureEnabled} from '@github-ui/feature-flags'
import {useMarkdownImageHandling} from '../../hooks/use-markdown-image-handling'
import {ModeSelector} from '../new-task-chat-input/ModeSelector'
import {useIntentDetectionContext} from '../../contexts/IntentDetectionContext'

interface TaskChatInputProps {
  taskAgentId?: number
  activeSession: SessionType | null
  onAddPendingSession: (text: string, options?: {agentId?: number; isPRComment?: boolean}) => void
  onAddPendingChat: (text: string) => void
  onClearPendingSession: () => void
  payload: AgentTaskAppPayload
  scrollToBottom: (options?: {offset?: number}) => void
  repoNwo: string
  task: APITask
  branchAliveChannel?: string
  setStreamingChatResponse?: (response: string | null) => void
  setIsStreamingChat?: (isStreamingChat: boolean) => void
}

export function TaskChatInputV2({
  taskAgentId,
  activeSession,
  onAddPendingSession,
  onAddPendingChat,
  onClearPendingSession,
  payload,
  scrollToBottom,
  repoNwo,
  task,
  branchAliveChannel,
  setStreamingChatResponse,
  setIsStreamingChat,
}: TaskChatInputProps) {
  const {pull, steeringEnabled, currentUserCanPush} = payload
  const [failedToSubmit, setFailedToSubmit] = useState(false)
  const {data: agentInfo} = useAgentInfo(taskAgentId)
  const {data: topLevelAgents, isLoading: isLoadingTopLevelAgents} = useTopLevelAgents(repoNwo)
  const agentNotEnabled =
    taskAgentId &&
    !isLoadingTopLevelAgents &&
    topLevelAgents &&
    topLevelAgents.length > 0 &&
    !topLevelAgents.some(agent => Number(agent.id) === taskAgentId)
  const name = agentInfo?.display_name?.toLowerCase() || 'agent'
  const isAgentCopilot = name === 'copilot'
  const {isUsingIntentDetection} = useIntentDetection(activeSession)
  const {mode, setMode} = useIntentDetectionContext()
  const steerable = !!activeSession && isAgentCopilot && !isUsingIntentDetection
  const startingSession = activeSession && isPendingSession(activeSession)
  const activeSessionOwner = payload.sessionOwners.find(owner => owner.id === activeSession?.user_id) || null
  const {currentUserIsSessionOwner} = useCurrentUser()
  const [text, setText] = useState('')
  const [isFocused, setIsFocused] = useState(false)
  const inputAreaRef = useRef<HTMLTextAreaElement | null>(null)
  const containerRef = useRef<HTMLDivElement | null>(null)

  // Image upload handling
  const isImageUploadEnabled = isFeatureEnabled('copilot_agent_image_upload')
  const repositoryId = task.repo_id?.toString()
  const {
    onPaste,
    dropTargetProps,
    isDraggedOver,
    isUploading: isImageUploading,
  } = useMarkdownImageHandling({
    textAreaRef: inputAreaRef,
    repositoryId,
    enabled: isImageUploadEnabled,
  })

  const branchArtifact = getBranchArtifactData(task?.artifacts)
  const baseRef = branchArtifact?.base_ref || pull?.base_ref_name
  const headRef = branchArtifact?.head_ref || pull?.head_ref_name

  // Reset error state when user starts typing, with a small delay to prevent swallowing the first character
  useEffect(() => {
    const inputElement = inputAreaRef.current
    if (!inputElement) return

    let timeout: NodeJS.Timeout
    const handleInput = () => {
      if (failedToSubmit) {
        // Use a small timeout to ensure the character is processed first
        timeout = setTimeout(() => {
          setFailedToSubmit(false)
        }, 0)
      }
    }

    inputElement.addEventListener('input', handleInput)
    return () => {
      inputElement.removeEventListener('input', handleInput)
      if (timeout) clearTimeout(timeout)
    }
  }, [failedToSubmit, inputAreaRef])

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    if (!inputAreaRef?.current) return

    setText((e.target as HTMLTextAreaElement).value)
  }

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSubmit()
    }
  }

  const {createSession} = useCreateAPISession({
    onError: () => {
      setFailedToSubmit(true)
      onClearPendingSession()
    },
    setStreamingChatResponse: isUsingIntentDetection ? setStreamingChatResponse : undefined,
    setIsStreamingChat: isUsingIntentDetection ? setIsStreamingChat : undefined,
  })

  const {createCommand} = useCreateCommand({
    onError: () => {
      setFailedToSubmit(true)
    },
  })

  const getBlockedText = (): string | React.ReactNode | undefined => {
    if (agentNotEnabled) {
      return 'Your organization has removed access for this agent. Contact your administrator for more information.'
    }

    // 3P agent is running, can't steer
    if (activeSession && !isAgentCopilot) {
      return `Wait for the session to be complete to steer ${agentInfo?.display_name || 'agent'} sessions`
    }

    // User doesn't have access to steering features
    if (!steeringEnabled) {
      return 'Steering Copilot requires an active subscription'
    }

    if (task.archived_at) {
      return 'This session has been archived'
    }

    // User doesn't have write access
    if (!currentUserCanPush) {
      return 'You do not have write permission on the repository'
    }

    // Pull is closed/merged, no steering allowed
    if (pull?.state === 'merged') {
      return (
        <>
          This pull request was merged. To continue iterating,{' '}
          <Link href={`/${repoNwo}/agents`} inline>
            start a new session
          </Link>
          .
        </>
      )
    } else if (pull?.state === 'closed') {
      return 'This pull request was closed. To continue iterating, reopen the pull request.'
    }

    // Single session view
    if (!currentUserIsSessionOwner) {
      if (steerable) {
        return `Only ${activeSessionOwner?.login ?? 'the session owner'} can steer this session`
      }

      return (
        <>
          Only the author of the task can ask for changes.{' '}
          {pull && (
            <>
              <Link href={pull.url} inline>
                View pull request
              </Link>{' '}
              to request more changes.
            </>
          )}
        </>
      )
    }

    return undefined
  }

  // Consider the input blocked if there's any blocked text to show
  const blockedText = getBlockedText()
  const isBlocked = !!blockedText

  // Get the container height dynamically for scroll offset (includes header + input)
  const getContainerOffset = () => containerRef.current?.offsetHeight ?? 0

  const handleActiveSessionCommandSubmit = (message: string) => {
    if (!steerable || !activeSession) return

    createCommand({
      sessionId: activeSession.id,
      content: message,
    })

    setText('')
  }

  const handleSubmit = async () => {
    // Always reset the error state when attempting a new submission
    setFailedToSubmit(false)

    try {
      // Prevent submitting empty messages or when blocked/starting/uploading
      if (!text.trim() || isBlocked || startingSession || isImageUploading) {
        return
      }

      if (steerable) {
        handleActiveSessionCommandSubmit(text)
        scrollToBottom()
        return
      }

      // For intent detection POC, chat-based sessions just route
      // through create session for task so if it needs to spawn a new
      // agent session (terminating the chat) it can.
      if (!isUsingIntentDetection) {
        // Show the pending session immediately
        onAddPendingSession(text, {agentId: taskAgentId, isPRComment: false})
      } else {
        onAddPendingChat(text)
      }

      // Clear the input
      setText('')

      createSession({
        nwo: repoNwo,
        taskId: task.id,
        problemStatement: text,
        agentId: taskAgentId,
        eventType: 'agent_task_post_session_steering',
        intentDetectionMode: mode,
      })

      requestAnimationFrame(() => {
        scrollToBottom({offset: getContainerOffset()})
      })
    } catch {
      setFailedToSubmit(true)

      // Throwing this error will repopulate the text in the input
      throw new ChatInputValidationError(text)
    }
  }

  const agentName = agentInfo?.display_name || 'Agent'
  const placeHolderText = startingSession
    ? `Waiting for ${agentName} to start session...`
    : steerable
      ? `Steer active session while ${agentName} is working`
      : 'What would you like to change?'

  return (
    <div
      className={clsx(styles.container, isImageUploadEnabled && isDraggedOver && styles.isDraggedOver)}
      ref={containerRef}
      {...(isImageUploadEnabled ? dropTargetProps : {})}
    >
      {baseRef && headRef && (
        <TaskChatInputHeader
          pull={pull}
          repoNwo={repoNwo}
          taskId={task.id}
          baseRef={baseRef}
          headRef={headRef}
          branchAliveChannel={branchAliveChannel}
          isSessionInProgress={activeSession ? isActiveSession(activeSession) : false}
        />
      )}
      <form
        onSubmit={e => {
          e.preventDefault()
          handleSubmit()
        }}
        id="task-chat-input-form"
        data-testid="task-chat-input-form"
      >
        <FormControl>
          <FormControl.Label visuallyHidden>Send message</FormControl.Label>
          <div className={clsx(styles.inputWrapper, isImageUploadEnabled && styles.inputWrapperWithToolbar)}>
            {isBlocked ? (
              <div className={styles.blockedContainer}>
                <div className={styles.blockedContent}>
                  <LockIcon size={16} className={styles.blockedIcon} />
                  <p className={styles.blockedText}>{blockedText}</p>
                </div>
              </div>
            ) : isUsingIntentDetection ? (
              <>
                <Stack direction="vertical" className={styles.inputContainer}>
                  <textarea
                    className={clsx(styles.input, (isFocused || text) && styles.inputFocused)}
                    onSubmit={handleSubmit}
                    aria-label={placeHolderText}
                    value={text}
                    onChange={handleChange}
                    onKeyDown={handleKeyDown}
                    placeholder={placeHolderText}
                    disabled={isBlocked}
                    ref={inputAreaRef}
                    rows={isFocused || text ? 3 : 1}
                    onFocus={() => setIsFocused(true)}
                    onBlur={() => setIsFocused(false)}
                  />
                  <Stack direction="horizontal" className={styles.modeAndButtonContainer}>
                    <span className={styles.modeSelector}>
                      <ModeSelector selectedMode={mode} setMode={setMode} />
                    </span>
                    <IconButton
                      variant="invisible"
                      size="medium"
                      icon={PaperAirplaneIcon}
                      aria-label="Send now"
                      inactive={startingSession || isBlocked}
                      aria-disabled={startingSession || isBlocked}
                      onClick={handleSubmit}
                      className={styles.sendButton}
                    />
                  </Stack>
                </Stack>
              </>
            ) : (
              <>
                <textarea
                  className={clsx(styles.input, (isFocused || text) && styles.inputFocused)}
                  onSubmit={handleSubmit}
                  aria-label={placeHolderText}
                  value={text}
                  onChange={handleChange}
                  onKeyDown={handleKeyDown}
                  onPaste={onPaste}
                  placeholder={placeHolderText}
                  disabled={isBlocked}
                  ref={inputAreaRef}
                  rows={isFocused || text ? 3 : 1}
                  onFocus={() => setIsFocused(true)}
                  onBlur={() => setIsFocused(false)}
                />
                {isImageUploadEnabled ? (
                  <div className={styles.inputToolbar}>
                    <ImageAttachButton textAreaRef={inputAreaRef} repositoryId={repositoryId} />
                    <IconButton
                      variant="invisible"
                      size="medium"
                      icon={PaperAirplaneIcon}
                      aria-label="Send now"
                      inactive={startingSession || isBlocked || isImageUploading}
                      aria-disabled={startingSession || isBlocked || isImageUploading}
                      onClick={handleSubmit}
                    />
                  </div>
                ) : (
                  <IconButton
                    variant="invisible"
                    size="medium"
                    icon={PaperAirplaneIcon}
                    aria-label="Send now"
                    inactive={startingSession || isBlocked}
                    aria-disabled={startingSession || isBlocked}
                    onClick={handleSubmit}
                    className={styles.sendButton}
                  />
                )}
              </>
            )}
          </div>
          {failedToSubmit && !isBlocked && (
            <FormControl.Validation variant="error" className="pt-2">
              Failed to submit latest message
            </FormControl.Validation>
          )}
        </FormControl>
      </form>
    </div>
  )
}

import {Banner} from '@primer/react'
import {clsx} from 'clsx'
import type {CreateAPITaskParams, CreateAPITaskMutationParams} from '../types/api-task'
import {truncateLines} from '../utils/truncate-lines'
import styles from './TaskCreationFailedBanner.module.css'

/**
 * Represents a failed task creation attempt using the new task API that can be retried.
 * Extends CreateAPITaskMutationParams so that all the original task creation parameters
 * (including clientGeneratedId) are preserved from the onError callback.
 */
export type FailedAPITaskCreationAttempt = CreateAPITaskMutationParams & {
  errorMessage: string
  timestamp: string
}

export type UIFailedTaskCreationAttempt = Pick<
  FailedAPITaskCreationAttempt,
  'problemStatement' | 'errorMessage' | 'timestamp'
>

/**
 * Extracts task creation parameters from a failed API task attempt,
 * removing the error-specific fields (errorMessage, timestamp) and clientGeneratedId
 * so that a new ID will be generated for the retry.
 */
export function getAPITaskParamsFromAttempt(attempt: FailedAPITaskCreationAttempt): CreateAPITaskParams {
  const {errorMessage, timestamp, clientGeneratedId, ...taskParams} = attempt
  return taskParams
}

interface TaskCreationFailedBannerProps {
  problemStatement?: string
  errorMessage?: string
  handleRetry: () => void
  handleDismiss: () => void
}

export function TaskCreationFailedBanner({
  problemStatement,
  errorMessage,
  handleRetry,
  handleDismiss,
}: TaskCreationFailedBannerProps) {
  const truncatedProblemStatement = truncateLines(problemStatement ?? '', 20, 1)
  const baseMessage = `Unable to start task for '${truncatedProblemStatement}'`

  const description = errorMessage ? `${baseMessage}: ${errorMessage}` : `${baseMessage}. Please try again.`

  return (
    <Banner
      variant="critical"
      title="Task Creation Failed"
      hideTitle
      description={description}
      secondaryAction={<Banner.SecondaryAction onClick={handleDismiss}>Dismiss</Banner.SecondaryAction>}
      primaryAction={<Banner.PrimaryAction onClick={handleRetry}>Retry</Banner.PrimaryAction>}
    />
  )
}

interface TaskCreationFailedBannerListProps {
  attempts: UIFailedTaskCreationAttempt[]
  onRetry: (index: number) => void
  onDismiss: (index: number) => void
  className?: string
}

export function TaskCreationFailedBannerList({
  attempts,
  onRetry,
  onDismiss,
  className,
}: TaskCreationFailedBannerListProps) {
  if (attempts.length === 0) {
    return null
  }

  return (
    <div className={clsx(styles.bannerList, className)}>
      {attempts.map((attempt, index) => (
        <TaskCreationFailedBanner
          key={`${attempt.problemStatement}-${attempt.timestamp}`}
          problemStatement={attempt.problemStatement}
          errorMessage={attempt.errorMessage}
          handleRetry={() => onRetry(index)}
          handleDismiss={() => onDismiss(index)}
        />
      ))}
    </div>
  )
}

import {Stack} from '@primer/react'
import {PreviewPaneButton} from './PreviewPaneButton'
import {OpenInMenu} from './OpenInMenu'
import {PullRequestButton} from './PullRequestButton'
import {FeedbackButton} from './feedback/FeedbackButton'
import {TaskHeaderMobileMenu} from './TaskHeaderMobileMenu'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {useChatStateValue} from '@github-ui/copilot-chat/CopilotChatContext'
import type {Pull} from '../../types/pull'
import type {Session} from '../../types/session'
import {PageDataContextProvider} from '@github-ui/pull-request-page-data-tooling/page-data-context'
import {TaskBreadcrumbs} from './Breadcrumbs'
import {clsx} from 'clsx'
import styles from './TaskHeader.module.css'

export function TaskHeader({
  pull,
  session,
  isContentPreviewOpen,
  openPreviewPane,
}: {
  pull: Pull | undefined
  session: Session | undefined
  isContentPreviewOpen: boolean
  openPreviewPane: () => void
}) {
  const basePageDataUrl = `/${pull?.repository_nwo}/pull/${pull?.number}`
  const optedInToUserFeedback = useChatStateValue('optedInToUserFeedback')

  return (
    <PageDataContextProvider basePageDataUrl={basePageDataUrl}>
      <div className={clsx(styles.container)}>
        <div className={styles.leftControls}>
          <TaskBreadcrumbs pull={pull} />
        </div>
        <div className={styles.rightControls}>
          <Stack direction="horizontal" align="center" gap="condensed">
            {pull && (
              <>
                <div className={styles.desktopButtons}>
                  {optedInToUserFeedback && <FeedbackButton sessionId={session?.id} />}
                  <OpenInMenu pull={pull} session={session} />
                  <PullRequestButton pullUrl={pull.url} taskId={pull.global_relay_id} repoNwo={pull.repository_nwo} />
                </div>
                <div className={styles.mobileMenu}>
                  <TaskHeaderMobileMenu pull={pull} />
                </div>
              </>
            )}
            <PreviewPaneButton isContentPreviewOpen={isContentPreviewOpen} openPreviewPane={openPreviewPane} />
          </Stack>
        </div>
      </div>
    </PageDataContextProvider>
  )
}

import {ActionMenu, ActionList, IconButton} from '@primer/react'
import {
  VscodeIcon,
  KebabHorizontalIcon,
  GitPullRequestIcon,
  TerminalIcon,
  DesktopDownloadIcon,
  CommentIcon,
} from '@primer/octicons-react'
import {isEnterprise} from '@github-ui/runtime-environment'
import {isFeatureEnabled} from '@github-ui/feature-flags'
import {buildCodespacesPath} from '@github-ui/code-dropdown-button/build-codespaces-path'
import {
  createHandleOpenInVSCode,
  createHandleOpenInVSCodeInsiders,
  createHandleOpenInGitHubDesktop,
  createHandleOpenInCodespaces,
} from './OpenInMenu'
import {useFeedbackDialog} from './feedback/FeedbackButton'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {useChatStateValue} from '@github-ui/copilot-chat/CopilotChatContext'
import type {Pull} from '../../types/pull'
import {useCallback, useRef} from 'react'

export interface TaskHeaderMobileMenuProps {
  pull: Pull
}

export function TaskHeaderMobileMenu({pull}: TaskHeaderMobileMenuProps) {
  const openAgentSessionInVSCodeInsiders = isFeatureEnabled('open_agent_session_in_vscode_insiders')
  const openAgentSessionInVSCodeStable = isFeatureEnabled('open_agent_session_in_vscode_stable')
  const handleOpenInVSCode = createHandleOpenInVSCode(pull.repository_nwo, pull.global_relay_id, pull.head_ref_name)
  const handleOpenInVSCodeInsiders = createHandleOpenInVSCodeInsiders(
    pull.repository_nwo,
    pull.global_relay_id,
    pull.head_ref_name,
  )
  const handleOpenInGitHubDesktop = createHandleOpenInGitHubDesktop(pull.repository_nwo, pull.number)
  const handleOpenInCodespaces = createHandleOpenInCodespaces(pull.repository_id, pull.head_ref_name)

  const {openFeedback, FeedbackDialog} = useFeedbackDialog()
  const optedInToUserFeedback = useChatStateValue('optedInToUserFeedback')
  const anchorRef = useRef<HTMLButtonElement>(null)
  const onFeedbackSelect = useCallback(() => openFeedback(), [openFeedback])

  const handleViewPullRequest = () => {
    window.open(pull.url, '_blank')
  }

  const isEnterpriseMode = isEnterprise()
  const codespacesPath = buildCodespacesPath(pull.repository_id, pull.head_ref_name)
  const shouldShowCodespaces = !!codespacesPath && !isEnterpriseMode

  return (
    <>
      <ActionMenu anchorRef={anchorRef}>
        <ActionMenu.Anchor>
          <IconButton icon={KebabHorizontalIcon} variant="invisible" aria-label="More options" size="small" />
        </ActionMenu.Anchor>
        <ActionMenu.Overlay align="end">
          <ActionList>
            <ActionList.Item onSelect={handleViewPullRequest}>
              <ActionList.LeadingVisual>
                <GitPullRequestIcon />
              </ActionList.LeadingVisual>
              View pull request
            </ActionList.Item>
            {optedInToUserFeedback && (
              <ActionList.Item onSelect={onFeedbackSelect}>
                <ActionList.LeadingVisual>
                  <CommentIcon />
                </ActionList.LeadingVisual>
                Give feedback
              </ActionList.Item>
            )}
            <ActionList.Divider />
            <ActionList.Group>
              <ActionList.GroupHeading>Open in</ActionList.GroupHeading>
              {openAgentSessionInVSCodeStable && (
                <ActionList.Item onSelect={handleOpenInVSCode}>
                  <ActionList.LeadingVisual>
                    <VscodeIcon />
                  </ActionList.LeadingVisual>
                  Open in VS Code
                </ActionList.Item>
              )}
              {openAgentSessionInVSCodeInsiders && (
                <ActionList.Item onSelect={handleOpenInVSCodeInsiders}>
                  <ActionList.LeadingVisual>
                    <VscodeIcon />
                  </ActionList.LeadingVisual>
                  Open in VS Code Insiders
                </ActionList.Item>
              )}
              <ActionList.Item onSelect={handleOpenInGitHubDesktop}>
                <ActionList.LeadingVisual>
                  <DesktopDownloadIcon />
                </ActionList.LeadingVisual>
                Checkout with GitHub Desktop
              </ActionList.Item>
              {shouldShowCodespaces && (
                <ActionList.Item onSelect={handleOpenInCodespaces}>
                  <ActionList.LeadingVisual>
                    <TerminalIcon />
                  </ActionList.LeadingVisual>
                  Open in Codespaces
                </ActionList.Item>
              )}
            </ActionList.Group>
          </ActionList>
        </ActionMenu.Overlay>
      </ActionMenu>
      <FeedbackDialog returnFocusRef={anchorRef} />
    </>
  )
}

import type {OptimisticTask, UITask, UnhydratedTask} from '../types/task'
import type {APITask} from '../types/api-task'
import {getGitHubArtifactData} from './task-artifact-helpers'
import {isFeatureEnabled} from '@github-ui/feature-flags'

/**
 * Gets the display title for a task.
 *
 * @param task - The task to get the title for
 * @param pullTitle - Optional pull request title to use as fallback
 * @returns The display title for the task
 */
export function getTaskTitle(task?: UITask | APITask, pullTitle?: string): string {
  const preferTaskName = isFeatureEnabled('copilot_mission_control_use_task_name')

  // Prefer task name or pull title based on feature flag
  if (preferTaskName) {
    if (task?.name) {
      return task.name
    }

    if (pullTitle) {
      return pullTitle
    }
  } else {
    if (pullTitle) {
      return pullTitle
    }

    if (task?.name) {
      return task.name
    }
  }

  return 'New task'
}

/**
 * Transforms a single API Task to UnhydratedTask format.
 * Used by the mutation to insert the real task into the cache after creation.
 * Returns null if the task has no GitHub artifact (can't be displayed).
 */
export function transformAPITaskToUnhydrated(apiTask: APITask): UnhydratedTask | null {
  const githubArtifact = getGitHubArtifactData(apiTask.artifacts)
  const agentId = apiTask.agent_collaborators?.[0]?.agent_id?.toString()

  return {
    id: apiTask.id,
    resource_type: githubArtifact?.type,
    resource_id: githubArtifact?.id,
    resource_global_id: githubArtifact?.global_id,
    session_count: apiTask.session_count,
    latest_session_state: apiTask.status,
    latest_session_updated_at: apiTask.last_updated_at,
    agentId,
    name: apiTask.name,
    task_id: apiTask.id,
    archived_at: apiTask.archived_at,
    creator_id: apiTask.creator_id,
    repo_id: apiTask.repo_id,
  } as UnhydratedTask
}

/**
 * Transforms an array of API Tasks to UnhydratedTask format.
 * Filters out tasks that have no GitHub artifact.
 */
export function transformAPITasksToUnhydrated(apiTasks: APITask[]): UnhydratedTask[] {
  return apiTasks.map(transformAPITaskToUnhydrated).filter((task): task is UnhydratedTask => task !== null)
}

/**
 * Merges server-fetched tasks with existing optimistic tasks from the cache.
 *
 * This function handles the transition from optimistic tasks (created client-side before
 * server confirmation) to server tasks:
 * 1. Identifies server tasks that match optimistic tasks via event_identifiers
 * 2. Preserves display metadata from optimistic tasks on their server counterparts
 * 3. Filters out optimistic tasks that now have server equivalents
 * 4. Returns a sorted array of all tasks (newest first)
 *
 * @param serverTasks - Tasks fetched from the server
 * @param optimisticTasks - Optimistic tasks from the local cache
 * @returns Merged and sorted array of tasks
 */
export function mergeServerTasksWithOptimistic(
  serverTasks: UnhydratedTask[],
  optimisticTasks: OptimisticTask[],
): Array<UnhydratedTask | OptimisticTask> {
  // Transform server tasks, marking those that replace optimistic tasks
  const serverTasksWithOptimistic = serverTasks.map(serverTask => {
    const matchingOptimisticTask = optimisticTasks.find(optimisticTask =>
      serverTask.event_identifiers?.includes(optimisticTask.clientGeneratedId),
    )

    return {
      ...serverTask,
      isOptimistic: !!matchingOptimisticTask,
      // Preserve original creation parameters from optimistic task for display
      ...(matchingOptimisticTask && {
        problemStatement: matchingOptimisticTask.problemStatement,
        nwo: matchingOptimisticTask.nwo,
        baseRef: matchingOptimisticTask.baseRef,
        clientGeneratedId: matchingOptimisticTask.clientGeneratedId,
        // Preserve name from optimistic task if server hasn't provided one yet
        name: serverTask.name ?? matchingOptimisticTask.name,
      }),
    }
  })

  // Filter out optimistic tasks that now have server equivalents
  const remainingOptimisticTasks = optimisticTasks.filter(
    optimisticTask =>
      !serverTasksWithOptimistic.some(serverTask =>
        serverTask.event_identifiers?.includes(optimisticTask.clientGeneratedId),
      ),
  )

  // Combine and sort all tasks
  return sortTasksByDate([...serverTasksWithOptimistic, ...remainingOptimisticTasks])
}

/**
 * Task with a latest_session_updated_at timestamp for sorting.
 */
interface TaskWithTimestamp {
  latest_session_updated_at: string
}

/**
 * Sorts tasks by latest_session_updated_at (newest first).
 * This is a generic utility that works with any task type that has a timestamp.
 *
 * @param tasks - Array of tasks to sort
 * @returns Sorted array (does not mutate the original)
 */
export function sortTasksByDate<T extends TaskWithTimestamp>(tasks: T[]): T[] {
  return [...tasks].sort(
    (a, b) => new Date(b.latest_session_updated_at).getTime() - new Date(a.latest_session_updated_at).getTime(),
  )
}

import {DotFillIcon} from '@primer/octicons-react'
import {memo} from 'react'
import type {SessionState} from '../types/session'
import {getLeadingVisualIconAttributes} from '../utils/get-leading-visual-icon-attributes'

export interface TaskLeadingVisualProps {
  isOptimistic?: boolean
  prState?: string
  prInMergeQueue?: boolean
  sessionState: SessionState
  isArchived?: boolean
  className?: string
}

/**
 * Displays a leading visual icon for a task/session based on its current state.
 *
 * This component is memoized to prevent animated icons (like CheckSpinner) from resetting
 * when other tasks in a list update.
 */
export const TaskLeadingVisual = memo(function TaskLeadingVisual({
  isOptimistic = false,
  prState,
  prInMergeQueue,
  sessionState,
  isArchived,
  className,
}: TaskLeadingVisualProps) {
  const iconAttributes = isOptimistic
    ? {icon: DotFillIcon, color: 'var(--fgColor-attention)', 'data-testid': 'icon-dot'}
    : getLeadingVisualIconAttributes(prState, prInMergeQueue, sessionState, isArchived)

  const Icon = iconAttributes.icon

  return (
    <div
      className={className}
      style={{
        color: iconAttributes.color,
        // Add margin-top for spinning icon to align properly
        marginTop: sessionState === 'in_progress' && !isOptimistic ? '3px' : undefined,
      }}
      data-testid={iconAttributes['data-testid']}
    >
      <Icon />
    </div>
  )
})

import {ListBlock} from '@github-ui/pacer/ListBlock'
import type {HydratedTask, UITask} from '../../types/task'
import styles from './TaskList.module.css'
import {OpenTaskList} from './OpenTaskList'
import {ClosedTaskList} from './ClosedTaskList'

export function TaskList({
  tasks,
  isError,
  activeTab,
  setActiveTab,
}: {
  tasks: UITask[]
  isError: boolean
  activeTab: 'open' | 'closed'
  setActiveTab: (tab: 'open' | 'closed') => void
}) {
  const openTasks = tasks.filter(task => !task.pull || (task.pull.state !== 'merged' && task.pull.state !== 'closed'))
  const closedTasks = tasks.filter((task): task is HydratedTask =>
    Boolean(task.pull && (task.pull.state === 'merged' || task.pull.state === 'closed')),
  )

  return (
    <ListBlock>
      <ListBlock.Header>
        <div role="tablist" aria-label="Filter pull requests" className={styles.filterButtons}>
          <button
            onClick={() => setActiveTab('open')}
            role="tab"
            aria-selected={activeTab === 'open'}
            aria-controls="tasks-list"
            id="open-tab"
            className={styles.button}
          >
            Open <span className={styles.counter}>{openTasks.length}</span>
          </button>
          <button
            onClick={() => setActiveTab('closed')}
            role="tab"
            aria-selected={activeTab === 'closed'}
            aria-controls="tasks-list"
            id="closed-tab"
            className={styles.button}
          >
            Closed <span className={styles.counter}>{closedTasks.length}</span>
          </button>
        </div>
      </ListBlock.Header>
      {activeTab === 'open' ? (
        <OpenTaskList tasks={openTasks} isError={isError} />
      ) : (
        <ClosedTaskList tasks={closedTasks} isError={isError} />
      )}
    </ListBlock>
  )
}

import {RelativeTime} from '@primer/react'
import {DotFillIcon} from '@primer/octicons-react'
import styles from './TaskListItem.module.css'
import {useMemo, useState, useEffect} from 'react'
import {getReadableSessionState, type SessionState} from '../../types/session'
import {ListBlock} from '@github-ui/pacer/ListBlock'
import {Icon} from '@github-ui/pacer/Icon'
import {PullRequestDiffSummaryText} from './PullRequestDiffSummaryText'
import type {PullRequestDiffSummary} from '../../types/pull-request-diff-summary'
import {getLeadingVisualIconAttributes} from '../../utils/get-leading-visual-icon-attributes'
import {generateTaskPathForRepo, shouldLinkToRepoTaskView} from '../../utils/generate-task-path'
// eslint-disable-next-line @github-ui/github-monorepo/restrict-relay-imports
import {WithShimmerEffect} from '@github-ui/copilot-chat/components/WithShimmerEffect'
import {useFeatureFlag} from '@github-ui/react-core/use-feature-flag'
import {useSearchParams} from '@github-ui/use-navigate'

export interface TaskListItemProps {
  state?: SessionState
  startedAt?: string
  revisionCount: number
  prState: string
  prInMergeQueue: boolean
  prUrl: string
  prTitle: string
  prNwo: string
  prNumber: number
  prGlobalId: string
  prDiffSummary?: PullRequestDiffSummary | null
}

export interface OptimisticTaskListItemProps {
  title: string
  repositoryNwo: string
}

interface IconAttributes {
  icon: React.ComponentType | (() => React.ReactElement)
  color: string
  'data-testid': string
}

const FadeText = ({text}: {text: string}) => {
  const [displayedText, setDisplayedText] = useState<string | null>(null)
  const [animationState, setAnimationState] = useState('none') // 'entering' | 'exiting' | 'none'

  useEffect(() => {
    if (displayedText === null) {
      // First render - set text immediately without animation
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setDisplayedText(text)
      return
    }

    if (text !== displayedText) {
      setAnimationState('exiting')
      const timeout = setTimeout(() => {
        setDisplayedText(text)
        setAnimationState('entering')
      }, 400)
      return () => clearTimeout(timeout)
    }
  }, [text, displayedText])

  return (
    <span
      className={`${styles.fadeText} ${
        animationState === 'entering' ? styles.entering : animationState === 'exiting' ? styles.exiting : null
      }`}
    >
      {displayedText}
    </span>
  )
}

export function TaskListItem({
  state,
  revisionCount,
  startedAt,
  prState,
  prTitle,
  prNwo,
  prNumber,
  prGlobalId,
  prInMergeQueue,
  prDiffSummary,
}: TaskListItemProps) {
  const [searchParams] = useSearchParams()
  // State for managing icon transitions
  const [displayedIconAttributes, setDisplayedIconAttributes] = useState<IconAttributes | null>(null)
  const [isIconTransitioning, setIsIconTransitioning] = useState(false)

  // Calculate the current log text
  const currentLogText = useMemo(() => {
    return prState === 'merged'
      ? 'Merged'
      : prState === 'closed'
        ? 'Closed'
        : prInMergeQueue
          ? 'Queued to merge'
          : (state && getReadableSessionState(state)) || ''
  }, [prInMergeQueue, prState, state])

  const leadingVisualIconAttributes = useMemo(
    () => getLeadingVisualIconAttributes(prState, prInMergeQueue, state),
    [prState, prInMergeQueue, state],
  )
  // Handle icon transitions when the icon changes
  useEffect(() => {
    if (!displayedIconAttributes) {
      // Initial mount - no animation
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setDisplayedIconAttributes(leadingVisualIconAttributes)
      return
    }

    // Compare the current icon with displayed icon to detect changes
    const hasIconChanged = displayedIconAttributes.icon !== leadingVisualIconAttributes.icon

    if (hasIconChanged) {
      // Icon is changing - start transition
      setIsIconTransitioning(true)

      // Fade out old icon, then fade in new icon
      const fadeOutTimer = setTimeout(() => {
        setDisplayedIconAttributes(leadingVisualIconAttributes)
        setIsIconTransitioning(false)
      }, 300)

      return () => clearTimeout(fadeOutTimer)
    }
  }, [leadingVisualIconAttributes, displayedIconAttributes])

  const revisionTextWithTrailingSeparator =
    revisionCount > 0 ? `${revisionCount} revision${revisionCount > 1 ? 's' : ''} · ` : null

  const linkToSessionsInRepo = useFeatureFlag('copilot_mission_control_link_to_sessions_in_repo')
  const linkToSessionsInHyperspace = useFeatureFlag('copilot_mission_control_link_to_hyperspace')
  const isExternalLink = shouldLinkToRepoTaskView(linkToSessionsInRepo, linkToSessionsInHyperspace)
  const baseTaskUrl = generateTaskPathForRepo({
    globalId: prGlobalId,
    repositoryNwo: prNwo,
    pullRequestNumber: prNumber,
    linkToSessionsInRepo: isExternalLink,
  })

  // Preserve the author filter when navigating to a task
  const authorParam = searchParams.get('author')
  const taskUrl = baseTaskUrl && authorParam ? `${baseTaskUrl}?author=${encodeURIComponent(authorParam)}` : baseTaskUrl

  return (
    <ListBlock.Item href={taskUrl} isExternalLink={isExternalLink}>
      <ListBlock.Item.LeadingVisual>
        <Icon
          {...leadingVisualIconAttributes}
          className={`${styles.iconTransition} ${isIconTransitioning ? styles.fadeOut : ''}`}
        />
      </ListBlock.Item.LeadingVisual>
      <ListBlock.Item.Title>{prTitle}</ListBlock.Item.Title>
      {state && state !== 'in_progress' && prDiffSummary && (
        <ListBlock.Item.Actions>
          <PullRequestDiffSummaryText prDiffSummary={prDiffSummary} />
        </ListBlock.Item.Actions>
      )}
      <ListBlock.Item.Description>
        <span className={styles.description}>
          {prNwo}#{prNumber} · started <RelativeTime format="micro" datetime={startedAt} /> ago ·{' '}
          {revisionTextWithTrailingSeparator}
          <FadeText text={currentLogText} />
        </span>
      </ListBlock.Item.Description>
    </ListBlock.Item>
  )
}

export function LoadingTaskListItem() {
  return <ListBlock.Item.Skeleton />
}

// TODO: Put inside TaskListItem with a prop, so we can get transition functionality included
export function OptimisticTaskListItem({repositoryNwo}: OptimisticTaskListItemProps) {
  return (
    <ListBlock.Item aria-label={`Creating task in ${repositoryNwo}`}>
      <ListBlock.Item.LeadingVisual>
        <Icon icon={DotFillIcon} color={'var(--fgColor-attention)' as const} />
      </ListBlock.Item.LeadingVisual>
      <ListBlock.Item.Title>
        <WithShimmerEffect className="fgColor-muted">Creating task</WithShimmerEffect>
      </ListBlock.Item.Title>
      <ListBlock.Item.Description>
        <span className={styles.description}>{repositoryNwo}</span> · Initializing pull request…
      </ListBlock.Item.Description>
    </ListBlock.Item>
  )
}

