function TaskView() {
  const {data: {pull, sessions, sessionsPollingInterval, currentUser} = {}} = useOrFetchTaskViewPayload()

  const {data: currentSessions} = useSessions({
    pullId: pull?.id ?? 0,
    initialData: sessions,
    sessionsPollingInterval: sessionsPollingInterval ?? 0,
  })

  const isContentPreviewOpen = useContentPreviewOpen()
  const {openPreviewPane, closePreviewPane, openItem, closeItem, updateItem, allOpenItems} = useContentPreview()
  const [searchParams] = useSearchParams()
  const openItemsCount = allOpenItems?.length ?? 0
  const {isNarrowViewport} = useViewportBreakpoint()
  const isTaskViewable = currentSessions?.length ? true : false

  // Get session_id from query parameters - indicates user came from "View sessions" button
  const sessionId = searchParams.get('session_id')
  const hasSessionId = Boolean(sessionId)

  const mostRecentSession = currentSessions?.toSorted((a, b) => {
    return new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
  })[0]

  const sessionCount = currentSessions?.length ?? 0
  const premiumRequestCount = currentSessions?.reduce((total, session) => total + session.premium_requests, 0) || 0

  const currentUserIsSessionOwner = !!(currentUser && currentUser?.id === currentSessions?.[0]?.user_id)

  // Check if any session is currently running
  const hasSessionInProgress = currentSessions?.some(session => session.state === 'in_progress') ?? false
  // Check if sessions are read-only
  const everySessionReadonly = currentSessions?.every(session => isReadonlyAgent(session)) ?? false

  // Get chat manager and available models
  const manager = useChatManager()
  // Always call the hook, but only use the result when feature flag is enabled
  const {models: agentModels} = useAgentModels()
  const availableModels = copilotFeatureFlags.codingAgentModelSelection ? agentModels : undefined
  const ref = useNavigableRef<HTMLTextAreaElement>()
  // Get agent display name from the currently running session if there is one, otherwise use the most recent session
  const currentlyRunningSession = currentSessions?.find(session => session.state === 'in_progress')
  const sessionForAgent = currentlyRunningSession ?? currentSessions?.[0]
  const {data: agentInfo} = useAgentInfo(sessionForAgent?.agent_id ?? null)
  const agentDisplayName = agentInfo?.display_name
  const isCopilot = isCopilotCodingAgent(agentInfo?.slug)

  // Fetch PR data - use initial data from the app payload to avoid an extra fetch
  const {
    data: fetchedPull,
    refetchBody,
    refetchPullRequest,
  } = usePullRequest({
    pullRequestId: pull?.id || 0,
    includeBody: false,
    initialData: pull,
    enabled: !!pull?.id, // Only enabled if we have a pull ID
  })

  // Subscribe to pull request alive updates for git, body, and title changes
  usePullRequestAliveUpdates(fetchedPull?.aliveChannel, refetchPullRequest, refetchBody)

  // Track which items have been opened to avoid re-opening on updates
  const openedItemIds = useRef(new Set<string>())
  const prevPullId = useRef<number | undefined>(undefined)
  const prevBodyRevisionCount = useRef<number | undefined>(undefined)

  // Reset the opened items tracking when the preview context is cleared (e.g., after navigation)
  useEffect(() => {
    if (openItemsCount === 0) {
      openedItemIds.current.clear()
    }
  }, [openItemsCount])

  useEffect(() => {
    if (!fetchedPull) return

    if (fetchedPull.id !== undefined && prevPullId.current !== undefined && prevPullId.current !== fetchedPull.id) {
      openedItemIds.current.clear()
      prevBodyRevisionCount.current = undefined
    }
    prevPullId.current = fetchedPull?.id

    const filesChangedCount = fetchedPull.changed_files ?? 0
    const headSha = fetchedPull.head_sha

    // Determine visibility conditions
    const hasAnySessions = sessionCount > 0
    const shouldShowFiles = hasAnySessions && filesChangedCount > 0

    // Resolve the selected model from the model ID
    const modelId = mostRecentSession?.model
    const selectedModel =
      modelId && availableModels ? availableModels.find(m => m.id === trimModelName(modelId)) : undefined

    // Create tab items
    const overviewItem = {
      ...makeItemForPluginSupportedReference(
        {
          body: fetchedPull?.body ?? '',
          bodyHTML: fetchedPull?.body_html,
          title: fetchedPull.title,
          number: fetchedPull.number,
          type: 'pr-overview',
          repositoryNwo: fetchedPull.repository_nwo,
          baseRef: fetchedPull.base_ref_name,
          headRef: fetchedPull.head_ref_name,
          headSha,
          sessionState: mostRecentSession?.state,
          sessionUpdatedAt: mostRecentSession?.last_updated_at,
          sessionCount,
          premiumRequestCount,
          selectedModel,
          isSingleSessionView: !currentUserIsSessionOwner,
          commitAliveChannel: fetchedPull.commit_alive_channel,
          isCopilotCodingAgent: isCopilot,
        } as PullRequestOverviewReference,
        NullMessageId,
      ),
      disableCloseButton: true,
      icon: NoteIcon,
    }

    const filesItem =
      pull && shouldShowFiles
        ? {
            ...makeItemForPluginSupportedReference(
              {
                type: 'pr-files-changed',
                headSha,
                basePath: `/${fetchedPull.repository_nwo}/pull/${fetchedPull.number}`,
                isSessionRunning: hasSessionInProgress,
                isSessionReadonly: everySessionReadonly,
                agentDisplayName,
              } as PullRequestFilesChangedReference,
              NullMessageId,
            ),
            disableCloseButton: true,
            trailingComponent: <CounterLabel>{filesChangedCount}</CounterLabel>,
            icon: FileIcon,
          }
        : null

    updateItem(overviewItem)
    if (filesItem) updateItem(filesItem)

    for (const itemId of allOpenItems) {
      if (itemId.includes('pr-files-changed:') && !shouldShowFiles) {
        closeItem(itemId)
      }
    }

    // Check if items are already open (user has selected a tab)
    const isOverviewAlreadyOpen = allOpenItems.includes(overviewItem.id)
    const isFilesAlreadyOpen = filesItem && allOpenItems.includes(filesItem.id)

    // Only open items on first render (not already tracked)
    const shouldOpenOverview = !openedItemIds.current.has(overviewItem.id) && !isOverviewAlreadyOpen
    const shouldOpenFiles = filesItem && !openedItemIds.current.has(filesItem.id) && !isFilesAlreadyOpen

    if (shouldOpenOverview) {
      openItem(overviewItem.id, !hasSessionId)
      if (!isNarrowViewport) openPreviewPane()
    }

    if (shouldOpenFiles) {
      openItem(filesItem.id, hasSessionId)
      if (hasSessionId && !isNarrowViewport) openPreviewPane()
    }

    // Mark items as tracked even if they were already open
    openedItemIds.current.add(overviewItem.id)
    if (filesItem) openedItemIds.current.add(filesItem.id)
  }, [
    fetchedPull,
    updateItem,
    openItem,
    closeItem,
    openPreviewPane,
    closePreviewPane,
    hasSessionId,
    pull,
    openItemsCount,
    mostRecentSession?.state,
    mostRecentSession?.last_updated_at,
    mostRecentSession?.model,
    sessionCount,
    premiumRequestCount,
    allOpenItems,
    isNarrowViewport,
    currentUserIsSessionOwner,
    hasSessionInProgress,
    everySessionReadonly,
    availableModels,
    agentDisplayName,
    isCopilot,
  ])

  const setContentPreviewPaneOpen = useCallback(
    (open: boolean) => {
      if (open) {
        openPreviewPane()
      } else {
        closePreviewPane()
      }
    },
    [openPreviewPane, closePreviewPane],
  )

  useEffect(() => {
    // Set the title of the page
    // TODO: Add more descriptive Task metadata to page title based
    const taskTitle = fetchedPull?.title
    if (taskTitle) {
      setTitle(`${taskTitle} · Task · GitHub Copilot`)
    } else {
      setTitle('Task · GitHub Copilot')
    }
  }, [fetchedPull?.title])

  useEffect(() => {
    // clear out the thread on mount
    manager.selectThread(null, {includeThreads: false, clearTopic: true})
  }, [manager])

  // Hook to detect SSO changes and clear relevant caches
  useSSOChangeDetection()

  return (
    <CurrentUserProvider currentUser={currentUser} currentUserIsSessionOwner={currentUserIsSessionOwner}>
      <PullContextProvider pull={fetchedPull}>
        <PacerLayout
          mainColumn="left"
          data-hpc
          secondaryColumnState={[isContentPreviewOpen, setContentPreviewPaneOpen]}
          slimLineTopTabs={copilotFeatureFlags.copilotWorkbenchSlimLineTopTabs}
        >
          {isTaskViewable && (
            <PacerLayout.Header>
              <TaskHeader
                pull={fetchedPull}
                session={mostRecentSession}
                isContentPreviewOpen={isContentPreviewOpen}
                openPreviewPane={openPreviewPane}
              />
            </PacerLayout.Header>
          )}
          <PacerLayout.Sidebar>
            <CopilotNavigationWithContext />
          </PacerLayout.Sidebar>
          <PacerLayout.ColumnLeft>
            <TaskChatSuspended />
          </PacerLayout.ColumnLeft>
          {isTaskViewable && (
            <PacerLayout.ColumnRight>
              <ContentPreview
                returnFocusRef={ref}
                disableActionsMenu
                disableResourcePanel
                className={styles.contentPreview}
              />
            </PacerLayout.ColumnRight>
          )}
        </PacerLayout>
      </PullContextProvider>
    </CurrentUserProvider>
  )
}

import {announce} from '@github-ui/aria-live'
import {DuplicateOnKeydownButton} from '@github-ui/code-view-shared/components/DuplicateOnKeydownButton'
import {
  useBlobFocusedModifierShortcuts,
  useBlobFocusedShortcuts,
  useShortcut,
} from '@github-ui/code-view-shared/hooks/shortcuts'
import useColorModes from '@github-ui/react-core/use-color-modes'
// eslint-disable-next-line no-restricted-imports
import {ScreenSize} from '@github-ui/screen-size'
import {useCodeViewOptions} from '@github-ui/use-code-view-options'
import {useState} from 'react'

import {useCurrentLineHeight} from '../../../../hooks/use-current-line-height'
import {minLeftOffsetBlob, scrollRightOffset, useIsCursorEnabled} from '../../../../hooks/use-cursor-navigation'
import {calculateLineNumberFromOffset, textAreaId} from '../../../../utilities/lines'
import {TextAreaHelpDialog} from './TextAreaHelpDialog'

//this is the height of the content that exists above where the code lines begin. This is also the
//approximation for users that do not have the staff bar enabled, which I think is the better choice to use
//it also highly likely will never be needed, but in the off chance something goes wrong this fallback is here
//to help approximate the correct offset
const approximateBlobYOffsetDesktop = 354
const approximateBlobYOffsetMobile = 423

export function TextArea({
  textAreaRef,
  setTextOverlayShouldBeVisible,
  setTextSelection,
  setAdditionalTextAreaInstructions,
  cursorClickStartRef,
  parentRef,
  tabSize,
  plainTextLinesAsString,
  numLines,
  setIsTextAreaFocused,
}: {
  textAreaRef: React.RefObject<HTMLTextAreaElement | null>
  setTextOverlayShouldBeVisible: (shouldRender: boolean) => void
  setTextSelection: ({
    start,
    end,
    keyboard,
  }: {
    start: number
    end: number
    keyboard: boolean
    displayStart: boolean
  }) => void
  setAdditionalTextAreaInstructions: (instructions: string) => void
  cursorClickStartRef: React.MutableRefObject<{startX: number; startY: number}> | undefined
  parentRef: React.RefObject<HTMLDivElement | null>
  tabSize: number
  plainTextLinesAsString: string
  numLines: number
  setIsTextAreaFocused: (value: React.SetStateAction<boolean>) => void
}) {
  const shouldUseCursor = useIsCursorEnabled()
  const wrapOption = useCodeViewOptions().codeWrappingOption
  const blobFocusShortcuts = useBlobFocusedShortcuts()
  const blobFocusModifierShortcuts = useBlobFocusedModifierShortcuts()
  const lineHeight = useCurrentLineHeight('react-line-numbers')

  const textAreaHeight = lineHeight * (numLines + 1)
  const [helpDialogOpen, setHelpDialogOpen] = useState(false)
  const {cursorNavigationOpenHelpDialog} = useShortcut()
  const {colorMode, dayScheme, nightScheme} = useColorModes()
  const activeScheme = colorMode === 'night' ? nightScheme : dayScheme
  const isHighContrast = activeScheme?.endsWith('high_contrast')

  //we wonly want an exact regex match of a single character, not a substring match
  function exactRegexMatch(regex: RegExp, text: string) {
    const match = regex.exec(text)
    return match && match[0] === text
  }

  function handleKeydownWithinTextArea(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    // we need to use the e.key syntax here because we need to know when to preventDefault and when not to
    if (
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      blobFocusShortcuts.includes(e.key) ||
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      (blobFocusModifierShortcuts.includes(e.key) &&
        (e.getModifierState('Control') ||
          e.getModifierState('Alt') ||
          e.getModifierState('Shift') ||
          e.getModifierState('Meta')))
    ) {
      //handle the scrolling for space and shift space (can't do it with data-hotkey because space is not a usable hotkey)
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      if (e.key === ' ') {
        e.preventDefault()
        if (e.shiftKey) {
          //appending the date.now to the end so that pressing the same key multiple times in a row still triggers
          //a sate update
          setAdditionalTextAreaInstructions(`PageUp${Date.now()}`)
        } else {
          setAdditionalTextAreaInstructions(`PageDown${Date.now()}`)
        }
      }

      //need to explicitly call out the dot hotkey because data-hotkey doesn't work with the dot character, like space
      //and because macs are weird, when you press option + a letter, it changes it to be some weird symbol by defualt
      //instead of just showing up as alt + the letter
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      if (e.altKey && e.ctrlKey && e.key === '˙') {
        setHelpDialogOpen(true)
      }
      setTextOverlayShouldBeVisible(false)
      requestAnimationFrame(() => {
        if (textAreaRef.current) {
          setTextSelection({
            start: textAreaRef.current.selectionStart,
            end: textAreaRef.current.selectionEnd,
            keyboard: true,
            displayStart: false,
          })
        }
      })
      //don't do anything because we want the hotkey behavior to be handled by the data-hotkey handlers
      //max line length requiring the eslint disable to be used multiple times
    } else if (
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      !e.ctrlKey &&
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      !e.metaKey &&
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      !e.altKey &&
      !e.shiftKey &&
      // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
      (exactRegexMatch(/[a-zA-Z0-9-_ ]{1,1}/, e.key) || e.key === 'Backspace' || e.key === 'Enter')
    ) {
      //add the you can't edit this popup
      announce('Code view is read only.')
      setTextOverlayShouldBeVisible(true)
      e.preventDefault()
    } else {
      //don't do anything because we want the regular key press to work (tab, etc)
    }
  }

  return (
    <>
      <textarea
        id={textAreaId}
        data-testid={textAreaId}
        ref={textAreaRef}
        onMouseUp={event =>
          mouseUpHandler(
            event,
            textAreaRef,
            setTextOverlayShouldBeVisible,
            setTextSelection,
            cursorClickStartRef,
            shouldUseCursor,
            parentRef,
            lineHeight,
          )
        }
        onMouseDown={event => mouseDownHandler(event, parentRef, shouldUseCursor, cursorClickStartRef, lineHeight)}
        aria-label={'file content'}
        aria-readonly
        //this prevents the virtual keyboard from being popped up when a user is on mobile
        inputMode={'none'}
        tabIndex={0}
        aria-multiline
        aria-haspopup={false}
        //needed to disable grammarly so that random code snippets don't get highlighted as grammar errors
        data-gramm="false"
        data-gramm_editor="false"
        data-enable-grammarly="false"
        style={{
          resize: 'none',
          marginTop: -2,
          paddingLeft: minLeftOffsetBlob,
          paddingRight: scrollRightOffset,
          display: 'hidden',
          width: '100%',
          backgroundColor: 'unset',
          boxSizing: 'border-box',
          color: 'transparent',
          position: 'absolute',
          border: 'none',
          tabSize,
          outline: 'none',
          overflowX: 'auto',
          height: textAreaHeight,
          fontSize: '12px',
          lineHeight: '20px',
          overflowY: 'hidden',
          overflowWrap: wrapOption.enabled ? 'anywhere' : 'normal',
          overscrollBehaviorX: 'none',
          whiteSpace: wrapOption.enabled ? 'pre-wrap' : 'pre',
          zIndex: 1,
        }}
        value={plainTextLinesAsString}
        onKeyDown={handleKeydownWithinTextArea}
        spellCheck={false}
        autoCorrect="off"
        autoCapitalize="off"
        autoComplete="off"
        data-ms-editor="false"
        onDrop={e => {
          //if a user dropped a URL on the text area, open it in a new tab like it normally would instead of eating it
          const text = e.dataTransfer.getData('Text')
          try {
            // eslint-disable-next-line no-restricted-syntax
            const url = new URL(text)
            window.open(url, '_blank')?.focus()
          } catch {
            //the thing dropped was not a URL, catch but don't do anything
          }
          return false
        }}
        onPaste={e => {
          e.preventDefault()
          return false
        }}
        onChange={() => {
          //need an empty on change handler to prevent react from complaining about a controlled component
          //we don't actually want to change the value on the textarea because it's readonly
          //but we can't put the readonly attribute on the textarea because then it won't be focusable
        }}
        className={`react-blob-textarea react-blob-print-hide${isHighContrast ? ' select-contrast' : ''}`}
        onFocus={() => {
          setIsTextAreaFocused(true)
        }}
      />
      {helpDialogOpen && (
        <TextAreaHelpDialog
          onDismiss={() => {
            setHelpDialogOpen(false)
          }}
        />
      )}
      <DuplicateOnKeydownButton
        buttonFocusId={textAreaId}
        buttonHotkey={cursorNavigationOpenHelpDialog.hotkey}
        onButtonClick={() => {
          setHelpDialogOpen(true)
        }}
        onlyAddHotkeyScopeButton
      />
    </>
  )
}

//mouseUpHandler will always fire before the onClick handler, so we will reset the information in the click handler
//if the user did a double or triple click
function mouseUpHandler(
  event: React.MouseEvent,
  textAreaRef: React.RefObject<HTMLTextAreaElement | null> | undefined,
  setTextOverlayShouldBeVisible: (shouldRender: boolean) => void,
  setTextSelection: ({
    start,
    end,
    keyboard,
  }: {
    start: number
    end: number
    keyboard: boolean
    displayStart: boolean
  }) => void,
  cursorClickStartRef: React.MutableRefObject<{startX: number; startY: number}> | undefined,
  shouldUseCursor: boolean,
  parentRef: React.RefObject<HTMLDivElement | null>,
  lineHeight: number,
) {
  if (!shouldUseCursor || event.defaultPrevented || !cursorClickStartRef) return

  if (event.button === 2) {
    event.preventDefault()
    event.stopPropagation()
    //it was a right click
  } else if (event.button === 0) {
    setTextOverlayShouldBeVisible(false)

    const isSmallScreen = window.matchMedia(`(max-width: ${ScreenSize.medium - 1}px)`).matches
    // Cache rect once to avoid layout thrashing - all reads happen synchronously
    const parentRect = parentRef.current?.getBoundingClientRect()

    const scrollTopOffset = parentRect?.top
      ? window.scrollY + parentRect.top
      : isSmallScreen
        ? approximateBlobYOffsetMobile
        : approximateBlobYOffsetDesktop
    // Check if it the click is in the lines excluding the scroll bar
    if (parentRef.current && event.pageY > scrollTopOffset + parentRef.current?.clientHeight) {
      cursorClickStartRef.current = {startX: -2, startY: -2}
      return
    }
    const lineNumberOfClick = calculateLineNumberFromOffset(event.pageY, scrollTopOffset, lineHeight)
    const leftClickOffset = parentRect?.left || 0
    const xOffset = event.clientX - leftClickOffset - minLeftOffsetBlob

    let displayAtStart = false
    if (
      lineNumberOfClick < cursorClickStartRef.current.startY ||
      (lineNumberOfClick === cursorClickStartRef.current.startY && xOffset < cursorClickStartRef.current.startX)
    ) {
      displayAtStart = true
    }
    requestAnimationFrame(() => {
      if (textAreaRef && textAreaRef.current) {
        setTextSelection({
          start: textAreaRef.current.selectionStart,
          end: textAreaRef.current.selectionEnd,
          keyboard: false,
          displayStart: displayAtStart,
        })
      }
    })
  }
}
function mouseDownHandler(
  event: React.MouseEvent,
  parentRef: React.RefObject<HTMLDivElement | null>,
  shouldUseCursor: boolean,
  cursorClickStartRef: React.MutableRefObject<{startX: number; startY: number}> | undefined,
  lineHeight: number,
) {
  if (!shouldUseCursor || event.defaultPrevented || !cursorClickStartRef) return
  if (event.button === 2) {
    event.preventDefault()
    event.stopPropagation()
    return
    //it was a right click
  } else if (event.button === 0) {
    //it was a left click

    // eslint-disable-next-line @github-ui/ui-commands/no-manual-shortcut-logic
    if (event.ctrlKey) {
      //it was a right click essentially
      event.preventDefault()
      event.stopPropagation()
      return
    }

    const isSmallScreen = window.matchMedia(`(max-width: ${ScreenSize.medium - 1}px)`).matches
    // Cache rect once to avoid layout thrashing - all reads happen synchronously
    const parentRect = parentRef.current?.getBoundingClientRect()

    const scrollTopOffset = parentRect?.top
      ? window.scrollY + parentRect.top
      : isSmallScreen
        ? approximateBlobYOffsetMobile
        : approximateBlobYOffsetDesktop
    // Check if it the click is in the lines excluding the scroll bar
    if (parentRef.current && event.pageY > scrollTopOffset + parentRef.current?.clientHeight) {
      cursorClickStartRef.current = {startX: -2, startY: -2}
      return
    }
    const lineNumberOfClick = calculateLineNumberFromOffset(event.pageY, scrollTopOffset, lineHeight)
    const leftClickOffset = parentRect?.left || 0
    const xOffset = event.clientX - leftClickOffset - minLeftOffsetBlob
    cursorClickStartRef.current = {startX: xOffset, startY: lineNumberOfClick}
  }
}

import {useShortcut} from '@github-ui/code-view-shared/hooks/shortcuts'
import {Dialog} from '@primer/react/experimental'
import {createPortal} from 'react-dom'

export function TextAreaHelpDialog({onDismiss}: {onDismiss: () => void}) {
  const {expandAndFocusLineContextMenu, cursorNavigationEnter, cursorNavigationHighlightLine} = useShortcut()
  return createPortal(
    <Dialog width="large" aria-label="Code Blob Focused Hotkeys" onClose={onDismiss} title="Code Blob Focused Hotkeys">
      <div>
        <div>
          <div className="p-1">
            Select the line the cursor is on <kbd>{cursorNavigationHighlightLine.text}</kbd>
          </div>
          <div className="p-1">
            Select the symbol under the cursor <kbd>{cursorNavigationEnter.text}</kbd>
          </div>
          <div className="p-1">
            Move focus to the highlighted line menu <kbd>{expandAndFocusLineContextMenu.text}</kbd>
          </div>
        </div>
      </div>
    </Dialog>,
    document.body,
  )
}

