// Maximum character length for markdown content to prevent parser performance issues
const MAX_MARKDOWN_LENGTH = 100_000
// Height threshold for tool content preview - content shorter than this will be shown fully expanded
// Imported from CSS modules to keep CSS and JS in sync
const TOOL_PREVIEW_HEIGHT_THRESHOLD = parseInt(styles.toolPreviewHeightThreshold, 10)

const wrapInCodeBlock = ({language, markdown}: {language: string; markdown: string}) => {
  if (!markdown) {
    return `~~~\nNothing to display\n~~~`
  }

  // Use ~~~ for the delimiter to avoid conflicts with backticks. This is acceptable by remark-gfm, the underlying rendering library.
  return `~~~${language}\n${markdown}\n~~~`
}

/**
 * Truncates markdown content to prevent the markdown parser from performance issues.
 * Returns the truncated content and a flag indicating if truncation occurred.
 * If truncation fails, returns the original markdown.
 */
function truncateMarkdownContent(
  markdown: string | undefined,
  maxLength: number = MAX_MARKDOWN_LENGTH,
): {markdown: string | undefined} {
  if (!markdown || markdown.length <= maxLength) {
    return {markdown}
  }

  const truncated = markdown.slice(0, maxLength)
  const truncationMessage = `\n\n⚠️ **Output truncated**`

  return {
    markdown: truncated + truncationMessage,
  }
}

