import type {TreePane} from '@github-ui/repos-file-tree-view'
import {createContext, use, useMemo} from 'react'

type TreePaneContextValue = TreePane & {
  onFindFilesShortcut: () => void
}

const TreePaneContext = createContext<TreePaneContextValue | null>(null)

export function TreePaneProvider({
  children,
  treePaneState,
  onFindFilesShortcut,
}: {
  children: React.ReactNode
  treePaneState: TreePane
  onFindFilesShortcut: () => void
}) {
  const {isTreeExpanded, expandTree, collapseTree, treeToggleElement, treeToggleRef, searchBoxRef} = treePaneState
  const value = useMemo(
    () => ({
      isTreeExpanded,
      expandTree,
      collapseTree,
      treeToggleElement,
      treeToggleRef,
      searchBoxRef,
      onFindFilesShortcut,
    }),
    [isTreeExpanded, expandTree, collapseTree, treeToggleElement, treeToggleRef, searchBoxRef, onFindFilesShortcut],
  )
  return <TreePaneContext value={value}>{children}</TreePaneContext>
}

export function useTreePaneContext() {
  const context = use(TreePaneContext)
  if (!context) {
    throw new Error('useTreePaneContext must be used within TreePaneProvider')
  }
  return context
}

// Makes sure we don't show the ultra long path, but rather just the path that's relevant to the user.
// Turns /home/runner/work/sweagentd/sweagentd/src/app/App.tsx into src/app/App.tsx.
// Also handles Windows paths like D:\a\cca-windows-test\cca-windows-test\src\app\App.tsx.

export function trimFileName(path: string): string | undefined {
  try {
    // Handle Windows-style paths (e.g., D:\a\repo-name\repo-name\...)
    // Regex breakdown:
    //   ^[A-Za-z]:    - Drive letter (e.g., D:)
    //   \\a\\         - The GitHub Actions work directory (\a\)
    //   [^\\]+\\      - First occurrence of repo name (e.g., cca-windows-test\)
    //   [^\\]+\\      - Second occurrence of repo name (GitHub Actions duplicates it)
    //   (.*)$         - Capture the remaining relative path
    const windowsMatch = path.match(/^[A-Za-z]:\\a\\[^\\]+\\[^\\]+\\(.*)$/)
    if (windowsMatch && windowsMatch[1] !== undefined) {
      // Convert Windows backslashes to forward slashes for consistency
      const relativePath = windowsMatch[1].replace(/\\/g, '/')
      return relativePath.length > 0 ? relativePath : undefined
    }

    // Handle Unix-style paths (e.g., /home/runner/work/repo-name/repo-name/...)
    const shortenedPath = path.replace('/home/runner/work/', '').split('/').slice(2).join('/')
    return shortenedPath.length > 0 ? shortenedPath : undefined // Special-case the root when viewing the repo, we handle outside
  } catch {
    return path
  }
}

import {SWEAGENT_CAPI_MODEL_PREFIX} from './constants'

export function trimModelName(modelName: string): string {
  return modelName.startsWith(SWEAGENT_CAPI_MODEL_PREFIX)
    ? modelName.slice(SWEAGENT_CAPI_MODEL_PREFIX.length)
    : modelName
}

export function truncateLines(text: string, maxCharsPerLine = 50, lines = 2): string {
  const maxChars = maxCharsPerLine * lines
  if (text.length <= maxChars) return text
  return `${text.substring(0, maxChars).trim()}...`
}

